import React, { useState, useEffect, useRef } from 'react';
import { generateAuraResponse, analyzeSearchIntent, generateAuraImage, generateTrendingProducts, SearchIntent } from '../services/geminiService';
import { getProducts, getVendors, getLiveSales } from '../services/mockData';
import { ProductCard } from '../components/ProductCard';
import { ChatMessage, Product, Vendor } from '../types';
import { Sparkles, Send, Trash2, Clock, Image as ImageIcon, Loader2, Filter, X, Wand2, Info, Tag, Building2, AlertCircle } from 'lucide-react';

export const Home: React.FC = () => {
  const [allProducts, setAllProducts] = useState<Product[]>([]);
  const [fictionalProducts, setFictionalProducts] = useState<Product[]>([]);
  const [products, setProducts] = useState<Product[]>([]);
  const [vendors, setVendors] = useState<Vendor[]>([]);
  const [salesTicker, setSalesTicker] = useState(0);
  const [isFiltered, setIsFiltered] = useState(false);
  const [selectedVendorId, setSelectedVendorId] = useState<number | null>(null);
  const [activeIntent, setActiveIntent] = useState<SearchIntent | null>(null);
  const [isGeneratingTrends, setIsGeneratingTrends] = useState(false);

  // Error handling state
  const [apiError, setApiError] = useState<string | null>(null);

  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'ai', content: "আসসালামু আলাইকুম। Snehalata-স্নেহলতা ইকোসিস্টেমে স্বাগতম। আমি Aura। আজ আপনার স্টাইল যাত্রায় কীভাবে সাহায্য করতে পারি?", timestamp: Date.now() }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [isGeneratingImage, setIsGeneratingImage] = useState(false);
  const chatContainerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const initialProducts = getProducts();
    setAllProducts(initialProducts);
    setProducts(initialProducts);
    setVendors(getVendors());
    setSalesTicker(getLiveSales());

    const interval = setInterval(() => {
        setSalesTicker(prev => prev + Math.floor(Math.random() * 500));
    }, 5000);
    return () => clearInterval(interval);
  }, []);

  // Auto-hide errors
  useEffect(() => {
    if (apiError) {
      const timer = setTimeout(() => setApiError(null), 5000);
      return () => clearTimeout(timer);
    }
  }, [apiError]);

  // Synchronize products based on filters and selected vendor
  useEffect(() => {
    applyFilters();
  }, [selectedVendorId, activeIntent, fictionalProducts]);

  const applyFilters = () => {
    let filtered = [...allProducts, ...fictionalProducts];
    let hasFilter = !!selectedVendorId || !!activeIntent;

    filtered = filtered.filter(p => {
        const productData = `${p.name} ${p.description} ${p.category}`.toLowerCase();

        // Manual Vendor Filter
        if (selectedVendorId && p.vendorId !== selectedVendorId) return false;

        // AI Intent Filtering
        if (activeIntent) {
            let score = 0;
            if (activeIntent.category && productData.includes(activeIntent.category.toLowerCase())) score += 10;
            if (activeIntent.color && productData.includes(activeIntent.color.toLowerCase())) score += 5;
            if (activeIntent.material && productData.includes(activeIntent.material.toLowerCase())) score += 8;
            if (activeIntent.style && productData.includes(activeIntent.style.toLowerCase())) score += 5;

            if (activeIntent.maxPrice && p.price > activeIntent.maxPrice) return false;
            if (activeIntent.minPrice && p.price < activeIntent.minPrice) return false;

            if (activeIntent.semanticKeywords && activeIntent.semanticKeywords.length > 0) {
                activeIntent.semanticKeywords.forEach(keyword => {
                    if (productData.includes(keyword.toLowerCase())) score += 2;
                });
            }

            // Only filter by intent if intent actually contains specific parameters
            if (activeIntent.category || activeIntent.color || activeIntent.material || activeIntent.style || (activeIntent.semanticKeywords && activeIntent.semanticKeywords.length > 0)) {
                if (score === 0) return false;
            }
        }

        return true;
    });

    setProducts(filtered);
    setIsFiltered(hasFilter);
  };

  useEffect(() => {
    if (chatContainerRef.current) {
      chatContainerRef.current.scrollTop = chatContainerRef.current.scrollHeight;
    }
  }, [messages, isTyping, isGeneratingImage]);

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isTyping) return;

    const userMsg: ChatMessage = { role: 'user', content: input, timestamp: Date.now() };
    setMessages(prev => [...prev, userMsg]);
    const currentInput = input;
    setInput('');
    setIsTyping(true);
    setApiError(null);

    try {
      const intentPromise = analyzeSearchIntent(currentInput);
      const responsePromise = generateAuraResponse(currentInput);

      const [auraResponse, intent] = await Promise.all([responsePromise, intentPromise]);

      setIsTyping(false);

      if (intent) {
        setActiveIntent(intent);
      }

      let generatedImageUrl = undefined;
      if (intent?.shouldGenerateImage && intent.imagePrompt) {
          setIsGeneratingImage(true);
          try {
            const img = await generateAuraImage(intent.imagePrompt);
            generatedImageUrl = img || undefined;
          } catch (imgErr) {
            console.error("Image generation failed", imgErr);
            setApiError("Aura ইমেজ জেনারেশনে সমস্যা হয়েছে। টেক্সট রেসপন্স দেখুন।");
          } finally {
            setIsGeneratingImage(false);
          }
      }

      setMessages(prev => [...prev, { 
          role: 'ai', 
          content: auraResponse || "আসসালামু আলাইকুম। দুঃখিত, আমি আপনার অনুরোধটি বুঝতে পারছি না।", 
          timestamp: Date.now(),
          generatedImageUrl 
      }]);
    } catch (error) {
      console.error("Aura interaction error:", error);
      setIsTyping(false);
      setApiError("দুঃখিত, Aura সার্ভারে সংযোগ করা যাচ্ছে না। দয়া করে আবার চেষ্টা করুন।");
      setMessages(prev => [...prev, { 
          role: 'ai', 
          content: "আসসালামু আলাইকুম। যান্ত্রিক ত্রুটির কারণে আমি এখন উত্তর দিতে পারছি না। কিছুক্ষণ পর আবার মেসেজ দিন।", 
          timestamp: Date.now() 
      }]);
    }
  };

  const handleGenerateTrends = async () => {
    if (isGeneratingTrends) return;
    setIsGeneratingTrends(true);
    setApiError(null);

    try {
      const trends = await generateTrendingProducts();
      if (!trends || trends.length === 0) {
        throw new Error("No trends generated");
      }

      const formattedTrends: Product[] = trends.map(t => ({
          ...t,
          vendorId: 0, 
          id: t.id + 1000 
      }));

      setFictionalProducts(prev => [...prev, ...formattedTrends]);

      setMessages(prev => [...prev, {
          role: 'ai',
          content: "আসসালামু আলাইকুম। আমি ২০২৬ সালের সম্ভাব্য ট্রেন্ড থেকে কিছু কাল্পনিক ডিজাইন তৈরি করেছি। আপনার গ্রিডের নিচে দেখুন!",
          timestamp: Date.now()
      }]);

      const section = document.getElementById('product-section');
      section?.scrollIntoView({ behavior: 'smooth' });
    } catch (error) {
      console.error("Trend generation error:", error);
      setApiError("ট্রেন্ডিং প্রোডাক্ট জেনারেট করা সম্ভব হয়নি। Aura সিস্টেম আপডেট হচ্ছে।");
    } finally {
      setIsGeneratingTrends(false);
    }
  };

  const resetFilters = () => {
      setSelectedVendorId(null);
      setActiveIntent(null);
      setIsFiltered(false);
  };

  const clearChat = () => {
    setMessages([{ role: 'ai', content: "আসসালামু আলাইকুম। নতুন করে শুরু করি? আমি Aura, আপনার সেবায় নিয়োজিত।", timestamp: Date.now() }]);
  };

  return (
    <div className="min-h-screen">
      {/* Error Notification Banner */}
      {apiError && (
        <div className="fixed top-24 left-1/2 -translate-x-1/2 z-[100] w-full max-w-md px-4 animate-in slide-in-from-top-10 duration-500">
           <div className="bg-red-500/90 backdrop-blur-xl text-white p-4 rounded-2xl shadow-2xl border border-red-400/50 flex items-start gap-3">
              <AlertCircle className="shrink-0 mt-0.5" size={18} />
              <div className="flex-1">
                 <h4 className="text-xs font-bold uppercase tracking-widest mb-1">Aura System Alert</h4>
                 <p className="text-sm font-medium">{apiError}</p>
              </div>
              <button onClick={() => setApiError(null)} className="p-1 hover:bg-white/20 rounded-lg transition-colors">
                 <X size={16} />
              </button>
           </div>
        </div>
      )}

      <section className="relative min-h-[600px] flex flex-col items-center justify-center px-6 py-20 overflow-hidden">
        {/* Core Glow Background */}
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[800px] h-[800px] bg-aura-purple/5 blur-[120px] rounded-full pointer-events-none" />

        <div className="relative z-10 w-full max-w-4xl flex flex-col gap-10">
          <div className="text-center space-y-4">
             <div className="inline-flex items-center gap-2 px-4 py-2 rounded-full border border-aura-glassBorder bg-white/5 backdrop-blur-md">
                <span className="relative flex h-2 w-2">
                  <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-400 opacity-75"></span>
                  <span className="relative inline-flex rounded-full h-2 w-2 bg-green-500"></span>
                </span>
                <span className="text-[10px] uppercase tracking-[0.2em] font-bold text-gray-400">
                   Ecosystem ভলিউম: ৳{salesTicker.toLocaleString()}
                </span>
             </div>
             <h1 className="text-4xl md:text-6xl font-serif font-black text-white leading-tight">
               SNEHALATA-স্নেহলতা
             </h1>
          </div>

          <div className="w-full bg-black/60 backdrop-blur-xl border border-white/10 rounded-3xl overflow-hidden shadow-2xl flex flex-col h-[500px]">
            <div className="flex items-center justify-between px-6 py-4 border-b border-white/10 bg-white/5">
                <div className="flex items-center gap-2">
                    <Sparkles size={16} className="text-aura-purple" />
                    <span className="text-xs font-bold uppercase tracking-widest text-white">Aura Live Assistant</span>
                </div>
                <button onClick={clearChat} className="text-gray-500 hover:text-red-400 transition-colors">
                    <Trash2 size={16} />
                </button>
            </div>

            <div className="flex-1 p-6 overflow-y-auto space-y-6 scroll-smooth" ref={chatContainerRef}>
              {messages.map((msg, idx) => (
                <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                  <div className={`max-w-[85%] rounded-2xl p-4 text-sm ${msg.role === 'user' ? 'bg-white text-black font-medium' : 'bg-white/10 text-gray-200 border border-white/5'}`}>
                    {msg.role === 'ai' && <div className="text-[10px] uppercase tracking-widest text-aura-purple mb-1 font-bold">Aura AI</div>}
                    <div className="whitespace-pre-wrap">{msg.content}</div>

                    {msg.generatedImageUrl && (
                        <div className="mt-4 rounded-xl overflow-hidden border border-white/10 shadow-lg">
                            <img src={msg.generatedImageUrl} alt="AI Concept" className="w-full h-auto" />
                            <div className="bg-black/40 backdrop-blur-md p-2 flex items-center gap-2 text-[10px] font-bold uppercase tracking-widest text-gray-400">
                                <ImageIcon size={12} /> Aura Conceptual Preview
                            </div>
                        </div>
                    )}

                    <div className="mt-2 text-[10px] flex items-center justify-end gap-1 opacity-50">
                        {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                        <Clock size={10} />
                    </div>
                  </div>
                </div>
              ))}

              {isTyping && (
                <div className="flex justify-start">
                   <div className="bg-white/5 rounded-2xl p-4 flex gap-2">
                     <span className="w-2 h-2 bg-aura-purple rounded-full animate-bounce"></span>
                     <span className="w-2 h-2 bg-aura-purple rounded-full animate-bounce delay-75"></span>
                     <span className="w-2 h-2 bg-aura-purple rounded-full animate-bounce delay-150"></span>
                   </div>
                </div>
              )}

              {isGeneratingImage && (
                <div className="flex justify-start">
                   <div className="bg-aura-purple/10 border border-aura-purple/20 rounded-2xl p-4 flex items-center gap-3">
                     <Loader2 size={16} className="text-aura-purple animate-spin" />
                     <span className="text-xs font-bold uppercase tracking-widest text-aura-purple animate-pulse">Aura is imagining your design...</span>
                   </div>
                </div>
              )}
            </div>

            <form onSubmit={handleSendMessage} className="p-4 bg-white/5 border-t border-white/10">
              <div className="flex gap-2">
                <div className="relative flex-1">
                    <input 
                    type="text" 
                    value={input}
                    onChange={(e) => setInput(e.target.value)}
                    placeholder="রঙ বা ডিজাইন বলুন (যেমন: 'লাল শাড়ি দেখাও')"
                    className="w-full bg-black/50 border border-white/10 rounded-xl pl-5 pr-12 py-4 focus:outline-none focus:border-aura-purple text-sm text-white disabled:opacity-50"
                    disabled={isTyping}
                    />
                    <button 
                      type="submit" 
                      disabled={!input.trim() || isTyping}
                      className="absolute right-2 top-2 p-2 bg-aura-purple rounded-lg text-white disabled:opacity-50 disabled:bg-gray-700"
                    >
                      <Send size={18} />
                    </button>
                </div>
                <button 
                    type="button" 
                    onClick={handleGenerateTrends}
                    disabled={isGeneratingTrends}
                    className="bg-white/5 hover:bg-white/10 border border-white/10 rounded-xl px-4 py-2 text-white flex items-center gap-2 transition-all disabled:opacity-50"
                >
                    {isGeneratingTrends ? (
                        <Loader2 size={18} className="animate-spin text-aura-purple" />
                    ) : (
                        <Wand2 size={18} className="text-aura-purple" />
                    )}
                    <span className="hidden md:inline text-xs font-bold uppercase tracking-widest">Trends</span>
                </button>
              </div>
            </form>
          </div>
        </div>
      </section>

      {/* Manual Vendor Filter Bar */}
      <div className="max-w-7xl mx-auto px-6 mb-12">
          <div className="flex items-center gap-4 overflow-x-auto pb-4 scrollbar-hide">
              <div className="flex items-center gap-2 text-xs font-bold uppercase tracking-widest text-gray-500 whitespace-nowrap">
                  <Building2 size={14} /> ভেন্ডর অনুযায়ী দেখুন:
              </div>
              <button 
                  onClick={() => setSelectedVendorId(null)}
                  className={`px-6 py-2 rounded-full text-[10px] font-bold uppercase tracking-widest border transition-all whitespace-nowrap ${!selectedVendorId ? 'bg-white text-black border-white' : 'bg-white/5 border-white/10 text-gray-400 hover:border-white/20'}`}
              >
                  All Hub
              </button>
              {vendors.filter(v => v.status === 'APPROVED').map(vendor => (
                  <button 
                      key={vendor.id}
                      onClick={() => setSelectedVendorId(vendor.id)}
                      className={`px-6 py-2 rounded-full text-[10px] font-bold uppercase tracking-widest border transition-all whitespace-nowrap ${selectedVendorId === vendor.id ? 'bg-aura-purple text-white border-aura-purple' : 'bg-white/5 border-white/10 text-gray-400 hover:border-white/20'}`}
                  >
                      {vendor.name}
                  </button>
              ))}
          </div>
      </div>

      {isFiltered && activeIntent && (
          <div className="max-w-7xl mx-auto px-6 mb-8 animate-in slide-in-from-top-4">
              <div className="bg-white/5 backdrop-blur-md border border-white/10 rounded-2xl p-4 flex flex-wrap items-center gap-4">
                  <div className="flex items-center gap-2 text-aura-purple font-bold text-xs uppercase tracking-widest">
                      <Info size={14} /> Aura Filters Active:
                  </div>
                  <div className="flex flex-wrap gap-2">
                      {activeIntent.category && <FilterChip label="Category" value={activeIntent.category} />}
                      {activeIntent.color && <FilterChip label="Color" value={activeIntent.color} />}
                      {activeIntent.material && <FilterChip label="Material" value={activeIntent.material} />}
                      {activeIntent.style && <FilterChip label="Style" value={activeIntent.style} />}
                      {activeIntent.maxPrice && <FilterChip label="Max Price" value={`৳${activeIntent.maxPrice}`} />}
                  </div>
                  <button onClick={resetFilters} className="ml-auto text-xs text-gray-500 hover:text-white underline decoration-aura-purple">
                      Reset Results
                  </button>
              </div>
          </div>
      )}

      <section id="product-section" className="max-w-7xl mx-auto px-6 py-10">
        <div className="flex items-center justify-between mb-10">
            <h2 className="text-2xl font-serif font-bold flex items-center gap-4">
                <Sparkles className="text-aura-purple" />
                {isFiltered ? 'Aura Filtered Results' : ' ট্রেন্ডিং কালেকশন'}
            </h2>
            {isFiltered && (
                <button onClick={resetFilters} className="flex items-center gap-2 px-4 py-2 bg-white/10 rounded-full text-[10px] font-bold uppercase tracking-widest hover:bg-white/20 transition-colors">
                    <X size={14} /> Clear All Filters
                </button>
            )}
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
            {products.length === 0 ? (
                <div className="col-span-full py-20 text-center bg-white/5 rounded-3xl border border-dashed border-white/10">
                    <Building2 className="mx-auto text-gray-600 mb-4" size={48} />
                    <h3 className="text-xl font-bold text-gray-400">এই ফিল্টারে কোনো পণ্য পাওয়া যায়নি</h3>
                    <p className="text-sm text-gray-600 mt-2">অন্য কোনো ভেন্ডর বা ডিজাইন ট্রাই করুন।</p>
                </div>
            ) : (
                products.map(p => (
                    <div key={p.id} className="relative">
                        {p.vendorId === 0 && (
                            <div className="absolute -top-3 -right-3 z-20 bg-aura-purple text-white px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-widest shadow-lg flex items-center gap-1">
                                <Sparkles size={10} /> AI Concept
                            </div>
                        )}
                        <ProductCard 
                            product={p} 
                            vendor={p.vendorId === 0 ? { id: 0, name: "Aura Innovations", slug: "aura", status: "APPROVED", description: "AI Generated Concepts" } : vendors.find(v => v.id === p.vendorId)} 
                        />
                    </div>
                ))
            )}
        </div>
      </section>
    </div>
  );
};

const FilterChip: React.FC<{ label: string, value: string, variant?: 'primary' | 'ghost' }> = ({ label, value, variant = 'primary' }) => (
    <div className={`px-3 py-1 rounded-lg border text-[10px] font-bold flex items-center gap-2 ${
        variant === 'primary' 
        ? 'bg-white/10 border-white/20 text-white' 
        : 'bg-transparent border-white/10 text-gray-400'
    }`}>
        <Tag size={10} className="text-aura-purple" />
        <span className="uppercase tracking-tighter opacity-60">{label}:</span>
        <span>{value}</span>
    </div>
);

import { GoogleGenAI, Type } from "@google/genai";
import { getProducts, getVendors } from "./mockData";

// --- SYSTEM CONTEXT ---
const buildAuraContext = () => {
  const products = getProducts();
  const vendors = getVendors();

  const productString = products.map(p => 
    `- ${p.name} (৳${p.price}) [Category: ${p.category}] by ${vendors.find(v => v.id === p.vendorId)?.name}. Desc: ${p.description}`
  ).join('\n');

  const vendorString = vendors.map(v => 
    `- ${v.name} (Status: ${v.status}): ${v.description}`
  ).join('\n');

  return `
Identity: AURA AI - The Divine Soul of SNEHALATA-স্নেহলতা Hub.
Tone: Formal, Artistic, Culturally respectful, Multi-lingual (Bangla & English).

CRITICAL DIRECTIVE:
ALWAYS start EVERY response with the greeting "আসসালামু আলাইকুম" (Assalamu Alaikum). This is mandatory for our ecosystem's brand identity.

Ecosystem Data:
VENDORS:
${vendorString}

PRODUCTS:
${productString}

Capabilities:
1. You can search products based on category, price, color, material, and style.
2. You can generate conceptual fashion images if users ask for specific colors or styles.
3. You provide governance for the multi-vendor marketplace.
  `;
};

// --- CHAT RESPONSE ---
export const generateAuraResponse = async (userPrompt: string): Promise<string> => {
  if (!process.env.API_KEY) return "Aura System Alert: API Key missing.";

  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: userPrompt,
      config: {
        systemInstruction: buildAuraContext(),
        temperature: 0.8,
      }
    });
    return response.text || "Aura is currently reflecting...";
  } catch (error) {
    console.error("Aura AI Error:", error);
    return "আসসালামু আলাইকুম। দুঃখিত, সংযোগে সমস্যা হচ্ছে।";
  }
};

// --- TRENDING PRODUCTS GENERATION ---
export const generateTrendingProducts = async (): Promise<any[]> => {
    if (!process.env.API_KEY) return [];

    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const prompt = `Generate 3 fictional, futuristic, or ultra-modern Bangladeshi fashion products that would be trending in 2026. 
        Focus on fusion of technology and tradition (e.g., smart Jamdani, LED Khadi, Cyberpunk Panjabi).
        Ensure prices are in BDT (৳).
        Include a category and a detailed description in a mix of English and Bengali.`;

        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            id: { type: Type.INTEGER },
                            name: { type: Type.STRING },
                            price: { type: Type.NUMBER },
                            description: { type: Type.STRING },
                            category: { type: Type.STRING },
                            imageUrl: { type: Type.STRING, description: "Use a placeholder like https://picsum.photos/400/600?random=ID" }
                        },
                        required: ["id", "name", "price", "description", "category", "imageUrl"]
                    }
                }
            }
        });

        const text = response.text;
        return text ? JSON.parse(text) : [];
    } catch (error) {
        console.error("Trend Gen Error:", error);
        return [];
    }
};

// --- IMAGE GENERATION ---
export const generateAuraImage = async (prompt: string): Promise<string | null> => {
    if (!process.env.API_KEY) return null;

    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash-image',
            contents: {
                parts: [{ text: `A photorealistic high-fashion editorial shot of a Bangladeshi garment, ${prompt}. High resolution, luxury fabric texture, professional studio lighting.` }],
            },
            config: {
                imageConfig: {
                    aspectRatio: "1:1"
                }
            }
        });

        for (const part of response.candidates[0].content.parts) {
            if (part.inlineData) {
                return `data:image/png;base64,${part.inlineData.data}`;
            }
        }
        return null;
    } catch (error) {
        console.error("Image Gen Error:", error);
        return null;
    }
};

// --- SEARCH INTENT ANALYSIS ---
export interface SearchIntent {
    category: string | null;
    maxPrice: number | null;
    minPrice: number | null;
    color: string | null;
    material: string | null;
    style: string | null;
    semanticKeywords: string[];
    isSearchQuery: boolean;
    shouldGenerateImage: boolean;
    imagePrompt: string | null;
}

export const analyzeSearchIntent = async (userPrompt: string): Promise<SearchIntent | null> => {
    if (!process.env.API_KEY) return null;

    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const prompt = `
        Analyze this fashion query for the Snehalata ecosystem: "${userPrompt}"

        Extract and Infer:
        1. Category (e.g., Saree, Panjabi)
        2. Price Range (min/max)
        3. Color (e.g., Red, Blue, Black)
        4. Material (e.g., Jamdani, Muslin, Cotton, Silk, Khadi)
        5. Style (e.g., Oversized, Formal, Traditional, Streetwear, Festive)
        6. semanticKeywords: Provide 10 related keywords in both English and Bengali that describe the VIBE, related materials, or synonyms. 
           Example: if "summer wear", add ["cotton", "lightweight", "breathable", "সুতি", "আরামদায়ক", "পাতলা"].

        Detection Rules:
        - If the user asks to "see", "show", "find" or mentions a product, isSearchQuery = true.
        - If the user asks to "imagine", "generate", or "concept", shouldGenerateImage = true.

        Return JSON ONLY:
        {
            "category": string | null,
            "maxPrice": number | null,
            "minPrice": number | null,
            "color": string | null,
            "material": string | null,
            "style": string | null,
            "semanticKeywords": string[],
            "isSearchQuery": boolean,
            "shouldGenerateImage": boolean,
            "imagePrompt": string | null
        }
        `;

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: { responseMimeType: 'application/json' }
        });

        return JSON.parse(response.text || '{}');
    } catch (error) {
        console.error("Intent Error:", error);
        return null;
    }
};

// --- TRY-ON ---
export const generateTryOnTransformation = async (userImageBase64: string, productImageBase64: string): Promise<string | null> => {
    if (!process.env.API_KEY) return null;
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const cleanUserImage = userImageBase64.replace(/^data:image\/(png|jpeg|jpg);base64,/, "");
      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: {
          parts: [
            { inlineData: { data: cleanUserImage, mimeType: 'image/jpeg' } },
            { text: "Drape the clothing item conceptually onto the person. Maintain realistic lighting." },
          ],
        },
      });
      for (const part of response.candidates[0].content.parts) {
          if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
      }
      return null; 
    } catch (error) {
      return null;
    }
};

// --- VENDOR AUDIT ---
export const auditVendorDescription = async (shopName: string, description: string, tradeLicense: string): Promise<{ status: 'APPROVED' | 'REJECTED' | 'PENDING'; reason: string }> => {
    if (!process.env.API_KEY) return { status: 'APPROVED', reason: 'Dev Mode' };
    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: `Shop Name: ${shopName}\nTrade License: ${tradeLicense}\nDescription: ${description}`,
            config: { 
                systemInstruction: `
                You are the Governance Auditor for SNEHALATA-স্নেহলতা.
                Audit the following vendor application for authenticity in the Bangladeshi fashion context.

                Rules:
                1. Look for cultural markers (Jamdani, Muslin, Khadi, heritage mentions).
                2. Verify if the description sounds professional and authentic.
                3. Trade License format check: Should typically contain alphanumeric patterns (e.g., TRD-YYYY-XXXX).
                4. If highly authentic and professional, status = APPROVED.
                5. If suspicious or counterfeit-sounding, status = REJECTED.
                6. If unsure but safe, status = PENDING.

                Respond in JSON: { "status": "APPROVED" | "REJECTED" | "PENDING", "reason": "Your reason in Bengali" }
                `,
                responseMimeType: 'application/json' 
            }
        });
        const result = JSON.parse(response.text || '{}');
        return {
            status: result.status || 'PENDING',
            reason: result.reason || 'আবেদনটি রিভিউ করা হচ্ছে।'
        };
    } catch (error) {
        return { status: 'PENDING', reason: 'Audit failed due to network issues.' };
    }
};

