                            {!websiteUrl && !isGenerating && (
                                <button onClick={handleGenerateWebsite} className="bg-white text-black px-8 py-4 rounded-xl font-bold uppercase tracking-widest hover:bg-gray-200 transition-colors flex items-center gap-2 shadow-xl">
                                    <Zap size={18} className="text-purple-600 fill-purple-600" /> জেনারেট করুন
                                </button>
                            )}
                            {isGenerating && (
                                <div className="space-y-4">
                                    <div className="w-full bg-white/10 h-2 rounded-full overflow-hidden">
                                        <div className="h-full bg-aura-purple animate-pulse transition-all duration-1000" style={{width: `${(generationStep / 3) * 100}%`}}></div>
                                    </div>
                                    <p className="text-[10px] uppercase tracking-widest text-aura-purple font-bold">
                                        {generationStep === 1 ? 'Mapping Inventory...' : generationStep === 2 ? 'Deploying Aura Engine...' : 'Finalizing Subdomain...'}
                                    </p>
                                </div>
                            )}
                            {websiteUrl && (
                                <div className="bg-green-500/10 border border-green-500/30 p-6 rounded-2xl animate-in zoom-in">
                                     <h3 className="font-bold text-green-400 mb-2 text-xs uppercase tracking-widest flex items-center gap-2">
                                        <ShieldCheck size={14} /> Live on Aura Hub
                                     </h3>
                                     <a href="#" className="text-xl text-white underline decoration-aura-purple underline-offset-8 font-mono hover:text-aura-purple transition-colors">{websiteUrl}</a>
                                </div>
                            )}
                        </>
                    )}
                </div>
            </div>

            <div className="bg-aura-glass border border-aura-glassBorder rounded-3xl p-8 flex flex-col">
                <h3 className="text-lg font-bold text-white mb-6 flex items-center gap-2"><Bot size={20} className="text-aura-purple" /> Aura AI Benefits</h3>
                <ul className="space-y-4 text-gray-400 text-sm flex-grow">
                    {[
                      "অটোমেটেড সাবডোমেইন জেনারেশন",
                      "রিয়েল-টাইম কাস্টমার চ্যাটবট",
                      "AI চালিত ইনভেন্টরি ফোরকাস্টিং",
                      "অটোমেটেড কোয়ালিটি কন্ট্রোল চেক"
                    ].map((f, i) => (
                        <li key={i} className="flex items-start gap-3">
                            <CheckCircle2 size={14} className="text-purple-400 mt-1 shrink-0" /> 
                            <span>{f}</span>
                        </li>
                    ))}
                </ul>
                <div className="mt-8 p-4 bg-white/5 rounded-xl border border-white/10 text-[10px] text-gray-500 uppercase tracking-widest leading-relaxed">
                   Governance Status: <span className={isPending ? 'text-amber-400' : 'text-green-400'}>{isPending ? 'Verifying' : 'Stable'}</span> <br/>
                   Sync Rate: <span className="text-white">99.98%</span>
                </div>
            </div>
        </div>

        {isFormOpen && (
          <div className="mb-12 bg-white/5 border border-white/10 p-8 rounded-3xl animate-in fade-in slide-in-from-top-4">
            <h2 className="text-xl font-bold mb-6 border-b border-white/10 pb-4 font-serif text-white">নতুন পণ্য যোগ করুন</h2>
            <form onSubmit={handleAddProduct} className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-2">
                <label className="text-xs uppercase tracking-widest text-gray-500 font-bold">Product Name</label>
                <input required value={newProduct.name} onChange={e => setNewProduct({...newProduct, name: e.target.value})} className="w-full bg-black/50 border border-white/20 rounded-xl px-4 py-3 text-sm text-white focus:border-aura-purple outline-none" placeholder="পণ্যর নাম" />
              </div>
              <div className="space-y-2">
                <label className="text-xs uppercase tracking-widest text-gray-500 font-bold">Price (BDT)</label>
                <input required type="number" value={newProduct.price} onChange={e => setNewProduct({...newProduct, price: e.target.value})} className="w-full bg-black/50 border border-white/20 rounded-xl px-4 py-3 text-sm text-white focus:border-aura-purple outline-none" placeholder="৳ মূল্য" />
              </div>
              <div className="md:col-span-2 space-y-2">
                <label className="text-xs uppercase tracking-widest text-gray-500 font-bold">Product Description</label>
                <textarea required value={newProduct.description} onChange={e => setNewProduct({...newProduct, description: e.target.value})} className="w-full bg-black/50 border border-white/20 rounded-xl px-4 py-3 text-sm text-white focus:border-aura-purple outline-none h-32" placeholder="পণ্যর বিস্তারিত বিবরণ..." />
              </div>
              <div className="md:col-span-2 flex justify-end">
                <button type="submit" className="bg-white text-black px-10 py-3 rounded-xl font-bold uppercase tracking-widest text-xs hover:bg-aura-purple hover:text-white transition-all shadow-xl">
                    Save Inventory
                </button>
              </div>
            </form>
          </div>
        )}

        <div>
          <div className="flex items-center justify-between mb-8">
            <h2 className="text-2xl font-serif font-bold text-white">আপনার বর্তমান ইনভেন্টরি ({products.length})</h2>
            <div className="text-[10px] text-gray-600 uppercase tracking-widest font-bold">Updated: Just Now</div>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
            {products.map(p => <ProductCard key={p.id} product={p} vendor={vendor} />)}
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { generateAuraResponse, analyzeSearchIntent, generateAuraImage, generateTrendingProducts, SearchIntent } from '../services/geminiService';
import { getProducts, getVendors, getLiveSales } from '../services/mockData';
import { ProductCard } from '../components/ProductCard';
import { ChatMessage, Product, Vendor } from '../types';
import { Sparkles, Send, Trash2, Clock, Image as ImageIcon, Loader2, Filter, X, Wand2, Info, Tag, Building2, AlertCircle, ChevronDown, ChevronUp, SlidersHorizontal } from 'lucide-react';

export const Home: React.FC = () => {
  const [allProducts, setAllProducts] = useState<Product[]>([]);
  const [fictionalProducts, setFictionalProducts] = useState<Product[]>([]);
  const [products, setProducts] = useState<Product[]>([]);
  const [vendors, setVendors] = useState<Vendor[]>([]);
  const [salesTicker, setSalesTicker] = useState(0);

  // Filtering states
  const [selectedVendorId, setSelectedVendorId] = useState<number | null>(null);
  const [activeIntent, setActiveIntent] = useState<SearchIntent | null>(null);
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [priceRange, setPriceRange] = useState<{ min: number; max: number }>({ min: 0, max: 100000 });
  const [showMobileFilters, setShowMobileFilters] = useState(false);

  // AI & UI states
  const [isGeneratingTrends, setIsGeneratingTrends] = useState(false);
  const [apiError, setApiError] = useState<string | null>(null);
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'ai', content: "আসসালামু আলাইকুম। Snehalata-স্নেহলতা ইকোসিস্টেমে স্বাগতম। আমি Aura। আজ আপনার স্টাইল যাত্রায় কীভাবে সাহায্য করতে পারি?", timestamp: Date.now() }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [isGeneratingImage, setIsGeneratingImage] = useState(false);
  const chatContainerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const initialProducts = getProducts();
    setAllProducts(initialProducts);
    setProducts(initialProducts);
    setVendors(getVendors());
    setSalesTicker(getLiveSales());

    const interval = setInterval(() => {
        setSalesTicker(prev => prev + Math.floor(Math.random() * 500));
    }, 5000);
    return () => clearInterval(interval);
  }, []);

  // Auto-hide errors
  useEffect(() => {
    if (apiError) {
      const timer = setTimeout(() => setApiError(null), 5000);
      return () => clearTimeout(timer);
    }
  }, [apiError]);

  // Derived categories from products
  const availableCategories = useMemo(() => {
    const cats = new Set<string>();
    [...allProducts, ...fictionalProducts].forEach(p => cats.add(p.category));
    return Array.from(cats);
  }, [allProducts, fictionalProducts]);

  // Synchronize products based on filters and selected vendor
  useEffect(() => {
    applyFilters();
  }, [selectedVendorId, activeIntent, fictionalProducts, selectedCategories, priceRange]);

  const applyFilters = () => {
    let filtered = [...allProducts, ...fictionalProducts];

    filtered = filtered.filter(p => {
        const productData = `${p.name} ${p.description} ${p.category}`.toLowerCase();

        // Manual Vendor Filter
        if (selectedVendorId && p.vendorId !== selectedVendorId) return false;

        // Category Filter
        if (selectedCategories.length > 0 && !selectedCategories.includes(p.category)) return false;

        // Price Range Filter
        if (p.price < priceRange.min || p.price > priceRange.max) return false;

        // AI Intent Filtering (Cumulative)
        if (activeIntent) {
            let score = 0;
            if (activeIntent.category && productData.includes(activeIntent.category.toLowerCase())) score += 10;
            if (activeIntent.color && productData.includes(activeIntent.color.toLowerCase())) score += 5;
            if (activeIntent.material && productData.includes(activeIntent.material.toLowerCase())) score += 8;
            if (activeIntent.style && productData.includes(activeIntent.style.toLowerCase())) score += 5;

            if (activeIntent.maxPrice && p.price > activeIntent.maxPrice) return false;
            if (activeIntent.minPrice && p.price < activeIntent.minPrice) return false;

            if (activeIntent.semanticKeywords && activeIntent.semanticKeywords.length > 0) {
                activeIntent.semanticKeywords.forEach(keyword => {
                    if (productData.includes(keyword.toLowerCase())) score += 2;
                });
            }

            // Only filter by intent if intent actually contains specific parameters
            if (activeIntent.category || activeIntent.color || activeIntent.material || activeIntent.style || (activeIntent.semanticKeywords && activeIntent.semanticKeywords.length > 0)) {
                if (score === 0) return false;
            }
        }

        return true;
    });

    setProducts(filtered);
  };

  const isFiltered = useMemo(() => {
      return !!selectedVendorId || !!activeIntent || selectedCategories.length > 0 || priceRange.min > 0 || priceRange.max < 100000;
  }, [selectedVendorId, activeIntent, selectedCategories, priceRange]);

  useEffect(() => {
    if (chatContainerRef.current) {
      chatContainerRef.current.scrollTop = chatContainerRef.current.scrollHeight;
    }
  }, [messages, isTyping, isGeneratingImage]);

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isTyping) return;

    const userMsg: ChatMessage = { role: 'user', content: input, timestamp: Date.now() };
    setMessages(prev => [...prev, userMsg]);
    const currentInput = input;
    setInput('');
    setIsTyping(true);
    setApiError(null);

    try {
      const intentPromise = analyzeSearchIntent(currentInput);
      const responsePromise = generateAuraResponse(currentInput);

      const [auraResponse, intent] = await Promise.all([responsePromise, intentPromise]);

      setIsTyping(false);

      if (intent) {
        setActiveIntent(intent);
      }

      let generatedImageUrl = undefined;
      if (intent?.shouldGenerateImage && intent.imagePrompt) {
          setIsGeneratingImage(true);
          try {
            const img = await generateAuraImage(intent.imagePrompt);
            generatedImageUrl = img || undefined;
          } catch (imgErr) {
            console.error("Image generation failed", imgErr);
            setApiError("Aura ইমেজ জেনারেশনে সমস্যা হয়েছে। টেক্সট রেসপন্স দেখুন।");
          } finally {
            setIsGeneratingImage(false);
          }
      }

      setMessages(prev => [...prev, { 
          role: 'ai', 
          content: auraResponse || "আসসালামু আলাইকুম। দুঃখিত, আমি আপনার অনুরোধটি বুঝতে পারছি না।", 
          timestamp: Date.now(),
          generatedImageUrl 
      }]);
    } catch (error) {
      console.error("Aura interaction error:", error);
      setIsTyping(false);
      setApiError("দুঃখিত, Aura সার্ভারে সংযোগ করা যাচ্ছে না। দয়া করে আবার চেষ্টা করুন।");
      setMessages(prev => [...prev, { 
          role: 'ai', 
          content: "আসসালামু আলাইকুম। যান্ত্রিক ত্রুটির কারণে আমি এখন উত্তর দিতে পারছি না। কিছুক্ষণ পর আবার মেসেজ দিন।", 
          timestamp: Date.now() 
      }]);
    }
  };

  const handleGenerateTrends = async () => {
    if (isGeneratingTrends) return;
    setIsGeneratingTrends(true);
    setApiError(null);

    try {
      const trends = await generateTrendingProducts();
      if (!trends || trends.length === 0) {
        throw new Error("No trends generated");
      }

      const formattedTrends: Product[] = trends.map(t => ({
          ...t,
          vendorId: 0, 
          id: t.id + 1000 
      }));

      setFictionalProducts(prev => [...prev, ...formattedTrends]);

      setMessages(prev => [...prev, {
          role: 'ai',
          content: "আসসালামু আলাইকুম। আমি ২০২৬ সালের সম্ভাব্য ট্রেন্ড থেকে কিছু কাল্পনিক ডিজাইন তৈরি করেছি। আপনার গ্রিডের নিচে দেখুন!",
          timestamp: Date.now()
      }]);

      const section = document.getElementById('product-section');
      section?.scrollIntoView({ behavior: 'smooth' });
    } catch (error) {
      console.error("Trend generation error:", error);
      setApiError("ট্রেন্ডিং প্রোডাক্ট জেনারেট করা সম্ভব হয়নি। Aura সিস্টেম আপডেট হচ্ছে।");
    } finally {
      setIsGeneratingTrends(false);
    }
  };

  const resetFilters = () => {
      setSelectedVendorId(null);
      setActiveIntent(null);
      setSelectedCategories([]);
      setPriceRange({ min: 0, max: 100000 });
  };

  const toggleCategory = (cat: string) => {
      setSelectedCategories(prev => 
        prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat]
      );
  };

  const clearChat = () => {
    setMessages([{ role: 'ai', content: "আসসালামু আলাইকুম। নতুন করে শুরু করি? আমি Aura, আপনার সেবায় নিয়োজিত।", timestamp: Date.now() }]);
  };

  return (
    <div className="min-h-screen">
      {/* Error Notification Banner */}
      {apiError && (
        <div className="fixed top-24 left-1/2 -translate-x-1/2 z-[100] w-full max-w-md px-4 animate-in slide-in-from-top-10 duration-500">
           <div className="bg-red-500/90 backdrop-blur-xl text-white p-4 rounded-2xl shadow-2xl border border-red-400/50 flex items-start gap-3">
              <AlertCircle className="shrink-0 mt-0.5" size={18} />
              <div className="flex-1">
                 <h4 className="text-xs font-bold uppercase tracking-widest mb-1">Aura System Alert</h4>
                 <p className="text-sm font-medium">{apiError}</p>
              </div>
              <button onClick={() => setApiError(null)} className="p-1 hover:bg-white/20 rounded-lg transition-colors">
                 <X size={16} />
              </button>
           </div>
        </div>
      )}

      {/* Hero Section */}
      <section className="relative min-h-[600px] flex flex-col items-center justify-center px-6 py-20 overflow-hidden">
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[800px] h-[800px] bg-aura-purple/5 blur-[120px] rounded-full pointer-events-none" />

        <div className="relative z-10 w-full max-w-4xl flex flex-col gap-10">
          <div className="text-center space-y-4">
             <div className="inline-flex items-center gap-2 px-4 py-2 rounded-full border border-aura-glassBorder bg-white/5 backdrop-blur-md">
                <span className="relative flex h-2 w-2">
                  <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-400 opacity-75"></span>
                  <span className="relative inline-flex rounded-full h-2 w-2 bg-green-500"></span>
                </span>
                <span className="text-[10px] uppercase tracking-[0.2em] font-bold text-gray-400">
                   Ecosystem ভলিউম: ৳{salesTicker.toLocaleString()}
                </span>
             </div>
             <h1 className="text-4xl md:text-6xl font-serif font-black text-white leading-tight">
               SNEHALATA-স্নেহলতা
             </h1>
          </div>

          <div className="w-full bg-black/60 backdrop-blur-xl border border-white/10 rounded-3xl overflow-hidden shadow-2xl flex flex-col h-[500px]">
            <div className="flex items-center justify-between px-6 py-4 border-b border-white/10 bg-white/5">
                <div className="flex items-center gap-2">
                    <Sparkles size={16} className="text-aura-purple" />
                    <span className="text-xs font-bold uppercase tracking-widest text-white">Aura Live Assistant</span>
                </div>
                <button onClick={clearChat} className="text-gray-500 hover:text-red-400 transition-colors">
                    <Trash2 size={16} />
                </button>
            </div>

            <div className="flex-1 p-6 overflow-y-auto space-y-6 scroll-smooth" ref={chatContainerRef}>
              {messages.map((msg, idx) => (
                <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                  <div className={`max-w-[85%] rounded-2xl p-4 text-sm ${msg.role === 'user' ? 'bg-white text-black font-medium' : 'bg-white/10 text-gray-200 border border-white/5'}`}>
                    {msg.role === 'ai' && <div className="text-[10px] uppercase tracking-widest text-aura-purple mb-1 font-bold">Aura AI</div>}
                    <div className="whitespace-pre-wrap">{msg.content}</div>

                    {msg.generatedImageUrl && (
                        <div className="mt-4 rounded-xl overflow-hidden border border-white/10 shadow-lg">
                            <img src={msg.generatedImageUrl} alt="AI Concept" className="w-full h-auto" />
                            <div className="bg-black/40 backdrop-blur-md p-2 flex items-center gap-2 text-[10px] font-bold uppercase tracking-widest text-gray-400">
                                <ImageIcon size={12} /> Aura Conceptual Preview
                            </div>
                        </div>
                    )}

                    <div className="mt-2 text-[10px] flex items-center justify-end gap-1 opacity-50">
                        {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                        <Clock size={10} />
                    </div>
                  </div>
                </div>
              ))}

              {isTyping && (
                <div className="flex justify-start">
                   <div className="bg-white/5 rounded-2xl p-4 flex gap-2">
                     <span className="w-2 h-2 bg-aura-purple rounded-full animate-bounce"></span>
                     <span className="w-2 h-2 bg-aura-purple rounded-full animate-bounce delay-75"></span>
                     <span className="w-2 h-2 bg-aura-purple rounded-full animate-bounce delay-150"></span>
                   </div>
                </div>
              )}

              {isGeneratingImage && (
                <div className="flex justify-start">
                   <div className="bg-aura-purple/10 border border-aura-purple/20 rounded-2xl p-4 flex items-center gap-3">
                     <Loader2 size={16} className="text-aura-purple animate-spin" />
                     <span className="text-xs font-bold uppercase tracking-widest text-aura-purple animate-pulse">Aura is imagining your design...</span>
                   </div>
                </div>
              )}
            </div>

            <form onSubmit={handleSendMessage} className="p-4 bg-white/5 border-t border-white/10">
              <div className="flex gap-2">
                <div className="relative flex-1">
                    <input 
                    type="text" 
                    value={input}
                    onChange={(e) => setInput(e.target.value)}
                    placeholder="রঙ বা ডিজাইন বলুন (যেমন: 'লাল শাড়ি দেখাও')"
                    className="w-full bg-black/50 border border-white/10 rounded-xl pl-5 pr-12 py-4 focus:outline-none focus:border-aura-purple text-sm text-white disabled:opacity-50"
                    disabled={isTyping}
                    />
                    <button 
                      type="submit" 
                      disabled={!input.trim() || isTyping}
                      className="absolute right-2 top-2 p-2 bg-aura-purple rounded-lg text-white disabled:opacity-50 disabled:bg-gray-700"
                    >
                      <Send size={18} />
                    </button>
                </div>
                <button 
                    type="button" 
                    onClick={handleGenerateTrends}
                    disabled={isGeneratingTrends}
                    className="bg-white/5 hover:bg-white/10 border border-white/10 rounded-xl px-4 py-2 text-white flex items-center gap-2 transition-all disabled:opacity-50"
                >
                    {isGeneratingTrends ? (
                        <Loader2 size={18} className="animate-spin text-aura-purple" />
                    ) : (
                        <Wand2 size={18} className="text-aura-purple" />
                    )}
                    <span className="hidden md:inline text-xs font-bold uppercase tracking-widest">Trends</span>
                </button>
              </div>
            </form>
          </div>
        </div>
      </section>

      {/* Main Content Area with Sidebar */}
      <div id="product-section" className="max-w-7xl mx-auto px-6 py-10">
        <div className="flex flex-col lg:flex-row gap-8">

          {/* Sidebar Filters */}
          <aside className={`lg:w-64 shrink-0 transition-all duration-300 ${showMobileFilters ? 'fixed inset-0 z-[60] bg-black/95 p-8 overflow-y-auto' : 'hidden lg:block'}`}>
            <div className="flex items-center justify-between lg:hidden mb-8">
                <h2 className="text-xl font-bold font-serif text-white">Filters</h2>
                <button onClick={() => setShowMobileFilters(false)} className="p-2 bg-white/10 rounded-full">
                    <X size={20} />
                </button>
            </div>

            <div className="space-y-8 sticky top-24">
                {/* Vendor Section */}
                <div className="space-y-4">
                    <h3 className="text-[10px] uppercase tracking-widest font-bold text-aura-purple flex items-center gap-2">
                        <Building2 size={14} /> ভেন্ডর (Vendors)
                    </h3>
                    <div className="flex flex-col gap-1">
                        <FilterOption 
                            label="All Hub" 
                            active={!selectedVendorId} 
                            onClick={() => setSelectedVendorId(null)} 
                        />
                        {vendors.filter(v => v.status === 'APPROVED').map(vendor => (
                            <FilterOption 
                                key={vendor.id} 
                                label={vendor.name} 
                                active={selectedVendorId === vendor.id} 
                                onClick={() => setSelectedVendorId(vendor.id)} 
                            />
                        ))}
                    </div>
                </div>

                {/* Categories Section */}
                <div className="space-y-4">
                    <h3 className="text-[10px] uppercase tracking-widest font-bold text-aura-purple flex items-center gap-2">
                        <Tag size={14} /> ক্যাটাগরি (Categories)
                    </h3>
                    <div className="flex flex-col gap-1">
                        {availableCategories.map(cat => (
                            <FilterCheckbox 
                                key={cat} 
                                label={cat} 
                                checked={selectedCategories.includes(cat)} 
                                onChange={() => toggleCategory(cat)} 
                            />
                        ))}
                    </div>
                </div>

                {/* Price Range Section */}
                <div className="space-y-4">
                    <h3 className="text-[10px] uppercase tracking-widest font-bold text-aura-purple flex items-center gap-2">
                        <SlidersHorizontal size={14} /> বাজেট (Price Range)
                    </h3>
                    <div className="space-y-4 px-2">
                        <div className="flex flex-col gap-2">
                            <span className="text-[10px] text-gray-500 uppercase font-bold">Max: ৳{priceRange.max.toLocaleString()}</span>
                            <input 
                                type="range" 
                                min="0" 
                                max="100000" 
                                step="500"
                                value={priceRange.max}
                                onChange={(e) => setPriceRange(prev => ({ ...prev, max: Number(e.target.value) }))}
                                className="w-full accent-aura-purple"
                            />
                        </div>
                        <div className="flex gap-2">
                            <input 
                                type="number" 
                                placeholder="Min" 
                                value={priceRange.min === 0 ? '' : priceRange.min}
                                onChange={(e) => setPriceRange(prev => ({ ...prev, min: Number(e.target.value) }))}
                                className="w-1/2 bg-white/5 border border-white/10 rounded-lg px-2 py-2 text-xs text-white focus:border-aura-purple focus:outline-none" 
                            />
                            <input 
                                type="number" 
                                placeholder="Max" 
                                value={priceRange.max === 100000 ? '' : priceRange.max}
                                onChange={(e) => setPriceRange(prev => ({ ...prev, max: Number(e.target.value) || 100000 }))}
                                className="w-1/2 bg-white/5 border border-white/10 rounded-lg px-2 py-2 text-xs text-white focus:border-aura-purple focus:outline-none" 
                            />
                        </div>
                    </div>
                </div>

                {isFiltered && (
                    <button 
                        onClick={resetFilters}
                        className="w-full py-3 rounded-xl border border-dashed border-aura-purple/30 text-[10px] font-bold uppercase tracking-widest text-aura-purple hover:bg-aura-purple/5 transition-all"
                    >
                        Reset All Filters
                    </button>
                )}
            </div>
          </aside>

          {/* Product Grid Area */}
          <main className="flex-1">
            <div className="flex flex-col md:flex-row md:items-center justify-between mb-10 gap-4">
                <div className="flex items-center gap-4">
                    <h2 className="text-2xl font-serif font-bold flex items-center gap-4">
                        <Sparkles className="text-aura-purple" />
                        {isFiltered ? 'Filtered Results' : ' ট্রেন্ডিং কালেকশন'}
                    </h2>
                    <span className="text-xs text-gray-500 bg-white/5 px-3 py-1 rounded-full">{products.length} Products</span>
                </div>

                <div className="flex items-center gap-2">
                    <button 
                        onClick={() => setShowMobileFilters(true)}
                        className="lg:hidden flex items-center gap-2 px-6 py-2 bg-white text-black rounded-full text-[10px] font-bold uppercase tracking-widest hover:bg-gray-200 transition-all"
                    >
                        <SlidersHorizontal size={14} /> Filters
                    </button>
                    {isFiltered && (
                        <button onClick={resetFilters} className="flex items-center gap-2 px-4 py-2 bg-white/10 rounded-full text-[10px] font-bold uppercase tracking-widest hover:bg-white/20 transition-colors">
                            <X size={14} /> Clear All
                        </button>
                    )}
                </div>
            </div>

            {/* AI Intent Chips Bar */}
            {activeIntent && (
                <div className="mb-8 animate-in slide-in-from-top-4">
                    <div className="bg-white/5 backdrop-blur-md border border-white/10 rounded-2xl p-4 flex flex-wrap items-center gap-4">
                        <div className="flex items-center gap-2 text-aura-purple font-bold text-xs uppercase tracking-widest">
                            <Info size={14} /> Aura Context:
                        </div>
                        <div className="flex flex-wrap gap-2">
                            {activeIntent.category && <FilterChip label="Category" value={activeIntent.category} />}
                            {activeIntent.color && <FilterChip label="Color" value={activeIntent.color} />}
                            {activeIntent.material && <FilterChip label="Material" value={activeIntent.material} />}
                            {activeIntent.style && <FilterChip label="Style" value={activeIntent.style} />}
                            {activeIntent.maxPrice && <FilterChip label="Max Price" value={`৳${activeIntent.maxPrice}`} />}
                        </div>
                        <button onClick={() => setActiveIntent(null)} className="ml-auto text-xs text-gray-500 hover:text-white underline decoration-aura-purple">
                            Clear Intent
                        </button>
                    </div>
                </div>
            )}

            <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-8">
                {products.length === 0 ? (
                    <div className="col-span-full py-20 text-center bg-white/5 rounded-3xl border border-dashed border-white/10">
                        <Building2 className="mx-auto text-gray-600 mb-4" size={48} />
                        <h3 className="text-xl font-bold text-gray-400">এই ফিল্টারে কোনো পণ্য পাওয়া যায়নি</h3>
                        <p className="text-sm text-gray-600 mt-2">অন্য কোনো ভেন্ডর বা ডিজাইন ট্রাই করুন।</p>
                    </div>
                ) : (
                    products.map(p => (
                        <div key={p.id} className="relative">
                            {p.vendorId === 0 && (
                                <div className="absolute -top-3 -right-3 z-20 bg-aura-purple text-white px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-widest shadow-lg flex items-center gap-1">
                                    <Sparkles size={10} /> AI Concept
                                </div>
                            )}
                            <ProductCard 
                                product={p} 
                                vendor={p.vendorId === 0 ? { id: 0, name: "Aura Innovations", slug: "aura", status: "APPROVED", description: "AI Generated Concepts" } : vendors.find(v => v.id === p.vendorId)} 
                            />
                        </div>
                    ))
                )}
            </div>
          </main>
        </div>
      </div>
    </div>
  );
};

const FilterOption: React.FC<{ label: string; active: boolean; onClick: () => void }> = ({ label, active, onClick }) => (
    <button 
        onClick={onClick}
        className={`w-full text-left px-4 py-2 rounded-xl text-xs font-medium transition-all ${
            active 
            ? 'bg-aura-purple text-white shadow-lg shadow-purple-900/20' 
            : 'text-gray-400 hover:bg-white/5 hover:text-white'
        }`}
    >
        {label}
    </button>
);

const FilterCheckbox: React.FC<{ label: string; checked: boolean; onChange: () => void }> = ({ label, checked, onChange }) => (
    <label className="flex items-center gap-3 px-4 py-2 cursor-pointer group">
        <div className={`w-4 h-4 rounded border flex items-center justify-center transition-all ${checked ? 'bg-aura-purple border-aura-purple' : 'border-white/20 group-hover:border-white/40'}`}>
            {checked && <X size={10} className="text-white" />}
        </div>
        <input type="checkbox" className="hidden" checked={checked} onChange={onChange} />
        <span className={`text-xs transition-colors ${checked ? 'text-white font-bold' : 'text-gray-400 group-hover:text-white'}`}>{label}</span>
    </label>
);

const FilterChip: React.FC<{ label: string, value: string, variant?: 'primary' | 'ghost' }> = ({ label, value, variant = 'primary' }) => (
    <div className={`px-3 py-1 rounded-lg border text-[10px] font-bold flex items-center gap-2 ${
        variant === 'primary' 
        ? 'bg-white/10 border-white/20 text-white' 
        : 'bg-transparent border-white/10 text-gray-400'
    }`}>
        <Tag size={10} className="text-aura-purple" />
        <span className="uppercase tracking-tighter opacity-60">{label}:</span>
        <span>{value}</span>
    </div>
);

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { generateAuraResponse, analyzeSearchIntent, generateAuraImage, generateTrendingProducts, SearchIntent } from '../services/geminiService';
import { getProducts, getVendors, getLiveSales } from '../services/mockData';
import { ProductCard } from '../components/ProductCard';
import { ChatMessage, Product, Vendor } from '../types';
import { Sparkles, Send, Trash2, Clock, Image as ImageIcon, Loader2, Filter, X, Wand2, Info, Tag, Building2, AlertCircle, ChevronDown, ChevronUp, SlidersHorizontal } from 'lucide-react';

export const Home: React.FC = () => {
  const [allProducts, setAllProducts] = useState<Product[]>([]);
  const [fictionalProducts, setFictionalProducts] = useState<Product[]>([]);
  const [products, setProducts] = useState<Product[]>([]);
  const [vendors, setVendors] = useState<Vendor[]>([]);
  const [salesTicker, setSalesTicker] = useState(0);

  // Filtering states
  const [selectedVendorId, setSelectedVendorId] = useState<number | null>(null);
  const [activeIntent, setActiveIntent] = useState<SearchIntent | null>(null);
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [priceRange, setPriceRange] = useState<{ min: number; max: number }>({ min: 0, max: 100000 });
  const [showMobileFilters, setShowMobileFilters] = useState(false);

  // AI & UI states
  const [isGeneratingTrends, setIsGeneratingTrends] = useState(false);
  const [apiError, setApiError] = useState<string | null>(null);
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'ai', content: "আসসালামু আলাইকুম। Snehalata-স্নেহলতা ইকোসিস্টেমে স্বাগতম। আমি Aura। আজ আপনার স্টাইল যাত্রায় কীভাবে সাহায্য করতে পারি?", timestamp: Date.now() }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [isGeneratingImage, setIsGeneratingImage] = useState(false);
  const chatContainerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const initialProducts = getProducts();
    setAllProducts(initialProducts);
    setProducts(initialProducts);
    setVendors(getVendors());
    setSalesTicker(getLiveSales());

    const interval = setInterval(() => {
        setSalesTicker(prev => prev + Math.floor(Math.random() * 500));
    }, 5000);
    return () => clearInterval(interval);
  }, []);

  // Auto-hide errors
  useEffect(() => {
    if (apiError) {
      const timer = setTimeout(() => setApiError(null), 5000);
      return () => clearTimeout(timer);
    }
  }, [apiError]);

  // Derived categories from products
  const availableCategories = useMemo(() => {
    const cats = new Set<string>();
    [...allProducts, ...fictionalProducts].forEach(p => cats.add(p.category));
    return Array.from(cats);
  }, [allProducts, fictionalProducts]);

  // Synchronize products based on filters and selected vendor
  useEffect(() => {
    applyFilters();
  }, [selectedVendorId, activeIntent, fictionalProducts, selectedCategories, priceRange]);

  const applyFilters = () => {
    let filtered = [...allProducts, ...fictionalProducts];

    filtered = filtered.filter(p => {
        const productData = `${p.name} ${p.description} ${p.category}`.toLowerCase();

        // Manual Vendor Filter
        if (selectedVendorId && p.vendorId !== selectedVendorId) return false;

        // Category Filter
        if (selectedCategories.length > 0 && !selectedCategories.includes(p.category)) return false;

        // Price Range Filter
        if (p.price < priceRange.min || p.price > priceRange.max) return false;

        // AI Intent Filtering (Cumulative)
        if (activeIntent) {
            let score = 0;
            if (activeIntent.category && productData.includes(activeIntent.category.toLowerCase())) score += 10;
            if (activeIntent.color && productData.includes(activeIntent.color.toLowerCase())) score += 5;
            if (activeIntent.material && productData.includes(activeIntent.material.toLowerCase())) score += 8;
            if (activeIntent.style && productData.includes(activeIntent.style.toLowerCase())) score += 5;

            if (activeIntent.maxPrice && p.price > activeIntent.maxPrice) return false;
            if (activeIntent.minPrice && p.price < activeIntent.minPrice) return false;

            if (activeIntent.semanticKeywords && activeIntent.semanticKeywords.length > 0) {
                activeIntent.semanticKeywords.forEach(keyword => {
                    if (productData.includes(keyword.toLowerCase())) score += 2;
                });
            }

            // Only filter by intent if intent actually contains specific parameters
            if (activeIntent.category || activeIntent.color || activeIntent.material || activeIntent.style || (activeIntent.semanticKeywords && activeIntent.semanticKeywords.length > 0)) {
                if (score === 0) return false;
            }
        }

        return true;
    });

    setProducts(filtered);
  };

  const isFiltered = useMemo(() => {
      return !!selectedVendorId || !!activeIntent || selectedCategories.length > 0 || priceRange.min > 0 || priceRange.max < 100000;
  }, [selectedVendorId, activeIntent, selectedCategories, priceRange]);

  useEffect(() => {
    if (chatContainerRef.current) {
      chatContainerRef.current.scrollTop = chatContainerRef.current.scrollHeight;
    }
  }, [messages, isTyping, isGeneratingImage]);

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isTyping) return;

    const userMsg: ChatMessage = { role: 'user', content: input, timestamp: Date.now() };
    setMessages(prev => [...prev, userMsg]);
    const currentInput = input;
    setInput('');
    setIsTyping(true);
    setApiError(null);

    try {
      const intentPromise = analyzeSearchIntent(currentInput);
      const responsePromise = generateAuraResponse(currentInput);

      const [auraResponse, intent] = await Promise.all([responsePromise, intentPromise]);

      setIsTyping(false);

      if (intent) {
        setActiveIntent(intent);
      }

      let generatedImageUrl = undefined;
      if (intent?.shouldGenerateImage && intent.imagePrompt) {
          setIsGeneratingImage(true);
          try {
            const img = await generateAuraImage(intent.imagePrompt);
            generatedImageUrl = img || undefined;
          } catch (imgErr) {
            console.error("Image generation failed", imgErr);
            setApiError("Aura ইমেজ জেনারেশনে সমস্যা হয়েছে। টেক্সট রেসপন্স দেখুন।");
          } finally {
            setIsGeneratingImage(false);
          }
      }

      setMessages(prev => [...prev, { 
          role: 'ai', 
          content: auraResponse || "আসসালামু আলাইকুম। দুঃখিত, আমি আপনার অনুরোধটি বুঝতে পারছি না।", 
          timestamp: Date.now(),
          generatedImageUrl 
      }]);
    } catch (error) {
      console.error("Aura interaction error:", error);
      setIsTyping(false);
      setApiError("দুঃখিত, Aura সার্ভারে সংযোগ করা যাচ্ছে না। দয়া করে আবার চেষ্টা করুন।");
      setMessages(prev => [...prev, { 
          role: 'ai', 
          content: "আসসালামু আলাইকুম। যান্ত্রিক ত্রুটির কারণে আমি এখন উত্তর দিতে পারছি না। কিছুক্ষণ পর আবার মেসেজ দিন।", 
          timestamp: Date.now() 
      }]);
    }
  };

  const handleGenerateTrends = async () => {
    if (isGeneratingTrends) return;
    setIsGeneratingTrends(true);
    setApiError(null);

    try {
      const trends = await generateTrendingProducts();
      if (!trends || trends.length === 0) {
        throw new Error("No trends generated");
      }

      const formattedTrends: Product[] = trends.map(t => ({
          ...t,
          vendorId: 0, 
          id: t.id + 1000 
      }));

      setFictionalProducts(prev => [...prev, ...formattedTrends]);

      setMessages(prev => [...prev, {
          role: 'ai',
          content: "আসসালামু আলাইকুম। আমি ২০২৬ সালের সম্ভাব্য ট্রেন্ড থেকে কিছু কাল্পনিক ডিজাইন তৈরি করেছি। আপনার গ্রিডের নিচে দেখুন!",
          timestamp: Date.now()
      }]);

      const section = document.getElementById('product-section');
      section?.scrollIntoView({ behavior: 'smooth' });
    } catch (error) {
      console.error("Trend generation error:", error);
      setApiError("ট্রেন্ডিং প্রোডাক্ট জেনারেট করা সম্ভব হয়নি। Aura সিস্টেম আপডেট হচ্ছে।");
    } finally {
      setIsGeneratingTrends(false);
    }
  };

  const resetFilters = () => {
      setSelectedVendorId(null);
      setActiveIntent(null);
      setSelectedCategories([]);
      setPriceRange({ min: 0, max: 100000 });
  };

  const toggleCategory = (cat: string) => {
      setSelectedCategories(prev => 
        prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat]
      );
  };

  const clearChat = () => {
    setMessages([{ role: 'ai', content: "আসসালামু আলাইকুম। নতুন করে শুরু করি? আমি Aura, আপনার সেবায় নিয়োজিত।", timestamp: Date.now() }]);
  };

  return (
    <div className="min-h-screen">
      {/* Error Notification Banner */}
      {apiError && (
        <div className="fixed top-24 left-1/2 -translate-x-1/2 z-[100] w-full max-w-md px-4 animate-in slide-in-from-top-10 duration-500">
           <div className="bg-red-500/90 backdrop-blur-xl text-white p-4 rounded-2xl shadow-2xl border border-red-400/50 flex items-start gap-3">
              <AlertCircle className="shrink-0 mt-0.5" size={18} />
              <div className="flex-1">
                 <h4 className="text-xs font-bold uppercase tracking-widest mb-1">Aura System Alert</h4>
                 <p className="text-sm font-medium">{apiError}</p>
              </div>
              <button onClick={() => setApiError(null)} className="p-1 hover:bg-white/20 rounded-lg transition-colors">
                 <X size={16} />
              </button>
           </div>
        </div>
      )}

      {/* Hero Section */}
      <section className="relative min-h-[600px] flex flex-col items-center justify-center px-6 py-20 overflow-hidden">
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[800px] h-[800px] bg-aura-purple/5 blur-[120px] rounded-full pointer-events-none" />

        <div className="relative z-10 w-full max-w-4xl flex flex-col gap-10">
          <div className="text-center space-y-4">
             <div className="inline-flex items-center gap-2 px-4 py-2 rounded-full border border-aura-glassBorder bg-white/5 backdrop-blur-md">
                <span className="relative flex h-2 w-2">
                  <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-400 opacity-75"></span>
                  <span className="relative inline-flex rounded-full h-2 w-2 bg-green-500"></span>
                </span>
                <span className="text-[10px] uppercase tracking-[0.2em] font-bold text-gray-400">
                   Ecosystem ভলিউম: ৳{salesTicker.toLocaleString()}
                </span>
             </div>
             <div className="flex flex-col items-center">
                <h1 className="text-4xl md:text-6xl font-serif font-black text-white leading-tight mb-2 tracking-tight">
                  SNEHALATA-স্নেহলতা
                </h1>
                <p className="text-sm md:text-base font-medium text-aura-ash uppercase tracking-[0.4em] opacity-80">
                  The Aura AI Driven Ecosystem
                </p>
             </div>
          </div>

          <div className="w-full bg-black/60 backdrop-blur-xl border border-white/10 rounded-3xl overflow-hidden shadow-2xl flex flex-col h-[500px]">
            <div className="flex items-center justify-between px-6 py-4 border-b border-white/10 bg-white/5">
                <div className="flex items-center gap-2">
                    <Sparkles size={16} className="text-aura-purple" />
                    <span className="text-xs font-bold uppercase tracking-widest text-white">Aura Live Assistant</span>
                </div>
                <button onClick={clearChat} className="text-gray-500 hover:text-red-400 transition-colors">
                    <Trash2 size={16} />
                </button>
            </div>

            <div className="flex-1 p-6 overflow-y-auto space-y-6 scroll-smooth" ref={chatContainerRef}>
              {messages.map((msg, idx) => (
                <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                  <div className={`max-w-[85%] rounded-2xl p-4 text-sm ${msg.role === 'user' ? 'bg-white text-black font-medium' : 'bg-white/10 text-gray-200 border border-white/5'}`}>
                    {msg.role === 'ai' && <div className="text-[10px] uppercase tracking-widest text-aura-purple mb-1 font-bold">Aura AI</div>}
                    <div className="whitespace-pre-wrap">{msg.content}</div>

                    {msg.generatedImageUrl && (
                        <div className="mt-4 rounded-xl overflow-hidden border border-white/10 shadow-lg">
                            <img src={msg.generatedImageUrl} alt="AI Concept" className="w-full h-auto" />
                            <div className="bg-black/40 backdrop-blur-md p-2 flex items-center gap-2 text-[10px] font-bold uppercase tracking-widest text-gray-400">
                                <ImageIcon size={12} /> Aura Conceptual Preview
                            </div>
                        </div>
                    )}

                    <div className="mt-2 text-[10px] flex items-center justify-end gap-1 opacity-50">
                        {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                        <Clock size={10} />
                    </div>
                  </div>
                </div>
              ))}

              {isTyping && (
                <div className="flex justify-start">
                   <div className="bg-white/5 rounded-2xl p-4 flex gap-2">
                     <span className="w-2 h-2 bg-aura-purple rounded-full animate-bounce"></span>
                     <span className="w-2 h-2 bg-aura-purple rounded-full animate-bounce delay-75"></span>
                     <span className="w-2 h-2 bg-aura-purple rounded-full animate-bounce delay-150"></span>
                   </div>
                </div>
              )}

              {isGeneratingImage && (
                <div className="flex justify-start">
                   <div className="bg-aura-purple/10 border border-aura-purple/20 rounded-2xl p-4 flex items-center gap-3">
                     <Loader2 size={16} className="text-aura-purple animate-spin" />
                     <span className="text-xs font-bold uppercase tracking-widest text-aura-purple animate-pulse">Aura is imagining your design...</span>
                   </div>
                </div>
              )}
            </div>

            <form onSubmit={handleSendMessage} className="p-4 bg-white/5 border-t border-white/10">
              <div className="flex gap-2">
                <div className="relative flex-1">
                    <input 
                    type="text" 
                    value={input}
                    onChange={(e) => setInput(e.target.value)}
                    placeholder="রঙ বা ডিজাইন বলুন (যেমন: 'লাল শাড়ি দেখাও')"
                    className="w-full bg-black/50 border border-white/10 rounded-xl pl-5 pr-12 py-4 focus:outline-none focus:border-aura-purple text-sm text-white disabled:opacity-50"
                    disabled={isTyping}
                    />
                    <button 
                      type="submit" 
                      disabled={!input.trim() || isTyping}
                      className="absolute right-2 top-2 p-2 bg-aura-purple rounded-lg text-white disabled:opacity-50 disabled:bg-gray-700"
                    >
                      <Send size={18} />
                    </button>
                </div>
                <button 
                    type="button" 
                    onClick={handleGenerateTrends}
                    disabled={isGeneratingTrends}
                    className="bg-white/5 hover:bg-white/10 border border-white/10 rounded-xl px-4 py-2 text-white flex items-center gap-2 transition-all disabled:opacity-50"
                >
                    {isGeneratingTrends ? (
                        <Loader2 size={18} className="animate-spin text-aura-purple" />
                    ) : (
                        <Wand2 size={18} className="text-aura-purple" />
                    )}
                    <span className="hidden md:inline text-xs font-bold uppercase tracking-widest">Trends</span>
                </button>
              </div>
            </form>
          </div>
        </div>
      </section>

      {/* Main Content Area with Sidebar */}
      <div id="product-section" className="max-w-7xl mx-auto px-6 py-10">
        <div className="flex flex-col lg:flex-row gap-8">

          {/* Sidebar Filters */}
          <aside className={`lg:w-64 shrink-0 transition-all duration-300 ${showMobileFilters ? 'fixed inset-0 z-[60] bg-black/95 p-8 overflow-y-auto' : 'hidden lg:block'}`}>
            <div className="flex items-center justify-between lg:hidden mb-8">
                <h2 className="text-xl font-bold font-serif text-white">Filters</h2>
                <button onClick={() => setShowMobileFilters(false)} className="p-2 bg-white/10 rounded-full">
                    <X size={20} />
                </button>
            </div>

            <div className="space-y-8 sticky top-24">
                {/* Vendor Section */}
                <div className="space-y-4">
                    <h3 className="text-[10px] uppercase tracking-widest font-bold text-aura-purple flex items-center gap-2">
                        <Building2 size={14} /> ভেন্ডর (Vendors)
                    </h3>
                    <div className="flex flex-col gap-1">
                        <FilterOption 
                            label="All Hub" 
                            active={!selectedVendorId} 
                            onClick={() => setSelectedVendorId(null)} 
                        />
                        {vendors.filter(v => v.status === 'APPROVED').map(vendor => (
                            <FilterOption 
                                key={vendor.id} 
                                label={vendor.name} 
                                active={selectedVendorId === vendor.id} 
                                onClick={() => setSelectedVendorId(vendor.id)} 
                            />
                        ))}
                    </div>
                </div>

                {/* Categories Section */}
                <div className="space-y-4">
                    <h3 className="text-[10px] uppercase tracking-widest font-bold text-aura-purple flex items-center gap-2">
                        <Tag size={14} /> ক্যাটাগরি (Categories)
                    </h3>
                    <div className="flex flex-col gap-1">
                        {availableCategories.map(cat => (
                            <FilterCheckbox 
                                key={cat} 
                                label={cat} 
                                checked={selectedCategories.includes(cat)} 
                                onChange={() => toggleCategory(cat)} 
                            />
                        ))}
                    </div>
                </div>

                {/* Price Range Section */}
                <div className="space-y-4">
                    <h3 className="text-[10px] uppercase tracking-widest font-bold text-aura-purple flex items-center gap-2">
                        <SlidersHorizontal size={14} /> বাজেট (Price Range)
                    </h3>
                    <div className="space-y-4 px-2">
                        <div className="flex flex-col gap-2">
                            <span className="text-[10px] text-gray-500 uppercase font-bold">Max: ৳{priceRange.max.toLocaleString()}</span>
                            <input 
                                type="range" 
                                min="0" 
                                max="100000" 
                                step="500"
                                value={priceRange.max}
                                onChange={(e) => setPriceRange(prev => ({ ...prev, max: Number(e.target.value) }))}
                                className="w-full accent-aura-purple"
                            />
                        </div>
                        <div className="flex gap-2">
                            <input 
                                type="number" 
                                placeholder="Min" 
                                value={priceRange.min === 0 ? '' : priceRange.min}
                                onChange={(e) => setPriceRange(prev => ({ ...prev, min: Number(e.target.value) }))}
                                className="w-1/2 bg-white/5 border border-white/10 rounded-lg px-2 py-2 text-xs text-white focus:border-aura-purple focus:outline-none" 
                            />
                            <input 
                                type="number" 
                                placeholder="Max" 
                                value={priceRange.max === 100000 ? '' : priceRange.max}
                                onChange={(e) => setPriceRange(prev => ({ ...prev, max: Number(e.target.value) || 100000 }))}
                                className="w-1/2 bg-white/5 border border-white/10 rounded-lg px-2 py-2 text-xs text-white focus:border-aura-purple focus:outline-none" 
                            />
                        </div>
                    </div>
                </div>

                {isFiltered && (
                    <button 
                        onClick={resetFilters}
                        className="w-full py-3 rounded-xl border border-dashed border-aura-purple/30 text-[10px] font-bold uppercase tracking-widest text-aura-purple hover:bg-aura-purple/5 transition-all"
                    >
                        Reset All Filters
                    </button>
                )}
            </div>
          </aside>

          {/* Product Grid Area */}
          <main className="flex-1">
            <div className="flex flex-col md:flex-row md:items-center justify-between mb-10 gap-4">
                <div className="flex items-center gap-4">
                    <h2 className="text-2xl font-serif font-bold flex items-center gap-4">
                        <Sparkles className="text-aura-purple" />
                        {isFiltered ? 'Filtered Results' : ' ট্রেন্ডিং কালেকশন'}
                    </h2>
                    <span className="text-xs text-gray-500 bg-white/5 px-3 py-1 rounded-full">{products.length} Products</span>
                </div>

                <div className="flex items-center gap-2">
                    <button 
                        onClick={() => setShowMobileFilters(true)}
                        className="lg:hidden flex items-center gap-2 px-6 py-2 bg-white text-black rounded-full text-[10px] font-bold uppercase tracking-widest hover:bg-gray-200 transition-all"
                    >
                        <SlidersHorizontal size={14} /> Filters
                    </button>
                    {isFiltered && (
                        <button onClick={resetFilters} className="flex items-center gap-2 px-4 py-2 bg-white/10 rounded-full text-[10px] font-bold uppercase tracking-widest hover:bg-white/20 transition-colors">
                            <X size={14} /> Clear All
                        </button>
                    )}
                </div>
            </div>

            {/* AI Intent Chips Bar */}
            {activeIntent && (
                <div className="mb-8 animate-in slide-in-from-top-4">
                    <div className="bg-white/5 backdrop-blur-md border border-white/10 rounded-2xl p-4 flex flex-wrap items-center gap-4">
                        <div className="flex items-center gap-2 text-aura-purple font-bold text-xs uppercase tracking-widest">
                            <Info size={14} /> Aura Context:
                        </div>
                        <div className="flex flex-wrap gap-2">
                            {activeIntent.category && <FilterChip label="Category" value={activeIntent.category} />}
                            {activeIntent.color && <FilterChip label="Color" value={activeIntent.color} />}
                            {activeIntent.material && <FilterChip label="Material" value={activeIntent.material} />}
                            {activeIntent.style && <FilterChip label="Style" value={activeIntent.style} />}
                            {activeIntent.maxPrice && <FilterChip label="Max Price" value={`৳${activeIntent.maxPrice}`} />}
                        </div>
                        <button onClick={() => setActiveIntent(null)} className="ml-auto text-xs text-gray-500 hover:text-white underline decoration-aura-purple">
                            Clear Intent
                        </button>
                    </div>
                </div>
            )}

            <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-8">
                {products.length === 0 ? (
                    <div className="col-span-full py-20 text-center bg-white/5 rounded-3xl border border-dashed border-white/10">
                        <Building2 className="mx-auto text-gray-600 mb-4" size={48} />
                        <h3 className="text-xl font-bold text-gray-400">এই ফিল্টারে কোনো পণ্য পাওয়া যায়নি</h3>
                        <p className="text-sm text-gray-600 mt-2">অন্য কোনো ভেন্ডর বা ডিজাইন ট্রাই করুন।</p>
                    </div>
                ) : (
                    products.map(p => (
                        <div key={p.id} className="relative">
                            {p.vendorId === 0 && (
                                <div className="absolute -top-3 -right-3 z-20 bg-aura-purple text-white px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-widest shadow-lg flex items-center gap-1">
                                    <Sparkles size={10} /> AI Concept
                                </div>
                            )}
                            <ProductCard 
                                product={p} 
                                vendor={p.vendorId === 0 ? { id: 0, name: "Aura Innovations", slug: "aura", status: "APPROVED", description: "AI Generated Concepts" } : vendors.find(v => v.id === p.vendorId)} 
                            />
                        </div>
                    ))
                )}
            </div>
          </main>
        </div>
      </div>
    </div>
  );
};

const FilterOption: React.FC<{ label: string; active: boolean; onClick: () => void }> = ({ label, active, onClick }) => (
    <button 
        onClick={onClick}
        className={`w-full text-left px-4 py-2 rounded-xl text-xs font-medium transition-all ${
            active 
            ? 'bg-aura-purple text-white shadow-lg shadow-purple-900/20' 
            : 'text-gray-400 hover:bg-white/5 hover:text-white'
        }`}
    >
        {label}
    </button>
);

const FilterCheckbox: React.FC<{ label: string; checked: boolean; onChange: () => void }> = ({ label, checked, onChange }) => (
    <label className="flex items-center gap-3 px-4 py-2 cursor-pointer group">
        <div className={`w-4 h-4 rounded border flex items-center justify-center transition-all ${checked ? 'bg-aura-purple border-aura-purple' : 'border-white/20 group-hover:border-white/40'}`}>
            {checked && <X size={10} className="text-white" />}
        </div>
        <input type="checkbox" className="hidden" checked={checked} onChange={onChange} />
        <span className={`text-xs transition-colors ${checked ? 'text-white font-bold' : 'text-gray-400 group-hover:text-white'}`}>{label}</span>
    </label>
);

const FilterChip: React.FC<{ label: string, value: string, variant?: 'primary' | 'ghost' }> = ({ label, value, variant = 'primary' }) => (
    <div className={`px-3 py-1 rounded-lg border text-[10px] font-bold flex items-center gap-2 ${
        variant === 'primary' 
        ? 'bg-white/10 border-white/20 text-white' 
        : 'bg-transparent border-white/10 text-gray-400'
    }`}>
        <Tag size={10} className="text-aura-purple" />
        <span className="uppercase tracking-tighter opacity-60">{label}:</span>
        <span>{value}</span>
    </div>
);

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { generateAuraResponse, analyzeSearchIntent, generateAuraImage, generateTrendingProducts, SearchIntent } from '../services/geminiService';
import { getProducts, getVendors, getLiveSales } from '../services/mockData';
import { ProductCard } from '../components/ProductCard';
import { ChatMessage, Product, Vendor } from '../types';
import { Sparkles, Send, Trash2, Clock, Image as ImageIcon, Loader2, Filter, X, Wand2, Info, Tag, Building2, AlertCircle, ChevronDown, ChevronUp, SlidersHorizontal } from 'lucide-react';

export const Home: React.FC = () => {
  const [allProducts, setAllProducts] = useState<Product[]>([]);
  const [fictionalProducts, setFictionalProducts] = useState<Product[]>([]);
  const [products, setProducts] = useState<Product[]>([]);
  const [vendors, setVendors] = useState<Vendor[]>([]);
  const [salesTicker, setSalesTicker] = useState(0);

  // Filtering states
  const [selectedVendorId, setSelectedVendorId] = useState<number | null>(null);
  const [activeIntent, setActiveIntent] = useState<SearchIntent | null>(null);
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [priceRange, setPriceRange] = useState<{ min: number; max: number }>({ min: 0, max: 100000 });
  const [showMobileFilters, setShowMobileFilters] = useState(false);

  // AI & UI states
  const [isGeneratingTrends, setIsGeneratingTrends] = useState(false);
  const [apiError, setApiError] = useState<string | null>(null);
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'ai', content: "আসসালামু আলাইকুম। Snehalata-স্নেহলতা ইকোসিস্টেমে স্বাগতম। আমি Aura। আজ আপনার স্টাইল যাত্রায় কীভাবে সাহায্য করতে পারি?", timestamp: Date.now() }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [isGeneratingImage, setIsGeneratingImage] = useState(false);
  const chatContainerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const initialProducts = getProducts();
    setAllProducts(initialProducts);
    setProducts(initialProducts);
    setVendors(getVendors());
    setSalesTicker(getLiveSales());

    const interval = setInterval(() => {
        setSalesTicker(prev => prev + Math.floor(Math.random() * 500));
    }, 5000);
    return () => clearInterval(interval);
  }, []);

  // Auto-hide errors
  useEffect(() => {
    if (apiError) {
      const timer = setTimeout(() => setApiError(null), 5000);
      return () => clearTimeout(timer);
    }
  }, [apiError]);

  // Derived categories from products
  const availableCategories = useMemo(() => {
    const cats = new Set<string>();
    [...allProducts, ...fictionalProducts].forEach(p => cats.add(p.category));
    return Array.from(cats);
  }, [allProducts, fictionalProducts]);

  // Synchronize products based on filters and selected vendor
  useEffect(() => {
    applyFilters();
  }, [selectedVendorId, activeIntent, fictionalProducts, selectedCategories, priceRange]);

  const applyFilters = () => {
    let filtered = [...allProducts, ...fictionalProducts];

    filtered = filtered.filter(p => {
        const productData = `${p.name} ${p.description} ${p.category}`.toLowerCase();

        // Manual Vendor Filter
        if (selectedVendorId && p.vendorId !== selectedVendorId) return false;

        // Category Filter
        if (selectedCategories.length > 0 && !selectedCategories.includes(p.category)) return false;

        // Price Range Filter
        if (p.price < priceRange.min || p.price > priceRange.max) return false;

        // AI Intent Filtering (Cumulative)
        if (activeIntent) {
            let score = 0;
            if (activeIntent.category && productData.includes(activeIntent.category.toLowerCase())) score += 10;
            if (activeIntent.color && productData.includes(activeIntent.color.toLowerCase())) score += 5;
            if (activeIntent.material && productData.includes(activeIntent.material.toLowerCase())) score += 8;
            if (activeIntent.style && productData.includes(activeIntent.style.toLowerCase())) score += 5;

            if (activeIntent.maxPrice && p.price > activeIntent.maxPrice) return false;
            if (activeIntent.minPrice && p.price < activeIntent.minPrice) return false;

            if (activeIntent.semanticKeywords && activeIntent.semanticKeywords.length > 0) {
                activeIntent.semanticKeywords.forEach(keyword => {
                    if (productData.includes(keyword.toLowerCase())) score += 2;
                });
            }

            // Only filter by intent if intent actually contains specific parameters
            if (activeIntent.category || activeIntent.color || activeIntent.material || activeIntent.style || (activeIntent.semanticKeywords && activeIntent.semanticKeywords.length > 0)) {
                if (score === 0) return false;
            }
        }

        return true;
    });

    setProducts(filtered);
  };

  const isFiltered = useMemo(() => {
      return !!selectedVendorId || !!activeIntent || selectedCategories.length > 0 || priceRange.min > 0 || priceRange.max < 100000;
  }, [selectedVendorId, activeIntent, selectedCategories, priceRange]);

  useEffect(() => {
    if (chatContainerRef.current) {
      chatContainerRef.current.scrollTop = chatContainerRef.current.scrollHeight;
    }
  }, [messages, isTyping, isGeneratingImage]);

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isTyping) return;

    const userMsg: ChatMessage = { role: 'user', content: input, timestamp: Date.now() };
    setMessages(prev => [...prev, userMsg]);
    const currentInput = input;
    setInput('');
    setIsTyping(true);
    setApiError(null);

    try {
      const intentPromise = analyzeSearchIntent(currentInput);
      const responsePromise = generateAuraResponse(currentInput);

      const [auraResponse, intent] = await Promise.all([responsePromise, intentPromise]);

      setIsTyping(false);

      if (intent) {
        setActiveIntent(intent);
      }

      let generatedImageUrl = undefined;
      if (intent?.shouldGenerateImage && intent.imagePrompt) {
          setIsGeneratingImage(true);
          try {
            const img = await generateAuraImage(intent.imagePrompt);
            generatedImageUrl = img || undefined;
          } catch (imgErr) {
            console.error("Image generation failed", imgErr);
            setApiError("Aura ইমেজ জেনারেশনে সমস্যা হয়েছে। টেক্সট রেসপন্স দেখুন।");
          } finally {
            setIsGeneratingImage(false);
          }
      }

      setMessages(prev => [...prev, { 
          role: 'ai', 
          content: auraResponse || "আসসালামু আলাইকুম। দুঃখিত, আমি আপনার অনুরোধটি বুঝতে পারছি না।", 
          timestamp: Date.now(),
          generatedImageUrl 
      }]);
    } catch (error) {
      console.error("Aura interaction error:", error);
      setIsTyping(false);
      setApiError("দুঃখিত, Aura সার্ভারে সংযোগ করা যাচ্ছে না। দয়া করে আবার চেষ্টা করুন।");
      setMessages(prev => [...prev, { 
          role: 'ai', 
          content: "আসসালামু আলাইকুম। যান্ত্রিক ত্রুটির কারণে আমি এখন উত্তর দিতে পারছি না। কিছুক্ষণ পর আবার মেসেজ দিন।", 
          timestamp: Date.now() 
      }]);
    }
  };

  const handleGenerateTrends = async () => {
    if (isGeneratingTrends) return;
    setIsGeneratingTrends(true);
    setApiError(null);

    try {
      const trends = await generateTrendingProducts();
      if (!trends || trends.length === 0) {
        throw new Error("No trends generated");
      }

      const formattedTrends: Product[] = trends.map(t => ({
          ...t,
          vendorId: 0, 
          id: t.id + 1000 
      }));

      setFictionalProducts(prev => [...prev, ...formattedTrends]);

      setMessages(prev => [...prev, {
          role: 'ai',
          content: "আসসালামু আলাইকুম। আমি ২০২৬ সালের সম্ভাব্য ট্রেন্ড থেকে কিছু কাল্পনিক ডিজাইন তৈরি করেছি। আপনার গ্রিডের নিচে দেখুন!",
          timestamp: Date.now()
      }]);

      const section = document.getElementById('product-section');
      section?.scrollIntoView({ behavior: 'smooth' });
    } catch (error) {
      console.error("Trend generation error:", error);
      setApiError("ট্রেন্ডিং প্রোডাক্ট জেনারেট করা সম্ভব হয়নি। Aura সিস্টেম আপডেট হচ্ছে।");
    } finally {
      setIsGeneratingTrends(false);
    }
  };

  const resetFilters = () => {
      setSelectedVendorId(null);
      setActiveIntent(null);
      setSelectedCategories([]);
      setPriceRange({ min: 0, max: 100000 });
  };

  const toggleCategory = (cat: string) => {
      setSelectedCategories(prev => 
        prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat]
      );
  };

  const clearChat = () => {
    setMessages([{ role: 'ai', content: "আসসালামু আলাইকুম। নতুন করে শুরু করি? আমি Aura, আপনার সেবায় নিয়োজিত।", timestamp: Date.now() }]);
  };

  return (
    <div className="min-h-screen">
      {/* Error Notification Banner */}
      {apiError && (
        <div className="fixed top-24 left-1/2 -translate-x-1/2 z-[100] w-full max-w-md px-4 animate-in slide-in-from-top-10 duration-500">
           <div className="bg-red-500/90 backdrop-blur-xl text-white p-4 rounded-2xl shadow-2xl border border-red-400/50 flex items-start gap-3">
              <AlertCircle className="shrink-0 mt-0.5" size={18} />
              <div className="flex-1">
                 <h4 className="text-xs font-bold uppercase tracking-widest mb-1">Aura System Alert</h4>
                 <p className="text-sm font-medium">{apiError}</p>
              </div>
              <button onClick={() => setApiError(null)} className="p-1 hover:bg-white/20 rounded-lg transition-colors">
                 <X size={16} />
              </button>
           </div>
        </div>
      )}

      {/* Hero Section */}
      <section className="relative min-h-[600px] flex flex-col items-center justify-center px-6 py-20 overflow-hidden">
        {/* Subdued Glow Background to enhance the Grid pattern */}
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[800px] h-[800px] bg-aura-purple/5 blur-[120px] rounded-full pointer-events-none" />

        <div className="relative z-10 w-full max-w-4xl flex flex-col gap-10">
          <div className="text-center space-y-4">
             <div className="inline-flex items-center gap-2 px-4 py-2 rounded-full border border-aura-glassBorder bg-white/5 backdrop-blur-md">
                <span className="relative flex h-2 w-2">
                  <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-400 opacity-75"></span>
                  <span className="relative inline-flex rounded-full h-2 w-2 bg-green-500"></span>
                </span>
                <span className="text-[10px] uppercase tracking-[0.2em] font-bold text-gray-400">
                   Ecosystem ভলিউম: ৳{salesTicker.toLocaleString()}
                </span>
             </div>
             <div className="flex flex-col items-center">
                <h1 className="text-4xl md:text-6xl font-serif font-black text-white leading-tight mb-2 tracking-tight">
                  SNEHALATA-স্নেহলতা
                </h1>
                <p className="text-sm md:text-base font-bold text-aura-ash uppercase tracking-[0.5em] opacity-90 drop-shadow-sm">
                  The Aura AI Driven Ecosystem
                </p>
             </div>
          </div>

          <div className="w-full bg-black/60 backdrop-blur-xl border border-white/10 rounded-3xl overflow-hidden shadow-2xl flex flex-col h-[500px]">
            <div className="flex items-center justify-between px-6 py-4 border-b border-white/10 bg-white/5">
                <div className="flex items-center gap-2">
                    <Sparkles size={16} className="text-aura-purple" />
                    <span className="text-xs font-bold uppercase tracking-widest text-white">Aura Live Assistant</span>
                </div>
                <button onClick={clearChat} className="text-gray-500 hover:text-red-400 transition-colors">
                    <Trash2 size={16} />
                </button>
            </div>

            <div className="flex-1 p-6 overflow-y-auto space-y-6 scroll-smooth" ref={chatContainerRef}>
              {messages.map((msg, idx) => (
                <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                  <div className={`max-w-[85%] rounded-2xl p-4 text-sm ${msg.role === 'user' ? 'bg-white text-black font-medium' : 'bg-white/10 text-gray-200 border border-white/5'}`}>
                    {msg.role === 'ai' && <div className="text-[10px] uppercase tracking-widest text-aura-purple mb-1 font-bold">Aura AI</div>}
                    <div className="whitespace-pre-wrap">{msg.content}</div>

                    {msg.generatedImageUrl && (
                        <div className="mt-4 rounded-xl overflow-hidden border border-white/10 shadow-lg">
                            <img src={msg.generatedImageUrl} alt="AI Concept" className="w-full h-auto" />
                            <div className="bg-black/40 backdrop-blur-md p-2 flex items-center gap-2 text-[10px] font-bold uppercase tracking-widest text-gray-400">
                                <ImageIcon size={12} /> Aura Conceptual Preview
                            </div>
                        </div>
                    )}

                    <div className="mt-2 text-[10px] flex items-center justify-end gap-1 opacity-50">
                        {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                        <Clock size={10} />
                    </div>
                  </div>
                </div>
              ))}

              {isTyping && (
                <div className="flex justify-start">
                   <div className="bg-white/5 rounded-2xl p-4 flex gap-2">
                     <span className="w-2 h-2 bg-aura-purple rounded-full animate-bounce"></span>
                     <span className="w-2 h-2 bg-aura-purple rounded-full animate-bounce delay-75"></span>
                     <span className="w-2 h-2 bg-aura-purple rounded-full animate-bounce delay-150"></span>
                   </div>
                </div>
              )}

              {isGeneratingImage && (
                <div className="flex justify-start">
                   <div className="bg-aura-purple/10 border border-aura-purple/20 rounded-2xl p-4 flex items-center gap-3">
                     <Loader2 size={16} className="text-aura-purple animate-spin" />
                     <span className="text-xs font-bold uppercase tracking-widest text-aura-purple animate-pulse">Aura is imagining your design...</span>
                   </div>
                </div>
              )}
            </div>

            <form onSubmit={handleSendMessage} className="p-4 bg-white/5 border-t border-white/10">
              <div className="flex gap-2">
                <div className="relative flex-1">
                    <input 
                    type="text" 
                    value={input}
                    onChange={(e) => setInput(e.target.value)}
                    placeholder="রঙ বা ডিজাইন বলুন (যেমন: 'লাল শাড়ি দেখাও')"
                    className="w-full bg-black/50 border border-white/10 rounded-xl pl-5 pr-12 py-4 focus:outline-none focus:border-aura-purple text-sm text-white disabled:opacity-50"
                    disabled={isTyping}
                    />
                    <button 
                      type="submit" 
                      disabled={!input.trim() || isTyping}
                      className="absolute right-2 top-2 p-2 bg-aura-purple rounded-lg text-white disabled:opacity-50 disabled:bg-gray-700"
                    >
                      <Send size={18} />
                    </button>
                </div>
                <button 
                    type="button" 
                    onClick={handleGenerateTrends}
                    disabled={isGeneratingTrends}
                    className="bg-white/5 hover:bg-white/10 border border-white/10 rounded-xl px-4 py-2 text-white flex items-center gap-2 transition-all disabled:opacity-50"
                >
                    {isGeneratingTrends ? (
                        <Loader2 size={18} className="animate-spin text-aura-purple" />
                    ) : (
                        <Wand2 size={18} className="text-aura-purple" />
                    )}
                    <span className="hidden md:inline text-xs font-bold uppercase tracking-widest">Trends</span>
                </button>
              </div>
            </form>
          </div>
        </div>
      </section>

      {/* Main Content Area with Sidebar */}
      <div id="product-section" className="max-w-7xl mx-auto px-6 py-10">
        <div className="flex flex-col lg:flex-row gap-8">

          {/* Sidebar Filters */}
          <aside className={`lg:w-64 shrink-0 transition-all duration-300 ${showMobileFilters ? 'fixed inset-0 z-[60] bg-black/95 p-8 overflow-y-auto' : 'hidden lg:block'}`}>
            <div className="flex items-center justify-between lg:hidden mb-8">
                <h2 className="text-xl font-bold font-serif text-white">Filters</h2>
                <button onClick={() => setShowMobileFilters(false)} className="p-2 bg-white/10 rounded-full">
                    <X size={20} />
                </button>
            </div>

            <div className="space-y-8 sticky top-24">
                {/* Vendor Section */}
                <div className="space-y-4">
                    <h3 className="text-[10px] uppercase tracking-widest font-bold text-aura-purple flex items-center gap-2">
                        <Building2 size={14} /> ভেন্ডর (Vendors)
                    </h3>
                    <div className="flex flex-col gap-1">
                        <FilterOption 
                            label="All Hub" 
                            active={!selectedVendorId} 
                            onClick={() => setSelectedVendorId(null)} 
                        />
                        {vendors.filter(v => v.status === 'APPROVED').map(vendor => (
                            <FilterOption 
                                key={vendor.id} 
                                label={vendor.name} 
                                active={selectedVendorId === vendor.id} 
                                onClick={() => setSelectedVendorId(vendor.id)} 
                            />
                        ))}
                    </div>
                </div>

                {/* Categories Section */}
                <div className="space-y-4">
                    <h3 className="text-[10px] uppercase tracking-widest font-bold text-aura-purple flex items-center gap-2">
                        <Tag size={14} /> ক্যাটাগরি (Categories)
                    </h3>
                    <div className="flex flex-col gap-1">
                        {availableCategories.map(cat => (
                            <FilterCheckbox 
                                key={cat} 
                                label={cat} 
                                checked={selectedCategories.includes(cat)} 
                                onChange={() => toggleCategory(cat)} 
                            />
                        ))}
                    </div>
                </div>

                {/* Price Range Section */}
                <div className="space-y-4">
                    <h3 className="text-[10px] uppercase tracking-widest font-bold text-aura-purple flex items-center gap-2">
                        <SlidersHorizontal size={14} /> বাজেট (Price Range)
                    </h3>
                    <div className="space-y-4 px-2">
                        <div className="flex flex-col gap-2">
                            <span className="text-[10px] text-gray-500 uppercase font-bold">Max: ৳{priceRange.max.toLocaleString()}</span>
                            <input 
                                type="range" 
                                min="0" 
                                max="100000" 
                                step="500"
                                value={priceRange.max}
                                onChange={(e) => setPriceRange(prev => ({ ...prev, max: Number(e.target.value) }))}
                                className="w-full accent-aura-purple"
                            />
                        </div>
                        <div className="flex gap-2">
                            <input 
                                type="number" 
                                placeholder="Min" 
                                value={priceRange.min === 0 ? '' : priceRange.min}
                                onChange={(e) => setPriceRange(prev => ({ ...prev, min: Number(e.target.value) }))}
                                className="w-1/2 bg-white/5 border border-white/10 rounded-lg px-2 py-2 text-xs text-white focus:border-aura-purple focus:outline-none" 
                            />
                            <input 
                                type="number" 
                                placeholder="Max" 
                                value={priceRange.max === 100000 ? '' : priceRange.max}
                                onChange={(e) => setPriceRange(prev => ({ ...prev, max: Number(e.target.value) || 100000 }))}
                                className="w-1/2 bg-white/5 border border-white/10 rounded-lg px-2 py-2 text-xs text-white focus:border-aura-purple focus:outline-none" 
                            />
                        </div>
                    </div>
                </div>

                {isFiltered && (
                    <button 
                        onClick={resetFilters}
                        className="w-full py-3 rounded-xl border border-dashed border-aura-purple/30 text-[10px] font-bold uppercase tracking-widest text-aura-purple hover:bg-aura-purple/5 transition-all"
                    >
                        Reset All Filters
                    </button>
                )}
            </div>
          </aside>

          {/* Product Grid Area */}
          <main className="flex-1">
            <div className="flex flex-col md:flex-row md:items-center justify-between mb-10 gap-4">
                <div className="flex items-center gap-4">
                    <h2 className="text-2xl font-serif font-bold flex items-center gap-4">
                        <Sparkles className="text-aura-purple" />
                        {isFiltered ? 'Filtered Results' : ' ট্রেন্ডিং কালেকশন'}
                    </h2>
                    <span className="text-xs text-gray-500 bg-white/5 px-3 py-1 rounded-full">{products.length} Products</span>
                </div>

                <div className="flex items-center gap-2">
                    <button 
                        onClick={() => setShowMobileFilters(true)}
                        className="lg:hidden flex items-center gap-2 px-6 py-2 bg-white text-black rounded-full text-[10px] font-bold uppercase tracking-widest hover:bg-gray-200 transition-all"
                    >
                        <SlidersHorizontal size={14} /> Filters
                    </button>
                    {isFiltered && (
                        <button onClick={resetFilters} className="flex items-center gap-2 px-4 py-2 bg-white/10 rounded-full text-[10px] font-bold uppercase tracking-widest hover:bg-white/20 transition-colors">
                            <X size={14} /> Clear All
                        </button>
                    )}
                </div>
            </div>

            {/* AI Intent Chips Bar */}
            {activeIntent && (
                <div className="mb-8 animate-in slide-in-from-top-4">
                    <div className="bg-white/5 backdrop-blur-md border border-white/10 rounded-2xl p-4 flex flex-wrap items-center gap-4">
                        <div className="flex items-center gap-2 text-aura-purple font-bold text-xs uppercase tracking-widest">
                            <Info size={14} /> Aura Context:
                        </div>
                        <div className="flex flex-wrap gap-2">
                            {activeIntent.category && <FilterChip label="Category" value={activeIntent.category} />}
                            {activeIntent.color && <FilterChip label="Color" value={activeIntent.color} />}
                            {activeIntent.material && <FilterChip label="Material" value={activeIntent.material} />}
                            {activeIntent.style && <FilterChip label="Style" value={activeIntent.style} />}
                            {activeIntent.maxPrice && <FilterChip label="Max Price" value={`৳${activeIntent.maxPrice}`} />}
                        </div>
                        <button onClick={() => setActiveIntent(null)} className="ml-auto text-xs text-gray-500 hover:text-white underline decoration-aura-purple">
                            Clear Intent
                        </button>
                    </div>
                </div>
            )}

            <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-8">
                {products.length === 0 ? (
                    <div className="col-span-full py-20 text-center bg-white/5 rounded-3xl border border-dashed border-white/10">
                        <Building2 className="mx-auto text-gray-600 mb-4" size={48} />
                        <h3 className="text-xl font-bold text-gray-400">এই ফিল্টারে কোনো পণ্য পাওয়া যায়নি</h3>
                        <p className="text-sm text-gray-600 mt-2">অন্য কোনো ভেন্ডর বা ডিজাইন ট্রাই করুন।</p>
                    </div>
                ) : (
                    products.map(p => (
                        <div key={p.id} className="relative">
                            {p.vendorId === 0 && (
                                <div className="absolute -top-3 -right-3 z-20 bg-aura-purple text-white px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-widest shadow-lg flex items-center gap-1">
                                    <Sparkles size={10} /> AI Concept
                                </div>
                            )}
                            <ProductCard 
                                product={p} 
                                vendor={p.vendorId === 0 ? { id: 0, name: "Aura Innovations", slug: "aura", status: "APPROVED", description: "AI Generated Concepts" } : vendors.find(v => v.id === p.vendorId)} 
                            />
                        </div>
                    ))
                )}
            </div>
          </main>
        </div>
      </div>
    </div>
  );
};

const FilterOption: React.FC<{ label: string; active: boolean; onClick: () => void }> = ({ label, active, onClick }) => (
    <button 
        onClick={onClick}
        className={`w-full text-left px-4 py-2 rounded-xl text-xs font-medium transition-all ${
            active 
            ? 'bg-aura-purple text-white shadow-lg shadow-purple-900/20' 
            : 'text-gray-400 hover:bg-white/5 hover:text-white'
        }`}
    >
        {label}
    </button>
);

const FilterCheckbox: React.FC<{ label: string; checked: boolean; onChange: () => void }> = ({ label, checked, onChange }) => (
    <label className="flex items-center gap-3 px-4 py-2 cursor-pointer group">
        <div className={`w-4 h-4 rounded border flex items-center justify-center transition-all ${checked ? 'bg-aura-purple border-aura-purple' : 'border-white/20 group-hover:border-white/40'}`}>
            {checked && <X size={10} className="text-white" />}
        </div>
        <input type="checkbox" className="hidden" checked={checked} onChange={onChange} />
        <span className={`text-xs transition-colors ${checked ? 'text-white font-bold' : 'text-gray-400 group-hover:text-white'}`}>{label}</span>
    </label>
);

const FilterChip: React.FC<{ label: string, value: string, variant?: 'primary' | 'ghost' }> = ({ label, value, variant = 'primary' }) => (
    <div className={`px-3 py-1 rounded-lg border text-[10px] font-bold flex items-center gap-2 ${
        variant === 'primary' 
        ? 'bg-white/10 border-white/20 text-white' 
        : 'bg-transparent border-white/10 text-gray-400'
    }`}>
        <Tag size={10} className="text-aura-purple" />
        <span className="uppercase tracking-tighter opacity-60">{label}:</span>
        <span>{value}</span>
    </div>
);

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { generateAuraResponse, analyzeSearchIntent, generateAuraImage, generateTrendingProducts, SearchIntent } from '../services/geminiService';
import { getProducts, getVendors, getLiveSales } from '../services/mockData';
import { ProductCard } from '../components/ProductCard';
import { ChatMessage, Product, Vendor } from '../types';
import { Sparkles, Send, Trash2, Clock, Image as ImageIcon, Loader2, Filter, X, Wand2, Info, Tag, Building2, AlertCircle, ChevronDown, ChevronUp, SlidersHorizontal } from 'lucide-react';

export const Home: React.FC = () => {
  const [allProducts, setAllProducts] = useState<Product[]>([]);
  const [fictionalProducts, setFictionalProducts] = useState<Product[]>([]);
  const [products, setProducts] = useState<Product[]>([]);
  const [vendors, setVendors] = useState<Vendor[]>([]);
  const [salesTicker, setSalesTicker] = useState(0);

  // Filtering states
  const [selectedVendorId, setSelectedVendorId] = useState<number | null>(null);
  const [activeIntent, setActiveIntent] = useState<SearchIntent | null>(null);
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [priceRange, setPriceRange] = useState<{ min: number; max: number }>({ min: 0, max: 100000 });
  const [showMobileFilters, setShowMobileFilters] = useState(false);

  // AI & UI states
  const [isGeneratingTrends, setIsGeneratingTrends] = useState(false);
  const [apiError, setApiError] = useState<string | null>(null);
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'ai', content: "আসসালামু আলাইকুম। Snehalata-স্নেহলতা ইকোসিস্টেমে স্বাগতম। আমি Aura। আজ আপনার স্টাইল যাত্রায় কীভাবে সাহায্য করতে পারি?", timestamp: Date.now() }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [isGeneratingImage, setIsGeneratingImage] = useState(false);
  const chatContainerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const initialProducts = getProducts();
    setAllProducts(initialProducts);
    setProducts(initialProducts);
    setVendors(getVendors());
    setSalesTicker(getLiveSales());

    const interval = setInterval(() => {
        setSalesTicker(prev => prev + Math.floor(Math.random() * 500));
    }, 5000);
    return () => clearInterval(interval);
  }, []);

  // Auto-hide errors
  useEffect(() => {
    if (apiError) {
      const timer = setTimeout(() => setApiError(null), 5000);
      return () => clearTimeout(timer);
    }
  }, [apiError]);

  // Derived categories from products
  const availableCategories = useMemo(() => {
    const cats = new Set<string>();
    [...allProducts, ...fictionalProducts].forEach(p => cats.add(p.category));
    return Array.from(cats);
  }, [allProducts, fictionalProducts]);

  // Synchronize products based on filters and selected vendor
  useEffect(() => {
    applyFilters();
  }, [selectedVendorId, activeIntent, fictionalProducts, selectedCategories, priceRange]);

  const applyFilters = () => {
    let filtered = [...allProducts, ...fictionalProducts];

    filtered = filtered.filter(p => {
        const productData = `${p.name} ${p.description} ${p.category}`.toLowerCase();

        // Manual Vendor Filter
        if (selectedVendorId && p.vendorId !== selectedVendorId) return false;

        // Category Filter
        if (selectedCategories.length > 0 && !selectedCategories.includes(p.category)) return false;

        // Price Range Filter
        if (p.price < priceRange.min || p.price > priceRange.max) return false;

        // AI Intent Filtering (Cumulative)
        if (activeIntent) {
            let score = 0;
            if (activeIntent.category && productData.includes(activeIntent.category.toLowerCase())) score += 10;
            if (activeIntent.color && productData.includes(activeIntent.color.toLowerCase())) score += 5;
            if (activeIntent.material && productData.includes(activeIntent.material.toLowerCase())) score += 8;
            if (activeIntent.style && productData.includes(activeIntent.style.toLowerCase())) score += 5;

            if (activeIntent.maxPrice && p.price > activeIntent.maxPrice) return false;
            if (activeIntent.minPrice && p.price < activeIntent.minPrice) return false;

            if (activeIntent.semanticKeywords && activeIntent.semanticKeywords.length > 0) {
                activeIntent.semanticKeywords.forEach(keyword => {
                    if (productData.includes(keyword.toLowerCase())) score += 2;
                });
            }

            // Only filter by intent if intent actually contains specific parameters
            if (activeIntent.category || activeIntent.color || activeIntent.material || activeIntent.style || (activeIntent.semanticKeywords && activeIntent.semanticKeywords.length > 0)) {
                if (score === 0) return false;
            }
        }

        return true;
    });

    setProducts(filtered);
  };

  const isFiltered = useMemo(() => {
      return !!selectedVendorId || !!activeIntent || selectedCategories.length > 0 || priceRange.min > 0 || priceRange.max < 100000;
  }, [selectedVendorId, activeIntent, selectedCategories, priceRange]);

  useEffect(() => {
    if (chatContainerRef.current) {
      chatContainerRef.current.scrollTop = chatContainerRef.current.scrollHeight;
    }
  }, [messages, isTyping, isGeneratingImage]);

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isTyping) return;

    const userMsg: ChatMessage = { role: 'user', content: input, timestamp: Date.now() };
    setMessages(prev => [...prev, userMsg]);
    const currentInput = input;
    setInput('');
    setIsTyping(true);
    setApiError(null);

    try {
      const intentPromise = analyzeSearchIntent(currentInput);
      const responsePromise = generateAuraResponse(currentInput);

      const [auraResponse, intent] = await Promise.all([responsePromise, intentPromise]);

      setIsTyping(false);

      if (intent) {
        setActiveIntent(intent);
      }

      let generatedImageUrl = undefined;
      if (intent?.shouldGenerateImage && intent.imagePrompt) {
          setIsGeneratingImage(true);
          try {
            const img = await generateAuraImage(intent.imagePrompt);
            generatedImageUrl = img || undefined;
          } catch (imgErr) {
            console.error("Image generation failed", imgErr);
            setApiError("Aura ইমেজ জেনারেশনে সমস্যা হয়েছে। টেক্সট রেসপন্স দেখুন।");
          } finally {
            setIsGeneratingImage(false);
          }
      }

      setMessages(prev => [...prev, { 
          role: 'ai', 
          content: auraResponse || "আসসালামু আলাইকুম। দুঃখিত, আমি আপনার অনুরোধটি বুঝতে পারছি না।", 
          timestamp: Date.now(),
          generatedImageUrl 
      }]);
    } catch (error) {
      console.error("Aura interaction error:", error);
      setIsTyping(false);
      setApiError("দুঃখিত, Aura সার্ভারে সংযোগ করা যাচ্ছে না। দয়া করে আবার চেষ্টা করুন।");
      setMessages(prev => [...prev, { 
          role: 'ai', 
          content: "আসসালামু আলাইকুম। যান্ত্রিক ত্রুটির কারণে আমি এখন উত্তর দিতে পারছি না। কিছুক্ষণ পর আবার মেসেজ দিন।", 
          timestamp: Date.now() 
      }]);
    }
  };

  const handleGenerateTrends = async () => {
    if (isGeneratingTrends) return;
    setIsGeneratingTrends(true);
    setApiError(null);

    try {
      const trends = await generateTrendingProducts();
      if (!trends || trends.length === 0) {
        throw new Error("No trends generated");
      }

      const formattedTrends: Product[] = trends.map(t => ({
          ...t,
          vendorId: 0, 
          id: t.id + 1000 
      }));

      setFictionalProducts(prev => [...prev, ...formattedTrends]);

      setMessages(prev => [...prev, {
          role: 'ai',
          content: "আসসালামু আলাইকুম। আমি ২০২৬ সালের সম্ভাব্য ট্রেন্ড থেকে কিছু কাল্পনিক ডিজাইন তৈরি করেছি। আপনার গ্রিডের নিচে দেখুন!",
          timestamp: Date.now()
      }]);

      const section = document.getElementById('product-section');
      section?.scrollIntoView({ behavior: 'smooth' });
    } catch (error) {
      console.error("Trend generation error:", error);
      setApiError("ট্রেন্ডিং প্রোডাক্ট জেনারেট করা সম্ভব হয়নি। Aura সিস্টেম আপডেট হচ্ছে।");
    } finally {
      setIsGeneratingTrends(false);
    }
  };

  const resetFilters = () => {
      setSelectedVendorId(null);
      setActiveIntent(null);
      setSelectedCategories([]);
      setPriceRange({ min: 0, max: 100000 });
  };

  const toggleCategory = (cat: string) => {
      setSelectedCategories(prev => 
        prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat]
      );
  };

  const clearChat = () => {
    setMessages([{ role: 'ai', content: "আসসালামু আলাইকুম। নতুন করে শুরু করি? আমি Aura, আপনার সেবায় নিয়োজিত।", timestamp: Date.now() }]);
  };

  return (
    <div className="min-h-screen">
      {/* Error Notification Banner */}
      {apiError && (
        <div className="fixed top-24 left-1/2 -translate-x-1/2 z-[100] w-full max-w-md px-4 animate-in slide-in-from-top-10 duration-500">
           <div className="bg-red-500/90 backdrop-blur-xl text-white p-4 rounded-2xl shadow-2xl border border-red-400/50 flex items-start gap-3">
              <AlertCircle className="shrink-0 mt-0.5" size={18} />
              <div className="flex-1">
                 <h4 className="text-xs font-bold uppercase tracking-widest mb-1">Aura System Alert</h4>
                 <p className="text-sm font-medium">{apiError}</p>
              </div>
              <button onClick={() => setApiError(null)} className="p-1 hover:bg-white/20 rounded-lg transition-colors">
                 <X size={16} />
              </button>
           </div>
        </div>
      )}

      {/* Hero Section */}
      <section className="relative min-h-[600px] flex flex-col items-center justify-center px-6 py-20 overflow-hidden">
        {/* Glow Background */}
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[800px] h-[800px] bg-aura-purple/5 blur-[120px] rounded-full pointer-events-none" />

        <div className="relative z-10 w-full max-w-4xl flex flex-col gap-10">
          <div className="text-center space-y-4">
             <div className="inline-flex items-center gap-2 px-4 py-2 rounded-full border border-aura-glassBorder bg-white/5 backdrop-blur-md">
                <span className="relative flex h-2 w-2">
                  <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-400 opacity-75"></span>
                  <span className="relative inline-flex rounded-full h-2 w-2 bg-green-500"></span>
                </span>
                <span className="text-[10px] uppercase tracking-[0.2em] font-bold text-gray-400">
                   Ecosystem ভলিউম: ৳{salesTicker.toLocaleString()}
                </span>
             </div>
             <div className="flex flex-col items-center">
                <h1 className="text-4xl md:text-6xl font-serif font-black text-white leading-tight mb-2 tracking-tight">
                  SNEHALATA-স্নেহলতা
                </h1>
                <p className="text-sm md:text-base font-bold text-aura-ash uppercase tracking-[0.5em] opacity-90">
                  The Aura AI Driven Ecosystem
                </p>
             </div>
          </div>

          <div className="w-full bg-black/60 backdrop-blur-xl border border-white/10 rounded-3xl overflow-hidden shadow-2xl flex flex-col h-[500px]">
            <div className="flex items-center justify-between px-6 py-4 border-b border-white/10 bg-white/5">
                <div className="flex items-center gap-2">
                    <Sparkles size={16} className="text-aura-purple" />
                    <span className="text-xs font-bold uppercase tracking-widest text-white">Aura Live Assistant</span>
                </div>
                <button onClick={clearChat} className="text-gray-500 hover:text-red-400 transition-colors">
                    <Trash2 size={16} />
                </button>
            </div>

            <div className="flex-1 p-6 overflow-y-auto space-y-6 scroll-smooth" ref={chatContainerRef}>
              {messages.map((msg, idx) => (
                <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                  <div className={`max-w-[85%] rounded-2xl p-4 text-sm ${msg.role === 'user' ? 'bg-white text-black font-medium' : 'bg-white/10 text-gray-200 border border-white/5'}`}>
                    {msg.role === 'ai' && <div className="text-[10px] uppercase tracking-widest text-aura-purple mb-1 font-bold">Aura AI</div>}
                    <div className="whitespace-pre-wrap">{msg.content}</div>

                    {msg.generatedImageUrl && (
                        <div className="mt-4 rounded-xl overflow-hidden border border-white/10 shadow-lg">
                            <img src={msg.generatedImageUrl} alt="AI Concept" className="w-full h-auto" />
                            <div className="bg-black/40 backdrop-blur-md p-2 flex items-center gap-2 text-[10px] font-bold uppercase tracking-widest text-gray-400">
                                <ImageIcon size={12} /> Aura Conceptual Preview
                            </div>
                        </div>
                    )}

                    <div className="mt-2 text-[10px] flex items-center justify-end gap-1 opacity-50">
                        {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                        <Clock size={10} />
                    </div>
                  </div>
                </div>
              ))}

              {isTyping && (
                <div className="flex justify-start">
                   <div className="bg-white/5 rounded-2xl p-4 flex gap-2">
                     <span className="w-2 h-2 bg-aura-purple rounded-full animate-bounce"></span>
                     <span className="w-2 h-2 bg-aura-purple rounded-full animate-bounce delay-75"></span>
                     <span className="w-2 h-2 bg-aura-purple rounded-full animate-bounce delay-150"></span>
                   </div>
                </div>
              )}

              {isGeneratingImage && (
                <div className="flex justify-start">
                   <div className="bg-aura-purple/10 border border-aura-purple/20 rounded-2xl p-4 flex items-center gap-3">
                     <Loader2 size={16} className="text-aura-purple animate-spin" />
                     <span className="text-xs font-bold uppercase tracking-widest text-aura-purple animate-pulse">Aura is imagining your design...</span>
                   </div>
                </div>
              )}
            </div>

            <form onSubmit={handleSendMessage} className="p-4 bg-white/5 border-t border-white/10">
              <div className="flex gap-2">
                <div className="relative flex-1">
                    <input 
                    type="text" 
                    value={input}
                    onChange={(e) => setInput(e.target.value)}
                    placeholder="রঙ বা ডিজাইন বলুন (যেমন: 'লাল শাড়ি দেখাও')"
                    className="w-full bg-black/50 border border-white/10 rounded-xl pl-5 pr-12 py-4 focus:outline-none focus:border-aura-purple text-sm text-white disabled:opacity-50"
                    disabled={isTyping}
                    />
                    <button 
                      type="submit" 
                      disabled={!input.trim() || isTyping}
                      className="absolute right-2 top-2 p-2 bg-aura-purple rounded-lg text-white disabled:opacity-50 disabled:bg-gray-700"
                    >
                      <Send size={18} />
                    </button>
                </div>
                <button 
                    type="button" 
                    onClick={handleGenerateTrends}
                    disabled={isGeneratingTrends}
                    className="bg-white/5 hover:bg-white/10 border border-white/10 rounded-xl px-4 py-2 text-white flex items-center gap-2 transition-all disabled:opacity-50"
                >
                    {isGeneratingTrends ? (
                        <Loader2 size={18} className="animate-spin text-aura-purple" />
                    ) : (
                        <Wand2 size={18} className="text-aura-purple" />
                    )}
                    <span className="hidden md:inline text-xs font-bold uppercase tracking-widest">Trends</span>
                </button>
              </div>
            </form>
          </div>
        </div>
      </section>

      {/* Main Content Area with Sidebar */}
      <div id="product-section" className="max-w-7xl mx-auto px-6 py-10">
        <div className="flex flex-col lg:flex-row gap-8">

          {/* Sidebar Filters */}
          <aside className={`lg:w-64 shrink-0 transition-all duration-300 ${showMobileFilters ? 'fixed inset-0 z-[60] bg-black/95 p-8 overflow-y-auto' : 'hidden lg:block'}`}>
            <div className="flex items-center justify-between lg:hidden mb-8">
                <h2 className="text-xl font-bold font-serif text-white">Filters</h2>
                <button onClick={() => setShowMobileFilters(false)} className="p-2 bg-white/10 rounded-full">
                    <X size={20} />
                </button>
            </div>

            <div className="space-y-8 sticky top-24">
                {/* Vendor Section */}
                <div className="space-y-4">
                    <h3 className="text-[10px] uppercase tracking-widest font-bold text-aura-purple flex items-center gap-2">
                        <Building2 size={14} /> ভেন্ডর (Vendors)
                    </h3>
                    <div className="flex flex-col gap-1">
                        <FilterOption 
                            label="All Hub" 
                            active={!selectedVendorId} 
                            onClick={() => setSelectedVendorId(null)} 
                        />
                        {vendors.filter(v => v.status === 'APPROVED').map(vendor => (
                            <FilterOption 
                                key={vendor.id} 
                                label={vendor.name} 
                                active={selectedVendorId === vendor.id} 
                                onClick={() => setSelectedVendorId(vendor.id)} 
                            />
                        ))}
                    </div>
                </div>

                {/* Categories Section */}
                <div className="space-y-4">
                    <h3 className="text-[10px] uppercase tracking-widest font-bold text-aura-purple flex items-center gap-2">
                        <Tag size={14} /> ক্যাটাগরি (Categories)
                    </h3>
                    <div className="flex flex-col gap-1">
                        {availableCategories.map(cat => (
                            <FilterCheckbox 
                                key={cat} 
                                label={cat} 
                                checked={selectedCategories.includes(cat)} 
                                onChange={() => toggleCategory(cat)} 
                            />
                        ))}
                    </div>
                </div>

                {/* Price Range Section */}
                <div className="space-y-4">
                    <h3 className="text-[10px] uppercase tracking-widest font-bold text-aura-purple flex items-center gap-2">
                        <SlidersHorizontal size={14} /> বাজেট (Price Range)
                    </h3>
                    <div className="space-y-4 px-2">
                        <div className="flex flex-col gap-2">
                            <span className="text-[10px] text-gray-500 uppercase font-bold">Max: ৳{priceRange.max.toLocaleString()}</span>
                            <input 
                                type="range" 
                                min="0" 
                                max="100000" 
                                step="500"
                                value={priceRange.max}
                                onChange={(e) => setPriceRange(prev => ({ ...prev, max: Number(e.target.value) }))}
                                className="w-full accent-aura-purple"
                            />
                        </div>
                        <div className="flex gap-2">
                            <input 
                                type="number" 
                                placeholder="Min" 
                                value={priceRange.min === 0 ? '' : priceRange.min}
                                onChange={(e) => setPriceRange(prev => ({ ...prev, min: Number(e.target.value) }))}
                                className="w-1/2 bg-white/5 border border-white/10 rounded-lg px-2 py-2 text-xs text-white focus:border-aura-purple focus:outline-none" 
                            />
                            <input 
                                type="number" 
                                placeholder="Max" 
                                value={priceRange.max === 100000 ? '' : priceRange.max}
                                onChange={(e) => setPriceRange(prev => ({ ...prev, max: Number(e.target.value) || 100000 }))}
                                className="w-1/2 bg-white/5 border border-white/10 rounded-lg px-2 py-2 text-xs text-white focus:border-aura-purple focus:outline-none" 
                            />
                        </div>
                    </div>
                </div>

                {isFiltered && (
                    <button 
                        onClick={resetFilters}
                        className="w-full py-3 rounded-xl border border-dashed border-aura-purple/30 text-[10px] font-bold uppercase tracking-widest text-aura-purple hover:bg-aura-purple/5 transition-all"
                    >
                        Reset All Filters
                    </button>
                )}
            </div>
          </aside>

          {/* Product Grid Area */}
          <main className="flex-1">
            <div className="flex flex-col md:flex-row md:items-center justify-between mb-10 gap-4">
                <div className="flex items-center gap-4">
                    <h2 className="text-2xl font-serif font-bold flex items-center gap-4">
                        <Sparkles className="text-aura-purple" />
                        {isFiltered ? 'Filtered Results' : ' ট্রেন্ডিং কালেকশন'}
                    </h2>
                    <span className="text-xs text-gray-500 bg-white/5 px-3 py-1 rounded-full">{products.length} Products</span>
                </div>

                <div className="flex items-center gap-2">
                    <button 
                        onClick={() => setShowMobileFilters(true)}
                        className="lg:hidden flex items-center gap-2 px-6 py-2 bg-white text-black rounded-full text-[10px] font-bold uppercase tracking-widest hover:bg-gray-200 transition-all"
                    >
                        <SlidersHorizontal size={14} /> Filters
                    </button>
                    {isFiltered && (
                        <button onClick={resetFilters} className="flex items-center gap-2 px-4 py-2 bg-white/10 rounded-full text-[10px] font-bold uppercase tracking-widest hover:bg-white/20 transition-colors">
                            <X size={14} /> Clear All
                        </button>
                    )}
                </div>
            </div>

            {/* AI Intent Chips Bar */}
            {activeIntent && (
                <div className="mb-8 animate-in slide-in-from-top-4">
                    <div className="bg-white/5 backdrop-blur-md border border-white/10 rounded-2xl p-4 flex flex-wrap items-center gap-4">
                        <div className="flex items-center gap-2 text-aura-purple font-bold text-xs uppercase tracking-widest">
                            <Info size={14} /> Aura Context:
                        </div>
                        <div className="flex flex-wrap gap-2">
                            {activeIntent.category && <FilterChip label="Category" value={activeIntent.category} />}
                            {activeIntent.color && <FilterChip label="Color" value={activeIntent.color} />}
                            {activeIntent.material && <FilterChip label="Material" value={activeIntent.material} />}
                            {activeIntent.style && <FilterChip label="Style" value={activeIntent.style} />}
                            {activeIntent.maxPrice && <FilterChip label="Max Price" value={`৳${activeIntent.maxPrice}`} />}
                        </div>
                        <button onClick={() => setActiveIntent(null)} className="ml-auto text-xs text-gray-500 hover:text-white underline decoration-aura-purple">
                            Clear Intent
                        </button>
                    </div>
                </div>
            )}

            <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-8">
                {products.length === 0 ? (
                    <div className="col-span-full py-20 text-center bg-white/5 rounded-3xl border border-dashed border-white/10">
                        <Building2 className="mx-auto text-gray-600 mb-4" size={48} />
                        <h3 className="text-xl font-bold text-gray-400">এই ফিল্টারে কোনো পণ্য পাওয়া যায়নি</h3>
                        <p className="text-sm text-gray-600 mt-2">অন্য কোনো ভেন্ডর বা ডিজাইন ট্রাই করুন।</p>
                    </div>
                ) : (
                    products.map(p => (
                        <div key={p.id} className="relative">
                            {p.vendorId === 0 && (
                                <div className="absolute -top-3 -right-3 z-20 bg-aura-purple text-white px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-widest shadow-lg flex items-center gap-1">
                                    <Sparkles size={10} /> AI Concept
                                </div>
                            )}
                            <ProductCard 
                                product={p} 
                                vendor={p.vendorId === 0 ? { id: 0, name: "Aura Innovations", slug: "aura", status: "APPROVED", description: "AI Generated Concepts" } : vendors.find(v => v.id === p.vendorId)} 
                            />
                        </div>
                    ))
                )}
            </div>
          </main>
        </div>
      </div>
    </div>
  );
};

const FilterOption: React.FC<{ label: string; active: boolean; onClick: () => void }> = ({ label, active, onClick }) => (
    <button 
        onClick={onClick}
        className={`w-full text-left px-4 py-2 rounded-xl text-xs font-medium transition-all ${
            active 
            ? 'bg-aura-purple text-white shadow-lg shadow-purple-900/20' 
            : 'text-gray-400 hover:bg-white/5 hover:text-white'
        }`}
    >
        {label}
    </button>
);

const FilterCheckbox: React.FC<{ label: string; checked: boolean; onChange: () => void }> = ({ label, checked, onChange }) => (
    <label className="flex items-center gap-3 px-4 py-2 cursor-pointer group">
        <div className={`w-4 h-4 rounded border flex items-center justify-center transition-all ${checked ? 'bg-aura-purple border-aura-purple' : 'border-white/20 group-hover:border-white/40'}`}>
            {checked && <X size={10} className="text-white" />}
        </div>
        <input type="checkbox" className="hidden" checked={checked} onChange={onChange} />
        <span className={`text-xs transition-colors ${checked ? 'text-white font-bold' : 'text-gray-400 group-hover:text-white'}`}>{label}</span>
    </label>
);

const FilterChip: React.FC<{ label: string, value: string, variant?: 'primary' | 'ghost' }> = ({ label, value, variant = 'primary' }) => (
    <div className={`px-3 py-1 rounded-lg border text-[10px] font-bold flex items-center gap-2 ${
        variant === 'primary' 
        ? 'bg-white/10 border-white/20 text-white' 
        : 'bg-transparent border-white/10 text-gray-400'
    }`}>
        <Tag size={10} className="text-aura-purple" />
        <span className="uppercase tracking-tighter opacity-60">{label}:</span>
        <span>{value}</span>
    </div>
);

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { generateAuraResponse, analyzeSearchIntent, generateAuraImage, generateTrendingProducts, SearchIntent } from '../services/geminiService';
import { getProducts, getVendors, getLiveSales } from '../services/mockData';
import { ProductCard } from '../components/ProductCard';
import { ChatMessage, Product, Vendor } from '../types';
import { Sparkles, Send, Trash2, Clock, Image as ImageIcon, Loader2, Filter, X, Wand2, Info, Tag, Building2, AlertCircle, ChevronDown, ChevronUp, SlidersHorizontal } from 'lucide-react';

export const Home: React.FC = () => {
  const [allProducts, setAllProducts] = useState<Product[]>([]);
  const [fictionalProducts, setFictionalProducts] = useState<Product[]>([]);
  const [products, setProducts] = useState<Product[]>([]);
  const [vendors, setVendors] = useState<Vendor[]>([]);
  const [salesTicker, setSalesTicker] = useState(0);

  // Filtering states
  const [selectedVendorId, setSelectedVendorId] = useState<number | null>(null);
  const [activeIntent, setActiveIntent] = useState<SearchIntent | null>(null);
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [priceRange, setPriceRange] = useState<{ min: number; max: number }>({ min: 0, max: 100000 });
  const [showMobileFilters, setShowMobileFilters] = useState(false);

  // AI & UI states
  const [isGeneratingTrends, setIsGeneratingTrends] = useState(false);
  const [apiError, setApiError] = useState<string | null>(null);
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'ai', content: "আসসালামু আলাইকুম। Snehalata-স্নেহলতা ইকোসিস্টেমে স্বাগতম। আমি Aura। আজ আপনার স্টাইল যাত্রায় কীভাবে সাহায্য করতে পারি?", timestamp: Date.now() }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [isGeneratingImage, setIsGeneratingImage] = useState(false);
  const chatContainerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const initialProducts = getProducts();
    setAllProducts(initialProducts);
    setProducts(initialProducts);
    setVendors(getVendors());
    setSalesTicker(getLiveSales());

    const interval = setInterval(() => {
        setSalesTicker(prev => prev + Math.floor(Math.random() * 500));
    }, 5000);
    return () => clearInterval(interval);
  }, []);

  // Auto-hide errors
  useEffect(() => {
    if (apiError) {
      const timer = setTimeout(() => setApiError(null), 5000);
      return () => clearTimeout(timer);
    }
  }, [apiError]);

  // Derived categories from products
  const availableCategories = useMemo(() => {
    const cats = new Set<string>();
    [...allProducts, ...fictionalProducts].forEach(p => cats.add(p.category));
    return Array.from(cats);
  }, [allProducts, fictionalProducts]);

  // Synchronize products based on filters and selected vendor
  useEffect(() => {
    applyFilters();
  }, [selectedVendorId, activeIntent, fictionalProducts, selectedCategories, priceRange]);

  const applyFilters = () => {
    let filtered = [...allProducts, ...fictionalProducts];

    filtered = filtered.filter(p => {
        const productData = `${p.name} ${p.description} ${p.category}`.toLowerCase();

        // Manual Vendor Filter
        if (selectedVendorId && p.vendorId !== selectedVendorId) return false;

        // Category Filter
        if (selectedCategories.length > 0 && !selectedCategories.includes(p.category)) return false;

        // Price Range Filter
        if (p.price < priceRange.min || p.price > priceRange.max) return false;

        // AI Intent Filtering (Cumulative)
        if (activeIntent) {
            let score = 0;
            if (activeIntent.category && productData.includes(activeIntent.category.toLowerCase())) score += 10;
            if (activeIntent.color && productData.includes(activeIntent.color.toLowerCase())) score += 5;
            if (activeIntent.material && productData.includes(activeIntent.material.toLowerCase())) score += 8;
            if (activeIntent.style && productData.includes(activeIntent.style.toLowerCase())) score += 5;

            if (activeIntent.maxPrice && p.price > activeIntent.maxPrice) return false;
            if (activeIntent.minPrice && p.price < activeIntent.minPrice) return false;

            if (activeIntent.semanticKeywords && activeIntent.semanticKeywords.length > 0) {
                activeIntent.semanticKeywords.forEach(keyword => {
                    if (productData.includes(keyword.toLowerCase())) score += 2;
                });
            }

            // Only filter by intent if intent actually contains specific parameters
            if (activeIntent.category || activeIntent.color || activeIntent.material || activeIntent.style || (activeIntent.semanticKeywords && activeIntent.semanticKeywords.length > 0)) {
                if (score === 0) return false;
            }
        }

        return true;
    });

    setProducts(filtered);
  };

  const isFiltered = useMemo(() => {
      return !!selectedVendorId || !!activeIntent || selectedCategories.length > 0 || priceRange.min > 0 || priceRange.max < 100000;
  }, [selectedVendorId, activeIntent, selectedCategories, priceRange]);

  useEffect(() => {
    if (chatContainerRef.current) {
      chatContainerRef.current.scrollTop = chatContainerRef.current.scrollHeight;
    }
  }, [messages, isTyping, isGeneratingImage]);

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isTyping) return;

    const userMsg: ChatMessage = { role: 'user', content: input, timestamp: Date.now() };
    setMessages(prev => [...prev, userMsg]);
    const currentInput = input;
    setInput('');
    setIsTyping(true);
    setApiError(null);

    try {
      const intentPromise = analyzeSearchIntent(currentInput);
      const responsePromise = generateAuraResponse(currentInput);

      const [auraResponse, intent] = await Promise.all([responsePromise, intentPromise]);

      setIsTyping(false);

      if (intent) {
        setActiveIntent(intent);
      }

      let generatedImageUrl = undefined;
      if (intent?.shouldGenerateImage && intent.imagePrompt) {
          setIsGeneratingImage(true);
          try {
            const img = await generateAuraImage(intent.imagePrompt);
            generatedImageUrl = img || undefined;
          } catch (imgErr) {
            console.error("Image generation failed", imgErr);
            setApiError("Aura ইমেজ জেনারেশনে সমস্যা হয়েছে। টেক্সট রেসপন্স দেখুন।");
          } finally {
            setIsGeneratingImage(false);
          }
      }

      setMessages(prev => [...prev, { 
          role: 'ai', 
          content: auraResponse || "আসসালামু আলাইকুম। দুঃখিত, আমি আপনার অনুরোধটি বুঝতে পারছি না।", 
          timestamp: Date.now(),
          generatedImageUrl 
      }]);
    } catch (error) {
      console.error("Aura interaction error:", error);
      setIsTyping(false);
      setApiError("দুঃখিত, Aura সার্ভারে সংযোগ করা যাচ্ছে না। দয়া করে আবার চেষ্টা করুন।");
      setMessages(prev => [...prev, { 
          role: 'ai', 
          content: "আসসালামু আলাইকুম। যান্ত্রিক ত্রুটির কারণে আমি এখন উত্তর দিতে পারছি না। কিছুক্ষণ পর আবার মেসেজ দিন।", 
          timestamp: Date.now() 
      }]);
    }
  };

  const handleGenerateTrends = async () => {
    if (isGeneratingTrends) return;
    setIsGeneratingTrends(true);
    setApiError(null);

    try {
      const trends = await generateTrendingProducts();
      if (!trends || trends.length === 0) {
        throw new Error("No trends generated");
      }

      const formattedTrends: Product[] = trends.map(t => ({
          ...t,
          vendorId: 0, 
          id: t.id + 1000 
      }));

      setFictionalProducts(prev => [...prev, ...formattedTrends]);

      setMessages(prev => [...prev, {
          role: 'ai',
          content: "আসসালামু আলাইকুম। আমি ২০২৬ সালের সম্ভাব্য ট্রেন্ড থেকে কিছু কাল্পনিক ডিজাইন তৈরি করেছি। আপনার গ্রিডের নিচে দেখুন!",
          timestamp: Date.now()
      }]);

      const section = document.getElementById('product-section');
      section?.scrollIntoView({ behavior: 'smooth' });
    } catch (error) {
      console.error("Trend generation error:", error);
