                            <span className="text-[10px] text-gray-500 uppercase font-bold">Max: ৳{priceRange.max.toLocaleString()}</span>
                            <input 
                                type="range" 
                                min="0" 
                                max="100000" 
                                step="500"
                                value={priceRange.max}
                                onChange={(e) => setPriceRange(prev => ({ ...prev, max: Number(e.target.value) }))}
                                className="w-full accent-aura-purple"
                            />
                        </div>
                        <div className="flex gap-2">
                            <input 
                                type="number" 
                                placeholder="Min" 
                                value={priceRange.min === 0 ? '' : priceRange.min}
                                onChange={(e) => setPriceRange(prev => ({ ...prev, min: Number(e.target.value) }))}
                                className="w-1/2 bg-white/5 border border-white/10 rounded-lg px-2 py-2 text-xs text-white focus:border-aura-purple focus:outline-none" 
                            />
                            <input 
                                type="number" 
                                placeholder="Max" 
                                value={priceRange.max === 100000 ? '' : priceRange.max}
                                onChange={(e) => setPriceRange(prev => ({ ...prev, max: Number(e.target.value) || 100000 }))}
                                className="w-1/2 bg-white/5 border border-white/10 rounded-lg px-2 py-2 text-xs text-white focus:border-aura-purple focus:outline-none" 
                            />
                        </div>
                    </div>
                </div>

                {isFiltered && (
                    <button 
                        onClick={resetFilters}
                        className="w-full py-3 rounded-xl border border-dashed border-aura-purple/30 text-[10px] font-bold uppercase tracking-widest text-aura-purple hover:bg-aura-purple/5 transition-all"
                    >
                        Reset All Filters
                    </button>
                )}
            </div>
          </aside>

          {/* Product Grid Area */}
          <main className="flex-1">
            <div className="flex flex-col md:flex-row md:items-center justify-between mb-10 gap-4">
                <div className="flex items-center gap-4">
                    <h2 className="text-2xl font-serif font-bold flex items-center gap-4">
                        <Sparkles className="text-aura-purple" />
                        {isFiltered ? 'Filtered Results' : ' ট্রেন্ডিং কালেকশন'}
                    </h2>
                    <span className="text-xs text-gray-500 bg-white/5 px-3 py-1 rounded-full">{products.length} Products</span>
                </div>

                <div className="flex items-center gap-2">
                    <button 
                        onClick={() => setShowMobileFilters(true)}
                        className="lg:hidden flex items-center gap-2 px-6 py-2 bg-white text-black rounded-full text-[10px] font-bold uppercase tracking-widest hover:bg-gray-200 transition-all"
                    >
                        <SlidersHorizontal size={14} /> Filters
                    </button>
                    {isFiltered && (
                        <button onClick={resetFilters} className="flex items-center gap-2 px-4 py-2 bg-white/10 rounded-full text-[10px] font-bold uppercase tracking-widest hover:bg-white/20 transition-colors">
                            <X size={14} /> Clear All
                        </button>
                    )}
                </div>
            </div>

            {/* AI Intent Chips Bar */}
            {activeIntent && (
                <div className="mb-8 animate-in slide-in-from-top-4">
                    <div className="bg-white/5 backdrop-blur-md border border-white/10 rounded-2xl p-4 flex flex-wrap items-center gap-4">
                        <div className="flex items-center gap-2 text-aura-purple font-bold text-xs uppercase tracking-widest">
                            <Info size={14} /> Aura Context:
                        </div>
                        <div className="flex flex-wrap gap-2">
                            {activeIntent.category && <FilterChip label="Category" value={activeIntent.category} />}
                            {activeIntent.color && <FilterChip label="Color" value={activeIntent.color} />}
                            {activeIntent.material && <FilterChip label="Material" value={activeIntent.material} />}
                            {activeIntent.style && <FilterChip label="Style" value={activeIntent.style} />}
                            {activeIntent.maxPrice && <FilterChip label="Max Price" value={`৳${activeIntent.maxPrice}`} />}
                        </div>
                        <button onClick={() => setActiveIntent(null)} className="ml-auto text-xs text-gray-500 hover:text-white underline decoration-aura-purple">
                            Clear Intent
                        </button>
                    </div>
                </div>
            )}

            <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-8">
                {products.length === 0 ? (
                    <div className="col-span-full py-20 text-center bg-white/5 rounded-3xl border border-dashed border-white/10">
                        <Building2 className="mx-auto text-gray-600 mb-4" size={48} />
                        <h3 className="text-xl font-bold text-gray-400">এই ফিল্টারে কোনো পণ্য পাওয়া যায়নি</h3>
                        <p className="text-sm text-gray-600 mt-2">অন্য কোনো ভেন্ডর বা ডিজাইন ট্রাই করুন।</p>
                    </div>
                ) : (
                    products.map(p => (
                        <div key={p.id} className="relative">
                            {p.vendorId === 0 && (
                                <div className="absolute -top-3 -right-3 z-20 bg-aura-purple text-white px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-widest shadow-lg flex items-center gap-1">
                                    <Sparkles size={10} /> AI Concept
                                </div>
                            )}
                            <ProductCard 
                                product={p} 
                                vendor={p.vendorId === 0 ? { id: 0, name: "Aura Innovations", slug: "aura", status: "APPROVED", description: "AI Generated Concepts" } : vendors.find(v => v.id === p.vendorId)} 
                            />
                        </div>
                    ))
                )}
            </div>
          </main>
        </div>
      </div>
    </div>
  );
};

const FilterOption: React.FC<{ label: string; active: boolean; onClick: () => void }> = ({ label, active, onClick }) => (
    <button 
        onClick={onClick}
        className={`w-full text-left px-4 py-2 rounded-xl text-xs font-medium transition-all ${
            active 
            ? 'bg-aura-purple text-white shadow-lg shadow-purple-900/20' 
            : 'text-gray-400 hover:bg-white/5 hover:text-white'
        }`}
    >
        {label}
    </button>
);

const FilterCheckbox: React.FC<{ label: string; checked: boolean; onChange: () => void }> = ({ label, checked, onChange }) => (
    <label className="flex items-center gap-3 px-4 py-2 cursor-pointer group">
        <div className={`w-4 h-4 rounded border flex items-center justify-center transition-all ${checked ? 'bg-aura-purple border-aura-purple' : 'border-white/20 group-hover:border-white/40'}`}>
            {checked && <X size={10} className="text-white" />}
        </div>
        <input type="checkbox" className="hidden" checked={checked} onChange={onChange} />
        <span className={`text-xs transition-colors ${checked ? 'text-white font-bold' : 'text-gray-400 group-hover:text-white'}`}>{label}</span>
    </label>
);

const FilterChip: React.FC<{ label: string, value: string, variant?: 'primary' | 'ghost' }> = ({ label, value, variant = 'primary' }) => (
    <div className={`px-3 py-1 rounded-lg border text-[10px] font-bold flex items-center gap-2 ${
        variant === 'primary' 
        ? 'bg-white/10 border-white/20 text-white' 
        : 'bg-transparent border-white/10 text-gray-400'
    }`}>
        <Tag size={10} className="text-aura-purple" />
        <span className="uppercase tracking-tighter opacity-60">{label}:</span>
        <span>{value}</span>
    </div>
);

import React, { useState, useEffect } from 'react';
import { getVendors, getProductsByVendor } from '../services/mockData';
import { Product, Vendor } from '../types';
import { 
  Plus, ShieldCheck, Globe, X, Rocket, Zap, CheckCircle2, Bot, 
  ShieldAlert, Shield, Info, AlertCircle, TrendingUp, Star, 
  Users, ShoppingBag, Fingerprint, Activity 
} from 'lucide-react';
import { ProductCard } from '../components/ProductCard';

export const VendorDashboard: React.FC = () => {
  const [vendor, setVendor] = useState<Vendor | null>(null);
  const [products, setProducts] = useState<Product[]>([]);
  const [isFormOpen, setIsFormOpen] = useState(false);

  const [isGenerating, setIsGenerating] = useState(false);
  const [generationStep, setGenerationStep] = useState(0);
  const [websiteUrl, setWebsiteUrl] = useState<string | null>(null);

  const [newProduct, setNewProduct] = useState({
    name: '',
    price: '',
    externalUrl: '',
    category: '',
    description: ''
  });

  useEffect(() => {
    const currentVendor = getVendors().find(v => v.id === 1);
    if (currentVendor) {
      setVendor(currentVendor);
      setProducts(getProductsByVendor(currentVendor.id));
    }
  }, []);

  const handleAddProduct = (e: React.FormEvent) => {
    e.preventDefault();
    if (!vendor) return;

    const product: Product = {
      id: Date.now(),
      vendorId: vendor.id,
      name: newProduct.name,
      price: Number(newProduct.price),
      externalUrl: newProduct.externalUrl || undefined,
      category: newProduct.category || 'General',
      description: newProduct.description,
      imageUrl: `https://picsum.photos/400/600?random=${Date.now()}`
    };

    setProducts([product, ...products]);
    setIsFormOpen(false);
    setNewProduct({ name: '', price: '', externalUrl: '', category: '', description: '' });
  };

  const handleGenerateWebsite = () => {
    if (!vendor || vendor.status !== 'APPROVED') return;
    setIsGenerating(true);
    setGenerationStep(1);
    setTimeout(() => setGenerationStep(2), 1500);
    setTimeout(() => setGenerationStep(3), 3000);
    setTimeout(() => {
        setWebsiteUrl(`https://${vendor.slug}.snehalata.com`);
        setIsGenerating(false);
    }, 4500);
  };

  if (!vendor) return <div className="p-10 text-center text-aura-purple animate-pulse font-bold tracking-widest">AURA CONSOLE INITIALIZING...</div>;

  const isPending = vendor.status === 'PENDING';

  return (
    <div className="min-h-screen bg-black pb-20">
      {/* Dashboard Header */}
      <div className="bg-aura-darkPurple/20 border-b border-aura-glassBorder relative overflow-hidden">
        <div className="absolute top-0 right-0 w-64 h-64 bg-purple-600/10 blur-[100px] rounded-full pointer-events-none"></div>
        <div className="max-w-7xl mx-auto px-6 py-10 relative z-10">
          <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
            <div>
              <div className="flex flex-wrap items-center gap-3 mb-3">
                <h1 className="text-3xl font-serif font-bold text-white">{vendor.name}</h1>
                <div className={`flex items-center gap-1.5 px-3 py-1 rounded-full border text-[10px] font-bold uppercase tracking-[0.15em] transition-all shadow-lg ${
                    vendor.status === 'APPROVED' 
                    ? 'bg-green-500/10 border-green-500/40 text-green-400 shadow-green-900/20' 
                    : vendor.status === 'PENDING'
                    ? 'bg-amber-500/10 border-amber-500/40 text-amber-400 shadow-amber-900/20 animate-pulse'
                    : 'bg-red-500/10 border-red-500/40 text-red-400 shadow-red-900/20'
                }`}>
                    {vendor.status === 'APPROVED' ? <ShieldCheck size={14} /> : vendor.status === 'PENDING' ? <Shield size={14} /> : <ShieldAlert size={14} />}
                    <span>{vendor.status === 'APPROVED' ? 'Aura Verified' : vendor.status === 'PENDING' ? 'Verification Pending' : 'Restricted Access'}</span>
                </div>
              </div>
              <p className="text-gray-400 text-sm max-w-xl line-clamp-2">{vendor.description}</p>
            </div>

            <div className="flex gap-4">
               {vendor.websiteUrl && (
                 <a href={vendor.websiteUrl} target="_blank" rel="noreferrer" className="flex items-center gap-2 px-4 py-3 bg-white/5 border border-white/10 rounded-xl hover:bg-white/10 transition-all text-xs font-bold uppercase tracking-widest text-white">
                   <Globe size={16} /> ওয়েবসাইট
                 </a>
               )}
               <button 
                onClick={() => setIsFormOpen(!isFormOpen)}
                className="flex items-center gap-2 px-6 py-3 bg-gradient-to-r from-purple-700 to-indigo-700 rounded-xl font-bold uppercase tracking-widest text-xs shadow-lg shadow-purple-900/40 hover:scale-105 transition-transform border border-white/10 text-white"
               >
                 {isFormOpen ? <X size={18} /> : <Plus size={18} />}
                 {isFormOpen ? 'Cancel' : 'পণ্য যোগ করুন'}
               </button>
            </div>
          </div>
        </div>
      </div>

      <div className="max-w-7xl mx-auto px-6 py-10">

        {/* Performance Metrics Section */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-12">
          <MetricCard title="Total Sales" value="৳৮৫,৪০০" icon={<TrendingUp className="text-green-400" />} trend="+১২% growth" />
