import React, { useState, useEffect, useRef, useMemo } from 'react';
import { generateAuraResponse, analyzeSearchIntent, generateAuraImage, generateTrendingProducts, SearchIntent } from '../services/geminiService';
import { getProducts, getVendors, getLiveSales } from '../services/mockData';
import { ProductCard } from '../components/ProductCard';
import { ChatMessage, Product, Vendor } from '../types';
import { Sparkles, Send, Trash2, Clock, Image as ImageIcon, Loader2, Filter, X, Wand2, Info, Tag, Building2, AlertCircle, ChevronDown, ChevronUp, SlidersHorizontal, Search, Sparkle } from 'lucide-react';

export const Home: React.FC = () => {
  const [allProducts, setAllProducts] = useState<Product[]>([]);
  const [fictionalProducts, setFictionalProducts] = useState<Product[]>([]);
  const [products, setProducts] = useState<Product[]>([]);
  const [vendors, setVendors] = useState<Vendor[]>([]);
  const [salesTicker, setSalesTicker] = useState(0);

  // Search & Filtering states
  const [searchInput, setSearchInput] = useState('');
  const [isSearching, setIsSearching] = useState(false);
  const [selectedVendorId, setSelectedVendorId] = useState<number | null>(null);
  const [activeIntent, setActiveIntent] = useState<SearchIntent | null>(null);
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [priceRange, setPriceRange] = useState<{ min: number; max: number }>({ min: 0, max: 100000 });
  const [showMobileFilters, setShowMobileFilters] = useState(false);

  // AI Generated Search Concept
  const [searchGeneratedImage, setSearchGeneratedImage] = useState<string | null>(null);

  // AI & UI states
  const [isGeneratingTrends, setIsGeneratingTrends] = useState(false);
  const [apiError, setApiError] = useState<string | null>(null);
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'ai', content: "আসসালামু আলাইকুম। Snehalata-স্নেহলতা ইকোসিস্টেমে স্বাগতম। আমি Aura। আজ আপনার স্টাইল যাত্রায় কীভাবে সাহায্য করতে পারি?", timestamp: Date.now() }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [isGeneratingImage, setIsGeneratingImage] = useState(false);
  const chatContainerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const initialProducts = getProducts();
    setAllProducts(initialProducts);
    setProducts(initialProducts);
    setVendors(getVendors());
    setSalesTicker(getLiveSales());

    const interval = setInterval(() => {
        setSalesTicker(prev => prev + Math.floor(Math.random() * 500));
    }, 5000);
    return () => clearInterval(interval);
  }, []);

  // Auto-hide errors
  useEffect(() => {
    if (apiError) {
      const timer = setTimeout(() => setApiError(null), 5000);
      return () => clearTimeout(timer);
    }
  }, [apiError]);

  // Derived categories from products
  const availableCategories = useMemo(() => {
    const cats = new Set<string>();
    [...allProducts, ...fictionalProducts].forEach(p => cats.add(p.category));
    return Array.from(cats);
  }, [allProducts, fictionalProducts]);

  // Synchronize products based on filters and selected vendor
  useEffect(() => {
    applyFilters();
  }, [selectedVendorId, activeIntent, fictionalProducts, selectedCategories, priceRange]);

  const applyFilters = () => {
    let filtered = [...allProducts, ...fictionalProducts];

    filtered = filtered.filter(p => {
        const productData = `${p.name} ${p.description} ${p.category}`.toLowerCase();

        // Manual Vendor Filter
        if (selectedVendorId && p.vendorId !== selectedVendorId) return false;

        // Category Filter
        if (selectedCategories.length > 0 && !selectedCategories.includes(p.category)) return false;

        // Price Range Filter
        if (p.price < priceRange.min || p.price > priceRange.max) return false;

        // AI Intent Filtering (Cumulative)
        if (activeIntent) {
            let score = 0;
            if (activeIntent.category && productData.includes(activeIntent.category.toLowerCase())) score += 10;
            if (activeIntent.color && productData.includes(activeIntent.color.toLowerCase())) score += 5;
            if (activeIntent.material && productData.includes(activeIntent.material.toLowerCase())) score += 8;
            if (activeIntent.style && productData.includes(activeIntent.style.toLowerCase())) score += 5;

            if (activeIntent.maxPrice && p.price > activeIntent.maxPrice) return false;
            if (activeIntent.minPrice && p.price < activeIntent.minPrice) return false;

            if (activeIntent.semanticKeywords && activeIntent.semanticKeywords.length > 0) {
                let keywordMatch = false;
                activeIntent.semanticKeywords.forEach(keyword => {
                    if (productData.includes(keyword.toLowerCase())) {
                      score += 2;
                      keywordMatch = true;
                    }
                });
            }

            // Only filter by intent if intent actually contains specific parameters
            if (activeIntent.category || activeIntent.color || activeIntent.material || activeIntent.style || (activeIntent.semanticKeywords && activeIntent.semanticKeywords.length > 0)) {
                if (score === 0) return false;
            }
        }

        return true;
    });

    setProducts(filtered);
  };

  const isFiltered = useMemo(() => {
      return !!selectedVendorId || !!activeIntent || selectedCategories.length > 0 || priceRange.min > 0 || priceRange.max < 100000;
  }, [selectedVendorId, activeIntent, selectedCategories, priceRange]);

  const handleAISearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!searchInput.trim() || isSearching) return;

    setIsSearching(true);
    setSearchGeneratedImage(null);
    setApiError(null);

    try {
      const intent = await analyzeSearchIntent(searchInput);
      if (intent) {
        setActiveIntent(intent);

        // Trigger image generation if requested in search
        if (intent.shouldGenerateImage && intent.imagePrompt) {
          setIsGeneratingImage(true);
          const img = await generateAuraImage(intent.imagePrompt);
          setSearchGeneratedImage(img);
          setIsGeneratingImage(false);
        }

        // Add to chat as well for continuity
        setMessages(prev => [...prev, 
          { role: 'user', content: searchInput, timestamp: Date.now() },
          { role: 'ai', content: `আসসালামু আলাইকুম। আমি আপনার জন্য "${searchInput}" অনুসন্ধান করেছি। ফলাফলগুলো নিচে দেখুন।`, timestamp: Date.now() }
        ]);

        // Scroll to grid
        document.getElementById('product-section')?.scrollIntoView({ behavior: 'smooth' });
      }
    } catch (err) {
      setApiError("Aura Search Engine currently unavailable.");
    } finally {
      setIsSearching(false);
    }
  };

  useEffect(() => {
    if (chatContainerRef.current) {
      chatContainerRef.current.scrollTop = chatContainerRef.current.scrollHeight;
    }
  }, [messages, isTyping, isGeneratingImage]);

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isTyping) return;

    const userMsg: ChatMessage = { role: 'user', content: input, timestamp: Date.now() };
    setMessages(prev => [...prev, userMsg]);
    const currentInput = input;
    setInput('');
    setIsTyping(true);
    setApiError(null);

    try {
      const intentPromise = analyzeSearchIntent(currentInput);
      const responsePromise = generateAuraResponse(currentInput);

      const [auraResponse, intent] = await Promise.all([responsePromise, intentPromise]);

      setIsTyping(false);

      if (intent) {
        setActiveIntent(intent);
      }

      let generatedImageUrl = undefined;
      if (intent?.shouldGenerateImage && intent.imagePrompt) {
          setIsGeneratingImage(true);
          try {
            const img = await generateAuraImage(intent.imagePrompt);
            generatedImageUrl = img || undefined;
          } catch (imgErr) {
            console.error("Image generation failed", imgErr);
            setApiError("Aura ইমেজ জেনারেশনে সমস্যা হয়েছে। টেক্সট রেসপন্স দেখুন।");
          } finally {
            setIsGeneratingImage(false);
          }
      }

      setMessages(prev => [...prev, { 
          role: 'ai', 
          content: auraResponse || "আসসালামু আলাইকুম। দুঃখিত, আমি আপনার অনুরোধটি বুঝতে পারছি না।", 
          timestamp: Date.now(),
          generatedImageUrl 
      }]);
    } catch (error) {
      console.error("Aura interaction error:", error);
      setIsTyping(false);
      setApiError("দুঃখিত, Aura সার্ভারে সংযোগ করা যাচ্ছে না। দয়া করে আবার চেষ্টা করুন।");
      setMessages(prev => [...prev, { 
          role: 'ai', 
          content: "আসসালামু আলাইকুম। যান্ত্রিক ত্রুটির কারণে আমি এখন উত্তর দিতে পারছি না। কিছুক্ষণ পর আবার মেসেজ দিন।", 
          timestamp: Date.now() 
      }]);
    }
  };

  const handleGenerateTrends = async () => {
    if (isGeneratingTrends) return;
    setIsGeneratingTrends(true);
    setApiError(null);

    try {
      const trends = await generateTrendingProducts();
      if (!trends || trends.length === 0) {
        throw new Error("No trends generated");
