              <SuggestionChip label="Black Jamdani < 20k" onClick={() => setSearchInput("Show me black Jamdani sarees under 20,000 BDT")} />
              <SuggestionChip label="Festive Streetwear" onClick={() => setSearchInput("Find festive oversized hoodies and streetwear")} />
           </div>
