                      ) : isAdded ? (
                          <Check size={16} />
                      ) : (
                          <ShoppingCart size={16} />
                      )}
                      <span>কার্টে যোগ করুন</span>
                    </button>
                  </>
                )}
              </div>

              {/* Buy Now Button - Prominent Navigation */}
              {!product.externalUrl && (
                <Link 
                  to="/cart"
                  className="w-full bg-aura-purple text-white py-4 rounded-2xl text-[11px] font-black uppercase tracking-[0.25em] text-center transition-all hover:bg-purple-600 flex items-center justify-center gap-3 shadow-[0_10px_30px_rgba(124,58,237,0.3)] hover:shadow-purple-900/50 transform active:scale-[0.98]"
                >
                   এখনই কিনুন <CreditCard size={16} />
                </Link>
              )}

              <Link 
                to={`/store/${vendor?.slug || 'unknown'}`}
                className="w-full py-2 text-[9px] font-bold uppercase tracking-widest text-gray-600 hover:text-white text-center transition-colors"
              >
                 পুরো কালেকশন দেখুন
              </Link>
            </div>
          </div>
        </div>
    </div>
  );
};

