  const [searchGeneratedImage, setSearchGeneratedImage] = useState<string | null>(null);
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'ai', content: "আসসালামু আলাইকুম। Snehalata-স্নেহলতা ইকোসিস্টেমে স্বাগতম। আমি Aura। আজ আপনার স্টাইল যাত্রায় কীভাবে সাহায্য করতে পারি?", timestamp: Date.now() }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [isGeneratingImage, setIsGeneratingImage] = useState(false);

  const chatContainerRef = useRef<HTMLDivElement>(null);
  const sortRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const initialProducts = getProducts();
    setAllProducts(initialProducts);
    setProducts(initialProducts);
    setVendors(getVendors());
    setSalesTicker(getLiveSales());

    const interval = setInterval(() => {
        setSalesTicker(prev => prev + Math.floor(Math.random() * 500));
    }, 5000);

    const handleClickOutside = (event: MouseEvent) => {
      if (sortRef.current && !sortRef.current.contains(event.target as Node)) {
        setShowSortDropdown(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);

    // Initial recommendations
    fetchRecommendations();

    const handleHistoryUpdate = () => fetchRecommendations();
    window.addEventListener('browsingHistoryUpdated', handleHistoryUpdate);

    return () => {
      clearInterval(interval);
      document.removeEventListener('mousedown', handleClickOutside);
      window.removeEventListener('browsingHistoryUpdated', handleHistoryUpdate);
    };
  }, []);

  const fetchRecommendations = async () => {
      const history = JSON.parse(localStorage.getItem('aura_browsing_history') || '[]');
      if (history.length === 0) return;

      setIsFetchingRecs(true);
      try {
        const recIds = await getAIRecommendations(history);
        const catalog = getProducts();
        const recProducts = recIds.map(id => catalog.find(p => p.id === id)).filter(Boolean) as Product[];
        setRecommendations(recProducts);
      } catch (err) {
        console.error("Failed to fetch AI recs", err);
      } finally {
        setIsFetchingRecs(false);
      }
  };

  const clearHistory = () => {
      localStorage.removeItem('aura_browsing_history');
      setRecommendations([]);
  };

  // Auto-hide errors
  useEffect(() => {
    if (apiError) {
      const timer = setTimeout(() => setApiError(null), 5000);
      return () => clearTimeout(timer);
    }
  }, [apiError]);

  const availableCategories = useMemo(() => {
    const cats = new Set<string>();
    [...allProducts, ...fictionalProducts].forEach(p => cats.add(p.category));
    return Array.from(cats);
  }, [allProducts, fictionalProducts]);

  useEffect(() => {
    applyFilters();
  }, [selectedVendorId, activeIntent, fictionalProducts, selectedCategories, priceRange, sortOption]);

  const applyFilters = () => {
    let filtered = [...allProducts, ...fictionalProducts];

    filtered = filtered.filter(p => {
        const productData = `${p.name} ${p.description} ${p.category}`.toLowerCase();
        if (selectedVendorId && p.vendorId !== selectedVendorId) return false;
        if (selectedCategories.length > 0 && !selectedCategories.includes(p.category)) return false;
        if (p.price < priceRange.min || p.price > priceRange.max) return false;

        if (activeIntent) {
            let score = 0;
            if (activeIntent.category && productData.includes(activeIntent.category.toLowerCase())) score += 10;
            if (activeIntent.color && productData.includes(activeIntent.color.toLowerCase())) score += 5;
            if (activeIntent.material && productData.includes(activeIntent.material.toLowerCase())) score += 8;
            if (activeIntent.style && productData.includes(activeIntent.style.toLowerCase())) score += 5;
            if (activeIntent.maxPrice && p.price > activeIntent.maxPrice) return false;
            if (activeIntent.minPrice && p.price < activeIntent.minPrice) return false;
            if (activeIntent.semanticKeywords && activeIntent.semanticKeywords.length > 0) {
                activeIntent.semanticKeywords.forEach(keyword => {
                    if (productData.includes(keyword.toLowerCase())) score += 2;
                });
            }
            if (activeIntent.category || activeIntent.color || activeIntent.material || activeIntent.style || (activeIntent.semanticKeywords && activeIntent.semanticKeywords.length > 0)) {
                if (score === 0) return false;
            }
        }
        return true;
    });

    if (sortOption === 'PRICE_LOW') {
      filtered.sort((a, b) => a.price - b.price);
    } else if (sortOption === 'PRICE_HIGH') {
      filtered.sort((a, b) => b.price - a.price);
    } else {
      filtered.sort((a, b) => b.id - a.id);
    }

    setProducts(filtered);
  };

  const isFiltered = useMemo(() => {
      return !!selectedVendorId || !!activeIntent || selectedCategories.length > 0 || priceRange.min > 0 || priceRange.max < 100000;
  }, [selectedVendorId, activeIntent, selectedCategories, priceRange]);

  const handleAISearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!searchInput.trim() || isSearching) return;
    setIsSearching(true);
    setSearchGeneratedImage(null);
    setApiError(null);
    try {
      const intent = await analyzeSearchIntent(searchInput);
      if (intent) {
        setActiveIntent(intent);
        if (intent.shouldGenerateImage && intent.imagePrompt) {
          setIsGeneratingImage(true);
          const img = await generateAuraImage(intent.imagePrompt);
          setSearchGeneratedImage(img);
          setIsGeneratingImage(false);
        }
        setMessages(prev => [...prev, 
          { role: 'user', content: searchInput, timestamp: Date.now() },
          { role: 'ai', content: `আসসালামু আলাইকুম। আমি আপনার জন্য "${searchInput}" অনুসন্ধান করেছি। ফলাফলগুলো নিচে দেখুন।`, timestamp: Date.now() }
        ]);
        document.getElementById('product-section')?.scrollIntoView({ behavior: 'smooth' });
      }
    } catch (err) {
      setApiError("Aura Search Engine currently unavailable.");
    } finally {
      setIsSearching(false);
    }
  };

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isTyping) return;
    const userMsg: ChatMessage = { role: 'user', content: input, timestamp: Date.now() };
    setMessages(prev => [...prev, userMsg]);
    const currentInput = input;
    setInput('');
    setIsTyping(true);
    setApiError(null);
    try {
      const intentPromise = analyzeSearchIntent(currentInput);
      const responsePromise = generateAuraResponse(currentInput);
      const [auraResponse, intent] = await Promise.all([responsePromise, intentPromise]);
      setIsTyping(false);
      if (intent) setActiveIntent(intent);
      let generatedImageUrl = undefined;
      if (intent?.shouldGenerateImage && intent.imagePrompt) {
          setIsGeneratingImage(true);
          try {
            const img = await generateAuraImage(intent.imagePrompt);
            generatedImageUrl = img || undefined;
          } catch (imgErr) {
            setApiError("Aura ইমেজ জেনারেশনে সমস্যা হয়েছে।");
          } finally {
            setIsGeneratingImage(false);
          }
      }
      setMessages(prev => [...prev, { 
          role: 'ai', 
          content: auraResponse || "আসসালামু আলাইকুম। দুঃখিত, আমি আপনার অনুরোধটি বুঝতে পারছি না।", 
          timestamp: Date.now(),
          generatedImageUrl 
      }]);
    } catch (error) {
      setIsTyping(false);
      setApiError("দুঃখিত, Aura সার্ভারে সংযোগ করা যাচ্ছে না।");
    }
  };

  const handleGenerateTrends = async () => {
    if (isGeneratingTrends) return;
    setIsGeneratingTrends(true);
    try {
      const trends = await generateTrendingProducts();
      const formattedTrends: Product[] = trends.map(t => ({ ...t, vendorId: 0, id: t.id + 1000 }));
      setFictionalProducts(prev => [...prev, ...formattedTrends]);
      setMessages(prev => [...prev, { role: 'ai', content: "আসসালামু আলাইকুম। আমি ২০২৬ সালের সম্ভাব্য ট্রেন্ড থেকে কিছু কাল্পনিক ডিজাইন তৈরি করেছি।", timestamp: Date.now() }]);
      document.getElementById('product-section')?.scrollIntoView({ behavior: 'smooth' });
    } catch (error) {
      setApiError("ট্রেন্ডিং প্রোডাক্ট জেনারেট করা সম্ভব হয়নি।");
    } finally {
      setIsGeneratingTrends(false);
    }
  };

  const resetFilters = () => {
      setSelectedVendorId(null);
      setActiveIntent(null);
      setSelectedCategories([]);
      setPriceRange({ min: 0, max: 100000 });
      setSearchGeneratedImage(null);
      setSearchInput('');
      setSortOption('NEWEST');
  };

  const toggleCategory = (cat: string) => {
      setSelectedCategories(prev => 
        prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat]
      );
  };

  const sortLabel = { 'NEWEST': 'Newest Arrivals', 'PRICE_LOW': 'Price: Low to High', 'PRICE_HIGH': 'Price: High to Low' }[sortOption];

  return (
    <div className="min-h-screen">
      {/* Error Notification Banner */}
      {apiError && (
        <div className="fixed top-24 left-1/2 -translate-x-1/2 z-[100] w-full max-w-md px-4 animate-in slide-in-from-top-10 duration-500">
           <div className="bg-red-500/90 backdrop-blur-xl text-white p-4 rounded-2xl shadow-2xl border border-red-400/50 flex items-start gap-3">
              <AlertCircle className="shrink-0 mt-0.5" size={18} />
              <div className="flex-1">
                 <h4 className="text-xs font-bold uppercase tracking-widest mb-1">Aura System Alert</h4>
                 <p className="text-sm font-medium">{apiError}</p>
              </div>
              <button onClick={() => setApiError(null)} className="p-1 hover:bg-white/20 rounded-lg transition-colors">
                 <X size={16} />
              </button>
           </div>
        </div>
      )}

      {/* Hero Section */}
      <section className="relative min-h-[600px] flex flex-col items-center justify-center px-6 py-20 overflow-hidden">
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[800px] h-[800px] bg-aura-purple/5 blur-[120px] rounded-full pointer-events-none" />

        <div className="relative z-10 w-full max-w-4xl flex flex-col gap-10">
          <div className="text-center space-y-4">
             <div className="inline-flex items-center gap-2 px-4 py-2 rounded-full border border-aura-glassBorder bg-white/5 backdrop-blur-md">
                <span className="relative flex h-2 w-2">
                  <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-400 opacity-75"></span>
                  <span className="relative inline-flex rounded-full h-2 w-2 bg-green-500"></span>
                </span>
                <span className="text-[10px] uppercase tracking-[0.2em] font-bold text-gray-400">
                   Ecosystem ভলিউম: ৳{salesTicker.toLocaleString()}
                </span>
             </div>
             <div className="flex flex-col items-center">
                <h1 className="text-4xl md:text-6xl font-serif font-black text-white leading-tight mb-2 tracking-tight">
                  SNEHALATA-স্নেহলতা
                </h1>
                <p className="text-sm md:text-base font-bold text-aura-ash uppercase tracking-[0.5em]">
                  The Aura AI Driven Ecosystem
                </p>
             </div>
          </div>

          <div className="w-full bg-black/60 backdrop-blur-xl border border-white/10 rounded-3xl overflow-hidden shadow-2xl flex flex-col h-[500px]">
            <div className="flex items-center justify-between px-6 py-4 border-b border-white/10 bg-white/5">
                <div className="flex items-center gap-2">
                    <Sparkles size={16} className="text-aura-purple" />
                    <span className="text-xs font-bold uppercase tracking-widest text-white">Aura Live Assistant</span>
                </div>
                <button onClick={() => setMessages([{ role: 'ai', content: "নতুন করে শুরু করি?", timestamp: Date.now() }])} className="text-gray-500 hover:text-red-400 transition-colors">
                    <Trash2 size={16} />
                </button>
            </div>

            <div className="flex-1 p-6 overflow-y-auto space-y-6 scroll-smooth" ref={chatContainerRef}>
              {messages.map((msg, idx) => (
                <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                  <div className={`max-w-[85%] rounded-2xl p-4 text-sm ${msg.role === 'user' ? 'bg-white text-black font-medium' : 'bg-white/10 text-gray-200 border border-white/5'}`}>
                    {msg.role === 'ai' && <div className="text-[10px] uppercase tracking-widest text-aura-purple mb-1 font-bold">Aura AI</div>}
                    <div className="whitespace-pre-wrap">{msg.content}</div>
                    {msg.generatedImageUrl && (
                        <div className="mt-4 rounded-xl overflow-hidden border border-white/10 shadow-lg">
                            <img src={msg.generatedImageUrl} alt="AI Concept" className="w-full h-auto" />
                        </div>
                    )}
                    <div className="mt-2 text-[10px] flex items-center justify-end gap-1 opacity-50">
                        {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                        <Clock size={10} />
                    </div>
                  </div>
                </div>
              ))}
              {isTyping && (
                <div className="flex justify-start">
                   <div className="bg-white/5 rounded-2xl p-4 flex gap-2">
                     <span className="w-2 h-2 bg-aura-purple rounded-full animate-bounce"></span>
                   </div>
                </div>
              )}
            </div>

            <form onSubmit={handleSendMessage} className="p-4 bg-white/5 border-t border-white/10">
              <div className="flex gap-2">
                <div className="relative flex-1">
                    <input 
                    type="text" 
                    value={input}
                    onChange={(e) => setInput(e.target.value)}
                    placeholder="রঙ বা ডিজাইন বলুন..."
                    className="w-full bg-black/50 border border-white/10 rounded-xl pl-5 pr-12 py-4 focus:outline-none focus:border-aura-purple text-sm text-white disabled:opacity-50"
                    disabled={isTyping}
                    />
                    <button type="submit" disabled={!input.trim() || isTyping} className="absolute right-2 top-2 p-2 bg-aura-purple rounded-lg text-white">
                      <Send size={18} />
                    </button>
                </div>
              </div>
            </form>
          </div>
        </div>
      </section>

      {/* AI Search Bar Section */}
      <section className="relative z-20 -mt-10 px-6 max-w-5xl mx-auto">
        <form onSubmit={handleAISearch} className="group relative">
           <div className="absolute -inset-1 bg-gradient-to-r from-aura-purple via-indigo-500 to-aura-purple rounded-[2.5rem] blur opacity-25 group-focus-within:opacity-100 transition duration-1000"></div>
           <div className="relative flex items-center bg-black/80 backdrop-blur-3xl border border-white/10 rounded-[2.2rem] overflow-hidden shadow-2xl p-1.5">
              <div className="pl-6 pr-4">
                 <Search className="text-aura-purple" size={24} />
              </div>
              <input 
                 type="text" 
                 value={searchInput}
                 onChange={(e) => setSearchInput(e.target.value)}
                 placeholder="Search with Aura AI..."
                 className="flex-1 bg-transparent border-none text-white py-4 md:py-6 text-base md:text-lg focus:outline-none placeholder-gray-600 font-medium"
                 disabled={isSearching}
              />
              <button type="submit" className="bg-aura-purple text-white px-8 md:px-12 py-4 md:py-5 rounded-[1.8rem] font-black uppercase tracking-[0.2em] text-xs transition-all hover:bg-purple-600">
                 {isSearching ? <Loader2 size={16} className="animate-spin" /> : <Sparkle size={16} />}
              </button>
           </div>
        </form>
      </section>

      {/* NEW: Personalization Section (Recommended for You) */}
      {(recommendations.length > 0 || isFetchingRecs) && (
        <section className="max-w-7xl mx-auto px-6 pt-24">
            <div className="flex items-center justify-between mb-8">
                <div className="flex items-center gap-3">
                    <UserCheck className="text-aura-purple" size={28} />
                    <div>
                        <h2 className="text-2xl font-serif font-bold text-white">Recommended for You</h2>
                        <p className="text-[10px] text-gray-500 uppercase tracking-widest font-bold">Based on your unique style journey</p>
                    </div>
                </div>
                <button 
                  onClick={clearHistory}
                  className="text-[10px] text-gray-500 hover:text-red-400 uppercase tracking-widest font-bold border border-white/5 px-4 py-2 rounded-full transition-all"
                >
                    Clear Personalization
                </button>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-8 relative">
                {isFetchingRecs && (
                    <div className="absolute inset-0 z-10 bg-black/20 backdrop-blur-[2px] flex items-center justify-center rounded-3xl">
                        <Loader2 className="animate-spin text-aura-purple" size={48} />
                    </div>
                )}
                {recommendations.map(p => (
                    <div key={p.id} className="animate-in fade-in slide-in-from-bottom-4 duration-500">
                        <ProductCard 
                          product={p} 
                          vendor={vendors.find(v => v.id === p.vendorId)} 
                          isRecommended={true}
                        />
                    </div>
                ))}
            </div>
        </section>
      )}

      {/* Main Content Area */}
      <div id="product-section" className="max-w-7xl mx-auto px-6 py-20">
        <div className="flex flex-col lg:flex-row gap-12">

          {/* Sidebar Filters */}
          <aside className={`lg:w-64 shrink-0 transition-all duration-300 ${showMobileFilters ? 'fixed inset-0 z-[60] bg-black/95 p-8 overflow-y-auto' : 'hidden lg:block'}`}>
            <div className="flex items-center justify-between lg:hidden mb-8">
                <h2 className="text-xl font-bold font-serif text-white">Filters</h2>
                <button onClick={() => setShowMobileFilters(false)} className="p-2 bg-white/10 rounded-full"><X size={20} /></button>
            </div>
            <div className="space-y-8 sticky top-24">
                <div className="space-y-4">
                    <h3 className="text-[10px] uppercase tracking-widest font-bold text-aura-purple flex items-center gap-2"><Building2 size={14} /> Vendors</h3>
                    <div className="flex flex-col gap-1">
                        <FilterOption label="All Hub" active={!selectedVendorId} onClick={() => setSelectedVendorId(null)} />
                        {vendors.filter(v => v.status === 'APPROVED').map(vendor => (
                            <FilterOption key={vendor.id} label={vendor.name} active={selectedVendorId === vendor.id} onClick={() => setSelectedVendorId(vendor.id)} />
                        ))}
                    </div>
                </div>
                <div className="space-y-4">
                    <h3 className="text-[10px] uppercase tracking-widest font-bold text-aura-purple flex items-center gap-2"><Tag size={14} /> Categories</h3>
                    <div className="flex flex-col gap-1">
                        {availableCategories.map(cat => (
                            <FilterCheckbox key={cat} label={cat} checked={selectedCategories.includes(cat)} onChange={() => toggleCategory(cat)} />
                        ))}
                    </div>
                </div>
                {isFiltered && (
                    <button onClick={resetFilters} className="w-full py-3 rounded-xl border border-dashed border-aura-purple/30 text-[10px] font-bold uppercase tracking-widest text-aura-purple hover:bg-aura-purple/5">Reset All</button>
                )}
            </div>
          </aside>

          {/* Product Grid Area */}
          <main className="flex-1">
            <div className="flex flex-col md:flex-row md:items-center justify-between mb-10 gap-4">
                <div className="flex items-center gap-4">
                    <h2 className="text-2xl font-serif font-bold flex items-center gap-4">
                        <Sparkles className="text-aura-purple" />
                        {isFiltered ? 'Filtered Results' : ' ট্রেন্ডিং কালেকশন'}
                    </h2>
                </div>
                <div className="flex items-center gap-3">
                    <div className="relative" ref={sortRef}>
                      <button onClick={() => setShowSortDropdown(!showSortDropdown)} className="flex items-center gap-2 px-6 py-2.5 bg-white/5 border border-white/10 rounded-full text-[10px] font-bold uppercase tracking-widest text-white transition-all">
                        <ListFilter size={14} className="text-aura-purple" />
                        <span>Sort: {sortLabel}</span>
                        <ChevronDown size={14} />
                      </button>
                      {showSortDropdown && (
                        <div className="absolute right-0 mt-2 w-56 bg-black/90 backdrop-blur-3xl border border-white/10 rounded-2xl p-2 shadow-2xl z-50 animate-in fade-in slide-in-from-top-2">
                           <SortItem active={sortOption === 'NEWEST'} label="Newest Arrivals" onClick={() => { setSortOption('NEWEST'); setShowSortDropdown(false); }} />
                           <SortItem active={sortOption === 'PRICE_LOW'} label="Price: Low to High" onClick={() => { setSortOption('PRICE_LOW'); setShowSortDropdown(false); }} />
                           <SortItem active={sortOption === 'PRICE_HIGH'} label="Price: High to Low" onClick={() => { setSortOption('PRICE_HIGH'); setShowSortDropdown(false); }} />
                        </div>
                      )}
                    </div>
                </div>
            </div>

            {activeIntent && (
                <div className="mb-8 animate-in slide-in-from-top-4">
                    <div className="bg-white/5 backdrop-blur-md border border-white/10 rounded-2xl p-4 flex flex-wrap items-center gap-4">
                        <div className="flex items-center gap-2 text-aura-purple font-bold text-xs uppercase tracking-widest"><Info size={14} /> Aura Context:</div>
                        <div className="flex flex-wrap gap-2">
                            {activeIntent.category && <FilterChip label="Category" value={activeIntent.category} />}
                            {activeIntent.maxPrice && <FilterChip label="Max Price" value={`৳${activeIntent.maxPrice}`} />}
                        </div>
                    </div>
                </div>
            )}

            <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-8">
                {products.length === 0 ? (
                    <div className="col-span-full py-20 text-center bg-white/5 rounded-3xl border border-dashed border-white/10">
                        <Building2 className="mx-auto text-gray-600 mb-4" size={48} />
                        <h3 className="text-xl font-bold text-gray-400">এই ফিল্টারে কোনো পণ্য পাওয়া যায়নি</h3>
                    </div>
                ) : (
                    products.map(p => (
                        <div key={p.id} className="relative">
                            {p.vendorId === 0 && (
                                <div className="absolute -top-3 -right-3 z-20 bg-aura-purple text-white px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest shadow-lg flex items-center gap-1">
                                    <Sparkles size={10} /> AI Concept
                                </div>
                            )}
                            <ProductCard product={p} vendor={p.vendorId === 0 ? { id: 0, name: "Aura Innovations", slug: "aura", status: "APPROVED", description: "AI Concepts" } : vendors.find(v => v.id === p.vendorId)} />
                        </div>
                    ))
                )}
            </div>
          </main>
        </div>
      </div>
    </div>
  );
};

const FilterOption: React.FC<{ label: string; active: boolean; onClick: () => void }> = ({ label, active, onClick }) => (
    <button onClick={onClick} className={`w-full text-left px-4 py-2 rounded-xl text-xs font-medium transition-all ${active ? 'bg-aura-purple text-white shadow-lg shadow-purple-900/20' : 'text-gray-400 hover:bg-white/5 hover:text-white'}`}>{label}</button>
);

const FilterCheckbox: React.FC<{ label: string; checked: boolean; onChange: () => void }> = ({ label, checked, onChange }) => (
    <label className="flex items-center gap-3 px-4 py-2 cursor-pointer group">
