export const VendorDashboard: React.FC = () => {
  const [vendor, setVendor] = useState<Vendor | null>(null);
  const [products, setProducts] = useState<Product[]>([]);
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [auditLogs, setAuditLogs] = useState<AuditEntry[]>(MOCK_AUDIT_LOGS);

  const [isGenerating, setIsGenerating] = useState(false);
  const [generationStep, setGenerationStep] = useState(0);
  const [websiteUrl, setWebsiteUrl] = useState<string | null>(null);

  const [newProduct, setNewProduct] = useState({
    name: '',
    price: '',
    externalUrl: '',
    category: '',
    description: ''
  });

  useEffect(() => {
    const currentVendor = getVendors().find(v => v.id === 1);
    if (currentVendor) {
      setVendor(currentVendor);
      setProducts(getProductsByVendor(currentVendor.id));
    }
  }, []);

  const handleAddProduct = (e: React.FormEvent) => {
    e.preventDefault();
    if (!vendor) return;

    const product: Product = {
      id: Date.now(),
      vendorId: vendor.id,
      name: newProduct.name,
      price: Number(newProduct.price),
      externalUrl: newProduct.externalUrl || undefined,
      category: newProduct.category || 'General',
      description: newProduct.description,
      imageUrl: `https://picsum.photos/400/600?random=${Date.now()}`
    };

    setProducts([product, ...products]);
    setIsFormOpen(false);
    setNewProduct({ name: '', price: '', externalUrl: '', category: '', description: '' });

    // Simulate an instant AI audit for new product
    const newAudit: AuditEntry = {
        id: `AUD-${Date.now()}`,
        type: 'COPYWRITING',
        status: 'PASSED',
        timestamp: 'Just now',
        label: 'New Inventory Audit',
        details: `Aura reviewed "${product.name}" description. Compliance score: 98%.`
    };
    setAuditLogs([newAudit, ...auditLogs]);
  };

  const handleGenerateWebsite = () => {
    if (!vendor || vendor.status !== 'APPROVED') return;
    setIsGenerating(true);
    setGenerationStep(1);
    setTimeout(() => setGenerationStep(2), 1500);
    setTimeout(() => setGenerationStep(3), 3000);
    setTimeout(() => {
        setWebsiteUrl(`https://${vendor.slug}.snehalata.com`);
        setIsGenerating(false);
    }, 4500);
  };

  if (!vendor) return <div className="p-10 text-center text-aura-purple animate-pulse font-bold tracking-widest">AURA CONSOLE INITIALIZING...</div>;

  const isPending = vendor.status === 'PENDING';

  return (
    <div className="min-h-screen bg-black pb-20">
      {/* Dashboard Header */}
      <div className="bg-aura-darkPurple/20 border-b border-aura-glassBorder relative overflow-hidden">
        <div className="absolute top-0 right-0 w-64 h-64 bg-purple-600/10 blur-[100px] rounded-full pointer-events-none"></div>
        <div className="max-w-7xl mx-auto px-6 py-10 relative z-10">
          <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
            <div>
              <div className="flex flex-wrap items-center gap-3 mb-3">
                <h1 className="text-3xl font-serif font-bold text-white">{vendor.name}</h1>
                <div className={`flex items-center gap-1.5 px-3 py-1 rounded-full border text-[10px] font-bold uppercase tracking-[0.15em] transition-all shadow-lg ${
                    vendor.status === 'APPROVED' 
                    ? 'bg-green-500/10 border-green-500/40 text-green-400 shadow-green-900/20' 
                    : vendor.status === 'PENDING'
                    ? 'bg-amber-500/10 border-amber-500/40 text-amber-400 shadow-amber-900/20 animate-pulse'
                    : 'bg-red-500/10 border-red-500/40 text-red-400 shadow-red-900/20'
                }`}>
                    {vendor.status === 'APPROVED' ? <ShieldCheck size={14} /> : vendor.status === 'PENDING' ? <Shield size={14} /> : <ShieldAlert size={14} />}
                    <span>{vendor.status === 'APPROVED' ? 'Aura Verified' : vendor.status === 'PENDING' ? 'Verification Pending' : 'Restricted Access'}</span>
                </div>
              </div>
              <p className="text-gray-400 text-sm max-w-xl line-clamp-2">{vendor.description}</p>
            </div>

            <div className="flex gap-4">
               {vendor.websiteUrl && (
                 <a href={vendor.websiteUrl} target="_blank" rel="noreferrer" className="flex items-center gap-2 px-4 py-3 bg-white/5 border border-white/10 rounded-xl hover:bg-white/10 transition-all text-xs font-bold uppercase tracking-widest text-white">
                   <Globe size={16} /> ওয়েবসাইট
                 </a>
               )}
               <button 
                onClick={() => setIsFormOpen(!isFormOpen)}
                className="flex items-center gap-2 px-6 py-3 bg-gradient-to-r from-purple-700 to-indigo-700 rounded-xl font-bold uppercase tracking-widest text-xs shadow-lg shadow-purple-900/40 hover:scale-105 transition-transform border border-white/10 text-white"
               >
                 {isFormOpen ? <X size={18} /> : <Plus size={18} />}
                 {isFormOpen ? 'Cancel' : 'পণ্য যোগ করুন'}
               </button>
            </div>
          </div>
        </div>
      </div>

      <div className="max-w-7xl mx-auto px-6 py-10">

        {/* Performance Metrics Section */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-12">
          <MetricCard title="Total Sales" value="৳৮৫,৪০০" icon={<TrendingUp className="text-green-400" />} trend="+১২% growth" />
          <MetricCard title="Orders" value="৪৬" icon={<ShoppingBag className="text-blue-400" />} trend="৮ pending" />
          <MetricCard title="Customer Rating" value="৪.৯/৫" icon={<Star className="text-yellow-400 fill-yellow-400" />} trend="১০২ reviews" />
          <MetricCard title="Aura Trust Score" value="৯৮" icon={<Zap className="text-purple-400" />} trend="Elite Level" />
        </div>

        {/* Store Generator Section */}
        <div className="mb-12">
            <div className={`bg-gradient-to-br from-indigo-900/40 to-purple-900/20 border border-aura-glassBorder rounded-3xl p-8 relative overflow-hidden group transition-all ${isPending ? 'opacity-50 grayscale cursor-not-allowed' : ''}`}>
                <div className="absolute top-0 right-0 p-32 bg-purple-500/10 blur-[80px] rounded-full group-hover:bg-purple-500/20 transition-all"></div>
                <div className="relative z-10 flex flex-col md:flex-row justify-between items-start md:items-center gap-8">
                    <div className="flex-1">
                        <div className="flex items-center gap-3 mb-4">
                            <Rocket className="text-purple-400" />
                            <h2 className="text-2xl font-serif font-bold text-white">1-Click Store Generator</h2>
                        </div>
                        <p className="text-gray-300 mb-8 max-w-lg leading-relaxed">
                            আপনার নিজস্ব ব্র্যান্ড পোর্টাল তৈরি করুন Aura-র সাহায্যে। এটি সরাসরি আপনার ইকোসিস্টেম ক্যাটালগের সাথে সিঙ্ক থাকবে এবং ডিরেক্ট-টু-ভেন্ডর সেলস বুস্ট করবে।
                        </p>
                        {!websiteUrl && !isGenerating && !isPending && (
                            <button onClick={handleGenerateWebsite} className="bg-white text-black px-8 py-4 rounded-xl font-bold uppercase tracking-widest hover:bg-gray-200 transition-colors flex items-center gap-2 shadow-xl active:scale-95 transition-transform">
                                <Zap size={18} className="text-purple-600 fill-purple-600" /> জেনারেট করুন
                            </button>
                        )}
                        {isGenerating && (
                            <div className="space-y-4 max-w-sm">
                                <div className="w-full bg-white/10 h-2 rounded-full overflow-hidden">
                                    <div className="h-full bg-aura-purple animate-pulse transition-all duration-1000" style={{width: `${(generationStep / 3) * 100}%`}}></div>
                                </div>
                                <p className="text-[10px] uppercase tracking-widest text-aura-purple font-bold flex items-center gap-2">
                                    <RefreshCcw size={12} className="animate-spin" />
                                    {generationStep === 1 ? 'Mapping Inventory...' : generationStep === 2 ? 'Deploying Aura Engine...' : 'Finalizing Subdomain...'}
                                </p>
                            </div>
                        )}
                        {websiteUrl && (
                            <div className="bg-green-500/10 border border-green-500/30 p-6 rounded-2xl animate-in zoom-in">
                                <h3 className="font-bold text-green-400 mb-2 text-xs uppercase tracking-widest flex items-center gap-2">
                                    <ShieldCheck size={14} /> Live on Aura Hub Subdomain
                                </h3>
                                <div className="flex flex-col sm:flex-row items-start sm:items-center gap-4">
                                    <a href="#" className="text-xl text-white underline decoration-aura-purple underline-offset-8 font-mono hover:text-aura-purple transition-colors truncate">
                                        {websiteUrl}
                                    </a>
                                    <button className="text-[10px] text-gray-500 border border-white/10 px-3 py-1 rounded-full hover:text-white transition-colors">Copy URL</button>
                                </div>
                            </div>
                        )}
                    </div>

                    <div className="hidden lg:flex flex-col items-center gap-4 p-8 bg-black/40 backdrop-blur-md rounded-3xl border border-white/5">
                        <Activity className="text-aura-purple animate-pulse" size={48} />
                        <div className="text-center">
                            <div className="text-xl font-bold text-white">99.8%</div>
                            <div className="text-[9px] uppercase tracking-widest text-gray-500">Node Availability</div>
                        </div>
                    </div>
                </div>
            </div>
        </div>

        {/* DEDICATED SECTION: Aura AI Governance Audit Logs */}
        <div className="mb-12">
            <div className="flex items-center justify-between mb-8 px-2">
                <div>
                    <h2 className="text-2xl font-serif font-bold text-white flex items-center gap-3">
                        <Fingerprint className="text-aura-purple" />
                        Aura AI Governance Audit Logs
                    </h2>
                    <p className="text-xs text-gray-500 mt-1 uppercase tracking-widest font-bold">Real-time transparency & compliance tracking</p>
                </div>
                <div className="flex items-center gap-4">
                    <div className="hidden md:flex bg-white/5 border border-white/10 rounded-full px-4 py-1.5 items-center gap-2">
                        <Search size={14} className="text-gray-600" />
                        <input type="text" placeholder="Search audits..." className="bg-transparent border-none text-[10px] text-white focus:outline-none placeholder-gray-700 w-32" />
                    </div>
                    <button className="p-2 bg-white/5 border border-white/10 rounded-full hover:text-white transition-colors">
                        <Filter size={16} className="text-gray-500" />
