interface ProductCardProps {
  product: Product;
  vendor?: Vendor;
  isRecommended?: boolean;
}

export const ProductCard: React.FC<ProductCardProps> = ({ product, vendor, isRecommended }) => {
  const [isAdding, setIsAdding] = useState(false);
  const [isAdded, setIsAdded] = useState(false);
  const [isInWishlist, setIsInWishlist] = useState(false);
  const [isAnimatingWishlist, setIsAnimatingWishlist] = useState(false);

  // Initialize wishlist state from localStorage
  useEffect(() => {
    const wishlist = JSON.parse(localStorage.getItem('aura_wishlist') || '[]');
    setIsInWishlist(wishlist.some((item: any) => item.id === product.id));
  }, [product.id]);

  const trackInteraction = () => {
    const history = JSON.parse(localStorage.getItem('aura_browsing_history') || '[]');
    // Only keep the last 10 unique interactions
    const filteredHistory = history.filter((h: any) => h.id !== product.id);
    const newHistory = [product, ...filteredHistory].slice(0, 10);
    localStorage.setItem('aura_browsing_history', JSON.stringify(newHistory));
    window.dispatchEvent(new Event('browsingHistoryUpdated'));
  };

  const toggleWishlist = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();

    // Trigger animation
    setIsAnimatingWishlist(false);
    requestAnimationFrame(() => {
        setIsAnimatingWishlist(true);
        setTimeout(() => setIsAnimatingWishlist(false), 450);
    });

    const wishlist = JSON.parse(localStorage.getItem('aura_wishlist') || '[]');
    let newWishlist;

    if (isInWishlist) {
      newWishlist = wishlist.filter((item: any) => item.id !== product.id);
    } else {
      newWishlist = [...wishlist, product];
      trackInteraction(); // Wishlist counts as high intent interaction
    }

    localStorage.setItem('aura_wishlist', JSON.stringify(newWishlist));
    setIsInWishlist(!isInWishlist);
    window.dispatchEvent(new Event('wishlistUpdated'));
  };

  const handleAddToCart = (e: React.MouseEvent) => {
    e.preventDefault();
    if (isAdding) return;
    setIsAdding(true);
    trackInteraction(); // Cart counts as high intent interaction

    setTimeout(() => {
        setIsAdding(false);
        setIsAdded(true);
        setTimeout(() => {
            setIsAdded(false);
        }, 2000);
    }, 600);
  };

  return (
    <div 
      onMouseEnter={trackInteraction}
      className={`group relative bg-aura-glass border rounded-[2rem] overflow-hidden transition-all duration-500 hover:shadow-[0_20px_50px_rgba(124,58,237,0.15)] flex flex-col h-full ${
        isRecommended 
        ? 'border-aura-purple/40 ring-1 ring-aura-purple/10' 
        : 'border-aura-glassBorder hover:border-aura-purple/50'
      }`}
    >

        {/* Image Section */}
        <div className="relative h-72 overflow-hidden">
          <img 
            src={product.imageUrl} 
            alt={product.name} 
            className="w-full h-full object-cover transform group-hover:scale-110 transition-transform duration-1000 ease-out"
          />
          <div className="absolute inset-0 bg-gradient-to-t from-black via-black/20 to-transparent opacity-80" />

          <div className="absolute top-4 left-4 flex flex-col gap-2">
              <span className="bg-aura-purple/20 backdrop-blur-md border border-aura-purple/30 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest text-aura-purple">
                  {product.category}
              </span>
              {isRecommended && (
                  <span className="bg-aura-purple text-white px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest flex items-center gap-1 shadow-lg animate-pulse">
                     <icon className="w-2.5 h-2.5"><Sparkles size={10} /></icon> Aura's Pick
                  </span>
              )}
          </div>

          {/* Wishlist Toggle Button */}
          <button 
            onClick={toggleWishlist}
            className={`absolute top-4 right-4 z-20 p-2.5 rounded-full backdrop-blur-xl border transition-all duration-300 transform active:scale-90 ${
              isAnimatingWishlist ? 'animate-heart-pop' : ''
            } ${
              isInWishlist 
              ? 'bg-aura-purple/20 border-aura-purple text-aura-purple shadow-[0_0_15px_rgba(124,58,237,0.4)]' 
              : 'bg-black/40 border-white/10 text-white hover:border-white/30 hover:bg-black/60'
            }`}
          >
            <Heart size={18} className={isInWishlist ? 'fill-aura-purple' : ''} />
          </button>

          {/* Virtual Try-On Badge */}
          <div className="absolute bottom-4 left-4 z-10">
             <Link 
               to={`/try-on/${product.id}`}
               className="bg-white/10 hover:bg-white/20 text-white px-4 py-2 rounded-xl text-[10px] font-bold uppercase tracking-widest flex items-center gap-2 backdrop-blur-xl border border-white/10 transition-all hover:scale-105 active:scale-95"
             >
               <Camera size={14} className="text-aura-purple" /> Virtual Try-On
             </Link>
          </div>
        </div>

        {/* Content Section */}
        <div className="p-6 flex flex-col flex-grow bg-gradient-to-b from-transparent to-black/40">
          <div className="mb-4">
            {vendor && (
              <div className="flex items-center gap-2 mb-1.5">
                <span className="text-[10px] text-aura-purple uppercase tracking-[0.2em] font-black">{vendor.name}</span>
                {vendor.status === 'APPROVED' && (
                   <Sparkles size={10} className="text-aura-purple animate-pulse" />
                )}
              </div>
            )}
            <h3 className="font-serif text-xl font-bold text-white mb-2 leading-tight group-hover:text-aura-purple transition-colors">
              {product.name}
            </h3>
            <p className="text-xs text-gray-500 line-clamp-2 font-medium leading-relaxed">
              {product.description}
            </p>
          </div>

          <div className="mt-auto pt-4 border-t border-white/5 space-y-4">
            <div className="flex justify-between items-baseline">
              <div className="text-2xl font-black text-white tracking-tighter">
                ৳{product.price.toLocaleString()}
              </div>
              <div className="text-[10px] text-gray-600 font-bold uppercase tracking-widest">In Stock</div>
            </div>

            <div className="grid grid-cols-1 gap-2.5">
              {/* Primary Actions */}
              <div className="flex gap-2">
                {product.externalUrl ? (
                  <a 
                    href={product.externalUrl}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="flex-1 bg-white text-black py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest text-center transition-all flex items-center justify-center gap-2 hover:bg-aura-purple hover:text-white"
                  >
                    ভেন্ডর সাইট <ExternalLink size={14} />
                  </a>
                ) : (
                  <>
                    <button 
                      onClick={handleAddToCart}
                      disabled={isAdding}
                      className={`flex-1 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest text-center transition-all flex items-center justify-center gap-2 border ${
                          isAdded 
                          ? 'bg-green-500/10 border-green-500/50 text-green-500' 
                          : 'bg-white/5 border-white/10 text-white hover:bg-white/10'
                      }`}
                    >
                      {isAdding ? (
                          <Loader2 size={16} className="animate-spin" />
                      ) : isAdded ? (
                          <Check size={16} />
                      ) : (
                          <ShoppingCart size={16} />
                      )}
                      <span>কার্টে যোগ করুন</span>
                    </button>
                  </>
                )}
              </div>

              {/* Buy Now Button - Prominent Navigation */}
              {!product.externalUrl && (
                <Link 
                  to="/cart"
                  className="w-full bg-aura-purple text-white py-4 rounded-2xl text-[11px] font-black uppercase tracking-[0.25em] text-center transition-all hover:bg-purple-600 flex items-center justify-center gap-3 shadow-[0_10px_30px_rgba(124,58,237,0.3)] hover:shadow-purple-900/50 transform active:scale-[0.98]"
                >
                   এখনই কিনুন <CreditCard size={16} />
                </Link>
              )}

              <Link 
                to={`/store/${vendor?.slug || 'unknown'}`}
                className="w-full py-2 text-[9px] font-bold uppercase tracking-widest text-gray-600 hover:text-white text-center transition-colors"
              >
                 পুরো কালেকশন দেখুন
              </Link>
            </div>
          </div>
        </div>
    </div>
  );
};

