          <MetricCard title="Total Sales" value="৳৮৫,৪০০" icon={<TrendingUp className="text-green-400" />} trend="+১২% growth" />
          <MetricCard title="Orders" value="৪৬" icon={<ShoppingBag className="text-blue-400" />} trend="৮ pending" />
