                {icon}
            </div>
            <span className="text-[10px] font-bold uppercase tracking-widest text-gray-600">{trend}</span>
        </div>
        <div className="text-3xl font-bold text-white mb-1">{value}</div>
        <div className="text-[10px] uppercase tracking-[0.2em] font-bold text-gray-600">{title}</div>
