import { Product } from '../types';

interface CartItem extends Product {
  quantity: number;
}

export const Cart: React.FC = () => {
  const [cartItems, setCartItems] = useState<CartItem[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    const loadCart = () => {
      const items = JSON.parse(localStorage.getItem('aura_cart') || '[]');
      setCartItems(items);
      setIsLoading(false);
    };

    loadCart();
    window.addEventListener('cartUpdated', loadCart);
    return () => window.removeEventListener('cartUpdated', loadCart);
  }, []);

  const updateQuantity = (id: number, delta: number) => {
    const newCart = cartItems.map(item => {
      if (item.id === id) {
        return { ...item, quantity: Math.max(1, item.quantity + delta) };
      }
      return item;
    });
    setCartItems(newCart);
    localStorage.setItem('aura_cart', JSON.stringify(newCart));
  };

  const removeItem = (id: number) => {
    const newCart = cartItems.filter(item => item.id !== id);
    setCartItems(newCart);
    localStorage.setItem('aura_cart', JSON.stringify(newCart));
  };

  const subtotal = cartItems.reduce((acc, item) => acc + (item.price * item.quantity), 0);
  const shipping = cartItems.length > 0 ? 120 : 0;
  const total = subtotal + shipping;

  if (isLoading) {
    return (
      <div className="min-h-[70vh] flex flex-col items-center justify-center gap-4">
        <div className="w-12 h-12 border-4 border-aura-purple border-t-transparent rounded-full animate-spin"></div>
        <p className="text-gray-500 font-bold uppercase tracking-[0.2em] text-xs">অর্ডার লোড হচ্ছে...</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-black pb-20 selection:bg-aura-purple selection:text-white">
      <div className="max-w-7xl mx-auto px-6 py-16">

        <div className="flex items-center gap-4 mb-12">
          <div className="p-3 bg-aura-purple/10 border border-aura-purple/20 rounded-2xl">
            <ShoppingBag className="text-aura-purple" size={32} />
          </div>
          <div>
            <h1 className="text-3xl font-serif font-bold text-white leading-none">আপনার শপিং ব্যাগ</h1>
            <p className="text-[10px] uppercase tracking-widest text-gray-500 font-bold mt-2">Aura Protected Checkout</p>
          </div>
        </div>

        {cartItems.length === 0 ? (
          <div className="text-center py-20 bg-white/5 border border-dashed border-white/10 rounded-3xl animate-in fade-in duration-700">
             <ShoppingBag className="mx-auto text-gray-700 mb-6" size={64} />
             <h2 className="text-xl font-bold text-gray-400 mb-2">আপনার ব্যাগটি এখনো খালি</h2>
             <p className="text-gray-600 text-sm mb-8">ইকোসিস্টেমের এক্সক্লুসিভ কালেকশনগুলো এক্সপ্লোর করুন।</p>
             <Link to="/" className="inline-block bg-white text-black px-10 py-3 rounded-xl font-bold uppercase tracking-widest hover:bg-aura-purple hover:text-white transition-all shadow-xl">
                শপিং শুরু করুন
             </Link>
          </div>
        ) : (
          <div className="flex flex-col lg:flex-row gap-12">
            {/* Items List */}
            <div className="flex-1 space-y-6">
              {cartItems.map((item) => (
                <div key={item.id} className="bg-aura-glass border border-aura-glassBorder rounded-3xl p-6 flex flex-col sm:flex-row gap-6 hover:border-aura-purple/30 transition-all group">
                  <div className="w-full sm:w-32 h-32 rounded-2xl overflow-hidden border border-white/5">
                    <img src={item.imageUrl} alt={item.name} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700" />
                  </div>

                  <div className="flex-1">
                    <div className="flex justify-between items-start mb-2">
                      <div>
                        <h3 className="text-lg font-bold text-white mb-1">{item.name}</h3>
                        <p className="text-xs text-gray-500 uppercase tracking-widest font-bold">{item.category}</p>
                      </div>
                      <button 
                        onClick={() => removeItem(item.id)}
                        className="p-2 text-gray-600 hover:text-red-400 transition-colors"
                      >
                        <Trash2 size={18} />
                      </button>
                    </div>

                    <div className="flex flex-wrap items-center justify-between gap-6 mt-4">
                      <div className="flex items-center gap-4 bg-black/40 rounded-xl p-1 border border-white/10">
                        <button 
                          onClick={() => updateQuantity(item.id, -1)}
                          className="p-2 text-gray-400 hover:text-white transition-colors"
                        >
                          <Minus size={16} />
                        </button>
                        <span className="text-sm font-bold text-white min-w-[1.5rem] text-center">{item.quantity}</span>
