                    <span className="text-gray-400">Estimated Shipping</span>
                    <span className="text-white font-bold">৳{shipping.toLocaleString()}</span>
                  </div>
                  <div className="h-px bg-white/5 my-4" />
                  <div className="flex justify-between items-baseline">
                    <span className="text-xs uppercase tracking-[0.2em] font-black text-aura-purple">Total</span>
                    <span className="text-3xl font-black text-white">৳{total.toLocaleString()}</span>
                  </div>
                </div>

                <div className="space-y-3 mb-8">
                   <div className="flex items-center gap-3 p-3 bg-green-500/10 border border-green-500/20 rounded-2xl text-[10px] font-bold text-green-400 uppercase tracking-widest">
                      <ShieldCheck size={16} /> Aura AI Quality Insured
                   </div>
                   <div className="flex items-center gap-3 p-3 bg-white/5 border border-white/10 rounded-2xl text-[10px] font-bold text-gray-400 uppercase tracking-widest">
                      <CreditCard size={16} /> Secure Multi-vendor Payment
                   </div>
                </div>

                <button className="w-full bg-white text-black py-5 rounded-2xl text-xs font-black uppercase tracking-[0.3em] hover:bg-aura-purple hover:text-white transition-all shadow-xl shadow-purple-900/10 flex items-center justify-center gap-3 active:scale-95 transform">
                   অর্ডার কনফার্ম করুন <ChevronRight size={18} />
                </button>

                <p className="text-[9px] text-center text-gray-600 mt-6 leading-relaxed">
