                                        className="w-full bg-transparent border-none text-[11px] text-gray-300 focus:outline-none placeholder-gray-700 leading-relaxed font-medium resize-none min-h-[60px]"
                                        placeholder="Tweak your vision here..."
                                    />
                                    <div className="flex justify-between items-center border-t border-white/5 pt-2">
