                                            <button onClick={() => updateMessagePrompt(idx, (msg.imagePrompt || '') + ', 8k resolution')} className="text-[7px] uppercase font-bold text-gray-600 hover:text-aura-purple transition-colors">+8K</button>
                                            <button onClick={() => updateMessagePrompt(idx, (msg.imagePrompt || '') + ', cinematic lighting')} className="text-[7px] uppercase font-bold text-gray-600 hover:text-aura-purple transition-colors">+Studio</button>
                                        </div>
                                        <button 
                                            onClick={() => handleInlineRegenerate(idx)}
                                            disabled={isRegenerating !== null}
