              <button type="submit" className="bg-aura-purple text-white px-8 md:px-12 py-4 md:py-5 rounded-[1.8rem] font-black uppercase tracking-[0.2em] text-xs transition-all hover:bg-purple-600">
                 {isSearching ? <Loader2 size={16} className="animate-spin" /> : <Sparkle size={16} />}
