            <div className="mt-auto pt-5 border-t border-white/5 space-y-5">
              <div className="flex justify-between items-baseline">
                <div className="text-2xl font-black text-white tracking-tighter">
                  ৳{product.price.toLocaleString()}
                </div>
                <div className="flex items-center gap-1.5">
                   <div className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse"></div>
                   <span className="text-[9px] text-gray-500 font-bold uppercase tracking-widest">In Stock</span>
                </div>
              </div>

              <div className="grid grid-cols-1 gap-3">
                <div className="flex gap-2.5">
                  {product.externalUrl ? (
                    <a 
                      href={product.externalUrl}
                      target="_blank"
                      rel="noopener noreferrer"
                      className="flex-1 bg-white text-black py-3.5 rounded-2xl text-[10px] font-black uppercase tracking-widest text-center transition-all flex items-center justify-center gap-2 hover:bg-aura-purple hover:text-white"
                    >
