                  ) : (
                    <button 
                      onClick={handleAddToCart}
                      disabled={isAdding}
                      className={`flex-1 py-3.5 rounded-2xl text-[10px] font-black uppercase tracking-widest text-center transition-all flex items-center justify-center gap-2 border ${
                          isAdded 
                          ? 'bg-green-500/10 border-green-500/50 text-green-500' 
                          : 'bg-white/5 border-white/10 text-white hover:bg-white/10 hover:border-white/20'
                      }`}
                    >
                      {isAdding ? (
                          <Loader2 size={16} className="animate-spin" />
                      ) : isAdded ? (
