                {!product.externalUrl && (
                  <button 
                    onClick={handleBuyNowClick}
                    className="w-full bg-aura-purple text-white py-4.5 rounded-2xl text-[11px] font-black uppercase tracking-[0.25em] text-center transition-all hover:bg-purple-600 flex items-center justify-center gap-3 shadow-[0_10px_30px_rgba(124,58,237,0.3)] hover:shadow-purple-900/50 transform active:scale-[0.98]"
