                     এখনই কিনুন <CreditCard size={16} />
                  </button>
                )}

                <Link 
                  to={`/store/${vendor?.slug || 'unknown'}`}
                  className="w-full py-1 text-[9px] font-bold uppercase tracking-[0.2em] text-gray-600 hover:text-aura-purple text-center transition-colors"
                >
