export const auditVendorDescription = async (shopName: string, description: string, tradeLicense: string): Promise<{ status: 'APPROVED' | 'REJECTED' | 'PENDING'; reason: string }> => {
    if (!process.env.API_KEY) return { status: 'APPROVED', reason: 'Dev Mode' };
    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: `Shop Name: ${shopName}\nTrade License: ${tradeLicense}\nDescription: ${description}`,
            config: { 
                systemInstruction: `
                You are the Governance Auditor for SNEHALATA-স্নেহলতা.
                Audit the following vendor application for authenticity in the Bangladeshi fashion context.

                Rules:
                1. Look for cultural markers (Jamdani, Muslin, Khadi, heritage mentions).
                2. Verify if the description sounds professional and authentic.
                3. Trade License format check: Should typically contain alphanumeric patterns (e.g., TRD-YYYY-XXXX).
                4. If highly authentic and professional, status = APPROVED.
                5. If suspicious or counterfeit-sounding, status = REJECTED.
                6. If unsure but safe, status = PENDING.

                Respond in JSON: { "status": "APPROVED" | "REJECTED" | "PENDING", "reason": "Your reason in Bengali" }
                `,
                responseMimeType: 'application/json' 
            }
        });
        const result = JSON.parse(response.text || '{}');
        return {
            status: result.status || 'PENDING',
            reason: result.reason || 'আবেদনটি রিভিউ করা হচ্ছে।'
        };
    } catch (error) {
        return { status: 'PENDING', reason: 'Audit failed due to network issues.' };
    }
};

import React, { useState, useEffect, useRef, useMemo } from 'react';
