type SortOption = 'NEWEST' | 'PRICE_LOW' | 'PRICE_HIGH';

export const Home: React.FC = () => {
  const [allProducts, setAllProducts] = useState<Product[]>([]);
  const [fictionalProducts, setFictionalProducts] = useState<Product[]>([]);
  const [products, setProducts] = useState<Product[]>([]);
  const [vendors, setVendors] = useState<Vendor[]>([]);
  const [recommendations, setRecommendations] = useState<Product[]>([]);
  const [salesTicker, setSalesTicker] = useState(0);

  // Search, Filtering & Sorting states
  const [searchInput, setSearchInput] = useState('');
  const [isSearching, setIsSearching] = useState(false);
  const [sortOption, setSortOption] = useState<SortOption>('NEWEST');
  const [selectedVendorId, setSelectedVendorId] = useState<number | null>(null);
  const [activeIntent, setActiveIntent] = useState<SearchIntent | null>(null);
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [priceRange, setPriceRange] = useState<{ min: number; max: number }>({ min: 0, max: 100000 });
  const [showMobileFilters, setShowMobileFilters] = useState(false);
  const [showSortDropdown, setShowSortDropdown] = useState(false);

  // AI & UI states
  const [isGeneratingTrends, setIsGeneratingTrends] = useState(false);
  const [isFetchingRecs, setIsFetchingRecs] = useState(false);
  const [apiError, setApiError] = useState<string | null>(null);
  const [searchGeneratedImage, setSearchGeneratedImage] = useState<string | null>(null);
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'ai', content: "আসসালামু আলাইকুম। Snehalata-স্নেহলতা ইকোসিস্টেমে স্বাগতম। আমি Aura। আজ আপনার স্টাইল যাত্রায় কীভাবে সাহায্য করতে পারি?", timestamp: Date.now() }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [isGeneratingImage, setIsGeneratingImage] = useState(false);

  // Refinement states
  const [isRegenerating, setIsRegenerating] = useState<number | null>(null); 
  const [expandedEditors, setExpandedEditors] = useState<Record<number, boolean>>({});

  const chatContainerRef = useRef<HTMLDivElement>(null);
  const sortRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const initialProducts = getProducts();
    setAllProducts(initialProducts);
    setProducts(initialProducts);
    setVendors(getVendors());
    setSalesTicker(getLiveSales());

    const interval = setInterval(() => {
        setSalesTicker(prev => prev + Math.floor(Math.random() * 500));
    }, 5000);

    const handleClickOutside = (event: MouseEvent) => {
      if (sortRef.current && !sortRef.current.contains(event.target as Node)) {
        setShowSortDropdown(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);

    // Initial recommendations
    fetchRecommendations();

    const handleHistoryUpdate = () => fetchRecommendations();
    window.addEventListener('browsingHistoryUpdated', handleHistoryUpdate);

    return () => {
      clearInterval(interval);
      document.removeEventListener('mousedown', handleClickOutside);
      window.removeEventListener('browsingHistoryUpdated', handleHistoryUpdate);
    };
  }, []);

  const fetchRecommendations = async () => {
      const history = JSON.parse(localStorage.getItem('aura_browsing_history') || '[]');
      if (history.length === 0) return;

      setIsFetchingRecs(true);
      try {
        const recIds = await getAIRecommendations(history);
        const catalog = getProducts();
        const recProducts = recIds.map(id => catalog.find(p => p.id === id)).filter(Boolean) as Product[];
        setRecommendations(recProducts);
      } catch (err) {
        console.error("Failed to fetch AI recs", err);
      } finally {
        setIsFetchingRecs(false);
      }
  };

  const clearHistory = () => {
      localStorage.removeItem('aura_browsing_history');
      setRecommendations([]);
  };

  useEffect(() => {
    if (apiError) {
      const timer = setTimeout(() => setApiError(null), 5000);
      return () => clearTimeout(timer);
    }
  }, [apiError]);

  const availableCategories = useMemo(() => {
    const cats = new Set<string>();
    [...allProducts, ...fictionalProducts].forEach(p => cats.add(p.category));
    return Array.from(cats);
  }, [allProducts, fictionalProducts]);

  useEffect(() => {
    applyFilters();
  }, [selectedVendorId, activeIntent, fictionalProducts, selectedCategories, priceRange, sortOption]);

  const applyFilters = () => {
    let filtered = [...allProducts, ...fictionalProducts];

    if (activeIntent || selectedVendorId || selectedCategories.length > 0) {
      filtered = filtered.map(p => {
          const productData = `${p.name} ${p.description} ${p.category}`.toLowerCase();
          let score = 0;

          // Global filters
          if (selectedVendorId && p.vendorId !== selectedVendorId) return { ...p, _score: -1 };
          if (selectedCategories.length > 0 && !selectedCategories.includes(p.category)) return { ...p, _score: -1 };
          if (p.price < priceRange.min || p.price > priceRange.max) return { ...p, _score: -1 };

          // Nuanced Search Scoring
          if (activeIntent) {
              // High Priority Attributes (+20 each)
              if (activeIntent.category && productData.includes(activeIntent.category.toLowerCase())) score += 20;
              if (activeIntent.material && productData.includes(activeIntent.material.toLowerCase())) score += 18;
              if (activeIntent.color && productData.includes(activeIntent.color.toLowerCase())) score += 15;

              // Key Phrases captured from nuanced queries (+12 each)
              if (activeIntent.keyPhrases && activeIntent.keyPhrases.length > 0) {
                  activeIntent.keyPhrases.forEach(phrase => {
                      if (productData.includes(phrase.toLowerCase())) score += 12;
                  });
              }

              // Secondary Modifiers (Style) (+6)
              if (activeIntent.style && productData.includes(activeIntent.style.toLowerCase())) score += 6;

              // Price Constraints
              if (activeIntent.maxPrice && p.price > activeIntent.maxPrice) return { ...p, _score: -1 };
              if (activeIntent.minPrice && p.price < activeIntent.minPrice) return { ...p, _score: -1 };

              // Semantic Synonyms (+3 each)
              if (activeIntent.semanticKeywords && activeIntent.semanticKeywords.length > 0) {
                  activeIntent.semanticKeywords.forEach(keyword => {
                      if (productData.includes(keyword.toLowerCase())) score += 3;
                  });
              }

              // Minimum threshold for search relevance
              if (activeIntent.category || activeIntent.color || activeIntent.material || activeIntent.style || (activeIntent.keyPhrases && activeIntent.keyPhrases.length > 0)) {
                  if (score === 0) return { ...p, _score: -1 };
              }
          }

          return { ...p, _score: score };
      }).filter(p => (p as any)._score !== -1);

      // Sort by score first, then by the selected sort option
      filtered.sort((a, b) => (b as any)._score - (a as any)._score);
    }

    if (sortOption === 'PRICE_LOW') {
      filtered.sort((a, b) => a.price - b.price);
    } else if (sortOption === 'PRICE_HIGH') {
      filtered.sort((a, b) => b.price - a.price);
    } else if (!activeIntent) {
      filtered.sort((a, b) => b.id - a.id);
    }

    setProducts(filtered);
  };

  const isFiltered = useMemo(() => {
      return !!selectedVendorId || !!activeIntent || selectedCategories.length > 0 || priceRange.min > 0 || priceRange.max < 100000;
  }, [selectedVendorId, activeIntent, selectedCategories, priceRange]);

  const resetFilters = () => {
    setSelectedVendorId(null);
    setActiveIntent(null);
    setSelectedCategories([]);
    setPriceRange({ min: 0, max: 100000 });
    setSearchInput('');
  };

  const handleAISearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!searchInput.trim() || isSearching) return;
    setIsSearching(true);
    setSearchGeneratedImage(null);
    setApiError(null);
    try {
      const intent = await analyzeSearchIntent(searchInput);
      if (intent) {
        setActiveIntent(intent);
        let img: string | null = null;
        if (intent.shouldGenerateImage && intent.imagePrompt) {
          setIsGeneratingImage(true);
          img = await generateAuraImage(intent.imagePrompt);
          setSearchGeneratedImage(img);
          setIsGeneratingImage(false);
        }
        setMessages(prev => [...prev, 
          { role: 'user', content: searchInput, timestamp: Date.now() },
          { 
            role: 'ai', 
            content: `আসসালামু আলাইকুম। আমি আপনার জন্য "${searchInput}" অনুসন্ধান করেছি। ফলাফলগুলো নিচে দেখুন।`, 
            timestamp: Date.now(),
            generatedImageUrl: img || undefined,
            imagePrompt: intent.imagePrompt || undefined
          }
        ]);
        document.getElementById('product-section')?.scrollIntoView({ behavior: 'smooth' });
      }
    } catch (err) {
      setApiError("Aura Search Engine currently unavailable.");
    } finally {
      setIsSearching(false);
    }
  };

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isTyping) return;
    const userMsg: ChatMessage = { role: 'user', content: input, timestamp: Date.now() };
    setMessages(prev => [...prev, userMsg]);
    const currentInput = input;
    setInput('');
    setIsTyping(true);
    setApiError(null);
    try {
      const intentPromise = analyzeSearchIntent(currentInput);
      const responsePromise = generateAuraResponse(currentInput);
      const [auraResponse, intent] = await Promise.all([responsePromise, intentPromise]);
      setIsTyping(false);
      if (intent) setActiveIntent(intent);
      let generatedImageUrl = undefined;
      if (intent?.shouldGenerateImage && intent.imagePrompt) {
          setIsGeneratingImage(true);
          try {
            const img = await generateAuraImage(intent.imagePrompt);
            generatedImageUrl = img || undefined;
          } catch (imgErr) {
            setApiError("Aura ইমেজ জেনারেশনে সমস্যা হয়েছে।");
          } finally {
            setIsGeneratingImage(false);
          }
      }
      setMessages(prev => [...prev, { 
          role: 'ai', 
          content: auraResponse || "আসসালামু আলাইকুম। দুঃখিত, আমি আপনার অনুরোধটি বুঝতে পারছি না।", 
          timestamp: Date.now(),
          generatedImageUrl,
          imagePrompt: intent?.imagePrompt || undefined
      }]);
    } catch (error) {
      setIsTyping(false);
      setApiError("দুঃখিত, Aura সার্ভারে সংযোগ করা যাচ্ছে না।");
    }
  };

  const handleInlineRegenerate = async (idx: number) => {
    const msg = messages[idx];
    if (!msg.imagePrompt?.trim() || isRegenerating !== null) return;

    setIsRegenerating(idx);
    setApiError(null);

    try {
      const newImg = await generateAuraImage(msg.imagePrompt);
      if (newImg) {
        setMessages(prev => prev.map((m, i) => i === idx ? { ...m, generatedImageUrl: newImg } : m));
      } else {
        setApiError("Aura ইমেজ জেনারেশনে সমস্যা হয়েছে।");
      }
    } catch (err) {
      setApiError("Aura সার্ভারে সংযোগ ত্রুটি।");
    } finally {
      setIsRegenerating(null);
    }
  };

  const updateMessagePrompt = (idx: number, newPrompt: string) => {
    setMessages(prev => prev.map((m, i) => i === idx ? { ...m, imagePrompt: newPrompt } : m));
  };

  const toggleEditor = (idx: number) => {
    setExpandedEditors(prev => ({ ...prev, [idx]: !prev[idx] }));
  };

  const appendToPrompt = (idx: number, suffix: string) => {
    const current = messages[idx].imagePrompt || '';
    const updated = current.includes(suffix) ? current : `${current}, ${suffix}`;
    updateMessagePrompt(idx, updated);
  };

  const sortLabel = { 'NEWEST': 'Newest Arrivals', 'PRICE_LOW': 'Price: Low to High', 'PRICE_HIGH': 'Price: High to Low' }[sortOption];

  return (
    <div className="min-h-screen">
      {/* Error Notification Banner */}
      {apiError && (
        <div className="fixed top-24 left-1/2 -translate-x-1/2 z-[100] w-full max-w-md px-4 animate-in slide-in-from-top-10 duration-500">
           <div className="bg-red-500/90 backdrop-blur-xl text-white p-4 rounded-2xl shadow-2xl border border-red-400/50 flex items-start gap-3">
              <AlertCircle className="shrink-0 mt-0.5" size={18} />
              <div className="flex-1">
                 <h4 className="text-xs font-bold uppercase tracking-widest mb-1">Aura System Alert</h4>
                 <p className="text-sm font-medium">{apiError}</p>
              </div>
              <button onClick={() => setApiError(null)} className="p-1 hover:bg-white/20 rounded-lg transition-colors">
                 <X size={16} />
              </button>
           </div>
        </div>
      )}

      {/* Hero Section */}
      <section className="relative min-h-[600px] flex flex-col items-center justify-center px-6 py-20 overflow-hidden">
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[800px] h-[800px] bg-aura-purple/5 blur-[120px] rounded-full pointer-events-none" />

        <div className="relative z-10 w-full max-w-4xl flex flex-col gap-10">
          <div className="text-center space-y-4">
             <div className="inline-flex items-center gap-2 px-4 py-2 rounded-full border border-aura-glassBorder bg-white/5 backdrop-blur-md">
                <span className="relative flex h-2 w-2">
                  <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-400 opacity-75"></span>
                  <span className="relative inline-flex rounded-full h-2 w-2 bg-green-500"></span>
                </span>
                <span className="text-[10px] uppercase tracking-[0.2em] font-bold text-gray-400">
                   Ecosystem ভলিউম: ৳{salesTicker.toLocaleString()}
                </span>
             </div>
             <div className="flex flex-col items-center">
                <h1 className="text-4xl md:text-6xl font-serif font-black text-white leading-tight mb-2 tracking-tight">
                  SNEHALATA-স্নেহলতা
                </h1>
                <p className="text-sm md:text-base font-bold text-aura-ash uppercase tracking-[0.5em]">
                  The Aura AI Driven Ecosystem
                </p>
             </div>
          </div>

          <div className="w-full bg-black/60 backdrop-blur-xl border border-white/10 rounded-3xl overflow-hidden shadow-2xl flex flex-col h-[550px]">
            <div className="flex items-center justify-between px-6 py-4 border-b border-white/10 bg-white/5">
                <div className="flex items-center gap-2">
                    <Sparkles size={16} className="text-aura-purple" />
                    <span className="text-xs font-bold uppercase tracking-widest text-white">Aura Live Assistant</span>
                </div>
                <button onClick={() => setMessages([{ role: 'ai', content: "নতুন করে শুরু করি?", timestamp: Date.now() }])} className="text-gray-500 hover:text-red-400 transition-colors">
                    <Trash2 size={16} />
                </button>
            </div>

            <div className="flex-1 p-6 overflow-y-auto space-y-6 scroll-smooth" ref={chatContainerRef}>
              {messages.map((msg, idx) => (
                <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                  <div className={`max-w-[85%] rounded-2xl p-4 text-sm ${msg.role === 'user' ? 'bg-white text-black font-medium' : 'bg-white/10 text-gray-200 border border-white/5'}`}>
                    {msg.role === 'ai' && <div className="text-[10px] uppercase tracking-widest text-aura-purple mb-1 font-bold">Aura AI</div>}
                    <div className="whitespace-pre-wrap">{msg.content}</div>

                    {msg.generatedImageUrl && (
                        <div className="mt-5 space-y-4 animate-in slide-in-from-bottom-2 duration-500">
                            {/* Image Container with Glow */}
                            <div className="relative group/img">
                                <div className="absolute -inset-1 bg-gradient-to-r from-aura-purple/20 to-transparent blur-xl opacity-0 group-hover/img:opacity-100 transition-opacity"></div>
                                <div className="relative overflow-hidden rounded-2xl border border-white/10 shadow-2xl bg-black/40 aspect-square">
                                    {isRegenerating === idx && (
                                        <div className="absolute inset-0 z-20 bg-black/70 backdrop-blur-md flex flex-col items-center justify-center gap-4 animate-in fade-in duration-300">
                                            <div className="relative">
                                                <div className="w-16 h-16 border-4 border-aura-purple/20 border-t-aura-purple rounded-full animate-spin"></div>
                                                <Zap className="absolute inset-0 m-auto text-aura-purple animate-pulse" size={24} />
                                            </div>
                                            <div className="flex flex-col items-center text-center">
                                                <span className="text-[11px] text-white font-black uppercase tracking-[0.2em] mb-1">Aura Re-imaging</span>
                                                <span className="text-[9px] text-gray-500 uppercase tracking-widest italic font-medium">Refining pixels with your vision...</span>
                                            </div>
                                        </div>
                                    )}
                                    <img 
                                        src={msg.generatedImageUrl} 
                                        alt="AI Concept" 
                                        className="w-full h-full object-cover transition-transform duration-[2000ms] hover:scale-110" 
                                    />
                                    {/* Concept Label */}
                                    <div className="absolute top-4 left-4 z-10 flex items-center gap-2 bg-black/60 backdrop-blur-md px-3 py-1.5 rounded-full border border-white/10">
                                        <Palette size={10} className="text-aura-purple" />
                                        <span className="text-[9px] font-black uppercase tracking-widest text-white">Concept v2.4</span>
                                    </div>
                                </div>
                            </div>

                            {/* Refine Prompt Button */}
                            <button 
                                onClick={() => toggleEditor(idx)}
                                className="flex items-center gap-2 px-4 py-2 bg-white/5 border border-white/10 rounded-xl text-[10px] font-black uppercase tracking-widest text-aura-purple hover:bg-white/10 transition-all active:scale-95 group/btn"
                            >
                                {expandedEditors[idx] ? <X size={14} /> : <Edit3 size={14} />}
                                {expandedEditors[idx] ? 'Close Editor' : 'Refine Prompt'}
                                {!expandedEditors[idx] && <ChevronRight size={12} className="group-hover/btn:translate-x-0.5 transition-transform" />}
                            </button>

                            {/* Expandable Prompt Editor */}
                            {expandedEditors[idx] && (
                                <div className="bg-white/[0.03] border border-white/10 rounded-2xl overflow-hidden group/editor focus-within:border-aura-purple/40 transition-all animate-in slide-in-from-top-4 duration-300">
                                    <div className="px-4 py-2 bg-white/[0.02] border-b border-white/5 flex items-center justify-between">
                                        <div className="flex items-center gap-2">
                                            <Wand2 size={12} className="text-aura-purple" />
                                            <span className="text-[9px] font-black uppercase tracking-widest text-gray-500">Aura Creative Lab</span>
                                        </div>
                                        <div className="flex gap-2">
                                            <button onClick={() => appendToPrompt(idx, 'cinematic lighting')} className="text-[8px] font-bold text-gray-600 hover:text-white transition-colors uppercase tracking-tighter">Studio</button>
                                            <button onClick={() => appendToPrompt(idx, 'hyper-realistic')} className="text-[8px] font-bold text-gray-600 hover:text-white transition-colors uppercase tracking-tighter">HD</button>
                                            <button onClick={() => appendToPrompt(idx, 'cyberpunk style')} className="text-[8px] font-bold text-gray-600 hover:text-white transition-colors uppercase tracking-tighter">Neo</button>
                                        </div>
                                    </div>

                                    <div className="p-3 space-y-3">
                                        <textarea 
                                            value={msg.imagePrompt || ''}
                                            onChange={(e) => updateMessagePrompt(idx, e.target.value)}
                                            className="w-full bg-transparent border-none text-[11px] text-gray-300 focus:outline-none placeholder-gray-700 leading-relaxed font-medium resize-none min-h-[50px]"
                                            placeholder="আপনার কল্পনাকে আরও নিখুঁত করুন..."
                                        />

                                        <div className="flex justify-between items-center">
                                            <div className="flex gap-1.5 flex-wrap">
                                                <span className="text-[8px] text-gray-700 font-bold uppercase py-1 px-2 border border-white/5 rounded-md">8K Res</span>
                                                <span className="text-[8px] text-gray-700 font-bold uppercase py-1 px-2 border border-white/5 rounded-md">Raw Lens</span>
                                            </div>
                                            <button 
                                                onClick={() => handleInlineRegenerate(idx)}
                                                disabled={isRegenerating !== null}
                                                className="flex items-center gap-2 bg-aura-purple text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all hover:bg-purple-600 shadow-xl shadow-purple-900/20 active:scale-95 disabled:opacity-50"
                                            >
                                                <RefreshCw size={14} className={isRegenerating === idx ? 'animate-spin' : ''} />
                                                রিজেনারেশন
                                            </button>
                                        </div>
                                    </div>
                                </div>
                            )}
                        </div>
                    )}

                    <div className="mt-2 text-[10px] flex items-center justify-end gap-1 opacity-40">
                        {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                        <Clock size={10} />
                    </div>
                  </div>
                </div>
              ))}
              {isTyping && (
                <div className="flex justify-start">
                   <div className="bg-white/5 rounded-2xl p-4 flex gap-2">
                     <span className="w-2 h-2 bg-aura-purple rounded-full animate-bounce"></span>
                   </div>
                </div>
              )}
            </div>

            <form onSubmit={handleSendMessage} className="p-4 bg-white/5 border-t border-white/10">
              <div className="flex gap-2">
                <div className="relative flex-1">
                    <input 
                    type="text" 
                    value={input}
                    onChange={(e) => setInput(e.target.value)}
                    placeholder="রঙ বা ডিজাইন বলুন..."
                    className="w-full bg-black/50 border border-white/10 rounded-xl pl-5 pr-12 py-4 focus:outline-none focus:border-aura-purple text-sm text-white disabled:opacity-50"
                    disabled={isTyping}
                    />
                    <button type="submit" disabled={!input.trim() || isTyping} className="absolute right-2 top-2 p-2 bg-aura-purple rounded-lg text-white">
                      <Send size={18} />
                    </button>
                </div>
              </div>
            </form>
          </div>
        </div>
      </section>

      {/* AI Search Bar Section */}
      <section className="relative z-20 -mt-10 px-6 max-w-5xl mx-auto">
        <form onSubmit={handleAISearch} className="group relative">
           <div className="absolute -inset-1 bg-gradient-to-r from-aura-purple via-indigo-500 to-aura-purple rounded-[2.5rem] blur opacity-25 group-focus-within:opacity-100 transition duration-1000"></div>
           <div className="relative flex items-center bg-black/80 backdrop-blur-3xl border border-white/10 rounded-[2.2rem] overflow-hidden shadow-2xl p-1.5">
              <div className="pl-6 pr-4">
                 <Search className="text-aura-purple" size={24} />
              </div>
              <input 
                 type="text" 
                 value={searchInput}
                 onChange={(e) => setSearchInput(e.target.value)}
                 placeholder="Search with Aura AI..."
                 className="flex-1 bg-transparent border-none text-white py-4 md:py-6 text-base md:text-lg focus:outline-none placeholder-gray-600 font-medium"
                 disabled={isSearching}
              />
              <button type="submit" className="bg-aura-purple text-white px-8 md:px-12 py-4 md:py-5 rounded-[1.8rem] font-black uppercase tracking-[0.2em] text-xs transition-all hover:bg-purple-600">
                 {isSearching ? <Loader2 size={16} className="animate-spin" /> : <Sparkle size={16} />}
              </button>
           </div>
        </form>
      </section>

      {/* Recommended Products */}
      {(recommendations.length > 0 || isFetchingRecs) && (
        <section className="max-w-7xl mx-auto px-6 pt-24">
            <div className="flex items-center justify-between mb-8">
                <div className="flex items-center gap-3">
                    <UserCheck className="text-aura-purple" size={28} />
                    <div>
                        <h2 className="text-2xl font-serif font-bold text-white">Recommended for You</h2>
                        <p className="text-[10px] text-gray-500 uppercase tracking-widest font-bold">Based on your unique style journey</p>
                    </div>
                </div>
                <button 
                  onClick={clearHistory}
                  className="text-[10px] text-gray-500 hover:text-red-400 uppercase tracking-widest font-bold border border-white/5 px-4 py-2 rounded-full transition-all"
                >
                    Clear Personalization
                </button>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-8 relative">
                {isFetchingRecs && (
                    <div className="absolute inset-0 z-10 bg-black/20 backdrop-blur-[2px] flex items-center justify-center rounded-3xl">
                        <Loader2 className="animate-spin text-aura-purple" size={48} />
                    </div>
                )}
                {recommendations.map(p => (
                    <div key={p.id} className="animate-in fade-in slide-in-from-bottom-4 duration-500">
                        <ProductCard 
                          product={p} 
                          vendor={vendors.find(v => v.id === p.vendorId)} 
                          isRecommended={true}
                        />
                    </div>
                ))}
            </div>
        </section>
      )}

      {/* Main Content Area */}
      <div id="product-section" className="max-w-7xl mx-auto px-6 py-20">
        <div className="flex flex-col lg:flex-row gap-12">

          {/* Sidebar Filters */}
          <aside className={`lg:w-64 shrink-0 transition-all duration-300 ${showMobileFilters ? 'fixed inset-0 z-[60] bg-black/95 p-8 overflow-y-auto' : 'hidden lg:block'}`}>
            <div className="flex items-center justify-between lg:hidden mb-8">
                <h2 className="text-xl font-bold font-serif text-white">Filters</h2>
                <button onClick={() => setShowMobileFilters(false)} className="p-2 bg-white/10 rounded-full"><X size={20} /></button>
            </div>
            <div className="space-y-8 sticky top-24">
                <div className="space-y-4">
                    <h3 className="text-[10px] uppercase tracking-widest font-bold text-aura-purple flex items-center gap-2"><Building2 size={14} /> Vendors</h3>
                    <div className="flex flex-col gap-1">
                        <FilterOption label="All Hub" active={!selectedVendorId} onClick={() => setSelectedVendorId(null)} />
                        {vendors.filter(v => v.status === 'APPROVED').map(vendor => (
                            <FilterOption key={vendor.id} label={vendor.name} active={selectedVendorId === vendor.id} onClick={() => setSelectedVendorId(vendor.id)} />
                        ))}
                    </div>
                </div>
                {isFiltered && (
                    <button onClick={resetFilters} className="w-full py-3 rounded-xl border border-dashed border-aura-purple/30 text-[10px] font-bold uppercase tracking-widest text-aura-purple hover:bg-aura-purple/5">Reset All</button>
                )}
            </div>
          </aside>

          {/* Product Grid Area */}
          <main className="flex-1">
            <div className="flex flex-col md:flex-row md:items-center justify-between mb-10 gap-4">
                <div className="flex items-center gap-4">
                    <h2 className="text-2xl font-serif font-bold flex items-center gap-4">
                        <Sparkles className="text-aura-purple" />
                        {isFiltered ? 'Filtered Results' : ' ট্রেন্ডিং কালেকশন'}
                    </h2>
                </div>
                <div className="flex items-center gap-3">
                    <div className="relative" ref={sortRef}>
                      <button onClick={() => setShowSortDropdown(!showSortDropdown)} className="flex items-center gap-2 px-6 py-2.5 bg-white/5 border border-white/10 rounded-full text-[10px] font-bold uppercase tracking-widest text-white transition-all">
                        <ListFilter size={14} className="text-aura-purple" />
                        <span>Sort: {sortLabel}</span>
                        <ChevronDown size={14} />
                      </button>
                      {showSortDropdown && (
                        <div className="absolute right-0 mt-2 w-56 bg-black/90 backdrop-blur-3xl border border-white/10 rounded-2xl p-2 shadow-2xl z-50 animate-in fade-in slide-in-from-top-2">
                           <SortItem active={sortOption === 'NEWEST'} label="Newest Arrivals" onClick={() => { setSortOption('NEWEST'); setShowSortDropdown(false); }} />
                           <SortItem active={sortOption === 'PRICE_LOW'} label="Price: Low to High" onClick={() => { setSortOption('PRICE_LOW'); setShowSortDropdown(false); }} />
                           <SortItem active={sortOption === 'PRICE_HIGH'} label="Price: High to Low" onClick={() => { setSortOption('PRICE_HIGH'); setShowSortDropdown(false); }} />
                        </div>
                      )}
                    </div>
                </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-8">
                {products.length === 0 ? (
                    <div className="col-span-full py-20 text-center bg-white/5 rounded-3xl border border-dashed border-white/10">
                        <Building2 className="mx-auto text-gray-600 mb-4" size={48} />
                        <h3 className="text-xl font-bold text-gray-400">এই ফিল্টারে কোনো পণ্য পাওয়া যায়নি</h3>
                    </div>
                ) : (
                    products.map(p => (
                        <div key={p.id} className="relative">
                            {p.vendorId === 0 && (
                                <div className="absolute -top-3 -right-3 z-20 bg-aura-purple text-white px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest shadow-lg flex items-center gap-1">
                                    <Sparkles size={10} /> AI Concept
                                </div>
                            )}
                            <ProductCard product={p} vendor={p.vendorId === 0 ? { id: 0, name: "Aura Innovations", slug: "aura", status: "APPROVED", description: "AI Concepts" } : vendors.find(v => v.id === p.vendorId)} />
                        </div>
                    ))
                )}
            </div>
          </main>
        </div>
      </div>
    </div>
  );
};

const FilterOption: React.FC<{ label: string; active: boolean; onClick: () => void }> = ({ label, active, onClick }) => (
    <button onClick={onClick} className={`w-full text-left px-4 py-2 rounded-xl text-xs font-medium transition-all ${active ? 'bg-aura-purple text-white shadow-lg shadow-purple-900/20' : 'text-gray-400 hover:bg-white/5 hover:text-white'}`}>{label}</button>
);

const SortItem: React.FC<{ active: boolean; label: string; onClick: () => void }> = ({ active, label, onClick }) => (
  <button onClick={onClick} className={`w-full text-left px-4 py-2.5 rounded-xl text-[10px] font-bold uppercase tracking-widest transition-all ${active ? 'bg-aura-purple text-white' : 'text-gray-400 hover:bg-white/5'}`}>{label}</button>
);

import React, { useState, useEffect, useRef } from 'react';
import { Product, Vendor } from '../types';
import { 
  ExternalLink, ShoppingCart, Camera, Check, Loader2, CreditCard, 
  Sparkles, Heart, Minus, Plus, X, ShoppingBag, ArrowRight, 
  ShieldCheck, Wand2, RefreshCcw, Palette, Sun, Map, Image as ImageIcon 
} from 'lucide-react';
import { Link } from './Navigation';
import { generateAuraImage } from '../services/geminiService';

interface ProductCardProps {
  product: Product;
  vendor?: Vendor;
  isRecommended?: boolean;
}

const FALLBACK_IMAGE = 'https://images.unsplash.com/photo-1515886657613-9f3515b0c78f?auto=format&fit=crop&q=80&w=800';

export const ProductCard: React.FC<ProductCardProps> = ({ product, vendor, isRecommended }) => {
  const [isAdding, setIsAdding] = useState(false);
  const [isAdded, setIsAdded] = useState(false);
  const [isInWishlist, setIsInWishlist] = useState(false);
  const [isAnimatingWishlist, setIsAnimatingWishlist] = useState(false);
  const [isBuyModalOpen, setIsBuyModalOpen] = useState(false);
  const [quantity, setQuantity] = useState(1);

  // Image State with Fallback handling
  const [displayImageUrl, setDisplayImageUrl] = useState(product.imageUrl || FALLBACK_IMAGE);
  const [hasImageError, setHasImageError] = useState(false);

  // Refinement State
  const [isRefineModalOpen, setIsRefineModalOpen] = useState(false);
  const [refinePrompt, setRefinePrompt] = useState(`A professional high-fashion photo of ${product.name}, ${product.description}`);
  const [isRefining, setIsRefining] = useState(false);
  const [refineError, setRefineError] = useState<string | null>(null);

  // Parallax state
  const [parallax, setParallax] = useState({ x: 0, y: 0 });
  const cardRef = useRef<HTMLDivElement>(null);

  // Initialize wishlist state from localStorage
  useEffect(() => {
    const wishlist = JSON.parse(localStorage.getItem('aura_wishlist') || '[]');
    setIsInWishlist(wishlist.some((item: any) => item.id === product.id));
  }, [product.id]);

  const trackInteraction = () => {
    const history = JSON.parse(localStorage.getItem('aura_browsing_history') || '[]');
    const filteredHistory = history.filter((h: any) => h.id !== product.id);
    const newHistory = [product, ...filteredHistory].slice(0, 10);
    localStorage.setItem('aura_browsing_history', JSON.stringify(newHistory));
    window.dispatchEvent(new Event('browsingHistoryUpdated'));
  };

  const handleMouseMove = (e: React.MouseEvent<HTMLDivElement>) => {
    if (!cardRef.current) return;

    const rect = cardRef.current.getBoundingClientRect();
    const x = (e.clientX - rect.left) / rect.width;
    const y = (e.clientY - rect.top) / rect.height;

    const moveX = (x - 0.5) * 20;
    const moveY = (y - 0.5) * 20;

    setParallax({ x: moveX, y: moveY });
  };

  const handleMouseLeave = () => {
    setParallax({ x: 0, y: 0 });
  };

  const toggleWishlist = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();

    setIsAnimatingWishlist(false);
    requestAnimationFrame(() => {
        setIsAnimatingWishlist(true);
        setTimeout(() => setIsAnimatingWishlist(false), 450);
    });

    const wishlist = JSON.parse(localStorage.getItem('aura_wishlist') || '[]');
    let newWishlist;

    if (isInWishlist) {
      newWishlist = wishlist.filter((item: any) => item.id !== product.id);
    } else {
      newWishlist = [...wishlist, product];
      trackInteraction(); 
    }

    localStorage.setItem('aura_wishlist', JSON.stringify(newWishlist));
    setIsInWishlist(!isInWishlist);
    window.dispatchEvent(new Event('wishlistUpdated'));
  };

  const handleAddToCart = (e?: React.MouseEvent) => {
    if (e) {
      e.preventDefault();
      e.stopPropagation();
    }
    if (isAdding) return;
    setIsAdding(true);
    trackInteraction(); 

    const cart = JSON.parse(localStorage.getItem('aura_cart') || '[]');
    const existingIndex = cart.findIndex((item: any) => item.id === product.id);

    if (existingIndex > -1) {
      cart[existingIndex].quantity += quantity;
    } else {
      cart.push({ ...product, quantity });
    }

    localStorage.setItem('aura_cart', JSON.stringify(cart));
    window.dispatchEvent(new Event('cartUpdated'));

    setTimeout(() => {
        setIsAdding(false);
        setIsAdded(true);
        setTimeout(() => {
            setIsAdded(false);
        }, 2000);
    }, 600);
  };

  const handleBuyNowClick = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setQuantity(1);
    setIsBuyModalOpen(true);
  };

  const confirmBuyNow = () => {
    handleAddToCart();
    window.location.hash = '/cart';
  };

  const handleRegenerateImage = async () => {
    if (isRefining) return;
    setIsRefining(true);
    setRefineError(null);
    try {
      const newImage = await generateAuraImage(refinePrompt);
      if (newImage) {
        setDisplayImageUrl(newImage);
        setHasImageError(false);
      } else {
        setRefineError("Aura was unable to visualize this specific request. Try a simpler prompt.");
      }
    } catch (err) {
      setRefineError("System connection interrupted. Please try again.");
    } finally {
      setIsRefining(false);
    }
  };

  const handleImageError = () => {
    if (!hasImageError) {
      setDisplayImageUrl(FALLBACK_IMAGE);
      setHasImageError(true);
    }
  };

  const appendToPrompt = (text: string) => {
    if (!refinePrompt.includes(text)) {
      setRefinePrompt(prev => `${prev}, ${text}`);
    }
  };

  return (
    <>
      <div 
        ref={cardRef}
        onMouseEnter={trackInteraction}
        onMouseMove={handleMouseMove}
        onMouseLeave={handleMouseLeave}
        className={`group relative bg-aura-glass border rounded-[2.5rem] overflow-hidden transition-all duration-500 hover:shadow-[0_25px_60px_rgba(124,58,237,0.2)] flex flex-col h-full ${
          isRecommended 
          ? 'border-aura-purple/50 ring-1 ring-aura-purple/20' 
          : 'border-aura-glassBorder hover:border-aura-purple/60'
        }`}
      >
          {/* Image Section */}
          <div className="relative h-80 overflow-hidden cursor-pointer">
            <img 
              src={displayImageUrl} 
              alt={product.name} 
              onError={handleImageError}
              style={{ 
                transform: `translate(${parallax.x}px, ${parallax.y}px) scale(1.18)`,
                transition: 'transform 0.2s cubic-bezier(0.33, 1, 0.68, 1)'
              }}
              className="w-full h-full object-cover transform"
            />
            <div className="absolute inset-0 bg-gradient-to-t from-black via-black/30 to-transparent opacity-90" />

            <div className="absolute top-6 left-6 flex flex-col gap-2 z-20">
                <span className="bg-aura-purple/30 backdrop-blur-xl border border-aura-purple/40 px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-[0.15em] text-white">
                    {product.category}
                </span>
                {isRecommended && (
                    <span className="bg-aura-purple text-white px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-[0.15em] flex items-center gap-1.5 shadow-2xl animate-pulse">
                       <Sparkles size={12} /> Aura's Pick
                    </span>
                )}
            </div>

            <div className="absolute top-6 right-6 z-30 flex flex-col gap-2">
              <button 
                onClick={toggleWishlist}
                className={`p-3 rounded-2xl backdrop-blur-2xl border transition-all duration-300 transform active:scale-90 ${
                  isAnimatingWishlist ? 'animate-heart-pop' : ''
                } ${
                  isInWishlist 
                  ? 'bg-aura-purple/30 border-aura-purple text-aura-purple shadow-[0_0_20px_rgba(124,58,237,0.5)]' 
                  : 'bg-black/40 border-white/10 text-white hover:border-white/40 hover:bg-black/70'
                }`}
              >
                <Heart size={20} className={isInWishlist ? 'fill-aura-purple' : ''} />
              </button>

              <button 
                onClick={(e) => { e.preventDefault(); e.stopPropagation(); setIsRefineModalOpen(true); }}
                className="p-3 bg-black/40 border border-white/10 text-white rounded-2xl backdrop-blur-2xl hover:bg-aura-purple hover:border-aura-purple hover:shadow-[0_0_20px_rgba(124,58,237,0.5)] transition-all transform active:scale-90"
                title="Refine with Aura AI"
              >
                <Wand2 size={20} />
              </button>
            </div>

            <div className="absolute bottom-6 left-6 z-20">
               <Link 
                 to={`/try-on/${product.id}`}
                 className="bg-white/10 hover:bg-aura-purple text-white px-5 py-2.5 rounded-2xl text-[10px] font-black uppercase tracking-[0.2em] flex items-center gap-2.5 backdrop-blur-2xl border border-white/10 transition-all hover:scale-105 active:scale-95 shadow-2xl"
               >
                 <Camera size={16} className="text-white" /> Virtual Try-On
               </Link>
            </div>
          </div>

          {/* Content Section */}
          <div className="p-8 flex flex-col flex-grow bg-gradient-to-b from-transparent to-black/60 relative z-10">
            <div className="mb-6">
              {vendor && (
                <div className="flex items-center gap-2.5 mb-2.5">
                  <div className="w-1.5 h-1.5 rounded-full bg-aura-purple"></div>
                  <span className="text-[10px] text-aura-ash uppercase tracking-[0.3em] font-black">{vendor.name}</span>
                </div>
              )}
              <h3 className="font-serif text-2xl font-bold text-white mb-3 leading-snug group-hover:text-aura-purple transition-colors">
                {product.name}
              </h3>
              <p className="text-xs text-gray-500 line-clamp-2 font-medium leading-relaxed mb-4">
                {product.description}
              </p>
            </div>

            <div className="mt-auto pt-6 border-t border-white/10 space-y-6">
              <div className="flex justify-between items-end">
                <div>
                  <div className="text-[10px] text-gray-600 font-bold uppercase tracking-widest mb-1">Ecosystem Price</div>
                  <div className="text-3xl font-black text-white tracking-tighter">
                    ৳{product.price.toLocaleString()}
                  </div>
                </div>
                <div className="flex items-center gap-2 text-green-500 bg-green-500/10 px-3 py-1.5 rounded-xl border border-green-500/20">
                   <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></div>
                   <span className="text-[10px] font-black uppercase tracking-widest">In Stock</span>
                </div>
              </div>

              <div className="grid grid-cols-1 gap-4">
                <div className="flex gap-3">
                  {product.externalUrl ? (
                    <a 
                      href={product.externalUrl}
                      target="_blank"
                      rel="noopener noreferrer"
                      className="flex-1 bg-white text-black py-4.5 rounded-2xl text-[11px] font-black uppercase tracking-[0.2em] text-center transition-all flex items-center justify-center gap-2.5 hover:bg-aura-purple hover:text-white group/ext"
                    >
                      ভেন্ডর সাইট <ExternalLink size={16} className="group-hover/ext:translate-x-0.5 transition-transform" />
                    </a>
                  ) : (
                    <button 
                      onClick={handleAddToCart}
                      disabled={isAdding}
                      className={`flex-1 py-4.5 rounded-2xl text-[11px] font-black uppercase tracking-[0.2em] text-center transition-all flex items-center justify-center gap-2.5 border backdrop-blur-md ${
                          isAdded 
                          ? 'bg-green-500/20 border-green-500 text-green-400 shadow-[0_0_15px_rgba(34,197,94,0.3)]' 
                          : 'bg-white/5 border-white/10 text-white hover:bg-white/10 hover:border-white/30'
                      }`}
                    >
                      {isAdding ? (
                          <Loader2 size={18} className="animate-spin" />
                      ) : isAdded ? (
                          <Check size={18} />
                      ) : (
                          <ShoppingCart size={18} />
                      )}
                      <span>{isAdded ? 'Added' : 'কার্টে যোগ'}</span>
                    </button>
                  )}
                </div>

                {!product.externalUrl && (
                  <button 
                    onClick={handleBuyNowClick}
                    className="w-full bg-aura-purple text-white py-5 rounded-2xl text-[12px] font-black uppercase tracking-[0.3em] text-center transition-all hover:bg-purple-600 flex items-center justify-center gap-3 shadow-[0_15px_40px_rgba(124,58,237,0.35)] hover:shadow-purple-900/60 transform active:scale-[0.97] hover:scale-[1.02]"
                  >
                     এখনই কিনুন <ArrowRight size={18} />
                  </button>
                )}
              </div>
            </div>
          </div>
      </div>

      {/* AI Image Refinement Modal */}
      {isRefineModalOpen && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-6 bg-black/90 backdrop-blur-2xl animate-in fade-in duration-500">
          <div className="bg-aura-glass border border-aura-glassBorder w-full max-w-2xl rounded-[3rem] p-10 shadow-2xl relative overflow-hidden animate-in zoom-in slide-in-from-bottom-12 duration-500">
            {/* Artistic Glows */}
            <div className="absolute top-0 right-0 w-80 h-80 bg-aura-purple/20 blur-[120px] rounded-full pointer-events-none -translate-y-1/2 translate-x-1/2" />
            <div className="absolute bottom-0 left-0 w-80 h-80 bg-blue-600/10 blur-[100px] rounded-full pointer-events-none translate-y-1/2 -translate-x-1/2" />

            <div className="relative z-10 flex flex-col md:flex-row gap-8">
              {/* Preview Side */}
              <div className="w-full md:w-1/2 space-y-4">
                <div className="relative aspect-square rounded-3xl overflow-hidden border border-white/10 bg-black/40 shadow-2xl">
                  {isRefining && (
                    <div className="absolute inset-0 z-20 bg-black/60 backdrop-blur-md flex flex-col items-center justify-center gap-4 animate-in fade-in duration-300">
                       <Loader2 size={40} className="text-aura-purple animate-spin" />
                       <div className="text-center px-4">
                          <p className="text-[10px] text-white font-black uppercase tracking-[0.2em] mb-1">Aura is dreaming...</p>
                          <p className="text-[8px] text-gray-500 uppercase tracking-widest italic">Wait for the visualization</p>
                       </div>
                    </div>
                  )}
                  <img 
                    src={displayImageUrl} 
                    alt="Aura Vision" 
                    onError={handleImageError}
                    className="w-full h-full object-cover" 
                  />
                </div>
                <div className="flex items-center gap-3 p-4 bg-white/5 rounded-2xl border border-white/5">
                   <ImageIcon size={16} className="text-aura-purple" />
                   <div className="flex-1">
                      <p className="text-[9px] text-gray-500 font-bold uppercase tracking-widest">Active Visualization</p>
                      <p className="text-xs text-white font-bold truncate">{product.name}</p>
                   </div>
                </div>
              </div>

              {/* Controls Side */}
              <div className="w-full md:w-1/2 flex flex-col">
                <div className="flex justify-between items-start mb-6">
                  <div>
                    <h3 className="text-2xl font-serif font-bold text-white mb-1">AI Creative Hub</h3>
                    <p className="text-[9px] text-aura-purple uppercase tracking-[0.2em] font-black">Refine Imagery with Aura</p>
                  </div>
                  <button 
                    onClick={() => setIsRefineModalOpen(false)}
                    className="p-2 bg-white/5 rounded-xl text-gray-500 hover:text-white transition-colors"
                  >
                    <X size={20} />
                  </button>
                </div>

                <div className="space-y-6 flex-1">
                   <div className="space-y-2">
                      <label className="text-[10px] text-gray-600 font-black uppercase tracking-widest flex items-center gap-2">
                        <Palette size={12} /> Artistic Style
                      </label>
                      <div className="flex flex-wrap gap-2">
                         <button onClick={() => appendToPrompt('High-fashion editorial style')} className="px-3 py-1.5 bg-white/5 border border-white/5 rounded-lg text-[9px] font-bold text-gray-300 hover:bg-aura-purple transition-all">Studio</button>
                         <button onClick={() => appendToPrompt('Cyberpunk Dhakai aesthetic')} className="px-3 py-1.5 bg-white/5 border border-white/5 rounded-lg text-[9px] font-bold text-gray-300 hover:bg-aura-purple transition-all">Cyber</button>
                         <button onClick={() => appendToPrompt('Ethereal morning light')} className="px-3 py-1.5 bg-white/5 border border-white/5 rounded-lg text-[9px] font-bold text-gray-300 hover:bg-aura-purple transition-all">Ethereal</button>
                         <button onClick={() => appendToPrompt('Street photography style')} className="px-3 py-1.5 bg-white/5 border border-white/5 rounded-lg text-[9px] font-bold text-gray-300 hover:bg-aura-purple transition-all">Street</button>
                      </div>
                   </div>

                   <div className="space-y-2">
                      <label className="text-[10px] text-gray-600 font-black uppercase tracking-widest flex items-center gap-2">
                        <Sun size={12} /> Lighting & Atmosphere
                      </label>
                      <div className="flex flex-wrap gap-2">
                         <button onClick={() => appendToPrompt('Neon glow accent')} className="px-3 py-1.5 bg-white/5 border border-white/5 rounded-lg text-[9px] font-bold text-gray-300 hover:bg-aura-purple transition-all">Neon</button>
                         <button onClick={() => appendToPrompt('Golden hour warmth')} className="px-3 py-1.5 bg-white/5 border border-white/5 rounded-lg text-[9px] font-bold text-gray-300 hover:bg-aura-purple transition-all">Golden</button>
                         <button onClick={() => appendToPrompt('Dramatic contrast')} className="px-3 py-1.5 bg-white/5 border border-white/5 rounded-lg text-[9px] font-bold text-gray-300 hover:bg-aura-purple transition-all">Dramatic</button>
                      </div>
                   </div>

                   <div className="space-y-2">
                      <label className="text-[10px] text-gray-600 font-black uppercase tracking-widest flex items-center gap-2">
                        <Map size={12} /> Background Vision
                      </label>
                      <div className="flex flex-wrap gap-2">
                         <button onClick={() => appendToPrompt('Dhaka street backdrop')} className="px-3 py-1.5 bg-white/5 border border-white/5 rounded-lg text-[9px] font-bold text-gray-300 hover:bg-aura-purple transition-all">Dhaka</button>
                         <button onClick={() => appendToPrompt('Minimalist architecture')} className="px-3 py-1.5 bg-white/5 border border-white/5 rounded-lg text-[9px] font-bold text-gray-300 hover:bg-aura-purple transition-all">Minimal</button>
                         <button onClick={() => appendToPrompt('Lush nature setting')} className="px-3 py-1.5 bg-white/5 border border-white/5 rounded-lg text-[9px] font-bold text-gray-300 hover:bg-aura-purple transition-all">Nature</button>
                      </div>
                   </div>

                   <div className="pt-4 border-t border-white/5">
                      <textarea 
                        value={refinePrompt}
                        onChange={(e) => setRefinePrompt(e.target.value)}
                        className="w-full bg-black/40 border border-white/10 rounded-2xl p-4 text-xs text-gray-300 focus:outline-none focus:border-aura-purple h-24 resize-none leading-relaxed"
                        placeholder="আপনার কল্পনাকে শব্দের মাধ্যমে বর্ণনা করুন..."
                      />
                   </div>

                   {refineError && (
                      <p className="text-[10px] text-red-400 font-bold bg-red-500/10 p-2 rounded-lg border border-red-500/20">{refineError}</p>
                   )}

                   <button 
                      onClick={handleRegenerateImage}
                      disabled={isRefining}
                      className="w-full bg-aura-purple text-white py-4 rounded-2xl text-[11px] font-black uppercase tracking-[0.25em] flex items-center justify-center gap-3 shadow-xl hover:bg-purple-600 transition-all transform active:scale-95 disabled:opacity-50"
                   >
                      {isRefining ? <RefreshCcw size={16} className="animate-spin" /> : <Sparkles size={16} />}
                      রিজেনারেট করুন
                   </button>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Buy Now Refactored Modal */}
      {isBuyModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-black/85 backdrop-blur-xl animate-in fade-in duration-500">
          <div className="bg-aura-glass border border-aura-glassBorder w-full max-w-lg rounded-[3rem] p-10 shadow-2xl relative overflow-hidden animate-in zoom-in slide-in-from-bottom-12 duration-500">
            {/* Visual Aura Glows */}
            <div className="absolute top-0 right-0 w-80 h-80 bg-aura-purple/20 blur-[120px] rounded-full pointer-events-none -translate-y-1/2 translate-x-1/2" />
            <div className="absolute bottom-0 left-0 w-80 h-80 bg-blue-600/10 blur-[100px] rounded-full pointer-events-none translate-y-1/2 -translate-x-1/2" />

            <div className="relative z-10">
              <div className="flex justify-between items-start mb-8">
                <div>
                  <h3 className="text-3xl font-serif font-bold text-white mb-2 leading-none">Aura Checkout</h3>
                  <div className="flex items-center gap-2">
                    <div className="w-1 h-1 rounded-full bg-aura-purple"></div>
                    <p className="text-[10px] text-gray-500 uppercase tracking-[0.2em] font-black">Direct Marketplace Confirmation</p>
