import { GoogleGenAI, Type, GenerateContentResponse, Chat } from "@google/genai";
import { getProducts, getVendors, getOrderById } from "./mockData";
import { Product } from "../types";

// --- SYSTEM CONTEXT ---
const buildAuraContext = () => {
  const products = getProducts();
  const vendors = getVendors();

  const productString = products.map(p => 
    `- ${p.name} (৳${p.price}) [Category: ${p.category}] by ${vendors.find(v => v.id === p.vendorId)}?.name. Desc: ${p.description}`
  ).join('\n');

  const vendorString = vendors.map(v => 
    `- ${v.name} (Status: ${v.status}): ${v.description}`
  ).join('\n');

  return `
Identity: AURA AI - The Divine Soul of SNEHALATA-স্নেহলতা Hub.
Tone: Formal, Artistic, Culturally respectful, Multi-lingual (Bangla & English).

CRITICAL DIRECTIVE:
ALWAYS start EVERY conversation with the greeting "আসসালামু আলাইকুম" (Assalamu Alaikum). 

Ecosystem Data:
VENDORS:
${vendorString}

PRODUCTS:
${productString}

Capabilities:
1. PRODUCT DISCOVERY: Use findProducts tool to filter items for the user.
2. CUSTOMER SUPPORT: Use checkOrderStatus tool to help users track their orders.
3. CREATIVITY: Generate conceptual fashion images if users ask to 'imagine' or 'design' something.
  `;
};

// --- FUNCTION CALLING TOOLS ---
const tools = [
  {
    functionDeclarations: [
      {
        name: "findProducts",
        description: "Search for products in the catalog by category, max price, or name keywords.",
        parameters: {
          type: Type.OBJECT,
          properties: {
            category: { type: Type.STRING, description: "Garment category like Saree, Panjabi, Hoodie" },
            maxPrice: { type: Type.NUMBER, description: "Maximum price in BDT" },
            keywords: { type: Type.STRING, description: "Keywords to match in product name or description" }
          }
        }
      },
      {
        name: "checkOrderStatus",
        description: "Retrieve the current status and tracking details for a specific order ID.",
        parameters: {
          type: Type.OBJECT,
          properties: {
            orderId: { type: Type.STRING, description: "The order ID, e.g., ORD-5001" }
          },
          required: ["orderId"]
        }
      }
    ]
  }
];

// --- STREAMING CHAT ---
export const startAuraChat = (): Chat => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  return ai.chats.create({
    model: 'gemini-3-flash-preview',
    config: {
      systemInstruction: buildAuraContext(),
      tools,
      temperature: 0.7,
    },
  });
};

// --- AI RECOMMENDATIONS ---
export const getAIRecommendations = async (historyProducts: Product[]): Promise<number[]> => {
    if (!process.env.API_KEY) return [];

    const catalog = getProducts();
    const historySummary = historyProducts.map(p => `${p.name} (${p.category}, ৳${p.price})`).join(', ');
    const catalogSummary = catalog.map(p => `ID: ${p.id}, Name: ${p.name}, Cat: ${p.category}, Price: ${p.price}`).join(' | ');

    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const prompt = `
            User Browsing History: [${historySummary}]
            Product Catalog: [${catalogSummary}]

            Analyze the user's taste based on their history (styles, price points, categories). 
            From the catalog, select exactly 3 product IDs that the user is MOST likely to be interested in. 
            Do not recommend products already in their history unless there are no other options.

            Return JSON ONLY: { "recommendedIds": number[] }
        `;

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: { responseMimeType: 'application/json' }
        });

        const result = JSON.parse(response.text || '{ "recommendedIds": [] }');
        return result.recommendedIds || [];
    } catch (error) {
        console.error("Recommendation Error:", error);
        return [];
    }
};

// --- IMAGE GENERATION ---
export const generateAuraImage = async (prompt: string): Promise<string | null> => {
    if (!process.env.API_KEY) return null;

    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash-image',
            contents: {
                parts: [{ text: `A photorealistic high-fashion editorial shot of a Bangladeshi garment, ${prompt}. High resolution, luxury fabric texture, professional studio lighting.` }],
            },
            config: {
                imageConfig: {
                    aspectRatio: "1:1"
                }
            }
        });

        for (const part of response.candidates[0].content.parts) {
            if (part.inlineData) {
                return `data:image/png;base64,${part.inlineData.data}`;
            }
        }
        return null;
    } catch (error) {
        console.error("Image Gen Error:", error);
        return null;
    }
};

