        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const prompt = `
        Analyze this fashion query: "${userPrompt}"
        Extract category, price, color, material, style.
        Return JSON.
        `;

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: { responseMimeType: 'application/json' }
        });

        return JSON.parse(response.text || '{}');
    } catch (error) {
        console.error("Intent Error:", error);
        return null;
    }
};

// --- TRY-ON ---
export const generateTryOnTransformation = async (userImageBase64: string, productImageBase64: string): Promise<string | null> => {
    if (!process.env.API_KEY) return null;
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const cleanUserImage = userImageBase64.replace(/^data:image\/(png|jpeg|jpg);base64,/, "");
      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: {
          parts: [
            { inlineData: { data: cleanUserImage, mimeType: 'image/jpeg' } },
            { text: "Drape the clothing item conceptually onto the person. Maintain realistic lighting." },
          ],
        },
      });
      for (const part of response.candidates[0].content.parts) {
          if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
      }
      return null; 
    } catch (error) {
      return null;
    }
};

// --- VENDOR AUDIT ---
export const auditVendorDescription = async (shopName: string, description: string, tradeLicense: string): Promise<{ status: 'APPROVED' | 'REJECTED' | 'PENDING'; reason: string }> => {
    if (!process.env.API_KEY) return { status: 'APPROVED', reason: 'Dev Mode' };
    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: `Shop Name: ${shopName}\nTrade License: ${tradeLicense}\nDescription: ${description}`,
            config: { 
                systemInstruction: `Audit for authenticity. Respond in JSON.`,
                responseMimeType: 'application/json' 
            }
        });
        const result = JSON.parse(response.text || '{}');
        return {
            status: result.status || 'PENDING',
            reason: result.reason || 'আবেদনটি রিভিউ করা হচ্ছে।'
        };
    } catch (error) {
        return { status: 'PENDING', reason: 'Audit failed.' };
    }
};

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { startAuraChat, analyzeSearchIntent, generateAuraImage, SearchIntent, getAIRecommendations } from '../services/geminiService';
import { getProducts, getVendors, getLiveSales, getOrderById } from '../services/mockData';
import { ProductCard } from '../components/ProductCard';
import { ChatMessage, Product, Vendor, Order } from '../types';
import { Sparkles, Send, Trash2, Clock, Image as ImageIcon, Loader2, Filter, X, Wand2, Info, Tag, Building2, AlertCircle, ChevronDown, ChevronUp, SlidersHorizontal, Search, Sparkle, ListFilter, UserCheck, Edit3, RefreshCw, Palette, Zap, ChevronRight, MessageSquare, ArrowRight, ShoppingCart, MessageCircle, PackageSearch } from 'lucide-react';
import { GenerateContentResponse } from '@google/genai';

type SortOption = 'NEWEST' | 'PRICE_LOW' | 'PRICE_HIGH';

export const Home: React.FC = () => {
  const [allProducts, setAllProducts] = useState<Product[]>([]);
  const [products, setProducts] = useState<Product[]>([]);
  const [vendors, setVendors] = useState<Vendor[]>([]);
  const [recommendations, setRecommendations] = useState<Product[]>([]);
  const [salesTicker, setSalesTicker] = useState(0);

  // Search, Filtering & Sorting states
  const [searchInput, setSearchInput] = useState('');
  const [isSearching, setIsSearching] = useState(false);
  const [sortOption, setSortOption] = useState<SortOption>('NEWEST');
  const [selectedVendorId, setSelectedVendorId] = useState<number | null>(null);
  const [activeIntent, setActiveIntent] = useState<SearchIntent | null>(null);
  const [priceRange, setPriceRange] = useState<{ min: number; max: number }>({ min: 0, max: 100000 });
  const [showSortDropdown, setShowSortDropdown] = useState(false);

  // AI & Chat State
  const [chatSession] = useState(() => startAuraChat());
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'ai', content: "আসসালামু আলাইকুম। Snehalata-স্নেহলতা ইকোসিস্টেমে স্বাগতম। আমি Aura। আজ আপনার স্টাইল যাত্রায় কীভাবে সাহায্য করতে পারি?", timestamp: Date.now() }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [isFloatingOpen, setIsFloatingOpen] = useState(false);
  const [showFloatingBubble, setShowFloatingBubble] = useState(false);

  // Discovery results in chat
  const [chatFoundProducts, setChatFoundProducts] = useState<Record<number, Product[]>>({});
  const [chatFoundOrder, setChatFoundOrder] = useState<Record<number, Order>>({});

  const chatContainerRef = useRef<HTMLDivElement>(null);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const initialProducts = getProducts();
    setAllProducts(initialProducts);
    setProducts(initialProducts);
    setVendors(getVendors());
    setSalesTicker(getLiveSales());

    const interval = setInterval(() => {
        setSalesTicker(prev => prev + Math.floor(Math.random() * 500));
    }, 5000);

    const handleScroll = () => {
        if (window.scrollY > 400) setShowFloatingBubble(true);
        else setShowFloatingBubble(false);
    };
    window.addEventListener('scroll', handleScroll);

    fetchRecommendations();
    const handleHistoryUpdate = () => fetchRecommendations();
    window.addEventListener('browsingHistoryUpdated', handleHistoryUpdate);

    return () => {
      clearInterval(interval);
      window.removeEventListener('scroll', handleScroll);
      window.removeEventListener('browsingHistoryUpdated', handleHistoryUpdate);
    };
  }, []);

  useEffect(() => {
    if (chatContainerRef.current) {
      chatContainerRef.current.scrollTop = chatContainerRef.current.scrollHeight;
    }
  }, [messages, isTyping]);

  const fetchRecommendations = async () => {
      const history = JSON.parse(localStorage.getItem('aura_browsing_history') || '[]');
      if (history.length === 0) return;
      try {
        const recIds = await getAIRecommendations(history);
        const catalog = getProducts();
        const recProducts = recIds.map(id => catalog.find(p => p.id === id)).filter(Boolean) as Product[];
        setRecommendations(recProducts);
      } catch (err) {
        console.error("Failed to fetch AI recs", err);
      }
  };

  const handleSendMessage = async (e: React.FormEvent, customInput?: string) => {
    if (e) e.preventDefault();
    const currentInput = customInput || input;
    if (!currentInput.trim() || isTyping) return;

    const userMsg: ChatMessage = { role: 'user', content: currentInput, timestamp: Date.now() };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsTyping(true);

    const aiMsgIndex = messages.length + 1;
    let accumulatedContent = "";

    try {
      const stream = await chatSession.sendMessageStream({ message: currentInput });

      // Initialize empty AI message for streaming
      setMessages(prev => [...prev, { role: 'ai', content: "", timestamp: Date.now() }]);

      for await (const chunk of stream) {
        const c = chunk as GenerateContentResponse;

        // Handle Tool Calls
        if (c.functionCalls) {
            for (const fc of c.functionCalls) {
                if (fc.name === 'findProducts') {
                    const args = fc.args as any;
                    const filtered = allProducts.filter(p => {
                        const matchCat = !args.category || p.category.toLowerCase().includes(args.category.toLowerCase());
                        const matchPrice = !args.maxPrice || p.price <= args.maxPrice;
                        const matchKey = !args.keywords || p.name.toLowerCase().includes(args.keywords.toLowerCase());
                        return matchCat && matchPrice && matchKey;
                    }).slice(0, 3);
                    setChatFoundProducts(prev => ({ ...prev, [aiMsgIndex]: filtered }));

                    // Send tool response back to Gemini
                    await chatSession.sendToolResponse({
                        functionResponses: {
                            id: fc.id,
                            name: fc.name,
                            response: { results: filtered.map(p => p.name) }
                        }
                    });
                }
                if (fc.name === 'checkOrderStatus') {
                    const args = fc.args as any;
                    const order = getOrderById(args.orderId);
                    if (order) {
                        setChatFoundOrder(prev => ({ ...prev, [aiMsgIndex]: order }));
                        await chatSession.sendToolResponse({
                            functionResponses: {
                                id: fc.id,
                                name: fc.name,
                                response: { status: order.currentStatus, delivery: order.estimatedDelivery }
                            }
                        });
                    }
                }
            }
        }

        if (c.text) {
          accumulatedContent += c.text;
          setMessages(prev => prev.map((m, i) => i === aiMsgIndex ? { ...m, content: accumulatedContent } : m));
        }
      }
    } catch (error) {
      setMessages(prev => [...prev, { role: 'ai', content: "আসসালামু আলাইকুম। কানেকশন এরর হয়েছে। আবার চেষ্টা করুন।", timestamp: Date.now() }]);
    } finally {
      setIsTyping(false);
    }
  };

  const handleAISearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!searchInput.trim() || isSearching) return;
    setIsSearching(true);
    try {
      const intent = await analyzeSearchIntent(searchInput);
      if (intent) {
        setActiveIntent(intent);
        handleSendMessage(null as any, `Search request: ${searchInput}`);
        document.getElementById('product-section')?.scrollIntoView({ behavior: 'smooth' });
      }
    } finally {
      setIsSearching(false);
    }
  };

  const sortLabel = { 'NEWEST': 'Newest Arrivals', 'PRICE_LOW': 'Price: Low to High', 'PRICE_HIGH': 'Price: High to Low' }[sortOption];

  return (
    <div className="min-h-screen">

      {/* Floating AI Bubble */}
      {showFloatingBubble && (
        <div className="fixed bottom-10 right-10 z-[100] group">
            {!isFloatingOpen ? (
                <button 
                    onClick={() => setIsFloatingOpen(true)}
                    className="relative w-16 h-16 bg-aura-purple rounded-full shadow-[0_0_40px_rgba(124,58,237,0.5)] border border-white/20 flex items-center justify-center hover:scale-110 active:scale-95 transition-all"
                >
                    <div className="absolute inset-0 bg-aura-purple rounded-full animate-ping opacity-20"></div>
                    <MessageCircle className="text-white" size={30} />
                </button>
            ) : (
                <div className="bg-aura-glass backdrop-blur-3xl border border-aura-glassBorder w-80 md:w-96 rounded-[2.5rem] shadow-2xl overflow-hidden animate-in zoom-in slide-in-from-bottom-10 origin-bottom-right flex flex-col h-[600px]">
                    <div className="p-6 bg-aura-purple flex items-center justify-between">
                        <div className="flex items-center gap-3">
                            <Sparkles className="text-white" size={20} />
                            <span className="text-xs font-black uppercase tracking-widest text-white">Aura AI Support</span>
                        </div>
                        <button onClick={() => setIsFloatingOpen(false)} className="text-white/60 hover:text-white transition-colors">
                            <X size={20} />
                        </button>
                    </div>

                    {/* Reuse Chat Components */}
                    <div className="flex-1 p-4 overflow-y-auto space-y-4" ref={chatContainerRef}>
                        {messages.map((msg, idx) => (
                            <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                                <div className={`max-w-[90%] rounded-2xl p-4 text-xs ${msg.role === 'user' ? 'bg-white text-black font-medium' : 'bg-white/5 text-gray-200 border border-white/10'}`}>
                                    <div className="whitespace-pre-wrap leading-relaxed">{msg.content}</div>

                                    {/* Action Results */}
                                    {chatFoundProducts[idx] && (
                                        <div className="mt-4 flex flex-col gap-2">
                                            {chatFoundProducts[idx].map(p => (
                                                <div key={p.id} className="flex items-center gap-3 bg-white/5 p-2 rounded-xl border border-white/5 group/p">
                                                    <img src={p.imageUrl} className="w-10 h-10 object-cover rounded-lg" />
                                                    <div className="flex-1 min-w-0">
                                                        <div className="text-[10px] text-white font-bold truncate">{p.name}</div>
                                                        <div className="text-[9px] text-aura-purple font-black">৳{p.price.toLocaleString()}</div>
                                                    </div>
                                                    <button className="p-1.5 bg-white/10 rounded-lg hover:bg-aura-purple transition-all">
                                                        <ShoppingCart size={12} />
                                                    </button>
                                                </div>
                                            ))}
                                        </div>
                                    )}

                                    {chatFoundOrder[idx] && (
                                        <div className="mt-4 p-3 bg-aura-purple/10 border border-aura-purple/20 rounded-xl">
