// --- AI RECOMMENDATIONS ---
export const getAIRecommendations = async (historyProducts: Product[]): Promise<number[]> => {
    if (!process.env.API_KEY) return [];

    const catalog = getProducts();
    const historySummary = historyProducts.map(p => `${p.name} (${p.category}, ৳${p.price})`).join(', ');
    const catalogSummary = catalog.map(p => `ID: ${p.id}, Name: ${p.name}, Cat: ${p.category}, Price: ${p.price}`).join(' | ');

    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const prompt = `
            User Browsing History: [${historySummary}]
            Product Catalog: [${catalogSummary}]

            Analyze the user's taste based on their history (styles, price points, categories). 
            From the catalog, select exactly 3 product IDs that the user is MOST likely to be interested in. 
            Do not recommend products already in their history unless there are no other options.

            Return JSON ONLY: { "recommendedIds": number[] }
        `;

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: { responseMimeType: 'application/json' }
        });

        const result = JSON.parse(response.text || '{ "recommendedIds": [] }');
        return result.recommendedIds || [];
    } catch (error) {
        console.error("Recommendation Error:", error);
        return [];
    }
};

// --- IMAGE GENERATION / EDITING ---
export const generateAuraImage = async (prompt: string, referenceImageBase64?: string): Promise<string | null> => {
    if (!process.env.API_KEY) return null;

    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const parts: any[] = [{ text: `A photorealistic high-fashion editorial shot. ${prompt}. High resolution, luxury fabric texture, professional studio lighting.` }];

        if (referenceImageBase64) {
            const cleanBase64 = referenceImageBase64.replace(/^data:image\/(png|jpeg|jpg);base64,/, "");
            parts.unshift({
                inlineData: {
                    data: cleanBase64,
                    mimeType: 'image/png'
                }
            });
            // Adjust text to guide re-styling
            parts[parts.length-1].text = `Re-imagine the garment in this image using the following style: ${prompt}. Keep the core shape of the garment consistent but transform the environment, lighting, and textures.`;
        }

        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash-image',
            contents: { parts },
            config: {
                imageConfig: {
                    aspectRatio: "1:1"
                }
            }
        });

        for (const part of response.candidates[0].content.parts) {
            if (part.inlineData) {
                return `data:image/png;base64,${part.inlineData.data}`;
            }
        }
        return null;
    } catch (error) {
        console.error("Image Gen Error:", error);
        return null;
    }
};

