                <button 
                  disabled={isRefining}
                  onClick={handleReset}
                  className="group relative flex flex-col items-center gap-4 p-8 bg-white/5 border border-white/10 rounded-3xl transition-all hover:bg-red-500/20 hover:border-red-500/40 disabled:opacity-50 active:scale-95"
