                </div>
              )}

              {refineError && (
                <p className="text-[10px] text-red-400 font-bold bg-red-500/10 p-4 rounded-2xl border border-red-500/20 text-center">
                  {refineError}
                </p>
              )}
            </div>
          </div>
        </div>
      )}

      {/* Unified Creative Studio Modal (Full Customization) */}
      {isCreativeModalOpen && (
        <div className="fixed inset-0 z-[140] flex items-center justify-center p-6 bg-black/95 backdrop-blur-3xl animate-in fade-in duration-500">
          <div className="bg-aura-glass border border-aura-glassBorder w-full max-w-4xl rounded-[3rem] p-10 shadow-2xl relative overflow-hidden animate-in zoom-in duration-500">
            <div className="absolute top-0 right-0 w-96 h-96 bg-aura-purple/20 blur-[150px] rounded-full pointer-events-none -translate-y-1/2 translate-x-1/2" />

            <div className="relative z-10 flex flex-col lg:flex-row gap-10">
              {/* Preview Side */}
              <div className="lg:w-1/2 space-y-6">
                <div className="flex justify-between items-center mb-4">
                  <div>
                    <h3 className="text-3xl font-serif font-bold text-white mb-2 tracking-tight">Creative Hub</h3>
                    <div className="flex items-center gap-2">
                      <Sparkles className="text-aura-purple" size={14} />
                      <p className="text-[10px] text-gray-400 uppercase tracking-[0.25em] font-black">Neural Core Customization</p>
                    </div>
                  </div>
                  <button onClick={() => setIsCreativeModalOpen(false)} className="lg:hidden p-3 bg-white/5 rounded-2xl text-gray-400">
                    <X size={20} />
                  </button>
                </div>

                <div className="relative aspect-square rounded-[2rem] overflow-hidden border border-white/10 bg-black/40 shadow-2xl">
                  {isRefining && (
                    <div className="absolute inset-0 z-20 bg-black/60 backdrop-blur-md flex flex-col items-center justify-center gap-4">
                       <Loader2 size={40} className="text-aura-purple animate-spin" />
                       <div className="text-center">
                          <p className="text-[10px] text-white font-black uppercase tracking-[0.3em] mb-1">Aura is dreaming...</p>
                          <p className="text-[8px] text-gray-500 uppercase tracking-widest italic">Crystallizing visual textures</p>
                       </div>
                    </div>
                  )}
                  <img src={displayImageUrl} alt="Preview" className="w-full h-full object-cover" />
                </div>

                <div className="flex items-center justify-between p-4 bg-white/5 rounded-2xl border border-white/5">
                   <div className="flex items-center gap-3">
                      <ImageIcon size={18} className="text-aura-purple" />
                      <div>
                        <p className="text-[9px] text-gray-500 font-bold uppercase tracking-widest">Active State</p>
                        <p className="text-xs text-white font-bold">{product.name}</p>
                      </div>
                   </div>
                   <button onClick={handleReset} className="p-2 text-gray-500 hover:text-red-400 transition-colors flex items-center gap-2 text-[10px] font-bold uppercase tracking-widest">
                     <RotateCcw size={14} /> Reset Original
                   </button>
                </div>
              </div>

              {/* Controls Side */}
              <div className="lg:w-1/2 flex flex-col">
                <div className="hidden lg:flex justify-end mb-6">
                  <button onClick={() => setIsCreativeModalOpen(false)} className="p-3 bg-white/5 rounded-2xl hover:bg-white/10 text-gray-400 transition-all border border-white/5">
                    <X size={20} />
                  </button>
                </div>

                <div className="flex-1 space-y-8">
                   <div className="space-y-4">
                      <label className="text-[10px] text-gray-500 font-black uppercase tracking-[0.2em] flex items-center gap-2">
                        <Edit3 size={14} className="text-aura-purple" /> Artistic Direction
                      </label>
                      <textarea 
                        value={refinePrompt}
                        onChange={(e) => setRefinePrompt(e.target.value)}
                        className="w-full bg-black/40 border border-white/10 rounded-2xl p-5 text-xs text-gray-300 focus:outline-none focus:border-aura-purple h-48 resize-none leading-relaxed transition-all"
                        placeholder="Describe how you'd like to re-imagine this artisan garment..."
                      />
                   </div>

                   {refineError && (
                      <p className="text-[10px] text-red-400 font-bold bg-red-500/10 p-3 rounded-xl border border-red-500/20 text-center">
                        {refineError}
                      </p>
                   )}

                   <div className="pt-4 space-y-4">
                      <button 
                          onClick={handleRegenerate}
                          disabled={isRefining}
                          className="w-full bg-aura-purple text-white py-5 rounded-2xl text-[11px] font-black uppercase tracking-[0.3em] flex items-center justify-center gap-3 shadow-2xl hover:bg-purple-600 transition-all active:scale-[0.98] disabled:opacity-50"
                      >
                          {isRefining ? <Loader2 size={18} className="animate-spin" /> : <RefreshCcw size={18} />}
                          Visualize Evolution
                      </button>

                      <div className="flex items-center justify-center gap-2 text-gray-600">
                          <InfoIcon size={12} />
                          <span className="text-[8px] uppercase tracking-widest font-bold">Aura preserves the core garment structure while refining aesthetics.</span>
                      </div>
                   </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Buy Now Modal */}
      {isBuyModalOpen && (
        <div className="fixed inset-0 z-[130] flex items-center justify-center p-6 bg-black/90 backdrop-blur-2xl animate-in fade-in duration-500">
          <div className="bg-aura-glass border border-aura-glassBorder w-full max-w-lg rounded-[3rem] p-10 shadow-2xl relative overflow-hidden animate-in zoom-in duration-500">
            <div className="absolute top-0 right-0 w-80 h-80 bg-aura-purple/20 blur-[120px] rounded-full pointer-events-none" />
            <div className="relative z-10">
              <div className="flex justify-between items-start mb-8">
                <div>
                  <h3 className="text-3xl font-serif font-bold text-white mb-2">Aura Checkout</h3>
                  <p className="text-[10px] text-gray-500 uppercase tracking-[0.2em] font-black">Ecosystem Hub Confirmation</p>
                </div>
                <button onClick={() => setIsBuyModalOpen(false)} className="p-3 bg-white/5 rounded-2xl text-gray-400"><X size={24} /></button>
              </div>

              <div className="flex gap-6 p-6 bg-white/[0.03] rounded-3xl border border-white/10 mb-10">
                <div className="w-24 h-24 rounded-2xl overflow-hidden border border-white/10 shrink-0">
                    <img src={displayImageUrl} alt={product.name} className="w-full h-full object-cover" />
                </div>
                <div className="flex flex-col justify-center">
                  <div className="text-[10px] text-aura-purple font-black uppercase tracking-widest mb-1">{vendor?.name}</div>
                  <h4 className="text-white font-bold text-lg truncate mb-1">{product.name}</h4>
                  <div className="text-xl font-black text-white">৳{product.price.toLocaleString()}</div>
                </div>
              </div>

              <div className="space-y-8 mb-12">
                <div className="flex flex-col items-center gap-4">
                  <div className="text-[10px] text-gray-600 font-black uppercase tracking-[0.2em]">Quantity</div>
                  <div className="flex items-center gap-10">
                    <button onClick={() => setQuantity(Math.max(1, quantity - 1))} className="w-12 h-12 rounded-2xl border border-white/10 bg-white/[0.02] flex items-center justify-center text-white hover:bg-aura-purple transition-all"><Minus size={20} /></button>
                    <span className="text-4xl font-serif font-black text-white">{quantity}</span>
                    <button onClick={() => setQuantity(quantity + 1)} className="w-12 h-12 rounded-2xl border border-white/10 bg-white/[0.02] flex items-center justify-center text-white hover:bg-aura-purple transition-all"><Plus size={20} /></button>
                  </div>
                </div>
                <div className="w-full flex justify-between items-center bg-white/[0.02] p-6 rounded-3xl border border-white/5">
                  <span className="text-[11px] text-gray-500 uppercase tracking-widest font-black">Subtotal</span>
                  <span className="text-3xl font-black text-white">৳{(product.price * quantity).toLocaleString()}</span>
                </div>
              </div>

              <button onClick={() => { handleAddToCart(); window.location.hash = '/cart'; }} className="w-full bg-white text-black py-6 rounded-3xl text-[13px] font-black uppercase tracking-[0.4em] transition-all hover:bg-aura-purple hover:text-white shadow-xl active:scale-95 flex items-center justify-center gap-4 group">
                <CreditCard size={20} /> Confirm & Checkout
              </button>
            </div>
          </div>
        </div>
      )}
    </>
  );
};

const InfoIcon = ({ size, className }: { size?: number, className?: string }) => (
    <svg xmlns="http://www.w3.org/2000/svg" width={size || 24} height={size || 24} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className={className}>
        <circle cx="12" cy="12" r="10"/><path d="M12 16v-4"/><path d="M12 8h.01"/>
    </svg>
);

import React, { useState, useEffect, useRef } from 'react';
import { Product, Vendor } from '../types';
import { 
  ExternalLink, ShoppingCart, Camera, Check, Loader2, CreditCard, 
  Sparkles, Heart, Minus, Plus, X, ArrowRight, 
  ShieldCheck, Wand2, RefreshCcw, Palette, Sun, Map, Image as ImageIcon,
  Layers, Zap, Wind, History, RotateCcw, Crown, Palmtree
} from 'lucide-react';
import { Link } from './Navigation';
import { generateAuraImage } from '../services/geminiService';

interface ProductCardProps {
  product: Product;
  vendor?: Vendor;
  isRecommended?: boolean;
}

const FALLBACK_IMAGE = 'https://images.unsplash.com/photo-1515886657613-9f3515b0c78f?auto=format&fit=crop&q=80&w=800';

const STYLE_PRESETS = [
  { 
    name: 'Vintage', 
