    color: 'from-green-500/20 to-emerald-900/40',
    description: 'Lush exotic vibes'
  }
];

export const ProductCard: React.FC<ProductCardProps> = ({ product, vendor, isRecommended }) => {
  const [isAdding, setIsAdding] = useState(false);
  const [isAdded, setIsAdded] = useState(false);
  const [isInWishlist, setIsInWishlist] = useState(false);
  const [isAnimatingWishlist, setIsAnimatingWishlist] = useState(false);
  const [isBuyModalOpen, setIsBuyModalOpen] = useState(false);
  const [isPresetsModalOpen, setIsPresetsModalOpen] = useState(false);
  const [quantity, setQuantity] = useState(1);

  // Image State
  const isValidUrl = (url: string | undefined) => !!url && url.trim().length > 0;
  const [displayImageUrl, setDisplayImageUrl] = useState(isValidUrl(product.imageUrl) ? product.imageUrl : FALLBACK_IMAGE);
  const [isRefining, setIsRefining] = useState(false);
  const [refineError, setRefineError] = useState<string | null>(null);

  // Parallax effect for the image
  const [parallax, setParallax] = useState({ x: 0, y: 0 });
  const cardRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const wishlist = JSON.parse(localStorage.getItem('aura_wishlist') || '[]');
    setIsInWishlist(wishlist.some((item: any) => item.id === product.id));
  }, [product.id]);

  const trackInteraction = () => {
    const history = JSON.parse(localStorage.getItem('aura_browsing_history') || '[]');
    const filteredHistory = history.filter((h: any) => h.id !== product.id);
    const newHistory = [product, ...filteredHistory].slice(0, 10);
    localStorage.setItem('aura_browsing_history', JSON.stringify(newHistory));
    window.dispatchEvent(new Event('browsingHistoryUpdated'));
  };

  const handleMouseMove = (e: React.MouseEvent<HTMLDivElement>) => {
    if (!cardRef.current) return;
    const rect = cardRef.current.getBoundingClientRect();
    const x = (e.clientX - rect.left) / rect.width;
    const y = (e.clientY - rect.top) / rect.height;
    setParallax({ x: (x - 0.5) * 15, y: (y - 0.5) * 15 });
  };

  const toggleWishlist = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsAnimatingWishlist(true);
    setTimeout(() => setIsAnimatingWishlist(false), 450);

    const wishlist = JSON.parse(localStorage.getItem('aura_wishlist') || '[]');
    let newWishlist;
    if (isInWishlist) {
      newWishlist = wishlist.filter((item: any) => item.id !== product.id);
    } else {
      newWishlist = [...wishlist, product];
      trackInteraction(); 
    }
    localStorage.setItem('aura_wishlist', JSON.stringify(newWishlist));
    setIsInWishlist(!isInWishlist);
    window.dispatchEvent(new Event('wishlistUpdated'));
  };

  const handleAddToCart = (e?: React.MouseEvent) => {
    if (e) { e.preventDefault(); e.stopPropagation(); }
    if (isAdding) return;
    setIsAdding(true);
    trackInteraction(); 
    const cart = JSON.parse(localStorage.getItem('aura_cart') || '[]');
    const existingIndex = cart.findIndex((item: any) => item.id === product.id);
    if (existingIndex > -1) { cart[existingIndex].quantity += quantity; }
    else { cart.push({ ...product, quantity }); }
    localStorage.setItem('aura_cart', JSON.stringify(cart));
    window.dispatchEvent(new Event('cartUpdated'));
    setTimeout(() => { setIsAdding(false); setIsAdded(true); setTimeout(() => setIsAdded(false), 2000); }, 600);
  };

  const getBase64FromUrl = async (url: string): Promise<string | null> => {
    if (url.startsWith('data:')) return url;
    try {
        const response = await fetch(url);
        const blob = await response.blob();
        return new Promise((resolve) => {
            const reader = new FileReader();
            reader.onloadend = () => resolve(reader.result as string);
            reader.readAsDataURL(blob);
        });
    } catch (e) { return null; }
  };

  const handleApplyStyle = async (presetPrompt: string) => {
    if (isRefining) return;
    setIsRefining(true);
    setRefineError(null);
    try {
      const base64Ref = await getBase64FromUrl(displayImageUrl);
      const newImage = await generateAuraImage(presetPrompt, base64Ref || undefined);
      if (newImage) {
        setDisplayImageUrl(newImage);
        setIsPresetsModalOpen(false);
      } else {
        setRefineError("Aura was unable to stylize this item. Try a different preset.");
      }
    } catch (err) {
      setRefineError("AI core connection interrupted.");
    } finally {
      setIsRefining(false);
    }
  };

  const handleReset = () => {
    setDisplayImageUrl(product.imageUrl || FALLBACK_IMAGE);
    setIsPresetsModalOpen(false);
  };

  return (
    <>
      <div 
        ref={cardRef}
        onMouseEnter={trackInteraction}
        onMouseMove={handleMouseMove}
        onMouseLeave={() => setParallax({ x: 0, y: 0 })}
        className={`group relative bg-aura-glass border rounded-[2.5rem] overflow-hidden transition-all duration-500 hover:shadow-[0_25px_60px_rgba(124,58,237,0.2)] flex flex-col h-full ${
          isRecommended ? 'border-aura-purple/50 ring-1 ring-aura-purple/20' : 'border-aura-glassBorder hover:border-aura-purple/60'
        }`}
      >
          {/* Image Section */}
          <div className="relative h-80 overflow-hidden cursor-pointer" onClick={() => setIsPresetsModalOpen(true)}>
            <img 
              src={displayImageUrl} 
              alt={product.name} 
              style={{ transform: `translate(${parallax.x}px, ${parallax.y}px) scale(1.15)`, transition: 'transform 0.2s ease-out' }}
              className={`w-full h-full object-cover transform ${isRefining ? 'animate-pulse opacity-50 blur-sm' : ''}`}
            />
            <div className="absolute inset-0 bg-gradient-to-t from-black via-black/30 to-transparent opacity-90" />

            <div className="absolute top-6 left-6 flex flex-col gap-2 z-20">
                <span className="bg-aura-purple/30 backdrop-blur-xl border border-aura-purple/40 px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-[0.15em] text-white">
                    {product.category}
                </span>
                {isRecommended && (
                    <span className="bg-aura-purple text-white px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-[0.15em] flex items-center gap-1.5 shadow-2xl animate-pulse">
                       <Sparkles size={12} /> Aura's Choice
                    </span>
                )}
            </div>

            <div className="absolute top-6 right-6 z-30 flex flex-col gap-2">
              <button 
                onClick={toggleWishlist} 
                className={`p-3 rounded-2xl backdrop-blur-2xl border transition-all duration-300 transform active:scale-90 ${isAnimatingWishlist ? 'animate-heart-pop' : ''} ${isInWishlist ? 'bg-aura-purple/30 border-aura-purple text-aura-purple' : 'bg-black/40 border-white/10 text-white hover:bg-black/70'}`}
              >
                <Heart size={20} className={isInWishlist ? 'fill-aura-purple' : ''} />
              </button>
              <button 
                onClick={(e) => { e.preventDefault(); e.stopPropagation(); setIsPresetsModalOpen(true); }} 
                className="p-3 bg-black/40 border border-white/10 text-white rounded-2xl backdrop-blur-2xl hover:bg-aura-purple transition-all transform active:scale-90 shadow-xl"
                title="Aura Refinement"
              >
                <Palette size={20} />
              </button>
            </div>

            <div className="absolute bottom-6 left-6 z-20">
               <Link to={`/try-on/${product.id}`} className="bg-white/10 hover:bg-aura-purple text-white px-5 py-2.5 rounded-2xl text-[10px] font-black uppercase tracking-[0.2em] flex items-center gap-2.5 backdrop-blur-2xl border border-white/10 transition-all hover:scale-105 active:scale-95">
                 <Camera size={16} /> Virtual Try-On
               </Link>
            </div>
          </div>

          {/* Content Section */}
          <div className="p-8 flex flex-col flex-grow bg-gradient-to-b from-transparent to-black/60 relative z-10">
            <div className="mb-6">
              {vendor && (
                <div className="flex items-center gap-2.5 mb-2.5">
                  <div className="w-1.5 h-1.5 rounded-full bg-aura-purple"></div>
                  <span className="text-[10px] text-aura-ash uppercase tracking-[0.3em] font-black">{vendor.name}</span>
                </div>
              )}
              <h3 className="font-serif text-2xl font-bold text-white mb-3 leading-snug group-hover:text-aura-purple transition-colors">{product.name}</h3>
              <p className="text-xs text-gray-500 line-clamp-2 font-medium leading-relaxed mb-4">{product.description}</p>
            </div>

            <div className="mt-auto pt-6 border-t border-white/10 space-y-6">
              <div className="flex justify-between items-end">
                <div>
                  <div className="text-[10px] text-gray-600 font-bold uppercase tracking-widest mb-1">Ecosystem Price</div>
                  <div className="text-3xl font-black text-white tracking-tighter">৳{product.price.toLocaleString()}</div>
                </div>
                <div className="flex items-center gap-2 text-green-500 bg-green-500/10 px-3 py-1.5 rounded-xl border border-green-500/20">
                   <div className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse"></div>
                   <span className="text-[10px] font-black uppercase tracking-widest">In Stock</span>
                </div>
              </div>

              <div className="grid grid-cols-1 gap-4">
                <div className="flex gap-3">
                  <button 
                    onClick={handleAddToCart} 
                    disabled={isAdding} 
                    className={`flex-1 py-4.5 rounded-2xl text-[11px] font-black uppercase tracking-[0.2em] flex items-center justify-center gap-2.5 border backdrop-blur-md transition-all ${isAdded ? 'bg-green-500/20 border-green-500 text-green-400' : 'bg-white/5 border-white/10 text-white hover:bg-white/10'}`}
                  >
                    {isAdding ? <Loader2 size={18} className="animate-spin" /> : isAdded ? <Check size={18} /> : <ShoppingCart size={18} />}
                    <span>{isAdded ? 'Added' : 'কার্টে যোগ'}</span>
                  </button>

                  {/* Refine Style Button */}
                  <button 
                    onClick={(e) => { e.preventDefault(); e.stopPropagation(); setIsPresetsModalOpen(true); }} 
                    className="flex-1 py-4.5 rounded-2xl text-[11px] font-black uppercase tracking-[0.2em] flex items-center justify-center gap-2.5 border border-white/10 bg-white/5 text-white hover:bg-aura-purple hover:border-aura-purple hover:shadow-[0_0_20px_rgba(124,58,237,0.3)] transition-all active:scale-[0.97]"
                  >
                    <Wand2 size={16} />
                    Refine Style
                  </button>
                </div>

                <button 
                  onClick={handleBuyNowClick} 
                  className="w-full bg-aura-purple text-white py-5 rounded-2xl text-[12px] font-black uppercase tracking-[0.3em] flex items-center justify-center gap-3 shadow-xl hover:bg-purple-600 transition-all active:scale-[0.97]"
                >
                   এখনই কিনুন <ArrowRight size={18} />
                </button>
              </div>
            </div>
          </div>
      </div>

      {/* Style Presets Modal */}
      {isPresetsModalOpen && (
        <div className="fixed inset-0 z-[150] flex items-center justify-center p-6 bg-black/90 backdrop-blur-3xl animate-in fade-in duration-500">
          <div className="bg-aura-glass border border-aura-glassBorder w-full max-w-2xl rounded-[3.5rem] p-12 shadow-2xl relative overflow-hidden animate-in zoom-in duration-500">
            <div className="absolute top-0 right-0 w-96 h-96 bg-aura-purple/20 blur-[150px] rounded-full pointer-events-none -translate-y-1/2 translate-x-1/2" />

            <div className="relative z-10">
              <div className="flex justify-between items-start mb-10">
                <div>
                  <h3 className="text-4xl font-serif font-bold text-white mb-2 tracking-tight">Aura Style Refinement</h3>
                  <div className="flex items-center gap-2">
                    <Sparkles className="text-aura-purple" size={16} />
                    <p className="text-[10px] text-gray-400 uppercase tracking-[0.3em] font-black">AI-Powered Visual Re-imagining</p>
                  </div>
                </div>
                <button 
                  onClick={() => setIsPresetsModalOpen(false)} 
                  className="p-3 bg-white/5 rounded-2xl hover:bg-white/10 text-gray-400 transition-all border border-white/5 active:scale-90"
                >
                  <X size={24} />
                </button>
              </div>

              <div className="grid grid-cols-2 md:grid-cols-3 gap-5 mb-10">
                {STYLE_PRESETS.map((style) => (
                  <button 
                    key={style.name}
                    disabled={isRefining}
                    onClick={() => handleApplyStyle(style.prompt)}
                    className={`group relative flex flex-col items-center gap-4 p-8 rounded-3xl border border-white/10 transition-all hover:border-aura-purple shadow-xl bg-gradient-to-br ${style.color} hover:scale-[1.03] active:scale-95 disabled:opacity-50 disabled:grayscale`}
                  >
                    <div className="p-4 bg-white/10 rounded-2xl group-hover:bg-white/20 transition-colors shadow-inner">
                      {style.icon}
                    </div>
                    <div className="text-center">
                      <span className="block text-xs font-black text-white uppercase tracking-[0.15em] mb-1">{style.name}</span>
                      <span className="block text-[8px] font-bold text-gray-400 uppercase tracking-widest leading-none">{style.description}</span>
                    </div>
                  </button>
                ))}

                <button 
                  disabled={isRefining}
                  onClick={handleReset}
                  className="group relative flex flex-col items-center gap-4 p-8 bg-white/5 border border-white/10 rounded-3xl transition-all hover:bg-red-500/20 hover:border-red-500/40 disabled:opacity-50 active:scale-95"
                >
                  <div className="p-4 bg-white/10 rounded-2xl group-hover:bg-white/20 transition-colors text-red-400">
                    <RotateCcw size={20} />
                  </div>
                  <div className="text-center">
                    <span className="block text-xs font-black text-white uppercase tracking-[0.15em] mb-1">Reset</span>
                    <span className="block text-[8px] font-bold text-gray-400 uppercase tracking-widest leading-none">Original Shot</span>
                  </div>
                </button>
              </div>

              {isRefining && (
                <div className="flex flex-col items-center gap-5 py-4 animate-in fade-in slide-in-from-bottom-4">
                   <div className="relative">
                     <Loader2 size={40} className="text-aura-purple animate-spin" />
                     <Sparkles className="absolute inset-0 m-auto text-aura-purple animate-pulse" size={16} />
                   </div>
                   <div className="text-center">
                      <p className="text-[12px] text-white font-black uppercase tracking-[0.4em] mb-1">Aura is dreaming...</p>
                      <p className="text-[9px] text-gray-500 uppercase tracking-widest italic font-bold">Refining textures and atmosphere</p>
                   </div>
                </div>
              )}

              {refineError && (
                <div className="text-[10px] text-red-400 font-bold bg-red-500/10 p-4 rounded-2xl border border-red-500/20 text-center animate-in shake duration-500">
                  {refineError}
                </div>
              )}
            </div>
          </div>
        </div>
      )}

      {/* Buy Now Modal */}
      {isBuyModalOpen && (
        <div className="fixed inset-0 z-[130] flex items-center justify-center p-6 bg-black/90 backdrop-blur-2xl animate-in fade-in duration-500">
          <div className="bg-aura-glass border border-aura-glassBorder w-full max-w-lg rounded-[3rem] p-10 shadow-2xl relative overflow-hidden animate-in zoom-in duration-500">
            <div className="absolute top-0 right-0 w-80 h-80 bg-aura-purple/20 blur-[120px] rounded-full pointer-events-none" />
            <div className="relative z-10">
              <div className="flex justify-between items-start mb-8">
                <div>
                  <h3 className="text-3xl font-serif font-bold text-white mb-2">Aura Checkout</h3>
                  <p className="text-[10px] text-gray-500 uppercase tracking-[0.2em] font-black">Ecosystem Hub Confirmation</p>
                </div>
                <button onClick={() => setIsBuyModalOpen(false)} className="p-3 bg-white/5 rounded-2xl text-gray-400 hover:text-white transition-colors"><X size={24} /></button>
              </div>

              <div className="flex gap-6 p-6 bg-white/[0.03] rounded-3xl border border-white/10 mb-10 shadow-inner group">
                <div className="w-24 h-24 rounded-2xl overflow-hidden border border-white/10 shrink-0">
                    <img src={displayImageUrl} alt={product.name} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500" />
                </div>
                <div className="flex flex-col justify-center">
                  <div className="text-[10px] text-aura-purple font-black uppercase tracking-widest mb-1">{vendor?.name}</div>
                  <h4 className="text-white font-bold text-lg truncate mb-1">{product.name}</h4>
                  <div className="text-xl font-black text-white">৳{product.price.toLocaleString()}</div>
                </div>
              </div>

              <div className="space-y-8 mb-12">
                <div className="flex flex-col items-center gap-4">
                  <div className="text-[10px] text-gray-600 font-black uppercase tracking-[0.2em]">Quantity</div>
                  <div className="flex items-center gap-10">
                    <button onClick={() => setQuantity(Math.max(1, quantity - 1))} className="w-12 h-12 rounded-2xl border border-white/10 bg-white/[0.02] flex items-center justify-center text-white hover:bg-aura-purple transition-all active:scale-90"><Minus size={20} /></button>
                    <span className="text-4xl font-serif font-black text-white">{quantity}</span>
                    <button onClick={() => setQuantity(quantity + 1)} className="w-12 h-12 rounded-2xl border border-white/10 bg-white/[0.02] flex items-center justify-center text-white hover:bg-aura-purple transition-all active:scale-90"><Plus size={20} /></button>
                  </div>
                </div>
                <div className="w-full flex justify-between items-center bg-white/[0.02] p-6 rounded-3xl border border-white/5">
                  <span className="text-[11px] text-gray-500 uppercase tracking-widest font-black">Subtotal</span>
                  <span className="text-3xl font-black text-white">৳{(product.price * quantity).toLocaleString()}</span>
                </div>
              </div>

              <button onClick={() => { handleAddToCart(); window.location.hash = '/cart'; }} className="w-full bg-white text-black py-6 rounded-3xl text-[13px] font-black uppercase tracking-[0.4em] transition-all hover:bg-aura-purple hover:text-white shadow-xl active:scale-95 flex items-center justify-center gap-4 group">
                <CreditCard size={20} className="group-hover:scale-110 transition-transform" /> Confirm & Checkout
              </button>
            </div>
          </div>
        </div>
      )}
    </>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Product, Vendor } from '../types';
import { 
  ExternalLink, ShoppingCart, Camera, Check, Loader2, CreditCard, 
  Sparkles, Heart, Minus, Plus, X, ArrowRight, 
  ShieldCheck, Wand2, RefreshCcw, Palette, Sun, Map, Image as ImageIcon,
  Layers, Zap, Wind, History, RotateCcw, Crown, Palmtree
} from 'lucide-react';
import { Link } from './Navigation';
import { generateAuraImage } from '../services/geminiService';

interface ProductCardProps {
  product: Product;
  vendor?: Vendor;
  isRecommended?: boolean;
}

const FALLBACK_IMAGE = 'https://images.unsplash.com/photo-1515886657613-9f3515b0c78f?auto=format&fit=crop&q=80&w=800';

const STYLE_PRESETS = [
  { 
    name: 'Vintage', 
    prompt: 'Vintage 1970s film aesthetic, warm grainy texture, nostalgic moody lighting, retro color grading', 
    icon: <History size={20} />, 
    color: 'from-amber-500/20 to-orange-900/40',
    description: 'Nostalgic film grain'
  },
  { 
    name: 'Cyberpunk', 
    prompt: 'Cyberpunk neon aesthetic, Dhakai city lights, violet and teal lighting, rainy night street reflections, high contrast', 
    icon: <Zap size={20} />, 
    color: 'from-fuchsia-600/20 to-blue-900/40',
    description: 'Neon night energy'
  },
  { 
    name: 'Minimalist', 
    prompt: 'High-end minimalist editorial, clean architectural concrete background, soft diffuse natural daylight, monochrome palette', 
    icon: <Layers size={20} />, 
    color: 'from-gray-400/20 to-slate-800/40',
    description: 'Clean & architectural'
  },
  { 
    name: 'Bohemian', 
    prompt: 'Bohemian chic, lush sun-drenched meadow, golden hour flare, soft artistic breeze, ethereal atmosphere', 
    icon: <Wind size={20} />, 
    color: 'from-yellow-400/20 to-orange-800/40',
    description: 'Ethereal golden hour'
  },
  { 
    name: 'Royal', 
    prompt: 'Royal palace interior, ornate Dhakai setting, gold accents, dramatic luxury shadows, velvet textures', 
    icon: <Crown size={20} />, 
    color: 'from-yellow-600/20 to-red-900/40',
    description: 'Majestic heritage'
  },
  { 
    name: 'Tropical', 
    prompt: 'Tropical resort paradise, lush green jungle leaves, vibrant exotic sunlight, misty garden atmosphere, high saturation', 
    icon: <Palmtree size={20} />, 
    color: 'from-green-500/20 to-emerald-900/40',
    description: 'Lush exotic vibes'
  }
];

export const ProductCard: React.FC<ProductCardProps> = ({ product, vendor, isRecommended }) => {
  const [isAdding, setIsAdding] = useState(false);
  const [isAdded, setIsAdded] = useState(false);
  const [isInWishlist, setIsInWishlist] = useState(false);
  const [isAnimatingWishlist, setIsAnimatingWishlist] = useState(false);
  const [isBuyModalOpen, setIsBuyModalOpen] = useState(false);
  const [isPresetsModalOpen, setIsPresetsModalOpen] = useState(false);
  const [quantity, setQuantity] = useState(1);

  // Image State
  const isValidUrl = (url: string | undefined) => !!url && url.trim().length > 0;
  const [displayImageUrl, setDisplayImageUrl] = useState(isValidUrl(product.imageUrl) ? product.imageUrl : FALLBACK_IMAGE);
  const [isRefining, setIsRefining] = useState(false);
  const [refineError, setRefineError] = useState<string | null>(null);

  // Parallax effect for the image
  const [parallax, setParallax] = useState({ x: 0, y: 0 });
  const cardRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const wishlist = JSON.parse(localStorage.getItem('aura_wishlist') || '[]');
    setIsInWishlist(wishlist.some((item: any) => item.id === product.id));
  }, [product.id]);

  const trackInteraction = () => {
    const history = JSON.parse(localStorage.getItem('aura_browsing_history') || '[]');
    const filteredHistory = history.filter((h: any) => h.id !== product.id);
    const newHistory = [product, ...filteredHistory].slice(0, 10);
    localStorage.setItem('aura_browsing_history', JSON.stringify(newHistory));
    window.dispatchEvent(new Event('browsingHistoryUpdated'));
  };

  const handleMouseMove = (e: React.MouseEvent<HTMLDivElement>) => {
    if (!cardRef.current) return;
    const rect = cardRef.current.getBoundingClientRect();
    const x = (e.clientX - rect.left) / rect.width;
    const y = (e.clientY - rect.top) / rect.height;
    setParallax({ x: (x - 0.5) * 15, y: (y - 0.5) * 15 });
  };

  const toggleWishlist = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsAnimatingWishlist(true);
    setTimeout(() => setIsAnimatingWishlist(false), 450);

    const wishlist = JSON.parse(localStorage.getItem('aura_wishlist') || '[]');
    let newWishlist;
    if (isInWishlist) {
      newWishlist = wishlist.filter((item: any) => item.id !== product.id);
    } else {
      newWishlist = [...wishlist, product];
      trackInteraction(); 
    }
    localStorage.setItem('aura_wishlist', JSON.stringify(newWishlist));
    setIsInWishlist(!isInWishlist);
    window.dispatchEvent(new Event('wishlistUpdated'));
  };

  const handleAddToCart = (e?: React.MouseEvent) => {
    if (e) { e.preventDefault(); e.stopPropagation(); }
    if (isAdding) return;
    setIsAdding(true);
    trackInteraction(); 
    const cart = JSON.parse(localStorage.getItem('aura_cart') || '[]');
    const existingIndex = cart.findIndex((item: any) => item.id === product.id);
    if (existingIndex > -1) { cart[existingIndex].quantity += quantity; }
    else { cart.push({ ...product, quantity }); }
    localStorage.setItem('aura_cart', JSON.stringify(cart));
    window.dispatchEvent(new Event('cartUpdated'));
    setTimeout(() => { setIsAdding(false); setIsAdded(true); setTimeout(() => setIsAdded(false), 2000); }, 600);
  };

  // Fix: Implemented handleBuyNowClick to open the buy modal when clicking the purchase button
  const handleBuyNowClick = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsBuyModalOpen(true);
  };

  const getBase64FromUrl = async (url: string): Promise<string | null> => {
    if (url.startsWith('data:')) return url;
    try {
        const response = await fetch(url);
        const blob = await response.blob();
        return new Promise((resolve) => {
            const reader = new FileReader();
            reader.onloadend = () => resolve(reader.result as string);
            reader.readAsDataURL(blob);
        });
    } catch (e) { return null; }
  };

  const handleApplyStyle = async (presetPrompt: string) => {
    if (isRefining) return;
    setIsRefining(true);
    setRefineError(null);
    try {
      const base64Ref = await getBase64FromUrl(displayImageUrl);
      const newImage = await generateAuraImage(presetPrompt, base64Ref || undefined);
      if (newImage) {
        setDisplayImageUrl(newImage);
        setIsPresetsModalOpen(false);
      } else {
        setRefineError("Aura was unable to stylize this item. Try a different preset.");
      }
    } catch (err) {
      setRefineError("AI core connection interrupted.");
    } finally {
      setIsRefining(false);
    }
  };

  const handleReset = () => {
    setDisplayImageUrl(product.imageUrl || FALLBACK_IMAGE);
    setIsPresetsModalOpen(false);
  };

  return (
    <>
      <div 
        ref={cardRef}
        onMouseEnter={trackInteraction}
        onMouseMove={handleMouseMove}
        onMouseLeave={() => setParallax({ x: 0, y: 0 })}
        className={`group relative bg-aura-glass border rounded-[2.5rem] overflow-hidden transition-all duration-500 hover:shadow-[0_25px_60px_rgba(124,58,237,0.2)] flex flex-col h-full ${
          isRecommended ? 'border-aura-purple/50 ring-1 ring-aura-purple/20' : 'border-aura-glassBorder hover:border-aura-purple/60'
        }`}
      >
          {/* Image Section */}
          <div className="relative h-80 overflow-hidden cursor-pointer" onClick={() => setIsPresetsModalOpen(true)}>
            <img 
              src={displayImageUrl} 
              alt={product.name} 
              style={{ transform: `translate(${parallax.x}px, ${parallax.y}px) scale(1.15)`, transition: 'transform 0.2s ease-out' }}
              className={`w-full h-full object-cover transform ${isRefining ? 'animate-pulse opacity-50 blur-sm' : ''}`}
            />
            <div className="absolute inset-0 bg-gradient-to-t from-black via-black/30 to-transparent opacity-90" />

            <div className="absolute top-6 left-6 flex flex-col gap-2 z-20">
                <span className="bg-aura-purple/30 backdrop-blur-xl border border-aura-purple/40 px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-[0.15em] text-white">
                    {product.category}
                </span>
                {isRecommended && (
                    <span className="bg-aura-purple text-white px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-[0.15em] flex items-center gap-1.5 shadow-2xl animate-pulse">
                       <Sparkles size={12} /> Aura's Choice
                    </span>
                )}
            </div>

            <div className="absolute top-6 right-6 z-30 flex flex-col gap-2">
              <button 
                onClick={toggleWishlist} 
                className={`p-3 rounded-2xl backdrop-blur-2xl border transition-all duration-300 transform active:scale-90 ${isAnimatingWishlist ? 'animate-heart-pop' : ''} ${isInWishlist ? 'bg-aura-purple/30 border-aura-purple text-aura-purple' : 'bg-black/40 border-white/10 text-white hover:bg-black/70'}`}
              >
                <Heart size={20} className={isInWishlist ? 'fill-aura-purple' : ''} />
              </button>
              <button 
                onClick={(e) => { e.preventDefault(); e.stopPropagation(); setIsPresetsModalOpen(true); }} 
                className="p-3 bg-black/40 border border-white/10 text-white rounded-2xl backdrop-blur-2xl hover:bg-aura-purple transition-all transform active:scale-90 shadow-xl"
                title="Aura Refinement"
              >
                <Palette size={20} />
              </button>
            </div>

            <div className="absolute bottom-6 left-6 z-20">
               <Link to={`/try-on/${product.id}`} className="bg-white/10 hover:bg-aura-purple text-white px-5 py-2.5 rounded-2xl text-[10px] font-black uppercase tracking-[0.2em] flex items-center gap-2.5 backdrop-blur-2xl border border-white/10 transition-all hover:scale-105 active:scale-95">
                 <Camera size={16} /> Virtual Try-On
               </Link>
            </div>
          </div>

          {/* Content Section */}
          <div className="p-8 flex flex-col flex-grow bg-gradient-to-b from-transparent to-black/60 relative z-10">
            <div className="mb-6">
              {vendor && (
                <div className="flex items-center gap-2.5 mb-2.5">
                  <div className="w-1.5 h-1.5 rounded-full bg-aura-purple"></div>
                  <span className="text-[10px] text-aura-ash uppercase tracking-[0.3em] font-black">{vendor.name}</span>
                </div>
              )}
              <h3 className="font-serif text-2xl font-bold text-white mb-3 leading-snug group-hover:text-aura-purple transition-colors">{product.name}</h3>
              <p className="text-xs text-gray-500 line-clamp-2 font-medium leading-relaxed mb-4">{product.description}</p>
            </div>

            <div className="mt-auto pt-6 border-t border-white/10 space-y-6">
              <div className="flex justify-between items-end">
                <div>
                  <div className="text-[10px] text-gray-600 font-bold uppercase tracking-widest mb-1">Ecosystem Price</div>
                  <div className="text-3xl font-black text-white tracking-tighter">৳{product.price.toLocaleString()}</div>
                </div>
                <div className="flex items-center gap-2 text-green-500 bg-green-500/10 px-3 py-1.5 rounded-xl border border-green-500/20">
                   <div className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse"></div>
                   <span className="text-[10px] font-black uppercase tracking-widest">In Stock</span>
                </div>
              </div>

              <div className="grid grid-cols-1 gap-4">
                <div className="flex gap-3">
                  <button 
                    onClick={handleAddToCart} 
                    disabled={isAdding} 
                    className={`flex-1 py-4.5 rounded-2xl text-[11px] font-black uppercase tracking-[0.2em] flex items-center justify-center gap-2.5 border backdrop-blur-md transition-all ${isAdded ? 'bg-green-500/20 border-green-500 text-green-400' : 'bg-white/5 border-white/10 text-white hover:bg-white/10'}`}
                  >
                    {isAdding ? <Loader2 size={18} className="animate-spin" /> : isAdded ? <Check size={18} /> : <ShoppingCart size={18} />}
                    <span>{isAdded ? 'Added' : 'কার্টে যোগ'}</span>
                  </button>

                  {/* Refine Style Button */}
                  <button 
                    onClick={(e) => { e.preventDefault(); e.stopPropagation(); setIsPresetsModalOpen(true); }} 
                    className="flex-1 py-4.5 rounded-2xl text-[11px] font-black uppercase tracking-[0.2em] flex items-center justify-center gap-2.5 border border-white/10 bg-white/5 text-white hover:bg-aura-purple hover:border-aura-purple hover:shadow-[0_0_20px_rgba(124,58,237,0.3)] transition-all active:scale-[0.97]"
                  >
                    <Wand2 size={16} />
                    Refine Style
                  </button>
                </div>

                <button 
                  onClick={handleBuyNowClick} 
                  className="w-full bg-aura-purple text-white py-5 rounded-2xl text-[12px] font-black uppercase tracking-[0.3em] flex items-center justify-center gap-3 shadow-xl hover:bg-purple-600 transition-all active:scale-[0.97]"
                >
                   এখনই কিনুন <ArrowRight size={18} />
                </button>
              </div>
            </div>
          </div>
      </div>

      {/* Style Presets Modal */}
      {isPresetsModalOpen && (
        <div className="fixed inset-0 z-[150] flex items-center justify-center p-6 bg-black/90 backdrop-blur-3xl animate-in fade-in duration-500">
          <div className="bg-aura-glass border border-aura-glassBorder w-full max-w-2xl rounded-[3.5rem] p-12 shadow-2xl relative overflow-hidden animate-in zoom-in duration-500">
            <div className="absolute top-0 right-0 w-96 h-96 bg-aura-purple/20 blur-[150px] rounded-full pointer-events-none -translate-y-1/2 translate-x-1/2" />

            <div className="relative z-10">
              <div className="flex justify-between items-start mb-10">
                <div>
                  <h3 className="text-4xl font-serif font-bold text-white mb-2 tracking-tight">Aura Style Refinement</h3>
                  <div className="flex items-center gap-2">
                    <Sparkles className="text-aura-purple" size={16} />
                    <p className="text-[10px] text-gray-400 uppercase tracking-[0.3em] font-black">AI-Powered Visual Re-imagining</p>
                  </div>
                </div>
                <button 
                  onClick={() => setIsPresetsModalOpen(false)} 
                  className="p-3 bg-white/5 rounded-2xl hover:bg-white/10 text-gray-400 transition-all border border-white/5 active:scale-90"
                >
                  <X size={24} />
                </button>
              </div>

              <div className="grid grid-cols-2 md:grid-cols-3 gap-5 mb-10">
                {STYLE_PRESETS.map((style) => (
                  <button 
                    key={style.name}
                    disabled={isRefining}
                    onClick={() => handleApplyStyle(style.prompt)}
                    className={`group relative flex flex-col items-center gap-4 p-8 rounded-3xl border border-white/10 transition-all hover:border-aura-purple shadow-xl bg-gradient-to-br ${style.color} hover:scale-[1.03] active:scale-95 disabled:opacity-50 disabled:grayscale`}
                  >
                    <div className="p-4 bg-white/10 rounded-2xl group-hover:bg-white/20 transition-colors shadow-inner">
                      {style.icon}
                    </div>
                    <div className="text-center">
                      <span className="block text-xs font-black text-white uppercase tracking-[0.15em] mb-1">{style.name}</span>
                      <span className="block text-[8px] font-bold text-gray-400 uppercase tracking-widest leading-none">{style.description}</span>
                    </div>
                  </button>
                ))}

                <button 
                  disabled={isRefining}
                  onClick={handleReset}
                  className="group relative flex flex-col items-center gap-4 p-8 bg-white/5 border border-white/10 rounded-3xl transition-all hover:bg-red-500/20 hover:border-red-500/40 disabled:opacity-50 active:scale-95"
                >
                  <div className="p-4 bg-white/10 rounded-2xl group-hover:bg-white/20 transition-colors text-red-400">
                    <RotateCcw size={20} />
                  </div>
                  <div className="text-center">
                    <span className="block text-xs font-black text-white uppercase tracking-[0.15em] mb-1">Reset</span>
                    <span className="block text-[8px] font-bold text-gray-400 uppercase tracking-widest leading-none">Original Shot</span>
                  </div>
                </button>
              </div>

              {isRefining && (
                <div className="flex flex-col items-center gap-5 py-4 animate-in fade-in slide-in-from-bottom-4">
                   <div className="relative">
                     <Loader2 size={40} className="text-aura-purple animate-spin" />
                     <Sparkles className="absolute inset-0 m-auto text-aura-purple animate-pulse" size={16} />
                   </div>
                   <div className="text-center">
