                <button onClick={handleBuyNowClick} className="w-full bg-aura-purple text-white py-5 rounded-2xl text-[12px] font-black uppercase tracking-[0.3em] flex items-center justify-center gap-3 shadow-xl hover:bg-purple-600 transition-all active:scale-97">
