            <div className="relative z-10">
              <div className="flex justify-between items-start mb-10">
                <div>
                  <h3 className="text-3xl font-serif font-bold text-white mb-2 tracking-tight">Aura Style Presets</h3>
                  <div className="flex items-center gap-2">
                    <Sparkles className="text-aura-purple" size={14} />
                    <p className="text-[10px] text-gray-400 uppercase tracking-[0.25em] font-black">AI Image Re-imagination</p>
                  </div>
                </div>
                <button onClick={() => setIsPresetsModalOpen(false)} className="p-3 bg-white/5 rounded-2xl hover:bg-white/10 text-gray-400 transition-all border border-white/5">
                  <X size={24} />
                </button>
              </div>

              <div className="grid grid-cols-2 md:grid-cols-3 gap-5 mb-10">
                {STYLE_PRESETS.map((style) => (
                  <button 
                    key={style.name}
                    disabled={isRefining}
                    onClick={() => handleApplyPresetImmediate(style.prompt)}
                    className={`group relative flex flex-col items-center gap-4 p-8 rounded-3xl border border-white/10 transition-all hover:border-aura-purple shadow-xl bg-gradient-to-br ${style.color} hover:scale-[1.03] active:scale-95 disabled:opacity-50 disabled:grayscale`}
                  >
                    <div className="p-4 bg-white/10 rounded-2xl group-hover:bg-white/20 transition-colors shadow-inner">
                      {style.icon}
                    </div>
                    <span className="text-xs font-black text-white uppercase tracking-[0.15em]">{style.name}</span>
                  </button>
                ))}

                <button 
                  disabled={isRefining}
                  onClick={handleReset}
                  className="group relative flex flex-col items-center gap-4 p-8 bg-white/5 border border-white/10 rounded-3xl transition-all hover:bg-red-500/20 hover:border-red-500/40 disabled:opacity-50 active:scale-95"
                >
                  <div className="p-4 bg-white/10 rounded-2xl group-hover:bg-white/20 transition-colors text-red-400">
                    <RotateCcw size={18} />
                  </div>
                  <span className="text-xs font-black text-white uppercase tracking-[0.15em]">Original</span>
                </button>
              </div>

              {isRefining && (
                <div className="flex flex-col items-center gap-4 animate-in fade-in slide-in-from-bottom-2">
                   <div className="relative">
                      <Loader2 size={32} className="text-aura-purple animate-spin" />
                      <Sparkles className="absolute inset-0 m-auto text-aura-purple opacity-50" size={12} />
                   </div>
                   <div className="text-center">
                      <p className="text-[10px] text-white font-black uppercase tracking-[0.3em] mb-1">Aura is Dreaming...</p>
                      <p className="text-[8px] text-gray-500 uppercase tracking-widest italic">Applying neural textures</p>
                   </div>
                </div>
              )}

              {refineError && (
                <p className="text-[10px] text-red-400 font-bold bg-red-500/10 p-4 rounded-2xl border border-red-500/20 text-center">
                  {refineError}
                </p>
              )}
            </div>
          </div>
        </div>
      )}

      {/* Unified Creative Studio Modal (Full Customization) */}
      {isCreativeModalOpen && (
        <div className="fixed inset-0 z-[140] flex items-center justify-center p-6 bg-black/95 backdrop-blur-3xl animate-in fade-in duration-500">
          <div className="bg-aura-glass border border-aura-glassBorder w-full max-w-4xl rounded-[3rem] p-10 shadow-2xl relative overflow-hidden animate-in zoom-in duration-500">
            <div className="absolute top-0 right-0 w-96 h-96 bg-aura-purple/20 blur-[150px] rounded-full pointer-events-none -translate-y-1/2 translate-x-1/2" />

            <div className="relative z-10 flex flex-col lg:flex-row gap-10">
              {/* Preview Side */}
              <div className="lg:w-1/2 space-y-6">
                <div className="flex justify-between items-center mb-4">
                  <div>
                    <h3 className="text-3xl font-serif font-bold text-white mb-2 tracking-tight">Creative Hub</h3>
                    <div className="flex items-center gap-2">
                      <Sparkles className="text-aura-purple" size={14} />
                      <p className="text-[10px] text-gray-400 uppercase tracking-[0.25em] font-black">Neural Core Customization</p>
                    </div>
                  </div>
                  <button onClick={() => setIsCreativeModalOpen(false)} className="lg:hidden p-3 bg-white/5 rounded-2xl text-gray-400">
                    <X size={20} />
                  </button>
                </div>

                <div className="relative aspect-square rounded-[2rem] overflow-hidden border border-white/10 bg-black/40 shadow-2xl">
                  {isRefining && (
                    <div className="absolute inset-0 z-20 bg-black/60 backdrop-blur-md flex flex-col items-center justify-center gap-4">
                       <Loader2 size={40} className="text-aura-purple animate-spin" />
                       <div className="text-center">
                          <p className="text-[10px] text-white font-black uppercase tracking-[0.3em] mb-1">Aura is dreaming...</p>
                          <p className="text-[8px] text-gray-500 uppercase tracking-widest italic">Crystallizing visual textures</p>
                       </div>
                    </div>
                  )}
                  <img 
                    src={displayImageUrl} 
                    alt={product.name} 
                    onError={handleImageError}
                    className="w-full h-full object-cover" 
                  />
                </div>

                <div className="flex items-center justify-between p-4 bg-white/5 rounded-2xl border border-white/5">
                   <div className="flex items-center gap-3">
                      <ImageIcon size={18} className="text-aura-purple" />
                      <div>
                        <p className="text-[9px] text-gray-500 font-bold uppercase tracking-widest">Active State</p>
                        <p className="text-xs text-white font-bold">{product.name}</p>
                      </div>
                   </div>
                   <button onClick={handleReset} className="p-2 text-gray-500 hover:text-red-400 transition-colors flex items-center gap-2 text-[10px] font-bold uppercase tracking-widest">
                     <RotateCcw size={14} /> Reset Original
