// --- AI RECOMMENDATIONS WITH FALLBACK ---
export const getAIRecommendations = async (historyProducts: Product[]): Promise<number[]> => {
    // Fallback logic in case of API failure (e.g., 429 Quota Exhausted)
    const getFallbackRecs = () => {
        const catalog = getProducts();
        const historyIds = new Set(historyProducts.map(p => p.id));
        const historyCats = new Set(historyProducts.map(p => p.category));

        // Try to find products in the same category not in history
        let matching = catalog.filter(p => !historyIds.has(p.id) && historyCats.has(p.category));
        if (matching.length < 3) {
            // Fill with other products if not enough category matches
            matching = [...matching, ...catalog.filter(p => !historyIds.has(p.id) && !historyCats.has(p.category))];
        }
        return matching.slice(0, 3).map(p => p.id);
    };

    if (!process.env.API_KEY) return getFallbackRecs();

    const catalog = getProducts();
    const historySummary = historyProducts.map(p => `${p.name} (${p.category}, ৳${p.price})`).join(', ');
    const catalogSummary = catalog.map(p => `ID: ${p.id}, Name: ${p.name}, Cat: ${p.category}, Price: ${p.price}`).join(' | ');

    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const prompt = `
            User Browsing History: [${historySummary}]
            Product Catalog: [${catalogSummary}]

            Analyze the user's taste based on their history (styles, price points, categories). 
            From the catalog, select exactly 3 product IDs that the user is MOST likely to be interested in. 
            Do not recommend products already in their history unless there are no other options.

            Return JSON ONLY: { "recommendedIds": number[] }
        `;

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: { responseMimeType: 'application/json' }
        });

        const result = JSON.parse(response.text || '{ "recommendedIds": [] }');
        return result.recommendedIds && result.recommendedIds.length > 0 ? result.recommendedIds : getFallbackRecs();
    } catch (error: any) {
        console.warn("AI Recommendation Quota/Error. Using local heuristic fallback.", error?.message);
        return getFallbackRecs();
    }
};

// --- IMAGE GENERATION / EDITING ---
export const generateAuraImage = async (prompt: string, referenceImageBase64?: string): Promise<string | null> => {
    if (!process.env.API_KEY) return null;

    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const parts: any[] = [{ text: `A photorealistic high-fashion editorial shot. ${prompt}. High resolution, luxury fabric texture, professional studio lighting.` }];

        if (referenceImageBase64) {
            const cleanBase64 = referenceImageBase64.replace(/^data:image\/(png|jpeg|jpg);base64,/, "");
            parts.unshift({
                inlineData: {
                    data: cleanBase64,
                    mimeType: 'image/png'
                }
            });
            parts[parts.length-1].text = `Re-imagine the garment in this image using the following style: ${prompt}. Keep the core shape of the garment consistent but transform the environment, lighting, and textures.`;
        }

        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash-image',
            contents: { parts },
            config: {
                imageConfig: {
                    aspectRatio: "1:1"
                }
            }
        });

        for (const part of response.candidates[0].content.parts) {
            if (part.inlineData) {
                return `data:image/png;base64,${part.inlineData.data}`;
            }
        }
        return null;
    } catch (error: any) {
        console.error("Image Gen Error:", error?.message);
        return null;
    }
};

// --- SEARCH INTENT ANALYSIS ---
export interface SearchIntent {
    category: string | null;
    maxPrice: number | null;
    minPrice: number | null;
    color: string | null;
    material: string | null;
    style: string | null;
    keyPhrases: string[]; 
    semanticKeywords: string[];
    isSearchQuery: boolean;
    shouldGenerateImage: boolean;
    imagePrompt: string | null;
}

export const analyzeSearchIntent = async (userPrompt: string): Promise<SearchIntent | null> => {
    const defaultIntent: SearchIntent = {
        category: null, maxPrice: null, minPrice: null, color: null, material: null, style: null,
        keyPhrases: [], semanticKeywords: [], isSearchQuery: true, shouldGenerateImage: false, imagePrompt: null
    };

    if (!process.env.API_KEY) return defaultIntent;

    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const prompt = `
        Analyze this fashion query: "${userPrompt}"
        Extract category, price, color, material, style.
        Return JSON.
        `;

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: { responseMimeType: 'application/json' }
        });

        return JSON.parse(response.text || JSON.stringify(defaultIntent));
    } catch (error: any) {
        console.warn("Intent Analysis Error/Quota. Falling back to basic search.", error?.message);
        return defaultIntent;
    }
};

// --- TRY-ON ---
export const generateTryOnTransformation = async (userImageBase64: string, productImageBase64: string): Promise<string | null> => {
    if (!process.env.API_KEY) return null;
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const cleanUserImage = userImageBase64.replace(/^data:image\/(png|jpeg|jpg);base64,/, "");
      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: {
          parts: [
            { inlineData: { data: cleanUserImage, mimeType: 'image/jpeg' } },
            { text: "Drape the clothing item conceptually onto the person. Maintain realistic lighting." },
          ],
        },
      });
      for (const part of response.candidates[0].content.parts) {
          if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
      }
      return null; 
    } catch (error: any) {
      console.error("Try-On Error:", error?.message);
      return null;
    }
};

// --- VENDOR AUDIT ---
export const auditVendorDescription = async (shopName: string, description: string, tradeLicense: string): Promise<{ status: 'APPROVED' | 'REJECTED' | 'PENDING'; reason: string }> => {
    if (!process.env.API_KEY) return { status: 'APPROVED', reason: 'Dev Mode' };
    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: `Shop Name: ${shopName}\nTrade License: ${tradeLicense}\nDescription: ${description}`,
            config: { 
                systemInstruction: `Audit for authenticity. Respond in JSON.`,
                responseMimeType: 'application/json' 
            }
        });
        const result = JSON.parse(response.text || '{}');
        return {
            status: result.status || 'PENDING',
            reason: result.reason || 'আবেদনটি রিভিউ করা হচ্ছে।'
        };
    } catch (error: any) {
        console.error("Audit Error:", error?.message);
        return { status: 'PENDING', reason: 'Audit system is currently offline due to high traffic. Your application will be reviewed manually.' };
    }
};

