                                        <div className="absolute inset-0 bg-black/20"></div>
                                    </div>
                                    <div className="p-3">
                                        <div className="text-[10px] text-white font-bold truncate mb-1">{p.name}</div>
                                        <div className="flex justify-between items-center">
                                            <span className="text-[9px] text-aura-purple font-black">৳{p.price.toLocaleString()}</span>
                                        </div>
                                    </div>
                                </div>
                            ))}
                        </div>
                    )}
                  </div>
                </div>
              ))}
            </div>

            <form onSubmit={handleSendMessage} className="p-6 bg-white/5 border-t border-white/10">
              <div className="flex gap-3">
                <input 
                    value={input}
                    onChange={(e) => setInput(e.target.value)}
                    placeholder="Ask Aura anything..."
                    className="flex-1 bg-black/50 border border-white/10 rounded-2xl px-6 py-4 focus:outline-none focus:border-aura-purple text-sm text-white"
                />
                <button type="submit" disabled={!input.trim() || isTyping} className="bg-aura-purple text-white px-6 rounded-2xl hover:bg-purple-600 transition-all active:scale-95 disabled:opacity-50">
                    <Send size={20} />
                </button>
              </div>
            </form>
          </div>
        </div>
      </section>

      {/* AI Search & Smart Filters Section */}
      <section className="relative z-20 -mt-10 px-6 max-w-5xl mx-auto space-y-4">
        <form onSubmit={handleAISearch} className="group relative">
           <div className="absolute -inset-1 bg-gradient-to-r from-aura-purple via-indigo-500 to-aura-purple rounded-[2.5rem] blur opacity-25 group-focus-within:opacity-100 transition duration-1000"></div>
           <div className="relative flex items-center bg-black/80 backdrop-blur-3xl border border-white/10 rounded-[2.2rem] overflow-hidden shadow-2xl p-1.5">
              <div className="pl-6 pr-4">
                 <Search className="text-aura-purple" size={24} />
              </div>
              <input 
                 type="text" 
                 value={searchInput}
                 onChange={(e) => setSearchInput(e.target.value)}
                 placeholder="Discovery: red saree under 20k..."
                 className="flex-1 bg-transparent border-none text-white py-4 md:py-6 text-base md:text-lg focus:outline-none placeholder-gray-600 font-medium"
              />
              <button 
                type="button" 
                onClick={() => setShowFilters(!showFilters)} 
                className={`p-4 md:p-5 rounded-full transition-all flex items-center justify-center ${showFilters ? 'bg-aura-purple text-white' : 'text-gray-500 hover:text-aura-purple'}`}
              >
                <SlidersHorizontal size={20} />
              </button>
              <button type="submit" className="bg-aura-purple text-white px-8 md:px-12 py-4 md:py-5 rounded-[1.8rem] font-black uppercase tracking-[0.2em] text-xs transition-all hover:bg-purple-600 ml-2">
                 {isSearching ? <Loader2 size={16} className="animate-spin" /> : <Sparkle size={16} />}
              </button>
           </div>
        </form>

        {/* Explicit Filter Panel */}
        {showFilters && (
          <div className="bg-aura-glass backdrop-blur-3xl border border-aura-glassBorder rounded-[2rem] p-8 animate-in slide-in-from-top-4 duration-500 shadow-2xl grid grid-cols-1 md:grid-cols-3 gap-8">
            <div className="space-y-4">
              <label className="text-[10px] text-gray-500 font-black uppercase tracking-widest flex items-center gap-2">
                <Layers size={14} className="text-aura-purple" /> Category
              </label>
              <div className="flex flex-wrap gap-2">
                {categories.map(cat => (
                  <button 
                    key={cat} 
                    onClick={() => setSelectedCategory(cat)}
                    className={`px-4 py-2 rounded-xl text-[10px] font-bold uppercase tracking-widest transition-all border ${selectedCategory === cat ? 'bg-aura-purple border-aura-purple text-white' : 'bg-white/5 border-white/10 text-gray-400 hover:border-white/20'}`}
                  >
                    {cat}
                  </button>
                ))}
              </div>
            </div>

            <div className="space-y-4">
              <label className="text-[10px] text-gray-500 font-black uppercase tracking-widest flex items-center gap-2">
                <Building2 size={14} className="text-aura-purple" /> Vendor
              </label>
              <select 
                value={selectedVendorId || ''} 
                onChange={(e) => setSelectedVendorId(e.target.value ? Number(e.target.value) : null)}
                className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-xs text-white focus:outline-none focus:border-aura-purple appearance-none"
              >
                <option value="">All Ecosystem Vendors</option>
                {vendors.filter(v => v.status === 'APPROVED').map(v => (
                  <option key={v.id} value={v.id}>{v.name}</option>
                ))}
              </select>
            </div>

            <div className="space-y-4">
              <label className="text-[10px] text-gray-500 font-black uppercase tracking-widest flex items-center gap-2">
                <Zap size={14} className="text-aura-purple" /> Price Max: ৳{priceRange.max.toLocaleString()}
              </label>
              <input 
                type="range" 
                min="0" 
                max="50000" 
                step="500"
                value={priceRange.max} 
                onChange={(e) => setPriceRange({ ...priceRange, max: Number(e.target.value) })}
                className="w-full accent-aura-purple"
              />
              <div className="flex justify-between text-[8px] font-black uppercase tracking-widest text-gray-600">
                <span>৳0</span>
                <span>৳50,000+</span>
              </div>
            </div>
          </div>
        )}

        {/* AI Active Intent Tags */}
        {activeIntent && (
          <div className="flex flex-wrap items-center gap-3 px-4 animate-in fade-in duration-700">
            <span className="text-[10px] text-gray-600 font-black uppercase tracking-widest">Aura Understood:</span>
            {activeIntent.category && (
              <IntentTag label={`Cat: ${activeIntent.category}`} onClear={() => setActiveIntent({ ...activeIntent, category: null })} />
            )}
            {activeIntent.maxPrice && (
              <IntentTag label={`Under ৳${activeIntent.maxPrice.toLocaleString()}`} onClear={() => setActiveIntent({ ...activeIntent, maxPrice: null })} />
            )}
            {activeIntent.semanticKeywords?.map(kw => (
              <IntentTag key={kw} label={kw} onClear={() => setActiveIntent({ ...activeIntent, semanticKeywords: activeIntent.semanticKeywords.filter(k => k !== kw) })} />
            )}
            <button 
              onClick={() => { setActiveIntent(null); setSearchInput(''); }}
              className="text-[10px] text-red-400 hover:text-red-300 font-black uppercase tracking-widest flex items-center gap-1 transition-colors"
            >
              <X size={12} /> Clear AI Context
            </button>
          </div>
        )}
      </section>

      {/* Recommended Products */}
      {recommendations.length > 0 && (
        <section className="max-w-7xl mx-auto px-6 pt-24">
            <div className="flex items-center gap-3 mb-8">
                <UserCheck className="text-aura-purple" size={28} />
                <h2 className="text-2xl font-serif font-bold text-white">Recommended for You</h2>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                {recommendations.map(p => (
                    <ProductCard key={p.id} product={p} vendor={vendors.find(v => v.id === p.vendorId)} isRecommended={true} />
                ))}
            </div>
        </section>
      )}

      {/* Main Content Area */}
      <div id="product-section" className="max-w-7xl mx-auto px-6 py-20">
        <div className="flex flex-col lg:flex-row gap-12">

          {/* Sidebar Filters */}
          <aside className="lg:w-64 shrink-0 hidden lg:block">
            <div className="space-y-8 sticky top-24">
                <div className="space-y-4">
                    <h3 className="text-[10px] uppercase tracking-widest font-bold text-aura-purple flex items-center gap-2"><Building2 size={14} /> Ecosystem Map</h3>
                    <div className="flex flex-col gap-1">
                        <FilterOption label="All Hub" active={!selectedVendorId} onClick={() => setSelectedVendorId(null)} />
                        {vendors.filter(v => v.status === 'APPROVED').map(vendor => (
                            <FilterOption key={vendor.id} label={vendor.name} active={selectedVendorId === vendor.id} onClick={() => setSelectedVendorId(vendor.id)} />
                        ))}
                    </div>
                </div>
            </div>
          </aside>

          {/* Product Grid Area */}
          <main className="flex-1">
            <div className="flex flex-col md:flex-row md:items-center justify-between mb-10 gap-4">
                <div className="flex flex-col">
                  <h2 className="text-2xl font-serif font-bold flex items-center gap-4">
                      <Sparkles className="text-aura-purple" />
                      ট্রেন্ডিং কালেকশন
                  </h2>
                  <p className="text-[10px] text-gray-500 uppercase tracking-widest font-bold mt-1">Showing {filteredProducts.length} items from ecosystem</p>
                </div>
                <div className="relative">
                  <button onClick={() => setShowSortDropdown(!showSortDropdown)} className="flex items-center gap-2 px-6 py-2.5 bg-white/5 border border-white/10 rounded-full text-[10px] font-bold uppercase tracking-widest text-white transition-all hover:border-aura-purple/50">
                    <ListFilter size={14} className="text-aura-purple" />
                    <span>Sort By</span>
                    <ChevronDown size={14} />
                  </button>
                  {showSortDropdown && (
                    <div className="absolute right-0 mt-2 w-56 bg-black/90 backdrop-blur-3xl border border-white/10 rounded-2xl p-2 shadow-2xl z-50">
                       <SortItem active={sortOption === 'NEWEST'} label="Newest Arrivals" onClick={() => { setSortOption('NEWEST'); setShowSortDropdown(false); }} />
                       <SortItem active={sortOption === 'PRICE_LOW'} label="Price: Low to High" onClick={() => { setSortOption('PRICE_LOW'); setShowSortDropdown(false); }} />
                       <SortItem active={sortOption === 'PRICE_HIGH'} label="Price: High to Low" onClick={() => { setSortOption('PRICE_HIGH'); setShowSortDropdown(false); }} />
                    </div>
                  )}
                </div>
            </div>

            {filteredProducts.length === 0 ? (
              <div className="py-20 text-center bg-white/[0.02] border border-dashed border-white/10 rounded-[3rem] animate-in fade-in">
                <Info className="mx-auto text-gray-700 mb-6" size={48} />
                <h3 className="text-xl font-bold text-gray-400 mb-2">No items found matching these filters</h3>
                <p className="text-xs text-gray-600 uppercase tracking-widest">Try adjusting your search or clearing AI context</p>
                <button 
                  onClick={() => { setActiveIntent(null); setSelectedCategory('All'); setSelectedVendorId(null); setPriceRange({min:0, max:100000}); }}
                  className="mt-8 text-aura-purple hover:underline text-[10px] font-black uppercase tracking-[0.2em]"
                >
                  Reset All Filters
                </button>
              </div>
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-8">
                  {filteredProducts.map(p => (
                      <ProductCard key={p.id} product={p} vendor={vendors.find(v => v.id === p.vendorId)} />
                  ))}
              </div>
            )}
          </main>
        </div>
      </div>
    </div>
  );
};

const IntentTag: React.FC<{ label: string; onClear: () => void }> = ({ label, onClear }) => (
  <div className="flex items-center gap-2 bg-aura-purple/10 border border-aura-purple/20 px-3 py-1.5 rounded-full text-[9px] font-black uppercase tracking-widest text-aura-purple">
    <span>{label}</span>
    <button onClick={onClear} className="hover:text-white transition-colors"><X size={10} /></button>
  </div>
);

const FilterOption: React.FC<{ label: string; active: boolean; onClick: () => void }> = ({ label, active, onClick }) => (
    <button onClick={onClick} className={`w-full text-left px-4 py-2 rounded-xl text-xs font-medium transition-all ${active ? 'bg-aura-purple text-white shadow-lg shadow-purple-900/20' : 'text-gray-400 hover:bg-white/5 hover:text-white'}`}>{label}</button>
);

const SortItem: React.FC<{ active: boolean; label: string; onClick: () => void }> = ({ active, label, onClick }) => (
  <button onClick={onClick} className={`w-full text-left px-4 py-2.5 rounded-xl text-[10px] font-bold uppercase tracking-widest transition-all ${active ? 'bg-aura-purple text-white' : 'text-gray-400 hover:bg-white/5'}`}>{label}</button>
);

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Product, Vendor } from '../types';
import { 
  ExternalLink, ShoppingCart, Camera, Check, Loader2, CreditCard, 
  Sparkles, Heart, Minus, Plus, X, ArrowRight, 
  ShieldCheck, Wand2, RefreshCcw, Palette, Sun, Map, Image as ImageIcon,
  Layers, Zap, Wind, History, RotateCcw, Crown, Palmtree, Edit3
} from 'lucide-react';
import { Link } from './Navigation';
import { generateAuraImage } from '../services/geminiService';

interface ProductCardProps {
  product: Product;
  vendor?: Vendor;
  isRecommended?: boolean;
}

const FALLBACK_IMAGE = 'https://images.unsplash.com/photo-1515886657613-9f3515b0c78f?auto=format&fit=crop&q=80&w=800';

const STYLE_PRESETS = [
  { name: 'Vintage', prompt: 'Vintage 1970s film aesthetic, warm grainy texture, nostalgic moody lighting', icon: <History size={18} />, color: 'from-amber-500/20 to-orange-900/40' },
  { name: 'Cyberpunk', prompt: 'Cyberpunk neon aesthetic, Dhakai city lights, violet and teal lighting, rainy night street reflections', icon: <Zap size={18} />, color: 'from-fuchsia-600/20 to-blue-900/40' },
  { name: 'Minimalist', prompt: 'High-end minimalist editorial, clean architectural concrete background, soft diffuse natural daylight', icon: <Layers size={18} />, color: 'from-gray-400/20 to-slate-800/40' },
  { name: 'Bohemian', prompt: 'Bohemian chic, lush sun-drenched meadow, golden hour flare, soft artistic breeze', icon: <Wind size={18} />, color: 'from-yellow-400/20 to-orange-800/40' },
  { name: 'Royal', prompt: 'Royal palace interior, ornate Dhakai Muslin setting, gold accents, dramatic luxury shadows', icon: <Crown size={18} />, color: 'from-yellow-600/20 to-red-900/40' },
  { name: 'Tropical', prompt: 'Tropical resort paradise, lush green jungle leaves, vibrant exotic sunlight, misty garden atmosphere', icon: <Palmtree size={18} />, color: 'from-green-500/20 to-emerald-900/40' }
];

export const ProductCard: React.FC<ProductCardProps> = ({ product, vendor, isRecommended }) => {
  const [isAdding, setIsAdding] = useState(false);
  const [isAdded, setIsAdded] = useState(false);
  const [isInWishlist, setIsInWishlist] = useState(false);
  const [isAnimatingWishlist, setIsAnimatingWishlist] = useState(false);
  const [isBuyModalOpen, setIsBuyModalOpen] = useState(false);
  const [isPresetsModalOpen, setIsPresetsModalOpen] = useState(false);
  const [isCreativeModalOpen, setIsCreativeModalOpen] = useState(false);
  const [quantity, setQuantity] = useState(1);

  // Robust Image Validation Logic
  const isValidUrl = useCallback((url: string | undefined | null): boolean => {
    if (!url || typeof url !== 'string' || url.trim().length === 0) return false;
    // Basic protocol and path checking
    return (
      url.startsWith('http://') || 
      url.startsWith('https://') || 
      url.startsWith('/') || 
      url.startsWith('data:image/')
    );
  }, []);

  const [displayImageUrl, setDisplayImageUrl] = useState<string>(() => 
    isValidUrl(product.imageUrl) ? product.imageUrl! : FALLBACK_IMAGE
  );
  const [hasImageError, setHasImageError] = useState<boolean>(false);

  // Sync state if product prop changes externally
  useEffect(() => {
    if (isValidUrl(product.imageUrl)) {
      setDisplayImageUrl(product.imageUrl!);
      setHasImageError(false);
    } else {
      setDisplayImageUrl(FALLBACK_IMAGE);
      setHasImageError(true);
    }
  }, [product.imageUrl, isValidUrl]);

  // Handle Image Loading Failures Gracefully
  const handleImageError = () => {
    // Only attempt to set the fallback once per image to avoid loops
    if (!hasImageError) {
      setHasImageError(true);
      setDisplayImageUrl(FALLBACK_IMAGE);
    }
  };

  // AI Refinement State
  const [refinePrompt, setRefinePrompt] = useState(`A professional high-fashion photo of ${product.name}, ${product.description}`);
  const [isRefining, setIsRefining] = useState(false);
  const [refineError, setRefineError] = useState<string | null>(null);

  // Parallax effect for premium feel
  const [parallax, setParallax] = useState({ x: 0, y: 0 });
  const cardRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const wishlist = JSON.parse(localStorage.getItem('aura_wishlist') || '[]');
    setIsInWishlist(wishlist.some((item: any) => item.id === product.id));
  }, [product.id]);

  const trackInteraction = () => {
    const history = JSON.parse(localStorage.getItem('aura_browsing_history') || '[]');
    const filteredHistory = history.filter((h: any) => h.id !== product.id);
    const newHistory = [product, ...filteredHistory].slice(0, 10);
    localStorage.setItem('aura_browsing_history', JSON.stringify(newHistory));
    window.dispatchEvent(new Event('browsingHistoryUpdated'));
  };

  const handleMouseMove = (e: React.MouseEvent<HTMLDivElement>) => {
    if (!cardRef.current) return;
    const rect = cardRef.current.getBoundingClientRect();
    const x = (e.clientX - rect.left) / rect.width;
    const y = (e.clientY - rect.top) / rect.height;
    setParallax({ x: (x - 0.5) * 20, y: (y - 0.5) * 20 });
  };

  const toggleWishlist = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsAnimatingWishlist(true);
    setTimeout(() => setIsAnimatingWishlist(false), 450);

    const wishlist = JSON.parse(localStorage.getItem('aura_wishlist') || '[]');
    let newWishlist;
    if (isInWishlist) {
      newWishlist = wishlist.filter((item: any) => item.id !== product.id);
    } else {
      newWishlist = [...wishlist, product];
      trackInteraction(); 
    }
    localStorage.setItem('aura_wishlist', JSON.stringify(newWishlist));
    setIsInWishlist(!isInWishlist);
    window.dispatchEvent(new Event('wishlistUpdated'));
  };

  const handleAddToCart = (e?: React.MouseEvent) => {
    if (e) { e.preventDefault(); e.stopPropagation(); }
    if (isAdding) return;
    setIsAdding(true);
    trackInteraction(); 
    const cart = JSON.parse(localStorage.getItem('aura_cart') || '[]');
    const existingIndex = cart.findIndex((item: any) => item.id === product.id);
    if (existingIndex > -1) { cart[existingIndex].quantity += quantity; }
    else { cart.push({ ...product, quantity }); }
    localStorage.setItem('aura_cart', JSON.stringify(cart));
    window.dispatchEvent(new Event('cartUpdated'));
    setTimeout(() => { setIsAdding(false); setIsAdded(true); setTimeout(() => setIsAdded(false), 2000); }, 600);
  };

  const handleBuyNowClick = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsBuyModalOpen(true);
  };

  const getBase64FromUrl = async (url: string): Promise<string | null> => {
    if (url.startsWith('data:')) return url;
    try {
        const response = await fetch(url);
        const blob = await response.blob();
        return new Promise((resolve) => {
            const reader = new FileReader();
            reader.onloadend = () => resolve(reader.result as string);
            reader.readAsDataURL(blob);
        });
    } catch (e) { return null; }
  };

  const handleApplyPresetImmediate = async (presetPrompt: string) => {
    if (isRefining) return;
    setIsRefining(true);
    setRefineError(null);
    try {
      const base64Ref = await getBase64FromUrl(displayImageUrl);
      const newImage = await generateAuraImage(presetPrompt, base64Ref || undefined);
      if (newImage) {
        setDisplayImageUrl(newImage);
        setHasImageError(false);
        setIsPresetsModalOpen(false);
      } else {
        setRefineError("Aura could not apply this style. Try another preset.");
      }
    } catch (err) {
      setRefineError("AI core connection interrupted.");
    } finally {
      setIsRefining(false);
    }
  };

  const handleRegenerate = async () => {
    if (isRefining) return;
    setIsRefining(true);
    setRefineError(null);
    try {
      const base64Ref = await getBase64FromUrl(displayImageUrl);
      const newImage = await generateAuraImage(refinePrompt, base64Ref || undefined);
      if (newImage) {
        setDisplayImageUrl(newImage);
        setHasImageError(false);
      } else {
        setRefineError("Aura was unable to visualize this request. Try a different prompt.");
      }
    } catch (err) {
      setRefineError("Neural sync interrupted. Please try again.");
    } finally {
      setIsRefining(false);
    }
  };

  const handleReset = () => {
    setDisplayImageUrl(product.imageUrl || FALLBACK_IMAGE);
    setHasImageError(false);
    setRefinePrompt(`A professional high-fashion photo of ${product.name}, ${product.description}`);
    setIsPresetsModalOpen(false);
    setIsCreativeModalOpen(false);
  };

  return (
    <>
      <div 
        ref={cardRef}
        onMouseEnter={trackInteraction}
        onMouseMove={handleMouseMove}
        onMouseLeave={() => setParallax({ x: 0, y: 0 })}
        className={`group relative bg-aura-glass border rounded-[2.5rem] overflow-hidden transition-all duration-500 hover:shadow-[0_25px_60px_rgba(124,58,237,0.2)] flex flex-col h-full ${
          isRecommended ? 'border-aura-purple/50 ring-1 ring-aura-purple/20' : 'border-aura-glassBorder hover:border-aura-purple/60'
        }`}
      >
          {/* Image Section */}
          <div className="relative h-80 overflow-hidden cursor-pointer" onClick={() => setIsCreativeModalOpen(true)}>
            <img 
              src={displayImageUrl} 
              alt={product.name} 
              onError={handleImageError}
              style={{ transform: `translate(${parallax.x}px, ${parallax.y}px) scale(1.18)`, transition: 'transform 0.2s ease-out' }}
              className={`w-full h-full object-cover transform transition-opacity duration-300 ${isRefining ? 'animate-pulse opacity-50 blur-sm' : 'opacity-100'} ${hasImageError ? 'grayscale' : ''}`}
            />
            <div className="absolute inset-0 bg-gradient-to-t from-black via-black/30 to-transparent opacity-90" />
            <div className="absolute top-6 left-6 flex flex-col gap-2 z-20">
                <span className="bg-aura-purple/30 backdrop-blur-xl border border-aura-purple/40 px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-[0.15em] text-white">
                    {product.category}
                </span>
                {isRecommended && (
                    <span className="bg-aura-purple text-white px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-[0.15em] flex items-center gap-1.5 shadow-2xl animate-pulse">
                       <Sparkles size={12} /> Aura's Pick
                    </span>
                )}
            </div>
            <div className="absolute top-6 right-6 z-30 flex flex-col gap-2">
              <button onClick={toggleWishlist} className={`p-3 rounded-2xl backdrop-blur-2xl border transition-all duration-300 transform active:scale-90 ${isAnimatingWishlist ? 'animate-heart-pop' : ''} ${isInWishlist ? 'bg-aura-purple/30 border-aura-purple text-aura-purple' : 'bg-black/40 border-white/10 text-white hover:bg-black/70'}`}>
                <Heart size={20} className={isInWishlist ? 'fill-aura-purple' : ''} />
              </button>
              <button onClick={(e) => { e.preventDefault(); e.stopPropagation(); setIsPresetsModalOpen(true); }} className="p-3 bg-black/40 border border-white/10 text-white rounded-2xl backdrop-blur-2xl hover:bg-aura-purple transition-all transform active:scale-90" title="Style Presets">
                <Palette size={20} />
              </button>
              <button onClick={(e) => { e.preventDefault(); e.stopPropagation(); setIsCreativeModalOpen(true); }} className="p-3 bg-black/40 border border-white/10 text-white rounded-2xl backdrop-blur-2xl hover:bg-aura-purple transition-all transform active:scale-90" title="Refine Image">
                <Wand2 size={20} />
              </button>
            </div>
