/**
 * AI RECOMMENDATIONS WITH RESILIENT FALLBACK
 * If the API fails or quota is exhausted (429), this returns products 
 * based on category matching from the user's history.
 */
export const getAIRecommendations = async (historyProducts: Product[]): Promise<number[]> => {
    const getFallbackRecs = () => {
        const catalog = getProducts();
        const historyIds = new Set(historyProducts.map(p => p.id));
        const historyCats = new Set(historyProducts.map(p => p.category));

        // Find products in same category not in history
        let matching = catalog.filter(p => !historyIds.has(p.id) && historyCats.has(p.category));

        // If not enough matches, fill with newest catalog items
        if (matching.length < 3) {
            const others = catalog.filter(p => !historyIds.has(p.id) && !historyCats.has(p.category));
            matching = [...matching, ...others];
        }

        return matching.slice(0, 3).map(p => p.id);
    };

    if (!process.env.API_KEY) return getFallbackRecs();

    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const catalog = getProducts();
        const historySummary = historyProducts.map(p => `${p.name} (${p.category})`).join(', ');
        const catalogSummary = catalog.map(p => `ID: ${p.id}, Name: ${p.name}, Cat: ${p.category}`).join(' | ');

        const prompt = `
            User History: [${historySummary}]
            Catalog: [${catalogSummary}]
            Pick 3 IDs user would like. Return JSON: { "recommendedIds": number[] }
        `;

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: { responseMimeType: 'application/json' }
        });

        const result = JSON.parse(response.text || '{ "recommendedIds": [] }');
        return result.recommendedIds?.length ? result.recommendedIds : getFallbackRecs();
    } catch (error: any) {
        // Silently fall back to heuristic matching on 429 or any other error
        console.warn("Aura Recommendation Quota reached. Using local category-match heuristics.");
        return getFallbackRecs();
    }
};

/**
 * IMAGE GENERATION / EDITING
 * Silently fails if quota is hit, returning null so UI can handle gracefully.
 */
export const generateAuraImage = async (prompt: string, referenceImageBase64?: string): Promise<string | null> => {
    if (!process.env.API_KEY) return null;

    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const parts: any[] = [{ text: `High-fashion editorial. ${prompt}` }];

        if (referenceImageBase64) {
            const cleanBase64 = referenceImageBase64.replace(/^data:image\/(png|jpeg|jpg);base64,/, "");
            parts.unshift({
                inlineData: {
                    data: cleanBase64,
                    mimeType: 'image/png'
                }
            });
        }

        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash-image',
            contents: { parts },
            config: { imageConfig: { aspectRatio: "1:1" } }
        });

        for (const part of response.candidates[0].content.parts) {
            if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
        }
        return null;
    } catch (error: any) {
        console.warn("Aura Image Generation Quota exhausted.");
        return null;
    }
};

/**
 * SEARCH INTENT ANALYSIS
 * Always returns a valid object even on API failure to prevent UI crashes.
 */
export interface SearchIntent {
    category: string | null;
    maxPrice: number | null;
    minPrice: number | null;
    color: string | null;
    material: string | null;
    style: string | null;
    keyPhrases: string[]; 
    semanticKeywords: string[];
    isSearchQuery: boolean;
    shouldGenerateImage: boolean;
    imagePrompt: string | null;
}

export const analyzeSearchIntent = async (userPrompt: string): Promise<SearchIntent | null> => {
    const defaultIntent: SearchIntent = {
        category: null, maxPrice: null, minPrice: null, color: null, material: null, style: null,
        keyPhrases: [], semanticKeywords: userPrompt.split(' '), isSearchQuery: true, shouldGenerateImage: false, imagePrompt: null
    };

    if (!process.env.API_KEY) return defaultIntent;

    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const prompt = `Analyze query: "${userPrompt}". Extract filters. Return JSON.`;

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: { responseMimeType: 'application/json' }
        });

        const parsed = JSON.parse(response.text || '{}');
        return { ...defaultIntent, ...parsed };
    } catch (error: any) {
        console.warn("Search Intent Quota reached. Falling back to basic keyword matching.");
        return defaultIntent;
    }
};

/**
 * TRY-ON TRANSFORMATION
 */
export const generateTryOnTransformation = async (userImageBase64: string, productImageBase64: string): Promise<string | null> => {
    if (!process.env.API_KEY) return null;
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const cleanUserImage = userImageBase64.replace(/^data:image\/(png|jpeg|jpg);base64,/, "");
      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: {
          parts: [
            { inlineData: { data: cleanUserImage, mimeType: 'image/jpeg' } },
            { text: "Drape clothing conceptually." },
          ],
        },
      });
      for (const part of response.candidates[0].content.parts) {
          if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
      }
      return null; 
    } catch (error: any) {
      console.warn("Try-On Quota exhausted.");
      return null;
    }
};

