                <div className="flex items-center gap-1.5 text-green-500 bg-green-500/10 px-3 py-1.5 rounded-xl border border-green-500/10">
                   <div className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse"></div>
                   <span className="text-[9px] font-black uppercase tracking-widest">Available</span>
                </div>
              </div>

              <div className="grid grid-cols-1 gap-3">
                <div className="flex gap-2">
                  <button onClick={handleAddToCart} disabled={isAdding} className={`flex-1 py-4 rounded-2xl text-[10px] font-black uppercase tracking-[0.2em] flex items-center justify-center gap-2 border backdrop-blur-md transition-all ${isAdded ? 'bg-green-500/20 border-green-500 text-green-400' : 'bg-white/5 border-white/10 text-white hover:bg-white/10'}`}>
                    {isAdding ? <Loader2 size={16} className="animate-spin" /> : isAdded ? <Check size={16} /> : <ShoppingCart size={16} />}
                    <span>{isAdded ? 'Added' : 'কার্টে যোগ'}</span>
                  </button>
                  <button onClick={(e) => { e.preventDefault(); e.stopPropagation(); setIsCreativeModalOpen(true); }} className="p-4 rounded-2xl border border-white/10 bg-white/5 text-white hover:bg-aura-purple hover:border-aura-purple transition-all active:scale-95">
                    <Wand2 size={16} />
                  </button>
                </div>
                <button onClick={(e) => { e.preventDefault(); e.stopPropagation(); setIsBuyModalOpen(true); }} className="w-full bg-aura-purple text-white py-4 rounded-2xl text-[11px] font-black uppercase tracking-[0.3em] flex items-center justify-center gap-2 shadow-lg hover:bg-purple-600 transition-all active:scale-95">
                   Buy Now <ArrowRight size={16} />
                </button>
              </div>
            </div>
          </div>
      </div>

      {/* Style Presets Modal */}
      {isPresetsModalOpen && (
        <div className="fixed inset-0 z-[150] flex items-center justify-center p-6 bg-black/90 backdrop-blur-2xl animate-in fade-in">
          <div className="bg-aura-glass border border-aura-glassBorder w-full max-w-xl rounded-[3rem] p-10 shadow-2xl relative overflow-hidden animate-in zoom-in">
            <div className="absolute top-0 right-0 w-80 h-80 bg-aura-purple/10 blur-[100px] rounded-full" />

            <div className="relative z-10">
              <div className="flex justify-between items-start mb-10">
                <div>
                  <h3 className="text-2xl font-serif font-bold text-white mb-2">Style Presets</h3>
                  <p className="text-[9px] text-gray-500 uppercase tracking-[0.25em] font-black flex items-center gap-2">
                    <Sparkles className="text-aura-purple" size={12} /> Neural Re-imagination
                  </p>
                </div>
                <button onClick={() => setIsPresetsModalOpen(false)} className="p-2 bg-white/5 rounded-xl hover:bg-white/10 text-gray-400 border border-white/5">
                  <X size={24} />
                </button>
              </div>

              <div className="grid grid-cols-2 gap-4 mb-8">
                {STYLE_PRESETS.map((style) => (
                  <button 
                    key={style.name}
                    disabled={isRefining}
                    onClick={() => handleApplyPreset(style.prompt)}
                    className={`group relative flex items-center gap-4 p-5 rounded-2xl border border-white/10 transition-all hover:border-aura-purple bg-gradient-to-br ${style.color} hover:scale-[1.02] active:scale-95 disabled:opacity-50`}
                  >
                    <div className="p-3 bg-white/10 rounded-xl group-hover:bg-white/20">
                      {style.icon}
                    </div>
                    <span className="text-[10px] font-black text-white uppercase tracking-widest">{style.name}</span>
                  </button>
                ))}
              </div>

              {isRefining && (
                <div className="flex flex-col items-center gap-3 animate-pulse">
                   <Loader2 size={24} className="text-aura-purple animate-spin" />
                   <p className="text-[9px] text-white font-black uppercase tracking-[0.3em]">Applying Neural Style...</p>
                </div>
              )}

              {refineError && (
                <p className="text-[9px] text-red-400 font-bold bg-red-500/10 p-3 rounded-xl border border-red-500/20 text-center">
                  {refineError}
                </p>
              )}
            </div>
          </div>
        </div>
      )}

      {/* Buy Modal */}
      {isBuyModalOpen && (
        <div className="fixed inset-0 z-[160] flex items-center justify-center p-6 bg-black/90 backdrop-blur-2xl animate-in fade-in">
          <div className="bg-aura-glass border border-aura-glassBorder w-full max-w-md rounded-[3rem] p-10 shadow-2xl relative animate-in zoom-in">
            <div className="flex justify-between items-start mb-8">
               <h3 className="text-2xl font-serif font-bold text-white">Checkout</h3>
               <button onClick={() => setIsBuyModalOpen(false)} className="text-gray-500 hover:text-white"><X size={24} /></button>
            </div>

            <div className="flex gap-4 p-4 bg-white/5 rounded-2xl border border-white/10 mb-8">
                <img src={displayImageUrl} className="w-20 h-20 object-cover rounded-xl" />
                <div>
                   <h4 className="text-white font-bold">{product.name}</h4>
                   <p className="text-lg font-black text-aura-purple">৳{product.price.toLocaleString()}</p>
                </div>
            </div>

            <button onClick={() => { handleAddToCart(); window.location.hash = '/cart'; }} className="w-full bg-white text-black py-5 rounded-2xl text-xs font-black uppercase tracking-[0.3em] flex items-center justify-center gap-3 shadow-xl active:scale-95">
                <CreditCard size={18} /> Confirm Order
            </button>
          </div>
        </div>
      )}
    </>
  );
};

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Product, Vendor } from '../types';
import { 
  ExternalLink, ShoppingCart, Camera, Check, Loader2, CreditCard, 
  Sparkles, Heart, Minus, Plus, X, ArrowRight, 
  ShieldCheck, Wand2, RefreshCcw, Palette, Sun, Map, Image as ImageIcon,
  Layers, Zap, Wind, History, RotateCcw, Crown, Palmtree, Edit3, Monitor, Camera as CameraIcon
} from 'lucide-react';
import { Link } from './Navigation';
import { generateAuraImage } from '../services/geminiService';

interface ProductCardProps {
  product: Product;
  vendor?: Vendor;
  isRecommended?: boolean;
}

const FALLBACK_IMAGE = 'https://images.unsplash.com/photo-1515886657613-9f3515b0c78f?auto=format&fit=crop&q=80&w=800';

const STYLE_PRESETS = [
  { name: 'Vintage', prompt: 'Vintage 1970s film aesthetic, warm grainy texture, nostalgic moody lighting, cinematic film stock', icon: <History size={20} />, color: 'from-amber-500/20 to-orange-900/40' },
  { name: 'Cyberpunk', prompt: 'Cyberpunk neon aesthetic, Dhakai city lights at night, violet and teal lighting, high-contrast reflections', icon: <Zap size={20} />, color: 'from-fuchsia-600/20 to-blue-900/40' },
  { name: 'Minimalist', prompt: 'High-end minimalist editorial, clean architectural concrete background, soft diffuse natural daylight, sharp focus', icon: <Layers size={20} />, color: 'from-gray-400/20 to-slate-800/40' },
  { name: 'Bohemian', prompt: 'Bohemian chic, lush sun-drenched meadow, golden hour lens flare, soft artistic breeze, dreamy atmosphere', icon: <Wind size={20} />, color: 'from-yellow-400/20 to-orange-800/40' },
  { name: 'Royal', prompt: 'Royal palace interior, ornate Dhakai Muslin luxury setting, gold accents, dramatic baroque lighting', icon: <Crown size={20} />, color: 'from-yellow-600/20 to-red-900/40' },
  { name: 'Studio', prompt: 'Professional high-fashion studio shot, solid seamless background, multi-point lighting, clean and commercial', icon: <CameraIcon size={20} />, color: 'from-blue-400/20 to-indigo-900/40' }
];

export const ProductCard: React.FC<ProductCardProps> = ({ product, vendor, isRecommended }) => {
  const [isAdding, setIsAdding] = useState(false);
  const [isAdded, setIsAdded] = useState(false);
  const [isInWishlist, setIsInWishlist] = useState(false);
  const [isAnimatingWishlist, setIsAnimatingWishlist] = useState(false);
  const [isBuyModalOpen, setIsBuyModalOpen] = useState(false);
  const [isPresetsModalOpen, setIsPresetsModalOpen] = useState(false);
  const [isCreativeModalOpen, setIsCreativeModalOpen] = useState(false);
  const [quantity, setQuantity] = useState(1);

  // Robust Image Validation Logic
  const isValidUrl = useCallback((url: string | undefined | null): boolean => {
    if (!url || typeof url !== 'string' || url.trim().length === 0) return false;
    return url.startsWith('http') || url.startsWith('/') || url.startsWith('data:');
  }, []);

  const [displayImageUrl, setDisplayImageUrl] = useState<string>(() => 
    isValidUrl(product.imageUrl) ? product.imageUrl! : FALLBACK_IMAGE
  );
  const [hasImageError, setHasImageError] = useState<boolean>(false);

  // Sync state if product prop changes externally
  useEffect(() => {
    setDisplayImageUrl(isValidUrl(product.imageUrl) ? product.imageUrl! : FALLBACK_IMAGE);
    setHasImageError(!isValidUrl(product.imageUrl));
  }, [product.imageUrl, isValidUrl]);

  const handleImageError = () => {
    if (!hasImageError) {
      setHasImageError(true);
      setDisplayImageUrl(FALLBACK_IMAGE);
    }
  };

  // AI Refinement State
  const [refinePrompt, setRefinePrompt] = useState(`A professional high-fashion photo of ${product.name}`);
  const [isRefining, setIsRefining] = useState(false);
  const [refineError, setRefineError] = useState<string | null>(null);

  // Advanced Parallax & 3D Tilt State
  const [parallax, setParallax] = useState({ x: 0, y: 0, tiltX: 0, tiltY: 0 });
  const cardRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const wishlist = JSON.parse(localStorage.getItem('aura_wishlist') || '[]');
    setIsInWishlist(wishlist.some((item: any) => item.id === product.id));
  }, [product.id]);

  const trackInteraction = () => {
    const history = JSON.parse(localStorage.getItem('aura_browsing_history') || '[]');
    const filteredHistory = history.filter((h: any) => h.id !== product.id);
    const newHistory = [product, ...filteredHistory].slice(0, 10);
    localStorage.setItem('aura_browsing_history', JSON.stringify(newHistory));
    window.dispatchEvent(new Event('browsingHistoryUpdated'));
  };

  const handleMouseMove = (e: React.MouseEvent<HTMLDivElement>) => {
    if (!cardRef.current) return;
    const rect = cardRef.current.getBoundingClientRect();

    // Calculate normalized coordinates (-0.5 to 0.5)
    const x = (e.clientX - rect.left) / rect.width - 0.5;
    const y = (e.clientY - rect.top) / rect.height - 0.5;

    // tiltX: tilt around horizontal axis (mapped to y)
    // tiltY: tilt around vertical axis (mapped to x)
    setParallax({ 
      x: x * 25, 
      y: y * 25,
      tiltX: y * -8, // Subtle tilt back and forth
      tiltY: x * 8    // Subtle tilt left and right
    });
  };

  const handleMouseLeave = () => {
    setParallax({ x: 0, y: 0, tiltX: 0, tiltY: 0 });
  };

  const toggleWishlist = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsAnimatingWishlist(true);
    setTimeout(() => setIsAnimatingWishlist(false), 450);

    const wishlist = JSON.parse(localStorage.getItem('aura_wishlist') || '[]');
    let newWishlist;
    if (isInWishlist) {
      newWishlist = wishlist.filter((item: any) => item.id !== product.id);
    } else {
      newWishlist = [...wishlist, product];
      trackInteraction(); 
    }
    localStorage.setItem('aura_wishlist', JSON.stringify(newWishlist));
    setIsInWishlist(!isInWishlist);
    window.dispatchEvent(new Event('wishlistUpdated'));
  };

  const handleAddToCart = (e?: React.MouseEvent) => {
    if (e) { e.preventDefault(); e.stopPropagation(); }
    if (isAdding) return;
    setIsAdding(true);
    trackInteraction(); 
    const cart = JSON.parse(localStorage.getItem('aura_cart') || '[]');
    const existingIndex = cart.findIndex((item: any) => item.id === product.id);
    if (existingIndex > -1) { cart[existingIndex].quantity += quantity; }
    else { cart.push({ ...product, quantity }); }
    localStorage.setItem('aura_cart', JSON.stringify(cart));
    window.dispatchEvent(new Event('cartUpdated'));
    setTimeout(() => { setIsAdding(false); setIsAdded(true); setTimeout(() => setIsAdded(false), 2000); }, 600);
  };

  const getBase64FromUrl = async (url: string): Promise<string | null> => {
    if (url.startsWith('data:')) return url;
    try {
        const response = await fetch(url);
        const blob = await response.blob();
        return new Promise((resolve) => {
            const reader = new FileReader();
            reader.onloadend = () => resolve(reader.result as string);
            reader.readAsDataURL(blob);
        });
    } catch (e) { return null; }
  };

  const handleApplyPreset = async (presetPrompt: string) => {
    if (isRefining) return;
    setIsRefining(true);
    setRefineError(null);
    try {
      const base64Ref = await getBase64FromUrl(displayImageUrl);
      const newImage = await generateAuraImage(presetPrompt, base64Ref || undefined);
      if (newImage) {
        setDisplayImageUrl(newImage);
        setHasImageError(false);
        setIsPresetsModalOpen(false);
      } else {
        setRefineError("এআই সিস্টেম বর্তমানে ব্যস্ত। অন্য একটি স্টাইল চেষ্টা করুন।");
      }
    } catch (err) {
      setRefineError("কানেকশন এরর হয়েছে।");
    } finally {
      setIsRefining(false);
    }
  };

  const handleRegenerate = async () => {
    if (isRefining) return;
    setIsRefining(true);
    setRefineError(null);
    try {
      const base64Ref = await getBase64FromUrl(displayImageUrl);
      const newImage = await generateAuraImage(refinePrompt, base64Ref || undefined);
      if (newImage) {
        setDisplayImageUrl(newImage);
        setHasImageError(false);
      } else {
        setRefineError("Aura was unable to visualize this request. Try a different prompt.");
      }
    } catch (err) {
      setRefineError("Neural sync interrupted.");
    } finally {
      setIsRefining(false);
    }
  };

  const handleReset = () => {
    setDisplayImageUrl(product.imageUrl || FALLBACK_IMAGE);
    setHasImageError(false);
    setRefinePrompt(`A professional high-fashion photo of ${product.name}`);
    setIsPresetsModalOpen(false);
    setIsCreativeModalOpen(false);
  };

  return (
    <>
      <div 
        ref={cardRef}
        onMouseEnter={trackInteraction}
        onMouseMove={handleMouseMove}
        onMouseLeave={handleMouseLeave}
        style={{ 
          transform: `perspective(1000px) rotateX(${parallax.tiltX}deg) rotateY(${parallax.tiltY}deg)`,
          transition: 'transform 0.1s ease-out'
        }}
        className={`group relative bg-aura-glass border rounded-[2.5rem] overflow-hidden transition-all duration-500 hover:shadow-[0_25px_60px_rgba(124,58,237,0.2)] flex flex-col h-full transform-gpu ${
          isRecommended ? 'border-aura-purple/50 ring-1 ring-aura-purple/20' : 'border-aura-glassBorder hover:border-aura-purple/60'
        }`}
      >
          {/* Image Section */}
          <div className="relative h-80 overflow-hidden cursor-pointer" onClick={() => setIsCreativeModalOpen(true)}>
            <img 
              src={displayImageUrl} 
              alt={product.name} 
              onError={handleImageError}
              style={{ 
                // Subtle parallax: image moves at half the rate of the "tilt" (slower than foreground content)
                transform: `translate(${parallax.x * 0.4}px, ${parallax.y * 0.4}px) scale(1.15)`, 
                transition: 'transform 0.15s ease-out' 
              }}
              className={`w-full h-full object-cover transform-gpu transition-opacity duration-300 ${isRefining ? 'animate-pulse opacity-50 blur-sm' : 'opacity-100'}`}
            />
            <div className="absolute inset-0 bg-gradient-to-t from-black via-black/20 to-transparent opacity-90" />

            <div className="absolute top-6 left-6 flex flex-col gap-2 z-20">
                <span className="bg-black/40 backdrop-blur-xl border border-white/10 px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-[0.15em] text-white">
                    {product.category}
                </span>
                {isRecommended && (
                    <span className="bg-aura-purple text-white px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-[0.15em] flex items-center gap-1.5 shadow-xl animate-pulse">
                       <Sparkles size={12} /> Aura's Choice
                    </span>
                )}
            </div>

            <div className="absolute top-6 right-6 z-30 flex flex-col gap-2">
              <button onClick={toggleWishlist} className={`p-3 rounded-2xl backdrop-blur-2xl border transition-all duration-300 transform active:scale-90 ${isAnimatingWishlist ? 'animate-heart-pop' : ''} ${isInWishlist ? 'bg-aura-purple/30 border-aura-purple text-aura-purple' : 'bg-black/40 border-white/10 text-white hover:bg-black/70'}`}>
                <Heart size={20} className={isInWishlist ? 'fill-aura-purple' : ''} />
              </button>
              <button onClick={(e) => { e.preventDefault(); e.stopPropagation(); setIsPresetsModalOpen(true); }} className="p-3 bg-black/40 border border-white/10 text-white rounded-2xl backdrop-blur-2xl hover:bg-aura-purple transition-all transform active:scale-90" title="Style Presets">
                <Palette size={20} />
              </button>
            </div>

            <div className="absolute bottom-6 left-6 z-20">
               <Link to={`/try-on/${product.id}`} className="bg-white/10 hover:bg-aura-purple text-white px-5 py-2.5 rounded-2xl text-[10px] font-black uppercase tracking-[0.2em] flex items-center gap-2.5 backdrop-blur-2xl border border-white/10 transition-all hover:scale-105">
                 <Camera size={16} /> Virtual Try-On
               </Link>
            </div>
          </div>

          {/* Content Section */}
          <div className="p-8 flex flex-col flex-grow bg-gradient-to-b from-transparent to-black/40 relative z-10">
            <div className="mb-6">
              {vendor && (
                <div className="flex items-center gap-2.5 mb-2">
                  <div className="w-1 h-1 rounded-full bg-aura-purple"></div>
                  <span className="text-[10px] text-aura-ash uppercase tracking-[0.3em] font-black">{vendor.name}</span>
                </div>
              )}
              <h3 className="font-serif text-2xl font-bold text-white mb-3 leading-snug group-hover:text-aura-purple transition-colors">{product.name}</h3>
              <p className="text-xs text-gray-500 line-clamp-2 font-medium leading-relaxed mb-4">{product.description}</p>
            </div>

            <div className="mt-auto pt-6 border-t border-white/5 space-y-6">
              <div className="flex justify-between items-end">
                <div>
                  <div className="text-[9px] text-gray-600 font-bold uppercase tracking-widest mb-1">Ecosystem Price</div>
                  <div className="text-2xl font-black text-white tracking-tighter">৳{product.price.toLocaleString()}</div>
                </div>
                <div className="flex items-center gap-1.5 text-green-500 bg-green-500/10 px-3 py-1.5 rounded-xl border border-green-500/10">
                   <div className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse"></div>
                   <span className="text-[9px] font-black uppercase tracking-widest">Available</span>
                </div>
              </div>

              <div className="grid grid-cols-1 gap-3">
                <div className="flex gap-2">
                  <button onClick={handleAddToCart} disabled={isAdding} className={`flex-1 py-4 rounded-2xl text-[10px] font-black uppercase tracking-[0.2em] flex items-center justify-center gap-2 border backdrop-blur-md transition-all ${isAdded ? 'bg-green-500/20 border-green-500 text-green-400' : 'bg-white/5 border-white/10 text-white hover:bg-white/10'}`}>
                    {isAdding ? <Loader2 size={16} className="animate-spin" /> : isAdded ? <Check size={16} /> : <ShoppingCart size={16} />}
                    <span>{isAdded ? 'Added' : 'কার্টে যোগ'}</span>
                  </button>
                  <button onClick={(e) => { e.preventDefault(); e.stopPropagation(); setIsCreativeModalOpen(true); }} className="p-4 rounded-2xl border border-white/10 bg-white/5 text-white hover:bg-aura-purple hover:border-aura-purple transition-all active:scale-95">
                    <Wand2 size={16} />
                  </button>
                </div>
                <button onClick={(e) => { e.preventDefault(); e.stopPropagation(); setIsBuyModalOpen(true); }} className="w-full bg-aura-purple text-white py-4 rounded-2xl text-[11px] font-black uppercase tracking-[0.3em] flex items-center justify-center gap-2 shadow-lg hover:bg-purple-600 transition-all active:scale-95">
                   Buy Now <ArrowRight size={16} />
                </button>
              </div>
            </div>
          </div>
      </div>

      {/* Style Presets Modal */}
      {isPresetsModalOpen && (
        <div className="fixed inset-0 z-[150] flex items-center justify-center p-6 bg-black/90 backdrop-blur-2xl animate-in fade-in">
          <div className="bg-aura-glass border border-aura-glassBorder w-full max-w-xl rounded-[3rem] p-10 shadow-2xl relative overflow-hidden animate-in zoom-in">
            <div className="absolute top-0 right-0 w-80 h-80 bg-aura-purple/10 blur-[100px] rounded-full" />

            <div className="relative z-10">
              <div className="flex justify-between items-start mb-10">
                <div>
                  <h3 className="text-2xl font-serif font-bold text-white mb-2">Style Presets</h3>
                  <p className="text-[9px] text-gray-500 uppercase tracking-[0.25em] font-black flex items-center gap-2">
                    <Sparkles className="text-aura-purple" size={12} /> Neural Re-imagination
                  </p>
                </div>
                <button onClick={() => setIsPresetsModalOpen(false)} className="p-2 bg-white/5 rounded-xl hover:bg-white/10 text-gray-400 border border-white/5">
                  <X size={24} />
                </button>
              </div>

              <div className="grid grid-cols-2 gap-4 mb-8">
                {STYLE_PRESETS.map((style) => (
                  <button 
                    key={style.name}
                    disabled={isRefining}
                    onClick={() => handleApplyPreset(style.prompt)}
                    className={`group relative flex items-center gap-4 p-5 rounded-2xl border border-white/10 transition-all hover:border-aura-purple bg-gradient-to-br ${style.color} hover:scale-[1.02] active:scale-95 disabled:opacity-50`}
                  >
                    <div className="p-3 bg-white/10 rounded-xl group-hover:bg-white/20">
                      {style.icon}
                    </div>
                    <span className="text-[10px] font-black text-white uppercase tracking-widest">{style.name}</span>
                  </button>
                ))}
              </div>

              {isRefining && (
                <div className="flex flex-col items-center gap-3 animate-pulse">
                   <Loader2 size={24} className="text-aura-purple animate-spin" />
                   <p className="text-[9px] text-white font-black uppercase tracking-[0.3em]">Applying Neural Style...</p>
                </div>
              )}

              {refineError && (
                <p className="text-[9px] text-red-400 font-bold bg-red-500/10 p-3 rounded-xl border border-red-500/20 text-center">
                  {refineError}
                </p>
              )}
            </div>
          </div>
        </div>
      )}

      {/* Buy Modal */}
      {isBuyModalOpen && (
        <div className="fixed inset-0 z-[160] flex items-center justify-center p-6 bg-black/90 backdrop-blur-2xl animate-in fade-in">
          <div className="bg-aura-glass border border-aura-glassBorder w-full max-w-md rounded-[3rem] p-10 shadow-2xl relative animate-in zoom-in">
            <div className="flex justify-between items-start mb-8">
               <h3 className="text-2xl font-serif font-bold text-white">Checkout</h3>
               <button onClick={() => setIsBuyModalOpen(false)} className="text-gray-500 hover:text-white"><X size={24} /></button>
            </div>

            <div className="flex gap-4 p-4 bg-white/5 rounded-2xl border border-white/10 mb-8">
                <img src={displayImageUrl} className="w-20 h-20 object-cover rounded-xl" />
                <div>
                   <h4 className="text-white font-bold">{product.name}</h4>
                   <p className="text-lg font-black text-aura-purple">৳{product.price.toLocaleString()}</p>
                </div>
            </div>

