                <CreditCard size={18} /> Confirm Order
            </button>
          </div>
        </div>
      )}
    </>
  );
};

import { GoogleGenAI, Type, GenerateContentResponse, Chat } from "@google/genai";
import { getProducts, getVendors, getOrderById } from "./mockData";
import { Product } from "../types";

// --- GLOBAL AI STATE (Circuit Breaker) ---
let isAuraCoolingDown = false;
const COOLDOWN_DURATION = 60000; // 60 seconds

const triggerNeuralCooldown = () => {
    if (isAuraCoolingDown) return;
    isAuraCoolingDown = true;
    console.warn("Aura AI: Quota reached. Entering Neural Cooldown (60s). Switching to Local Heuristic Engine.");
    setTimeout(() => {
        isAuraCoolingDown = false;
        console.log("Aura AI: Neural patterns restored. API access re-enabled.");
    }, COOLDOWN_DURATION);
};

// --- SYSTEM CONTEXT ---
const buildAuraContext = () => {
  const products = getProducts();
  const vendors = getVendors();

  const productString = products.map(p => 
    `- ${p.name} (৳${p.price}) [Category: ${p.category}] by ${vendors.find(v => v.id === p.vendorId)?.name}. Desc: ${p.description}`
  ).join('\n');

  const vendorString = vendors.map(v => 
    `- ${v.name} (Status: ${v.status}): ${v.description}`
  ).join('\n');

  return `
Identity: AURA AI - The Divine Soul of SNEHALATA-স্নেহলতা Hub.
Tone: Formal, Artistic, Culturally respectful, Multi-lingual (Bangla & English).

CRITICAL DIRECTIVE:
ALWAYS start EVERY conversation with the greeting "আসসালামু আলাইকুম" (Assalamu Alaikum). 

Ecosystem Data:
VENDORS:
${vendorString}

PRODUCTS:
${productString}
  `;
};

// --- SEARCH INTENT INTERFACE ---
export interface SearchIntent {
    category: string | null;
    maxPrice: number | null;
    minPrice: number | null;
    color: string | null;
    material: string | null;
    style: string | null;
    keyPhrases: string[]; 
    semanticKeywords: string[];
    isSearchQuery: boolean;
    shouldGenerateImage: boolean;
    imagePrompt: string | null;
}

const DEFAULT_INTENT = (query: string): SearchIntent => ({
    category: null, maxPrice: null, minPrice: null, color: null, material: null, style: null,
    keyPhrases: [], semanticKeywords: query.toLowerCase().split(' '), isSearchQuery: true, shouldGenerateImage: false, imagePrompt: null
});

// --- RESILIENT WRAPPER ---
async function withAuraResilience<T>(apiCall: () => Promise<T>, fallback: T): Promise<T> {
    if (isAuraCoolingDown || !process.env.API_KEY) return fallback;
    try {
        return await apiCall();
    } catch (error: any) {
        if (error?.message?.includes('429') || error?.message?.includes('quota')) {
            triggerNeuralCooldown();
        }
        return fallback;
    }
}

// --- STREAMING CHAT ---
export const startAuraChat = (): Chat => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  return ai.chats.create({
    model: 'gemini-3-flash-preview',
    config: {
      systemInstruction: buildAuraContext(),
      tools: [{
        functionDeclarations: [
          {
            name: "findProducts",
            description: "Search for products by category or keywords.",
            parameters: {
              type: Type.OBJECT,
              properties: {
                category: { type: Type.STRING },
                maxPrice: { type: Type.NUMBER },
                keywords: { type: Type.STRING }
              }
            }
          }
        ]
      }],
      temperature: 0.7,
    },
  });
};

/**
 * AI RECOMMENDATIONS
 */
export const getAIRecommendations = async (historyProducts: Product[]): Promise<number[]> => {
    const localFallback = () => {
        const catalog = getProducts();
        const historyCats = new Set(historyProducts.map(p => p.category));
        return catalog
            .filter(p => historyCats.has(p.category))
            .sort(() => 0.5 - Math.random())
            .slice(0, 3)
            .map(p => p.id);
    };

    return withAuraResilience(async () => {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const historySummary = historyProducts.map(p => p.name).join(', ');
        const prompt = `Based on user history: [${historySummary}], pick 3 relevant product IDs from the catalog. Return JSON: { "recommendedIds": number[] }`;

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: { responseMimeType: 'application/json' }
        });
        const result = JSON.parse(response.text || '{}');
        return result.recommendedIds || localFallback();
    }, localFallback());
};

/**
 * SEARCH INTENT ANALYSIS
 */
export const analyzeSearchIntent = async (userPrompt: string): Promise<SearchIntent | null> => {
    return withAuraResilience(async () => {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const prompt = `Analyze: "${userPrompt}". Extract category, maxPrice, keywords. Return JSON.`;

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: { responseMimeType: 'application/json' }
        });
        const parsed = JSON.parse(response.text || '{}');
        return { ...DEFAULT_INTENT(userPrompt), ...parsed };
    }, DEFAULT_INTENT(userPrompt));
};

/**
 * IMAGE GENERATION
 */
export const generateAuraImage = async (prompt: string, referenceImageBase64?: string): Promise<string | null> => {
    return withAuraResilience(async () => {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const parts: any[] = [{ text: prompt }];

        if (referenceImageBase64) {
            parts.unshift({
                inlineData: {
                    data: referenceImageBase64.replace(/^data:image\/(png|jpeg|jpg);base64,/, ""),
                    mimeType: 'image/png'
                }
            });
        }

        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash-image',
            contents: { parts }
        });

        for (const part of response.candidates[0].content.parts) {
            if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
        }
        return null;
    }, null);
};

/**
 * TRY-ON
 */
export const generateTryOnTransformation = async (userImageBase64: string, productImageBase64: string): Promise<string | null> => {
    return withAuraResilience(async () => {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash-image',
            contents: {
                parts: [
                    { inlineData: { data: userImageBase64.replace(/^data:image\/(png|jpeg|jpg);base64,/, ""), mimeType: 'image/jpeg' } },
                    { text: "Drape this garment realistically." }
                ]
            }
        });
        for (const part of response.candidates[0].content.parts) {
            if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
        }
        return null;
    }, null);
};

