            <form onSubmit={handleSendMessage} className="p-6 bg-white/5 border-t border-white/10">
              <div className="flex gap-3">
                <input value={input} onChange={(e) => setInput(e.target.value)} placeholder="Ask Aura anything..." className="flex-1 bg-black/50 border border-white/10 rounded-2xl px-6 py-4 text-sm text-white" />
                <button type="submit" className="bg-aura-purple text-white px-6 rounded-2xl"><Send size={20} /></button>
              </div>
            </form>
