            <div className="grid grid-cols-1 md:grid-cols-3 gap-8">{recommendations.map(p => <ProductCard key={p.id} product={p} vendor={vendors.find(v => v.id === p.vendorId)} isRecommended={true} />)}</div>
        </section>
      )}

      {/* Grid Area */}
      <div id="product-section" className="max-w-7xl mx-auto px-6 py-20">
        <div className="flex flex-col lg:flex-row gap-12">
          <aside className="lg:w-64 shrink-0 hidden lg:block">
            <div className="space-y-4">
                <h3 className="text-[10px] uppercase tracking-widest font-bold text-aura-purple flex items-center gap-2"><Building2 size={14} /> Ecosystem Map</h3>
                <div className="flex flex-col gap-1">
                    <button onClick={() => setSelectedVendorId(null)} className={`text-left px-4 py-2 rounded-xl text-xs ${!selectedVendorId ? 'bg-aura-purple text-white' : 'text-gray-400 hover:text-white'}`}>All Hub</button>
                    {vendors.filter(v => v.status === 'APPROVED').map(v => (
                        <button key={v.id} onClick={() => setSelectedVendorId(v.id)} className={`text-left px-4 py-2 rounded-xl text-xs ${selectedVendorId === v.id ? 'bg-aura-purple text-white' : 'text-gray-400 hover:text-white'}`}>{v.name}</button>
                    ))}
                </div>
            </div>
          </aside>

          <main className="flex-1">
            <h2 className="text-2xl font-serif font-bold flex items-center gap-4 mb-10"><Sparkles className="text-aura-purple" /> ট্রেন্ডিং কালেকশন</h2>
            <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-8">
                {filteredProducts.map(p => <ProductCard key={p.id} product={p} vendor={vendors.find(v => v.id === p.vendorId)} />)}
            </div>
          </main>
        </div>
      </div>
    </div>
  );
};

