        contents: {
            parts: [
                { inlineData: { data: userImg.split(',')[1], mimeType: 'image/jpeg' } },
                { inlineData: { data: productImg.split(',')[1], mimeType: 'image/jpeg' } },
                { text: "Overlay this garment onto the person naturally." }
            ]
        }
