                        {STYLE_PRESETS.map((p) => (
                            <button key={p.name} onClick={() => handleApplyPreset(p.prompt)} className="flex flex-col items-center gap-2 p-4 bg-white/5 border border-white/10 rounded-2xl hover:border-aura-purple transition-all">
