  }, [paramOrderId]);

  const fetchOrder = (id: string) => {
    setLoading(true);
    setError('');

    setTimeout(() => {
        const foundOrder = getOrderById(id);
        if (foundOrder) {
            setOrder(foundOrder);
        } else {
            setOrder(null);
            setError('অর্ডারটি খুঁজে পাওয়া যায়নি। দয়া করে Order ID টি চেক করুন। (Try: ORD-5001)');
        }
