export const VendorOnboarding: React.FC = () => {
  const [formData, setFormData] = useState({
    ownerName: '',
    shopName: '',
    description: '',
    contact: '',
    tradeLicense: ''
  });
  const [step, setStep] = useState(1);
  const [status, setStatus] = useState<'IDLE' | 'AUDITING' | 'SAVING' | 'SUCCESS' | 'REJECTED' | 'PENDING_HUB'>('IDLE');
  const [auditResult, setAuditResult] = useState<{ status: string; reason: string } | null>(null);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setStatus('AUDITING');

    const audit = await auditVendorDescription(formData.shopName, formData.description, formData.tradeLicense);
    setAuditResult(audit);

    if (audit.status === 'REJECTED') {
        setStatus('REJECTED');
        return;
    }

    setStatus('SAVING');
    const finalStatus = audit.status as 'APPROVED' | 'PENDING';

    const { error } = await submitVendorRequest({
        name: formData.shopName,
        description: formData.description,
        owner: formData.ownerName,
        contact: formData.contact,
        tradeLicense: formData.tradeLicense,
        status: finalStatus, 
        joined_at: new Date().toISOString()
    });

    if (error) {
        console.error(error);
        setStatus('IDLE');
    } else {
        setStatus(finalStatus === 'APPROVED' ? 'SUCCESS' : 'PENDING_HUB');
