import React, { useState, useEffect, createContext, useContext } from 'react';
import { Cpu, ShoppingBag, LayoutDashboard, Camera, PackageSearch, UserPlus, Heart, History, Sparkles } from 'lucide-react';

const RouterContext = createContext<{ path: string }>({ path: '/' });

export const HashRouter: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [path, setPath] = useState('/');
  useEffect(() => {
    const handleHashChange = () => {
      let hash = window.location.hash.slice(1);
      if (!hash) hash = '/';
      setPath(hash);
    };
    handleHashChange();
    window.addEventListener('hashchange', handleHashChange);
    return () => window.removeEventListener('hashchange', handleHashChange);
  }, []);
  return <RouterContext.Provider value={{ path }}>{children}</RouterContext.Provider>;
};

export const useLocation = () => useContext(RouterContext);

export const useParams = <T extends Record<string, string>>(): T => {
  const { path } = useContext(RouterContext);
  const parts = path.split('/');
  if (parts[1] === 'store' && parts[2]) return { slug: parts[2] } as any;
  if (parts[1] === 'try-on' && parts[2]) return { id: parts[2] } as any;
  if (parts[1] === 'tracking' && parts[2]) return { orderId: parts[2] } as any;
  if (parts[1] === 'orders' && parts[2]) return { orderId: parts[2] } as any;
  return {} as T;
};

export const Link: React.FC<{ to: string; className?: string; children: React.ReactNode }> = ({ to, className, children }) => (
  <a href={`#${to}`} className={className}>{children}</a>
);

export const Routes: React.FC<{ children: React.ReactNode }> = ({ children }) => <>{children}</>;
export const Route: React.FC<{ path: string; element: React.ReactNode }> = ({ path, element }) => {
  const { path: currentPath } = useContext(RouterContext);
  if (path === currentPath) return <>{element}</>;
  if (path.includes('/:')) {
      const base = path.split('/:')[0]; 
      if (currentPath.startsWith(base + '/') && currentPath.length > base.length + 1) return <>{element}</>;
  }
  return null;
};

