import React, { useState, useEffect, useRef, useMemo } from 'react';
import { startAuraChat, analyzeSearchIntent, SearchIntent, getAIRecommendations } from '../services/geminiService';
import { getProducts, getVendors, getLiveSales } from '../services/mockData';
import { ProductCard } from '../components/ProductCard';
import { ChatMessage, Product, Vendor } from '../types';
import { Sparkles, Send, MessageCircle, X, Search, Sparkle, Loader2, Building2, UserCheck, Cpu } from 'lucide-react';
import { GenerateContentResponse } from '@google/genai';

export const Home: React.FC = () => {
  const [allProducts, setAllProducts] = useState<Product[]>([]);
  const [vendors, setVendors] = useState<Vendor[]>([]);
  const [recommendations, setRecommendations] = useState<Product[]>([]);
  const [salesTicker, setSalesTicker] = useState(0);
  const [searchInput, setSearchInput] = useState('');
  const [isSearching, setIsSearching] = useState(false);
  const [selectedVendorId, setSelectedVendorId] = useState<number | null>(null);
  const [activeIntent, setActiveIntent] = useState<SearchIntent | null>(null);
  const [chatSession] = useState(() => startAuraChat());
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'ai', content: "আসসালামু আলাইকুম। Snehalata-স্নেহলতা ইকোসিস্টেমে স্বাগতম। আমি Aura AI। আজ আপনার জন্য কী খুঁজে দেব?", timestamp: Date.now() }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [isFloatingOpen, setIsFloatingOpen] = useState(false);
  const chatContainerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    setAllProducts(getProducts());
    setVendors(getVendors());
    setSalesTicker(getLiveSales());
    fetchRecommendations();
    const interval = setInterval(() => setSalesTicker(prev => prev + Math.floor(Math.random() * 500)), 5000);
    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    if (chatContainerRef.current) chatContainerRef.current.scrollTop = chatContainerRef.current.scrollHeight;
  }, [messages, isTyping]);

  const fetchRecommendations = async () => {
      const history = JSON.parse(localStorage.getItem('aura_browsing_history') || '[]');
      const recIds = await getAIRecommendations(history);
      const catalog = getProducts();
      setRecommendations(recIds.map(id => catalog.find(p => p.id === id)).filter(Boolean) as Product[]);
  };

  const handleSendMessage = async (e: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!input.trim() || isTyping) return;
    const userMsg: ChatMessage = { role: 'user', content: input, timestamp: Date.now() };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsTyping(true);
    try {
      const stream = await chatSession.sendMessageStream({ message: userMsg.content });
      setMessages(prev => [...prev, { role: 'ai', content: "", timestamp: Date.now() }]);
      let accumulated = "";
      for await (const chunk of stream) {
        const c = chunk as GenerateContentResponse;
        if (c.text) {
          accumulated += c.text;
          setMessages(prev => prev.map((m, i) => i === prev.length - 1 ? { ...m, content: accumulated } : m));
        }
      }
    } catch (err) {
      setMessages(prev => [...prev, { role: 'ai', content: "দুঃখিত, Aura সিস্টেম বর্তমানে ব্যস্ত। দয়া করে কিছুক্ষণ পর আবার চেষ্টা করুন।", timestamp: Date.now() }]);
    } finally {
      setIsTyping(false);
    }
  };

  const handleAISearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!searchInput.trim() || isSearching) return;
    setIsSearching(true);
    const intent = await analyzeSearchIntent(searchInput);
    if (intent) {
      setActiveIntent(intent);
      document.getElementById('product-section')?.scrollIntoView({ behavior: 'smooth' });
    }
    setIsSearching(false);
  };

  const filteredProducts = useMemo(() => {
    let result = [...allProducts];
    if (selectedVendorId) result = result.filter(p => p.vendorId === selectedVendorId);
    if (activeIntent) {
      if (activeIntent.category) result = result.filter(p => p.category.toLowerCase().includes(activeIntent.category!.toLowerCase()));
      if (activeIntent.maxPrice) result = result.filter(p => p.price <= activeIntent.maxPrice!);
    }
    return result;
  }, [allProducts, selectedVendorId, activeIntent]);

  return (
    <div className="min-h-screen">
      {/* Floating Chat */}
      <div className="fixed bottom-10 right-10 z-[100]">
          {!isFloatingOpen ? (
              <button onClick={() => setIsFloatingOpen(true)} className="w-16 h-16 bg-aura-purple rounded-full shadow-[0_0_40px_rgba(124,58,237,0.5)] flex items-center justify-center hover:scale-110 transition-all border border-white/20 animate-bounce">
                  <MessageCircle className="text-white" size={30} />
              </button>
          ) : (
              <div className="bg-aura-glass backdrop-blur-3xl border border-aura-glassBorder w-80 md:w-96 rounded-[2.5rem] shadow-2xl overflow-hidden animate-in zoom-in slide-in-from-bottom-10 flex flex-col h-[500px]">
                  <div className="p-6 bg-aura-purple flex justify-between items-center">
                      <div className="flex items-center gap-2 text-white text-xs font-black uppercase tracking-widest"><Sparkles size={16} /> Aura AI</div>
                      <button onClick={() => setIsFloatingOpen(false)} className="text-white/60 hover:text-white"><X size={20} /></button>
                  </div>
                  <div className="flex-1 p-4 overflow-y-auto space-y-4" ref={chatContainerRef}>
                      {messages.map((m, i) => (
                          <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                              <div className={`max-w-[85%] rounded-2xl p-4 text-xs ${m.role === 'user' ? 'bg-white text-black font-bold' : 'bg-white/5 text-gray-200 border border-white/10'}`}>{m.content}</div>
                          </div>
                      ))}
                  </div>
                  <form onSubmit={handleSendMessage} className="p-4 bg-black/40 border-t border-white/10 flex gap-2">
                      <input value={input} onChange={e => setInput(e.target.value)} placeholder="Aura কে কিছু জিজ্ঞাসা করুন..." className="flex-1 bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-xs text-white outline-none" />
                      <button className="p-3 bg-aura-purple text-white rounded-xl"><Send size={16} /></button>
                  </form>
              </div>
          )}
      </div>

      <section className="relative min-h-[500px] flex flex-col items-center justify-center px-6 pt-20">
        <div className="text-center space-y-6 max-w-4xl">
            <div className="inline-flex items-center gap-2 px-4 py-1.5 rounded-full border border-aura-glassBorder bg-white/5 backdrop-blur-md">
                <span className="text-[10px] uppercase tracking-[0.2em] font-black text-aura-purple">Live Volume: ৳{salesTicker.toLocaleString()}</span>
            </div>
            <h1 className="text-6xl md:text-8xl font-serif font-black text-white">SNEHALATA</h1>
            <p className="text-sm font-bold text-gray-500 uppercase tracking-[1em]">AURA ECOSYSTEM</p>

            <form onSubmit={handleAISearch} className="mt-12 relative flex items-center bg-black/80 backdrop-blur-3xl border border-white/10 rounded-[2.2rem] p-1.5 shadow-2xl w-full max-w-3xl mx-auto">
                <div className="pl-6 pr-4 text-aura-purple"><Search size={24} /></div>
                <input value={searchInput} onChange={(e) => setSearchInput(e.target.value)} placeholder="Discovery: red saree under 20k..." className="flex-1 bg-transparent border-none text-white py-6 text-lg focus:outline-none" />
                <button type="submit" className="bg-aura-purple text-white px-10 py-5 rounded-[1.8rem] font-black uppercase tracking-[0.2em] text-xs transition-all hover:bg-purple-600">
                    {isSearching ? <Loader2 className="animate-spin" /> : <Sparkle size={16} />}
                </button>
            </form>
        </div>
      </section>

      {/* Recommendations */}
      {recommendations.length > 0 && (
        <section className="max-w-7xl mx-auto px-6 pt-24">
            <div className="flex items-center gap-3 mb-8"><UserCheck className="text-aura-purple" size={28} /><h2 className="text-2xl font-serif font-bold text-white">Recommended for You</h2></div>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-8">{recommendations.map(p => <ProductCard key={p.id} product={p} vendor={vendors.find(v => v.id === p.vendorId)} isRecommended={true} />)}</div>
        </section>
      )}

      <div id="product-section" className="max-w-7xl mx-auto px-6 py-32">
        <div className="flex flex-col lg:flex-row gap-12">
          <aside className="lg:w-64 space-y-8 hidden lg:block">
            <h3 className="text-[10px] uppercase tracking-widest font-black text-aura-purple flex items-center gap-2"><Building2 size={14} /> Artisan Map</h3>
            <div className="flex flex-col gap-2">
                <button onClick={() => setSelectedVendorId(null)} className={`text-left px-5 py-3 rounded-2xl text-xs font-bold ${!selectedVendorId ? 'bg-aura-purple text-white shadow-xl' : 'text-gray-500 hover:text-white hover:bg-white/5 transition-all'}`}>All Hub</button>
                {vendors.filter(v => v.status === 'APPROVED').map(v => (
                    <button key={v.id} onClick={() => setSelectedVendorId(v.id)} className={`text-left px-5 py-3 rounded-2xl text-xs font-bold ${selectedVendorId === v.id ? 'bg-aura-purple text-white shadow-xl' : 'text-gray-500 hover:text-white hover:bg-white/5 transition-all'}`}>{v.name}</button>
                ))}
            </div>
          </aside>
          <main className="flex-1">
            <h2 className="text-2xl font-serif font-bold flex items-center gap-4 mb-10"><Cpu className="text-aura-purple" /> Trending Manifest</h2>
            <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-8">
                {filteredProducts.map(p => <ProductCard key={p.id} product={p} vendor={vendors.find(v => v.id === p.vendorId)} />)}
            </div>
          </main>
        </div>
      </div>
    </div>
  );
};

