import React, { useState, useEffect, useRef, useMemo } from 'react';
import { startAuraChat, analyzeSearchIntent, SearchIntent, getAIRecommendations } from '../services/geminiService';
import { getProducts, getVendors, getLiveSales } from '../services/mockData';
import { ProductCard } from '../components/ProductCard';
import { ChatMessage, Product, Vendor } from '../types';
import { Sparkles, Send, MessageCircle, X, Search, Sparkle, Loader2, Building2, UserCheck, Cpu } from 'lucide-react';
import { GenerateContentResponse } from '@google/genai';

export const Home: React.FC = () => {
  const [allProducts, setAllProducts] = useState<Product[]>([]);
  const [vendors, setVendors] = useState<Vendor[]>([]);
  const [recommendations, setRecommendations] = useState<Product[]>([]);
  const [salesTicker, setSalesTicker] = useState(0);
  const [searchInput, setSearchInput] = useState('');
  const [isSearching, setIsSearching] = useState(false);
  const [selectedVendorId, setSelectedVendorId] = useState<number | null>(null);
  const [activeIntent, setActiveIntent] = useState<SearchIntent | null>(null);
  const [chatSession] = useState(() => startAuraChat());
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'ai', content: "আসসালামু আলাইকুম। স্নেহলতা ইকোসিস্টেমে স্বাগতম। আমি Aura AI। আজ আপনার জন্য কী খুঁজে দেব?", timestamp: Date.now() }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [isFloatingOpen, setIsFloatingOpen] = useState(false);
  const chatContainerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    setAllProducts(getProducts());
    setVendors(getVendors());
    setSalesTicker(getLiveSales());
    fetchRecommendations();
    const interval = setInterval(() => setSalesTicker(prev => prev + Math.floor(Math.random() * 500)), 5000);
    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    if (chatContainerRef.current) chatContainerRef.current.scrollTop = chatContainerRef.current.scrollHeight;
  }, [messages, isTyping]);

  const fetchRecommendations = async () => {
      const history = JSON.parse(localStorage.getItem('aura_browsing_history') || '[]');
      const recIds = await getAIRecommendations(history);
      const catalog = getProducts();
      setRecommendations(recIds.map(id => catalog.find(p => p.id === id)).filter(Boolean) as Product[]);
  };

  const handleSendMessage = async (e: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!input.trim() || isTyping) return;
    const userMsg: ChatMessage = { role: 'user', content: input, timestamp: Date.now() };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsTyping(true);
    try {
      const stream = await chatSession.sendMessageStream({ message: userMsg.content });
      setMessages(prev => [...prev, { role: 'ai', content: "", timestamp: Date.now() }]);
      let accumulated = "";
      for await (const chunk of stream) {
        const c = chunk as GenerateContentResponse;
        if (c.text) {
          accumulated += c.text;
          setMessages(prev => prev.map((m, i) => i === prev.length - 1 ? { ...m, content: accumulated } : m));
        }
      }
    } catch (err) {
      setMessages(prev => [...prev, { role: 'ai', content: "দুঃখিত, Aura সিস্টেম বর্তমানে ব্যস্ত। দয়া করে কিছুক্ষণ পর আবার চেষ্টা করুন।", timestamp: Date.now() }]);
    } finally {
      setIsTyping(false);
    }
  };

  const handleAISearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!searchInput.trim() || isSearching) return;
    setIsSearching(true);
    const intent = await analyzeSearchIntent(searchInput);
    if (intent) {
      setActiveIntent(intent);
      document.getElementById('product-section')?.scrollIntoView({ behavior: 'smooth' });
    }
    setIsSearching(false);
  };

  const filteredProducts = useMemo(() => {
    let result = [...allProducts];
    if (selectedVendorId) result = result.filter(p => p.vendorId === selectedVendorId);
    if (activeIntent) {
      if (activeIntent.category) result = result.filter(p => p.category.toLowerCase().includes(activeIntent.category!.toLowerCase()));
      if (activeIntent.maxPrice) result = result.filter(p => p.price <= activeIntent.maxPrice!);
    }
    return result;
  }, [allProducts, selectedVendorId, activeIntent]);

  return (
    <div className="min-h-screen relative">
      {/* Floating Chat */}
      <div className="fixed bottom-10 right-10 z-[100]">
          {!isFloatingOpen ? (
              <button onClick={() => setIsFloatingOpen(true)} className="w-16 h-16 bg-aura-purple rounded-full shadow-[0_0_40px_rgba(124,58,237,0.5)] flex items-center justify-center hover:scale-110 transition-all border border-white/20 animate-bounce">
                  <MessageCircle className="text-white" size={30} />
              </button>
          ) : (
              <div className="bg-aura-black/90 backdrop-blur-3xl border border-aura-glassBorder w-80 md:w-96 rounded-[2.5rem] shadow-2xl overflow-hidden animate-in zoom-in slide-in-from-bottom-10 flex flex-col h-[500px]">
                  <div className="p-6 bg-aura-purple flex justify-between items-center shadow-lg">
                      <div className="flex items-center gap-2 text-white text-xs font-black uppercase tracking-widest"><Sparkles size={16} /> Aura AI</div>
                      <button onClick={() => setIsFloatingOpen(false)} className="text-white/60 hover:text-white"><X size={20} /></button>
                  </div>
                  <div className="flex-1 p-4 overflow-y-auto space-y-4 bg-gradient-to-b from-aura-deep/40 to-black" ref={chatContainerRef}>
                      {messages.map((m, i) => (
                          <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                              <div className={`max-w-[85%] rounded-2xl p-4 text-xs ${m.role === 'user' ? 'bg-white text-black font-bold' : 'bg-aura-purple/10 text-gray-200 border border-aura-purple/20 shadow-sm'}`}>{m.content}</div>
                          </div>
                      ))}
                  </div>
                  <form onSubmit={handleSendMessage} className="p-4 bg-black/40 border-t border-white/10 flex gap-2">
                      <input value={input} onChange={e => setInput(e.target.value)} placeholder="Aura কে কিছু জিজ্ঞাসা করুন..." className="flex-1 bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-xs text-white outline-none" />
                      <button className="p-3 bg-aura-purple text-white rounded-xl"><Send size={16} /></button>
                  </form>
              </div>
          )}
      </div>

      <section className="relative min-h-[600px] flex flex-col items-center justify-center px-6 pt-24 overflow-hidden">
        {/* Abstract Glow Shapes */}
        <div className="absolute top-[20%] left-[20%] w-96 h-96 bg-aura-purple/10 blur-[120px] rounded-full pointer-events-none"></div>
        <div className="absolute bottom-[20%] right-[20%] w-[30rem] h-[30rem] bg-indigo-900/10 blur-[150px] rounded-full pointer-events-none"></div>

        <div className="text-center space-y-8 max-w-5xl relative z-10">
            <div className="inline-flex items-center gap-2 px-6 py-2 rounded-full border border-aura-glassBorder bg-aura-purple/10 backdrop-blur-md">
                <span className="text-[10px] uppercase tracking-[0.3em] font-black text-aura-purple bn-heavy">লাইভ সেলস ভলিউম: ৳{salesTicker.toLocaleString()}</span>
            </div>
            <div className="space-y-2">
                <p className="text-sm font-bold text-gray-500 uppercase tracking-[1.5em] opacity-60">SNEHALATA</p>
                <h1 className="text-8xl md:text-[10rem] font-black text-white leading-none tracking-tighter bn-heavy drop-shadow-[0_0_30px_rgba(124,58,237,0.2)]">স্নেহলতা</h1>
                <p className="text-lg md:text-xl font-medium text-aura-purple/80 uppercase tracking-[0.5em] bn-heavy mt-4">আর্টিজান ইকোসিস্টেম</p>
            </div>

            <form onSubmit={handleAISearch} className="mt-16 relative flex items-center bg-white/[0.03] backdrop-blur-3xl border border-white/10 rounded-[2.5rem] p-2 shadow-[0_0_60px_rgba(0,0,0,0.5)] w-full max-w-3xl mx-auto group hover:border-aura-purple/30 transition-all">
                <div className="pl-8 pr-4 text-aura-purple group-focus-within:scale-110 transition-transform"><Search size={28} /></div>
                <input value={searchInput} onChange={(e) => setSearchInput(e.target.value)} placeholder="Discovery: নীল রঙের জামদানি..." className="flex-1 bg-transparent border-none text-white py-6 text-xl focus:outline-none placeholder:text-gray-700 bn-heavy" />
                <button type="submit" className="bg-aura-purple text-white px-12 py-5 rounded-[2rem] font-black uppercase tracking-[0.2em] text-sm transition-all hover:bg-purple-600 shadow-xl active:scale-95">
                    {isSearching ? <Loader2 className="animate-spin" /> : <Sparkle size={18} />}
                </button>
            </form>
        </div>
      </section>

      {/* Recommendations */}
      {recommendations.length > 0 && (
        <section className="max-w-7xl mx-auto px-6 pt-32">
            <div className="flex items-center gap-4 mb-10"><UserCheck className="text-aura-purple" size={32} /><h2 className="text-3xl font-serif font-bold text-white bn-heavy">আপনার জন্য রিকমেন্ডেশন</h2></div>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-10">{recommendations.map(p => <ProductCard key={p.id} product={p} vendor={vendors.find(v => v.id === p.vendorId)} isRecommended={true} />)}</div>
        </section>
      )}

      <div id="product-section" className="max-w-7xl mx-auto px-6 py-40">
        <div className="flex flex-col lg:flex-row gap-16">
          <aside className="lg:w-72 space-y-10 hidden lg:block">
            <h3 className="text-[10px] uppercase tracking-widest font-black text-aura-purple flex items-center gap-2 bn-heavy"><Building2 size={16} /> স্টোর ম্যাপ</h3>
            <div className="flex flex-col gap-3">
                <button onClick={() => setSelectedVendorId(null)} className={`text-left px-6 py-4 rounded-2xl text-xs font-bold transition-all ${!selectedVendorId ? 'bg-aura-purple text-white shadow-xl scale-105' : 'text-gray-500 hover:text-white hover:bg-white/5'}`}>সবগুলো</button>
                {vendors.filter(v => v.status === 'APPROVED').map(v => (
                    <button key={v.id} onClick={() => setSelectedVendorId(v.id)} className={`text-left px-6 py-4 rounded-2xl text-xs font-bold transition-all ${selectedVendorId === v.id ? 'bg-aura-purple text-white shadow-xl scale-105' : 'text-gray-500 hover:text-white hover:bg-white/5'}`}>{v.name}</button>
                ))}
