          <main className="flex-1">
            <h2 className="text-3xl font-serif font-bold flex items-center gap-5 mb-12 bn-heavy"><Cpu className="text-aura-purple" /> ট্রেন্ডিং কালেকশন</h2>
            <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-10">
                {filteredProducts.map(p => <ProductCard key={p.id} product={p} vendor={vendors.find(v => v.id === p.vendorId)} />)}
