import React, { useState, useEffect, useRef } from 'react';
import { MessageSquare, X, Send, Sparkles, Bot, User, Loader2, Cpu } from 'lucide-react';
import { startAuraChat } from '../services/geminiService';
import { ChatMessage } from '../types';

export const ChatAssistant: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const chatRef = useRef<any>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (isOpen && messages.length === 0) {
      // Initial greeting
      setMessages([{
        role: 'ai',
        content: 'আসসালামু আলাইকুম! আমি Aura AI। SNEHALATA ইকোসিস্টেমে আপনাকে স্বাগতম। আমি আপনাকে কীভাবে সাহায্য করতে পারি?',
        timestamp: Date.now()
      }]);
    }
  }, [isOpen]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isTyping) return;

    const userMsg: ChatMessage = {
      role: 'user',
      content: input,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsTyping(true);

    try {
      if (!chatRef.current) {
        chatRef.current = startAuraChat();
      }

      const response = await chatRef.current.sendMessage({ message: input });
      const aiMsg: ChatMessage = {
        role: 'ai',
        content: response.text || 'দুঃখিত, আমি এই মুহূর্তে সংযোগ করতে পারছি না।',
        timestamp: Date.now()
      };
      setMessages(prev => [...prev, aiMsg]);
    } catch (error) {
      setMessages(prev => [...prev, {
        role: 'ai',
        content: 'একটি টেকনিক্যাল সমস্যা হয়েছে। দয়া করে কিছুক্ষণ পর আবার চেষ্টা করুন।',
        timestamp: Date.now()
      }]);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <div className="fixed bottom-8 right-8 z-[150] font-sans">
      {/* Floating Toggle Button */}
      <button
        onClick={() => setIsOpen(!isOpen)}
        className={`w-16 h-16 rounded-2xl flex items-center justify-center shadow-2xl transition-all duration-500 group relative overflow-hidden ${
          isOpen ? 'bg-white text-black rotate-90 scale-90' : 'bg-aura-purple text-white hover:scale-110 active:scale-95'
        }`}
      >
        <div className="absolute inset-0 bg-gradient-to-tr from-white/20 to-transparent opacity-0 group-hover:opacity-100 transition-opacity" />
        {isOpen ? <X size={28} /> : <MessageSquare size={28} />}
        {!isOpen && (
          <div className="absolute -top-1 -right-1 w-4 h-4 bg-red-500 rounded-full border-2 border-black animate-pulse" />
        )}
      </button>

      {/* Chat Window */}
      {isOpen && (
        <div className="absolute bottom-20 right-0 w-[400px] max-w-[calc(100vw-2rem)] h-[600px] max-h-[calc(100vh-10rem)] bg-aura-glass border border-aura-glassBorder rounded-[2.5rem] shadow-2xl backdrop-blur-3xl flex flex-col overflow-hidden animate-in slide-in-from-bottom-10 fade-in duration-500">
          {/* Header */}
          <header className="p-6 bg-white/5 border-b border-white/5 flex items-center justify-between relative overflow-hidden">
            <div className="absolute top-0 left-0 w-full h-full bg-aura-purple/5 blur-[40px] pointer-events-none" />
            <div className="flex items-center gap-3 relative z-10">
              <div className="w-10 h-10 bg-aura-purple/20 rounded-xl flex items-center justify-center border border-aura-purple/30">
                <Cpu className="text-aura-purple animate-pulse" size={20} />
              </div>
              <div>
                <h3 className="text-white font-bold text-sm tracking-widest flex items-center gap-2">
                  AURA AI জিজ্ঞাসা <Sparkles size={12} className="text-aura-purple" />
                </h3>
                <p className="text-[9px] uppercase tracking-[0.2em] text-green-400 font-black">Neural Link Active</p>
              </div>
            </div>
          </header>

          {/* Messages Area */}
          <div className="flex-1 overflow-y-auto p-6 space-y-6 scrollbar-hide">
            {messages.map((msg, idx) => (
              <div
                key={idx}
                className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-in fade-in slide-in-from-bottom-2`}
              >
                <div className={`flex gap-3 max-w-[85%] ${msg.role === 'user' ? 'flex-row-reverse' : ''}`}>
                  <div className={`w-8 h-8 rounded-lg shrink-0 flex items-center justify-center border ${
                    msg.role === 'user' ? 'bg-white/10 border-white/10' : 'bg-aura-purple/20 border-aura-purple/30'
                  }`}>
                    {msg.role === 'user' ? <User size={14} className="text-gray-400" /> : <Bot size={14} className="text-aura-purple" />}
                  </div>
                  <div className={`p-4 rounded-2xl text-xs leading-relaxed ${
                    msg.role === 'user' 
                    ? 'bg-white text-black font-medium rounded-tr-none' 
                    : 'bg-white/5 text-gray-200 border border-white/5 rounded-tl-none'
                  }`}>
                    {msg.content}
                  </div>
                </div>
              </div>
            ))}
            {isTyping && (
              <div className="flex justify-start animate-pulse">
                <div className="bg-white/5 border border-white/5 p-4 rounded-2xl rounded-tl-none flex gap-2">
                  <div className="w-1.5 h-1.5 bg-aura-purple rounded-full animate-bounce" />
                  <div className="w-1.5 h-1.5 bg-aura-purple rounded-full animate-bounce [animation-delay:0.2s]" />
                  <div className="w-1.5 h-1.5 bg-aura-purple rounded-full animate-bounce [animation-delay:0.4s]" />
                </div>
              </div>
            )}
            <div ref={messagesEndRef} />
          </div>

          {/* Input Area */}
          <form onSubmit={handleSendMessage} className="p-6 bg-white/5 border-t border-white/5">
            <div className="relative flex items-center">
              <input
                type="text"
                value={input}
                onChange={(e) => setInput(e.target.value)}
                placeholder="আপনার প্রশ্নটি লিখুন..."
                className="w-full bg-black/40 border border-white/10 rounded-xl pl-5 pr-14 py-4 text-xs text-white focus:outline-none focus:border-aura-purple transition-all placeholder:text-gray-700"
              />
              <button
                type="submit"
                disabled={!input.trim() || isTyping}
                className={`absolute right-2 p-2 rounded-lg transition-all ${
                  !input.trim() || isTyping ? 'text-gray-600' : 'text-aura-purple hover:bg-aura-purple hover:text-white'
                }`}
              >
                {isTyping ? <Loader2 size={18} className="animate-spin" /> : <Send size={18} />}
              </button>
            </div>
            <p className="text-[8px] text-center text-gray-600 uppercase tracking-widest font-black mt-4">
              Powered by Aura Neural Hub • Gemini 3.0 Pro
            </p>
          </form>
        </div>
      )}
    </div>
  );
};

