    };
};

export const mapsGroundedAura = async (query: string, lat?: number, lng?: number) => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const config: any = { tools: [{ googleMaps: {} }] };
    if (lat && lng) {
